@app.before_request
def before_request():
    """
    HTTPリクエストごとに利用するGeminiプロジェクトをランダムに1つ選択する。
    同一HTTPリクエスト内の複数のAI呼び出しでは、ここで選択されたプロジェクトを共有して利用する。
    """
    targets = getattr(config, "GEMINI_API_TARGETS", [])
    if targets:
        chosen = random.choice(targets)
        g.google_cloud_name = chosen["name"]
    else:
        # 分散設定がない場合は従来通り単一構成とみなし、特に指定しない
        g.google_cloud_name = config.GOOGLE_CLOUD_NAME
        
    # --- ユーザー情報を取得して g.user_info にセット
    try:
        user_info = get_entra_user_info(request)

    except Exception as e:
        logger.error(f"Failed to get user info: {e}", exc_info=True)
        user_info = {
            "userId": "unknown",
            "userName": "Unknown User",
            "userEmail": None,
        }
    g.user_info = user_info
    logger.info(f"path:{request.path} - userId:{user_info.get('userId')} - userName:{user_info.get('userName')} - userEmail:{user_info.get('userEmail')} - Selected Gemini API target:{g.google_cloud_name}")


@app.after_request
def after_request(response):
    """
    各HTTPレスポンス後に実行される処理。
    リクエスト処理の成否を出力する。
    """
    logger.info(f"Response status: {response.status}")
    return response

