executor = ThreadPoolExecutor(max_workers=max(4, os.cpu_count() or 1))


def _submit_with_request_id(fn, *args, **kwargs):
    """現在のHTTPリクエストのrequest_idをバックグラウンドタスクに伝播させて実行するヘルパー。"""

    try:
        req_id = current_request_id()
    except Exception:
        req_id = None

    def _wrapped(*inner_args, **inner_kwargs):
        # バックグラウンドスレッド側で request_id をスレッドローカルに設定
        customLogger.set_request_id_for_current_thread(req_id)
        return fn(*inner_args, **inner_kwargs)

    return executor.submit(_wrapped, *args, **kwargs)

