@app.route('/api/admin/token_usage', methods=['GET'])
def get_token_usage_stats():
    """
    トークン使用量集計API
    クエリパラメータ: start_date (YYYY-MM-DD), end_date (YYYY-MM-DD)
    """
    # 日付のデフォルトは「今日」
    today = datetime.now(timezone.utc)
    start_str = request.args.get('start_date')
    end_str = request.args.get('end_date')

    try:
        if start_str:
            start_date = datetime.strptime(start_str, '%Y-%m-%d').replace(tzinfo=timezone.utc)
        else:
            start_date = today

        if end_str:
            end_date = datetime.strptime(end_str, '%Y-%m-%d').replace(tzinfo=timezone.utc)
        else:
            end_date = today
        
        # 終了日はその日の終わりまで含めるため、時刻を調整するか翌日の0時にする等の考慮が必要
        # ここでは簡易的に start <= date <= end で判定するため、時間はそのまま扱います
        
        result = aggregate_token_usage(start_date, end_date)
        return jsonify(result)

    except Exception as e:
        logger.error(f"Analytics error: {e}", exc_info=True)
        return jsonify({"error": str(e)}), 500

