# Entra ID ユーザー情報取得ヘルパー
def get_entra_user_info(current_request):
    user_id = current_request.headers.get("X-MS-CLIENT-PRINCIPAL-ID")
    principal_name = current_request.headers.get("X-MS-CLIENT-PRINCIPAL-NAME")
    user_email = principal_name  # 初期値として設定
    user_name = principal_name   # 初期値として設定 (UPNが使われる)

    client_principal_b64 = current_request.headers.get("X-MS-CLIENT-PRINCIPAL")

    # デバッグ用に初期取得値をログに出力
    logger.debug(f"Initial user_id from X-MS-CLIENT-PRINCIPAL-ID: {user_id}")
    logger.debug(f"Initial principal_name from X-MS-CLIENT-PRINCIPAL-NAME: {principal_name}")
    logger.debug(f"Base64 client_principal from X-MS-CLIENT-PRINCIPAL: {'Present' if client_principal_b64 else 'Not Present'}")

    if client_principal_b64:
        try:
            client_principal_json = base64.b64decode(client_principal_b64).decode('utf-8')
            client_principal_data = json.loads(client_principal_json)
            
            claims = client_principal_data.get("claims", [])
            logger.debug(f"X-MS-CLIENT-PRINCIPAL claims: {claims}")

            for claim in claims:
                claim_type = claim.get("typ", "").lower()
                claim_value = claim.get("val")

                if claim_type == "name":
                    user_name = claim_value
                elif claim_type == "email":
                    user_email = claim_value
                elif claim_type == "preferred_username" and "@" in claim_value and (user_email == principal_name or not user_email): # principal_nameもメール形式でない場合を考慮
                    user_email = claim_value
                elif claim_type == "http://schemas.microsoft.com/identity/claims/objectidentifier" or claim_type == "oid":
                    if not user_id: # X-MS-CLIENT-PRINCIPAL-IDが取れていない場合のフォールバック
                        logger.debug(f"Falling back to oid/objectidentifier for user_id: {claim_value}")
                        user_id = claim_value
                elif claim_type == "sub":
                     if not user_id: # 更なるフォールバック
                        logger.debug(f"Falling back to sub for user_id: {claim_value}")
                        user_id = claim_value
            
            if user_email == principal_name and principal_name and "@" not in principal_name:
                user_email = None 

        except Exception as e:
            logger.error(f"Failed to parse X-MS-CLIENT-PRINCIPAL header: {e}", exc_info=True)

    if not user_id:
        logger.warning("User ID (X-MS-CLIENT-PRINCIPAL-ID or from claims) could not be retrieved.")
    if not user_name: # user_name が principal_name のまま、かつ principal_name が None だった場合など
        user_name = "Unknown User"
        logger.warning("User Name could not be retrieved, set to 'Unknown User'.")
    if not user_email:
        logger.warning("User Email could not be retrieved from claims or UPN.")
        # UPNがメール形式でなかった場合など、user_emailはNoneのままになることがある

    user_info_result = {
        "userId": user_id or "local-dev-user", # ローカル用フォールバック
        "userName": user_name or "Local Dev User", # ローカル用フォールバック
        "userEmail": user_email or "local-dev@example.com" # ローカル用フォールバック
    }
    logger.info(f"Returning: {json.dumps(user_info_result)}")
    return user_info_result

