# === 新しいAPIエンドポイント: チャットプロンプト用 ===
@app.route('/api/chat/prompt_categories', methods=['GET'])
def list_chat_prompt_categories_endpoint():
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    
    # 1. GCSから共有カテゴリを取得
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    base_folder = os.environ.get("GCS_CHAT_PROMPT_BASE_FOLDER", "prompts/")
    if not base_folder.endswith('/'): base_folder += '/'
    
    shared_categories = []
    if gcs_bucket_name:
        gcs_cats = _list_gcs_folders_in_prefix(gcs_bucket_name, base_folder)
        if gcs_cats:
            shared_categories = [{"name": cat, "isPersonal": False} for cat in gcs_cats]

    # 2. Cosmos DBから個人用カテゴリを取得
    personal_categories = []
    if user_id:
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                query = "SELECT DISTINCT c.category FROM c WHERE c.userId = @userId AND c.type = 'PersonalChatPrompt' AND IS_DEFINED(c.category)"
                params = [{"name": "@userId", "value": user_id}]
                # enable_cross_partition_query は partition_key を指定すれば不要
                items = sessions_container.query_items(query=query, parameters=params, partition_key=user_id)
                personal_cats_list = [item['category'] for item in items if item.get('category')]
                personal_categories = [{"name": cat, "isPersonal": True} for cat in sorted(list(set(personal_cats_list)))]
            except Exception as e:
                logger.error(f"Failed to fetch personal chat prompt categories for user {user_id}: {e}")

    # 3. マージして返す
    all_categories = sorted(shared_categories + personal_categories, key=lambda x: x['name'])
    return jsonify({"categories": all_categories})

@app.route('/api/chat/prompts_in_category', methods=['GET'])
def list_chat_prompts_in_category_endpoint():
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    category = request.args.get('category')
    is_personal_str = request.args.get('isPersonal', 'false').lower()

    if not category:
        return jsonify({"error": "カテゴリが指定されていません。"}), 400

    # 共有プロンプトの取得
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    base_folder = os.environ.get("GCS_CHAT_PROMPT_BASE_FOLDER", "prompts/")
    if not base_folder.endswith('/'): base_folder += '/'
    
    prompts = []
    
    # isPersonalがfalseまたは指定なしの場合、GCSから共有プロンプトを取得
    if is_personal_str == 'false':
        if gcs_bucket_name:
            category_prefix = f"{base_folder}{category}/"
            gcs_prompts = _list_gcs_files_in_prefix(gcs_bucket_name, category_prefix, extension_filter=".txt")
            if gcs_prompts:
                prompts.extend([{"name": p_name, "isPersonal": False} for p_name in gcs_prompts])

    # ユーザーがログインしており、isPersonalがtrueの場合、Cosmos DBから個人用プロンプトを取得
    if user_id and is_personal_str == 'true':
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                query = "SELECT c.promptName FROM c WHERE c.userId = @userId AND c.type = 'PersonalChatPrompt' AND c.category = @category"
                params = [{"name": "@userId", "value": user_id}, {"name": "@category", "value": category}]
                items = sessions_container.query_items(query=query, parameters=params, partition_key=user_id)
                personal_prompts_list = [item['promptName'] for item in items if item.get('promptName')]
                prompts.extend([{"name": p_name, "isPersonal": True} for p_name in sorted(list(set(personal_prompts_list)))])
            except Exception as e:
                logger.error(f"Failed to fetch personal chat prompts for user {user_id} in category {category}: {e}")
                return jsonify({"error": f"個人用プロンプトの取得に失敗しました。"}), 500
    
    return jsonify({"prompts": prompts})

@app.route('/api/chat/prompt_content', methods=['GET'])
def get_chat_prompt_content_endpoint():
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    category = request.args.get('category')
    prompt_name = request.args.get('prompt_name')
    is_personal_str = request.args.get('isPersonal', 'false').lower()

    if not category or not prompt_name:
        return jsonify({"error": "カテゴリまたはプロンプト名が指定されていません。"}), 400

    content = None
    if is_personal_str == 'true':
        # 個人用プロンプトをCosmos DBから取得
        if not user_id:
            return jsonify({"error": "個人用プロンプトの取得にはログインが必要です。"}), 401
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                # IDで直接ドキュメントを特定する
                prompt_id = f"chatprompt_{user_id}_{category}_{prompt_name}"
                item = sessions_container.read_item(item=prompt_id, partition_key=user_id)
                content = item.get('promptContent')
            except cosmos_exceptions.CosmosResourceNotFoundError:
                logger.warning(f"Personal chat prompt not found with ID: {prompt_id}")
                return jsonify({"error": "指定された個人用プロンプトが見つかりません。"}), 404
            except Exception as e:
                logger.error(f"Failed to read personal chat prompt {prompt_id}: {e}")
                return jsonify({"error": "個人用プロンプトの読み込みに失敗しました。"}), 500
    else:
        # 共有プロンプトをGCSから取得 (既存ロジック)
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        base_folder = os.environ.get("GCS_CHAT_PROMPT_BASE_FOLDER", "prompts/")
        if not base_folder.endswith('/'): base_folder += '/'
        if not gcs_bucket_name:
            return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500
        
        file_path = f"{base_folder.rstrip('/')}/{category.strip('/')}/{prompt_name}.txt"
        content = _load_gcs_prompt_content(gcs_bucket_name, file_path)

    if content is not None:
        return jsonify({"content": content})
    else:
        return jsonify({"error": "プロンプト内容の読み込みに失敗しました。"}), 404

# --- 新しいAPIエンドポイント: チャットプロンプト存在確認 ---
@app.route('/api/chat/prompts/exists', methods=['GET'])
def check_chat_prompt_exists_endpoint():
    category_name_raw = request.args.get('category')
    prompt_name_raw = request.args.get('prompt_name')

    if not category_name_raw or not prompt_name_raw:
        return jsonify({"error": "カテゴリ名とプロンプト名が必要です。"}), 400

    category_name = _sanitize_gcs_object_name_part(category_name_raw, is_folder=True)
    prompt_filename_base = _sanitize_gcs_object_name_part(prompt_name_raw)

    if not category_name or not prompt_filename_base:
        return jsonify({"error": "カテゴリ名またはプロンプト名が無効です。"}), 400

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    base_folder = os.environ.get("GCS_CHAT_PROMPT_BASE_FOLDER", "prompts/")
    if not base_folder.endswith('/'): base_folder += '/'

    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    prompt_file_path_on_gcs = f"{base_folder.rstrip('/')}/{category_name}/{prompt_filename_base}.txt"
    
    exists = _gcs_blob_exists(gcs_bucket_name, prompt_file_path_on_gcs)
    
    return jsonify({"exists": exists, "path_checked": prompt_file_path_on_gcs})

# === 新しいAPIエンドポイント: チャットプロンプト集へのアップロード ===
@app.route('/api/chat/prompts/upload', methods=['POST'])
def upload_chat_prompt_endpoint():
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    data = request.get_json()
    
    category = data.get('category')
    prompt_name = data.get('prompt_name')
    prompt_content = data.get('prompt_content')
    save_as_personal = data.get('saveAsPersonal', False)
    overwrite = data.get('overwrite', False)

    if not all([category, prompt_name, prompt_content]):
        return jsonify({"error": "カテゴリ、プロンプト名、内容は必須です。"}), 400

    if save_as_personal:
        # 個人用プロンプトとしてCosmos DBに保存
        if not user_id:
            return jsonify({"error": "個人用プロンプトの保存にはログインが必要です。"}), 401
        sessions_container = get_sessions_container()
        if not sessions_container:
            return jsonify({"error": "個人用プロンプトを保存するデータベースが利用できません。"}), 500
        
        try:
            prompt_id = f"chatprompt_{user_id}_{category}_{prompt_name}"
            
            if not overwrite:
                try:
                    sessions_container.read_item(item=prompt_id, partition_key=user_id)
                    return jsonify({"success": False, "exists": True, "message": "同じ名前の個人用プロンプトが既に存在します。上書きしますか？"}), 200
                except cosmos_exceptions.CosmosResourceNotFoundError:
                    pass # 存在しないので処理を続行

            prompt_doc = {
                "id": prompt_id,
                "userId": user_id,
                "type": "PersonalChatPrompt",
                "category": category,
                "promptName": prompt_name,
                "promptContent": prompt_content,
                "createdAt": datetime.now(timezone.utc).isoformat()
            }
            sessions_container.upsert_item(body=prompt_doc)
            return jsonify({"success": True, "message": "個人用プロンプトとして保存しました。"})
        except Exception as e:
            logger.error(f"Failed to save personal chat prompt for user {user_id}: {e}")
            return jsonify({"error": "個人用プロンプトの保存に失敗しました。"}), 500

    else:
        # 共有プロンプトとしてGCSに保存 (既存ロジック)
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        base_folder = os.environ.get("GCS_CHAT_PROMPT_BASE_FOLDER", "prompts/")
        if not base_folder.endswith('/'): base_folder += '/'
        if not gcs_bucket_name:
            return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

        prompt_file_path = f"{base_folder.rstrip('/')}/{category}/{prompt_name}.txt"
        
        if not overwrite and _gcs_blob_exists(gcs_bucket_name, prompt_file_path):
            return jsonify({"success": False, "exists": True, "message": "同じ名前の共有プロンプトが既に存在します。上書きしますか？"}), 200

        gcs_uri = _upload_text_to_gcs(gcs_bucket_name, prompt_file_path, prompt_content)
        if gcs_uri:
            return jsonify({"success": True, "message": "共有プロンプトとして保存しました。", "gcs_path": gcs_uri})
        else:
            return jsonify({"error": "共有プロンプトの保存に失敗しました。"}), 500


# --- 新しいAPIエンドポイント: System Prompt存在確認 ---
@app.route('/api/chat/system_prompts/exists', methods=['GET'])
def check_system_prompt_exists_endpoint():
    prompt_name_raw = request.args.get('prompt_name')
    if not prompt_name_raw:
        return jsonify({"error": "System Prompt名が指定されていません。"}), 400

    prompt_filename_base = _sanitize_gcs_object_name_part(prompt_name_raw)
    if not prompt_filename_base:
        return jsonify({"error": "無効なSystem Prompt名です。"}), 400

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    system_prompt_base_folder = get_system_prompt_base_folder()
    file_path_on_gcs = f"{system_prompt_base_folder.rstrip('/')}/{prompt_filename_base}.txt"
    
    exists = _gcs_blob_exists(gcs_bucket_name, file_path_on_gcs)
    
    return jsonify({"exists": exists, "path_checked": file_path_on_gcs})

def get_system_prompt_base_folder():
    folder = os.environ.get(config.GCS_SYSTEM_PROMPT_BASE_FOLDER_VAR_NAME, config.GCS_SYSTEM_PROMPT_BASE_FOLDER_DEFAULT)
    if not folder.endswith('/'):
        folder += '/'
    return folder

def fetch_m365_content(access_token, item_type, item_id, raw_data=None):
    """
    Microsoft Graph APIを使用してM365アイテムのコンテンツを取得する。
    m365_search.py のロジックを再利用・統合。
    """
    if not access_token:
        logger.error("fetch_m365_content: No access token provided.")
        return None, None

    headers = {"Authorization": f"Bearer {access_token}"}
    content = ""
    title = "Unknown Item"
    
    # raw_dataが文字列で渡された場合はJSONパースを試みる
    if isinstance(raw_data, str):
        try:
            raw_data = json.loads(raw_data)
        except json.JSONDecodeError:
            raw_data = {}
    elif raw_data is None:
        raw_data = {}

    try:
        if item_type == 'mail':
            # ... (メール取得ロジックは変更なし) ...
            safe_item_id = requests.utils.quote(str(item_id), safe='')
            mail_headers = headers.copy()
            mail_headers['Prefer'] = 'outlook.body-content-type="text"'
            
            try:
                url = f"https://graph.microsoft.com/v1.0/me/messages/{safe_item_id}?$select=body,subject"
                resp = requests.get(url, headers=mail_headers)
                resp.raise_for_status()
                data = resp.json()
                content = data.get("body", {}).get("content", "")
                title = data.get("subject", "No Subject")
            except requests.exceptions.HTTPError:
                # フォールバック
                sender_upn = (raw_data.get('sender') or raw_data.get('from') or {}).get('emailAddress', {}).get('address')
                if sender_upn:
                    safe_upn = requests.utils.quote(sender_upn, safe='')
                    url = f"https://graph.microsoft.com/v1.0/users/{safe_upn}/messages/{safe_item_id}?$select=body,subject"
                    resp = requests.get(url, headers=mail_headers)
                    resp.raise_for_status()
                    data = resp.json()
                    content = data.get("body", {}).get("content", "")
                    title = data.get("subject", "No Subject")
                else:
                    raise

        elif item_type == 'teams' or item_type == 'teams_message':
            # Teamsメッセージを取得
            # raw_dataから必要なIDを取得
            channel_info = raw_data.get('channelIdentity')
            team_id = channel_info.get('teamId') if channel_info else raw_data.get('teamId')
            channel_id = channel_info.get('channelId') if channel_info else raw_data.get('channelId')
            chat_id = raw_data.get('chatId')
            
            # 単一メッセージの本文がすでにrawDataにある場合
            if raw_data.get('body', {}).get('content'):
                 body_content = raw_data.get('body', {}).get('content', '')
                 content = re.sub(r'<[^>]+?>', '', body_content).strip()
                 title = f"Teams Message ({item_id})"
            
            # メッセージ一覧を取得する場合（チャネルやチャット全体を指定された場合）
            elif team_id and channel_id:
                safe_team_id = requests.utils.quote(team_id, safe='')
                safe_channel_id = requests.utils.quote(channel_id, safe='')
                url = f"https://graph.microsoft.com/v1.0/teams/{safe_team_id}/channels/{safe_channel_id}/messages?$top=50"
                resp = requests.get(url, headers=headers)
                resp.raise_for_status()
                messages = resp.json().get('value', [])
                title = f"Teams Channel Messages"
                
                def html_to_text(h): return re.sub(r'<[^>]+?>', '', h or '').strip()
                messages.sort(key=lambda x: x.get('createdDateTime') or '')
                lines = []
                for msg in messages:
                    body_content = msg.get('body', {}).get('content', '')
                    text_content = html_to_text(body_content)
                    if not text_content: continue
                    sender_name = (msg.get('from', {}).get('user', {}) or {}).get('displayName', 'Unknown')
                    created_time = msg.get('createdDateTime', '')
                    lines.append(f"[{created_time}] {sender_name}: {text_content}")
                content = "\n".join(lines)

        elif item_type == 'file':
            # ファイルコンテンツを取得 (OneDrive/SharePoint)
            # raw_data内の driveId を優先、なければ parentReference 内を確認
            drive_id = raw_data.get('driveId')
            if not drive_id:
                parent_ref = raw_data.get('parentReference', {})
                drive_id = parent_ref.get('driveId')
            
            safe_item_id = requests.utils.quote(str(item_id), safe='')
            
            download_url = ""
            if drive_id:
                safe_drive_id = requests.utils.quote(drive_id, safe='')
                download_url = f"https://graph.microsoft.com/v1.0/drives/{safe_drive_id}/items/{safe_item_id}/content"
            else:
                # driveIdがない場合は /me/drive (個人のOneDrive) を試行
                download_url = f"https://graph.microsoft.com/v1.0/me/drive/items/{safe_item_id}/content"
            
            resp = requests.get(download_url, headers=headers)
            resp.raise_for_status()
            file_bytes = resp.content
            
            filename = raw_data.get('name', 'unknown_file')
            title = filename
            
            # 簡易的なテキスト抽出 (拡張子判定)
            if filename.lower().endswith('.pdf'):
                import fitz
                with fitz.open(stream=file_bytes, filetype="pdf") as doc:
                    content = "".join([page.get_text() for page in doc])
            elif filename.lower().endswith('.docx'):
                import docx
                doc = docx.Document(io.BytesIO(file_bytes))
                content = "\n".join([p.text for p in doc.paragraphs])
            elif filename.lower().endswith('.pptx'):
                from pptx import Presentation
                prs = Presentation(io.BytesIO(file_bytes))
                text_runs = []
                for slide in prs.slides:
                    for shape in slide.shapes:
                        if hasattr(shape, "text"):
                            text_runs.append(shape.text)
                content = "\n".join(text_runs)
            else:
                # テキストファイルとして試行
                content = file_bytes.decode('utf-8', errors='ignore')

    except Exception as e:
        logger.error(f"Error fetching M365 content (Type: {item_type}, ID: {item_id}): {e}", exc_info=True)
        return None, None

    return content, title

@app.route('/api/chat/system_prompts/upload', methods=['POST'])
def upload_system_prompt_endpoint():
    """
    System Promptの登録と、RAGが有効な場合はナレッジベースの構築を行うエンドポイント。
    フォルダ管理対応: prompt_name にパス区切り文字('/')が含まれる場合に対応。
    """
    import re # 正規表現モジュールが必要

    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"success": False, "error": "認証されていません。"}), 401

    try:
        # FormDataからデータを取得
        prompt_name = request.form.get('prompt_name')
        prompt_content = request.form.get('prompt_content')
        save_as_personal = request.form.get('saveAsPersonal') == 'true'
        is_confidential = request.form.get('system_instruction_conf') == 'true'
        
        # RAG関連のパラメータを取得
        rag_enabled = request.form.get('rag_enabled') == 'true'
        rag_mode = request.form.get('rag_mode', 'persona')
        rag_use_ai_extraction = request.form.get('rag_use_ai_extraction') == 'true'
        rag_files_storage = request.files.getlist('rag_files')

        persona_id_from_form = request.form.get('persona_id_for_rag')
        
        # M365参照データの取得
        m365_references_json = request.form.get('m365_references', '[]')
        m365_references = []
        try:
            m365_references = json.loads(m365_references_json)
        except json.JSONDecodeError:
            logger.warning("Failed to parse m365_references JSON.")

        if not all([prompt_name, prompt_content]):
            return jsonify({"success": False, "error": "プロンプト名と内容は必須です。"}), 400
        
        # パス・トラバーサル対策
        if '..' in prompt_name or prompt_name.startswith('/'):
             return jsonify({"success": False, "error": "無効なファイルパスです。"}), 400

        icon_data = request.form.get('icon_data')

        persona_id_for_rag = None

        # RAGが有効な場合の処理
        if rag_enabled:
            # 1. ファイル数チェック
            total_items_count = len(rag_files_storage) + len(m365_references)
            if total_items_count > config.MAX_RAG_FILES_PER_PROMPT:
                return jsonify({
                    "success": False,
                    "error": f"RAGに登録できるアイテム数は最大{config.MAX_RAG_FILES_PER_PROMPT}個までです。現在 {total_items_count}個選択されています。"
                }), 400

            # 1.5. 全てのファイルを一度だけ読み込み、メモリに保持する
            in_memory_files = []
            
            # ローカルアップロードファイルの処理
            for file_storage in rag_files_storage:
                filename = os.path.basename(file_storage.filename)
                if filename:
                    file_bytes = file_storage.read()
                    in_memory_files.append({'name': filename, 'bytes': file_bytes, 'type': 'file'})

            # M365アイテムの処理
            auth_token = request.headers.get('x-ms-token-aad-access-token')
            if m365_references and not auth_token:
                return jsonify({"success": False, "error": "M365アイテムを処理するための認証トークンが取得できませんでした。"}), 401

            if m365_references:
                # M365アイテムの展開処理
                expanded_references = []
                
                for ref in m365_references:
                    item_type = ref.get('type')
                    # チャット系アイテムかどうかの判定
                    is_chat_item = (item_type in ['chat', 'meeting', 'oneOnOne', 'group']) or (ref.get('chatType') is not None)
                    
                    # コンテナフラグの確認
                    is_container = ref.get('isContainer')
                    
                    # チャット系の場合はコンテナフラグを無視して展開しない
                    if is_container and not is_chat_item:
                        item_id = ref.get('id')
                        try:
                            if item_type == 'folder' and ref.get('driveId'): 
                                # SharePoint / OneDrive Folder
                                drive_id = ref.get('driveId')
                                url = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/items/{item_id}/children"
                                resp = requests.get(url, headers={"Authorization": f"Bearer {auth_token}"})
                                if resp.ok:
                                    children = resp.json().get('value', [])
                                    for child in children:
                                        if 'file' in child:
                                            expanded_references.append({
                                                'type': 'file', 
                                                'id': child['id'], 
                                                'title': child.get('name'), 
                                                'driveId': drive_id,
                                                'rawData': child
                                            })
                            
                            elif item_type == 'folder' and not ref.get('driveId'):
                                # Outlook Folder
                                url = f"https://graph.microsoft.com/v1.0/me/mailFolders/{item_id}/messages?$top=50"
                                resp = requests.get(url, headers={"Authorization": f"Bearer {auth_token}"})
                                if resp.ok:
                                    messages = resp.json().get('value', [])
                                    for msg in messages:
                                        expanded_references.append({
                                            'type': 'mail',
                                            'id': msg['id'],
                                            'title': msg.get('subject') or "(No Subject)",
                                            'rawData': msg
                                        })

                            elif item_type == 'channel':
                                # Teams Channel -> そのまま追加
                                expanded_references.append(ref)
                                
                            elif item_type == 'drive':
                                # Document Library
                                drive_id = ref.get('driveId')
                                url = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/root/children"
                                resp = requests.get(url, headers={"Authorization": f"Bearer {auth_token}"})
                                if resp.ok:
                                    children = resp.json().get('value', [])
                                    for child in children:
                                        if 'file' in child:
                                            expanded_references.append({
                                                'type': 'file', 
                                                'id': child['id'], 
                                                'title': child.get('name'), 
                                                'driveId': drive_id,
                                                'rawData': child
                                            })
                        except Exception as e:
                            logger.error(f"Error expanding container {item_type} {item_id}: {e}")
                    else:
                        # コンテナでない、またはチャット系アイテムの場合はそのままリストに追加
                        expanded_references.append(ref)

                # 展開後のリストからコンテンツを取得
                for ref in expanded_references:
                    # 変数の初期化
                    content_text = None
                    virtual_filename = None
                    
                    item_type = ref.get('type')
                    item_id = ref.get('id')
                    title = ref.get('title') or "Untitled"
                    raw_data = ref.get('rawData') or ref

                    is_chat_item = (item_type in ['chat', 'meeting', 'oneOnOne', 'group']) or (ref.get('chatType') is not None)

                    try:
                        # --- 1. チャット (スレッド全体) ---
                        if is_chat_item:
                            # 最新20件を新しい順に取得し、後で逆順にする
                            msgs_url = f"https://graph.microsoft.com/v1.0/me/chats/{item_id}/messages?$top=20&$orderby=createdDateTime desc"
                            msgs_resp = requests.get(msgs_url, headers={"Authorization": f"Bearer {auth_token}"})
                            
                            if msgs_resp.ok:
                                messages = msgs_resp.json().get('value', [])
                                # 時系列順（古い順）に並べ替え
                                messages.sort(key=lambda x: x.get('createdDateTime', ''))
                                
                                lines = []
                                display_title = title if title and title != "Untitled" else (ref.get('topic') or "No Title Chat")
                                lines.append(f"Chat History: {display_title}")
                                lines.append("-" * 30)
                                
                                for msg in messages:
                                    sender = msg.get('from', {}).get('user', {}).get('displayName', 'Unknown')
                                    body_content = msg.get('body', {}).get('content', '')
                                    text_body = re.sub('<[^>]+>', '', body_content).strip()
                                    if text_body:
                                        lines.append(f"[{sender}] {text_body}")
                                
                                content_text = "\n".join(lines)
                                safe_title = re.sub(r'[\\/*?:"<>|]', '_', display_title)
                                virtual_filename = f"[Chat] {safe_title}.txt"
                            else:
                                logger.warning(f"Failed to fetch chat messages for {item_id}: {msgs_resp.status_code}")

                        # --- 2. メール ---
                        elif item_type == 'mail':
                            url = f"https://graph.microsoft.com/v1.0/me/messages/{item_id}"
                            resp = requests.get(url, headers={"Authorization": f"Bearer {auth_token}"})
                            if resp.ok:
                                data = resp.json()
                                subject = data.get('subject', 'No Subject')
                                sender = data.get('from', {}).get('emailAddress', {}).get('name', 'Unknown')
                                body_content = data.get('body', {}).get('content', '')
                                text_body = re.sub('<[^>]+>', '', body_content).strip()
                                
                                content_text = f"Subject: {subject}\nFrom: {sender}\n\n{text_body}"
                                safe_title = re.sub(r'[\\/*?:"<>|]', '_', subject)
                                virtual_filename = f"[Mail] {safe_title}.txt"

                        # --- 3. チャットメッセージ (単体) ---
                        elif item_type == 'message':
                            content_text = f"Selected Message Content for ID: {item_id}\n(Content retrieval requires Chat ID)"
                            virtual_filename = f"[Message] {item_id[:10]}.txt"

                        # --- 4. ファイル ---
                        elif item_type == 'file':
                            content_text, fetched_title = fetch_m365_content(auth_token, item_type, item_id, raw_data)
                            if fetched_title:
                                title = fetched_title
                            virtual_filename = title

                        # --- 5. その他 ---
                        else:
                            content_text, fetched_title = fetch_m365_content(auth_token, item_type, item_id, raw_data)
                            if fetched_title:
                                title = fetched_title
                            safe_title = re.sub(r'[\\/*?:"<>|]', '_', title)
                            virtual_filename = f"[{item_type}] {safe_title}.txt"

                        # --- 共通: 保存処理 ---
                        if content_text and virtual_filename:
                            in_memory_files.append({
                                'name': virtual_filename,
                                'bytes': content_text.encode('utf-8'),
                                'type': 'm365_text'
                            })
                        else:
                            logger.warning(f"Skipping empty or failed item: {item_type} {item_id}")

                    except Exception as e:
                        logger.error(f"Error processing item {item_type} {item_id}: {e}")
                        continue

            # 2. ファイルがない場合の既存RAGチェック
            if not in_memory_files:
                # 新規ファイルがない場合、既存の設定でRAGが有効か確認する
                existing_rag_valid = False
                
                if persona_id_from_form:
                    existing_rag_valid = True
                    persona_id_for_rag = persona_id_from_form
                    logger.info(f"Persona ID provided in request for '{prompt_name}'. Inheriting existing RAG knowledge base.")

                elif save_as_personal:
                    # 個人用: Cosmos DBを確認
                    sessions_container = get_sessions_container()
                    if sessions_container:
                        try:
                            # ID生成: スラッシュを置換
                            safe_prompt_id_name = prompt_name.replace('/', '__SLASH__')
                            prompt_id = f"systemprompt_{user_id}_{safe_prompt_id_name}"
                            
                            item = sessions_container.read_item(item=prompt_id, partition_key=user_id)
                            if item.get('rag_enabled') and item.get('persona_id_for_rag'):
                                existing_rag_valid = True
                                persona_id_for_rag = item.get('persona_id_for_rag')
                        except cosmos_exceptions.CosmosResourceNotFoundError:
                            # 旧ID形式での検索も試行（移行期間用）
                            try:
                                prompt_id_legacy = f"systemprompt_{user_id}_{prompt_name}"
                                item = sessions_container.read_item(item=prompt_id_legacy, partition_key=user_id)
                                if item.get('rag_enabled') and item.get('persona_id_for_rag'):
                                    existing_rag_valid = True
                                    persona_id_for_rag = item.get('persona_id_for_rag')
                            except:
                                pass
                        except Exception as e:
                            logger.warning(f"Failed to check existing personal prompt: {e}")
                else:
                    # 共有用: GCSを確認
                    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
                    if gcs_bucket_name:
                        system_prompt_base_folder = get_system_prompt_base_folder()
                        file_path_on_gcs = f"{system_prompt_base_folder.rstrip('/')}/{prompt_name}.txt"
                        _, metadata = _load_gcs_prompt_content(gcs_bucket_name, file_path_on_gcs)
                        if metadata and metadata.get('rag_enabled') == 'true' and metadata.get('persona_id_for_rag'):
                            existing_rag_valid = True
                            persona_id_for_rag = metadata.get('persona_id_for_rag')

                if existing_rag_valid:
                    logger.info(f"Existing RAG configuration found for '{prompt_name}'. Skipping file processing.")
                else:
                    return jsonify({"success": False, "error": "RAGを有効にするにはファイルまたはM365アイテムが必要です（既存のRAG設定も見つかりませんでした）。"}), 400
            
            else:
                # --- ファイルがある場合の通常処理 (インデックス構築) ---
                
                # 合計ファイルサイズチェック
                total_size_bytes = sum(len(f['bytes']) for f in in_memory_files)
                max_size_bytes = config.MAX_RAG_TOTAL_SIZE_MB * 1024 * 1024
                if total_size_bytes > max_size_bytes:
                    return jsonify({
                        "success": False,
                        "error": f"RAGに登録できる合計サイズは最大{config.MAX_RAG_TOTAL_SIZE_MB}MBまでです。"
                    }), 400

                # ID生成: フォルダ構造を考慮し、安全な文字のみ使用したハッシュ等を使うか、
                # 単純にユーザーIDとプロンプト名（スラッシュ置換）を組み合わせる
                safe_prompt_name_for_rag_id = prompt_name.replace('/', '_').replace('\\', '_')
                persona_id_for_rag = f"rag_{user_id}_{safe_prompt_name_for_rag_id}"
                
                logger.info(f"RAG有効。{len(in_memory_files)}個のアイテムを処理します。Persona ID: {persona_id_for_rag}")
                
                # --- Phase 1: テキスト抽出・チャンキング（embedding無し） ---
                pending_docs = []  # embedding待ちドキュメントを収集

                for file_data in in_memory_files:
                    filename = file_data['name']
                    file_bytes = file_data['bytes']
                    data_type = file_data.get('type', 'file')

                    # 元ファイルをAzure Blob Storageにアップロード
                    original_file_blob_name = f"rag_source_files/{persona_id_for_rag}/{filename}"
                    if not upload_bytes_to_blob(file_bytes, original_file_blob_name):
                        continue

                    if data_type == 'm365_text':
                        # M365テキストデータ (シンプル抽出)
                        raw_text = file_bytes.decode('utf-8', errors='ignore')

                        # ファイル単位で日付を取得
                        last_updated = extract_date_from_document(filename, raw_text[:500], rag_use_ai_extraction, user_info)
                        registered_at = datetime.now(timezone.utc).isoformat()

                        chunk_size = 1000
                        overlap = 200
                        text_len = len(raw_text)
                        chunk_counter = 0
                        start_pos = 0

                        while start_pos < text_len:
                            end_pos = min(start_pos + chunk_size, text_len)
                            chunk_text = raw_text[start_pos:end_pos]

                            doc_id = f"{persona_id_for_rag}_{filename}_{chunk_counter}"
                            doc_id_safe = base64.urlsafe_b64encode(doc_id.encode()).decode()

                            pending_docs.append({
                                "id": doc_id_safe,
                                "persona_id": persona_id_for_rag,
                                "user_id": user_id,
                                "original_filename": filename,
                                "chunk_id": str(chunk_counter),
                                "content_type": "text_chunk",
                                "content_for_llm": chunk_text,
                                "summary_for_search": chunk_text[:250],
                                "keywords_for_search": [],
                                "original_file_blob_name": original_file_blob_name,
                                "last_updated": last_updated,
                                "registered_at": registered_at,
                                "_text_for_embedding": chunk_text
                            })
                            chunk_counter += 1

                            start_pos += (chunk_size - overlap)
                            if chunk_size <= overlap: start_pos += chunk_size

                    else:
                        # 通常ファイル (AI抽出 or シンプル抽出)
                        if rag_use_ai_extraction:
                            # === AI構造化抽出ルート ===
                            logger.info(f"  - [AI抽出] ファイル'{filename}'の構造化抽出を開始...")
                            file_stream = io.BytesIO(file_bytes)
                            file_stream.filename = filename

                            structured_content = _extract_structured_content_with_ai(file_stream, user_info, filename)

                            if not structured_content or not structured_content.get("content_blocks"):
                                logger.warning(f"    - ファイル'{filename}'から構造化コンテンツを抽出できませんでした。スキップします。")
                                continue

                            # ファイル単位で日付を取得（冒頭ブロックのテキストを利用）
                            head_text_parts = [
                                block.get("raw_text") or block.get("description") or ""
                                for block in structured_content["content_blocks"][:3]
                            ]
                            raw_text_head_for_date = " ".join(p[:200] for p in head_text_parts)[:500]
                            last_updated = extract_date_from_document(filename, raw_text_head_for_date, rag_use_ai_extraction, user_info)
                            registered_at = datetime.now(timezone.utc).isoformat()

                            chunk_counter = 0
                            for block in structured_content["content_blocks"]:
                                block_type = block.get("type")
                                if block_type == "heading": continue

                                content_for_llm = ""
                                summary_for_search = block.get("summary", "")
                                keywords_for_search = block.get("keywords", [])

                                if block_type == "paragraph":
                                    content_for_llm = block.get("raw_text", "")
                                elif block_type == "table":
                                    content_for_llm = block.get("markdown_representation", "")
                                elif block_type == "image_analysis":
                                    desc = block.get("description", "")
                                    ocr = block.get("ocr_text", "")
                                    content_for_llm = f"画像の説明: {desc}\n\n画像内のテキスト:\n{ocr}"

                                if not content_for_llm.strip(): continue

                                doc_id = f"{persona_id_for_rag}_{filename}_{chunk_counter}"
                                doc_id_safe = base64.urlsafe_b64encode(doc_id.encode()).decode()

                                pending_docs.append({
                                    "id": doc_id_safe,
                                    "persona_id": persona_id_for_rag,
                                    "user_id": user_id,
                                    "original_filename": filename,
                                    "chunk_id": str(chunk_counter),
                                    "content_type": block_type,
                                    "content_for_llm": content_for_llm,
                                    "summary_for_search": summary_for_search,
                                    "keywords_for_search": keywords_for_search,
                                    "original_file_blob_name": original_file_blob_name,
                                    "last_updated": last_updated,
                                    "registered_at": registered_at,
                                    "_text_for_embedding": content_for_llm
                                })
                                chunk_counter += 1

                        else:
                            # === シンプルテキスト抽出ルート ===
                            logger.info(f"  - [Simple抽出] ファイル'{filename}'のテキスト抽出とチャンキングを開始...")
                            raw_text = extract_text_for_simple_rag(file_bytes, filename)

                            if not raw_text or not raw_text.strip():
                                logger.warning(f"    - ファイル'{filename}'からテキストを抽出できませんでした。スキップします。")
                                continue

                            # ファイル単位で日付を取得
                            last_updated = extract_date_from_document(filename, raw_text[:500], rag_use_ai_extraction, user_info)
                            registered_at = datetime.now(timezone.utc).isoformat()

                            chunk_size = 1000
                            overlap = 200
                            text_len = len(raw_text)
                            chunk_counter = 0
                            start_pos = 0

                            while start_pos < text_len:
                                end_pos = min(start_pos + chunk_size, text_len)
                                chunk_text = raw_text[start_pos:end_pos]

                                doc_id = f"{persona_id_for_rag}_{filename}_{chunk_counter}"
                                doc_id_safe = base64.urlsafe_b64encode(doc_id.encode()).decode()

                                pending_docs.append({
                                    "id": doc_id_safe,
                                    "persona_id": persona_id_for_rag,
                                    "user_id": user_id,
                                    "original_filename": filename,
                                    "chunk_id": str(chunk_counter),
                                    "content_type": "text_chunk",
                                    "content_for_llm": chunk_text,
                                    "summary_for_search": chunk_text[:250],
                                    "keywords_for_search": [],
                                    "original_file_blob_name": original_file_blob_name,
                                    "last_updated": last_updated,
                                    "registered_at": registered_at,
                                    "_text_for_embedding": chunk_text
                                })
                                chunk_counter += 1

                                start_pos += (chunk_size - overlap)
                                if chunk_size <= overlap: start_pos += chunk_size

                # --- Phase 2: バッチEmbedding生成 ---
                if not pending_docs:
                    return jsonify({"success": False, "error": "どのアイテムからも有効なテキストを抽出できませんでした。"}), 400

                texts_for_embedding = [doc["_text_for_embedding"] for doc in pending_docs]
                logger.info(f"合計 {len(texts_for_embedding)}個のチャンクをバッチEmbedding処理します...")
                embeddings = get_embeddings_batch(texts_for_embedding)

                # Embedding成功分のみを最終ドキュメントとして構築
                documents_for_search = []
                for doc, emb in zip(pending_docs, embeddings):
                    if emb is not None:
                        del doc["_text_for_embedding"]
                        doc["content_vector"] = emb
                        documents_for_search.append(doc)

                # --- Phase 3: Azure AI Search登録 ---
                if documents_for_search:
                    logger.info(f"合計 {len(documents_for_search)}個のドキュメントをAzure AI Searchにアップロードします...")
                    success = upload_documents_to_search_index(documents_for_search)
                    if not success:
                        return jsonify({"success": False, "error": "ナレッジベース（Azure AI Search）への登録に失敗しました。"}), 500
                    logger.info("Azure AI Searchへのアップロードが完了しました。")
                else:
                    return jsonify({"success": False, "error": "どのアイテムからも有効なテキストを抽出できませんでした。"}), 400

        # --- 以下、System Prompt自体の保存処理 ---
        message_suffix = ""
        if save_as_personal:
            sessions_container = get_sessions_container()
            if not sessions_container:
                return jsonify({"success": False, "error": "データベースが利用できません。"}), 500
            
            # CosmosDBのIDにはスラッシュを含められないため置換する
            safe_prompt_id_name = prompt_name.replace('/', '__SLASH__')
            prompt_id = f"systemprompt_{user_id}_{safe_prompt_id_name}"
            
            prompt_doc = {
                "id": prompt_id, "userId": user_id, "type": "PersonalSystemPrompt",
                "promptName": prompt_name, # ここには元のパス(スラッシュ付き)を保存
                "promptContent": prompt_content,
                "createdAt": datetime.now(timezone.utc).isoformat(),
                "rag_enabled": rag_enabled,
                "rag_mode": rag_mode if rag_enabled else None,
                "persona_id_for_rag": persona_id_for_rag if rag_enabled else None,
                "rag_use_ai_extraction": rag_use_ai_extraction,
                "system_instruction_conf": is_confidential,
                "iconData": icon_data if icon_data else None
            }
            sessions_container.upsert_item(body=prompt_doc)
            message_suffix = "個人用System Promptとして保存しました。"
        else:
            gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
            if not gcs_bucket_name:
                return jsonify({"success": False, "error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500
            
            system_prompt_base_folder = get_system_prompt_base_folder()
            # GCSはスラッシュをフォルダ区切りとして扱えるため、そのままパスとして使用
            file_path_on_gcs = f"{system_prompt_base_folder.rstrip('/')}/{prompt_name}.txt"
            
            upload_metadata = {
                "confidential": str(is_confidential).lower(),
                "rag_enabled": str(rag_enabled).lower(),
                "rag_mode": rag_mode if rag_enabled else "",
                "rag_use_ai_extraction": str(rag_use_ai_extraction).lower(),
                "persona_id_for_rag": persona_id_for_rag if rag_enabled else "",
                "icon_data": icon_data if icon_data else ""
            }
            gcs_uri = _upload_text_to_gcs(gcs_bucket_name, file_path_on_gcs, prompt_content, metadata=upload_metadata)
            if not gcs_uri:
                return jsonify({"success": False, "error": "共有System PromptのGCSへの保存に失敗しました。"}), 500
            message_suffix = "共有System Promptとして保存しました。"

        final_message = f"System Promptの登録が完了しました。({message_suffix})"
        if rag_enabled:
            if in_memory_files:
                final_message += " ナレッジベースも更新されました。"
            else:
                final_message += " ナレッジベースは既存の設定を維持しました。"

        return jsonify({"success": True, "message": final_message})

    except Exception as e:
        logger.error(f"System Promptのアップロード処理中に予期せぬエラー: {e}", exc_info=True)
        return jsonify({"success": False, "error": f"サーバー内部で予期しないエラーが発生しました: {type(e).__name__}"}), 500

@app.route('/api/chat/system_prompts/list', methods=['GET'])
def list_system_prompts_endpoint():
    user_info = g.user_info
    user_id = user_info.get("userId")

    # 1. GCSから共有システムプロンプトを取得 (再帰的に全取得するように修正)
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    shared_prompts = []
    
    if gcs_bucket_name:
        try:
            storage_client = get_main_gcs_client()
            if storage_client:
                system_prompt_base_folder = get_system_prompt_base_folder()
                
                # delimiterを指定せずにlist_blobsを呼ぶことで、サブフォルダ内も再帰的に全て取得する
                blobs = storage_client.list_blobs(gcs_bucket_name, prefix=system_prompt_base_folder)
                
                for blob in blobs:
                    name = blob.name
                    
                    # フォルダマーカー自体（末尾が/）はスキップ
                    if name.endswith('/'):
                        continue
                        
                    # ベースフォルダ名（プレフィックス）を除去して相対パスにする
                    display_name = name
                    if name.startswith(system_prompt_base_folder):
                        display_name = name[len(system_prompt_base_folder):]
                    
                    # .txt 拡張子を除去
                    if display_name.endswith('.txt'):
                        display_name = display_name[:-4]
                    
                    if not display_name:
                        continue

                    shared_prompts.append({
                        "name": display_name, # パス付きの名前 (例: "folder/file", "folder/.keep")
                        "isPersonal": False,
                        "path": display_name
                    })
            else:
                logger.error("GCS client initialization failed.")
        except Exception as e:
            logger.error(f"Failed to list GCS blobs: {e}", exc_info=True)

    # 2. Cosmos DBから個人用システムプロンプトを取得
    personal_prompts = []
    if user_id:
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                query = "SELECT c.promptName FROM c WHERE c.userId = @userId AND c.type = 'PersonalSystemPrompt'"
                params = [{"name": "@userId", "value": user_id}]
                items = sessions_container.query_items(query=query, parameters=params, partition_key=user_id)
                
                for item in items:
                    name = item.get('promptName')
                    if name:
                        personal_prompts.append({
                            "name": name,
                            "isPersonal": True,
                            "path": name
                        })
            except Exception as e:
                logger.error(f"Failed to fetch personal system prompts for user {user_id}: {e}")

    # 3. マージして返す
    all_prompts = sorted(shared_prompts + personal_prompts, key=lambda x: x['name'])
    return jsonify({"system_prompts": all_prompts})

@app.route('/api/chat/system_prompts/content', methods=['GET'])
def get_system_prompt_content_endpoint():
    user_info = g.user_info
    user_id = user_info.get("userId")
    prompt_name = request.args.get('prompt_name')
    is_personal_str = request.args.get('isPersonal', 'false').lower()
    
    if not prompt_name:
        return jsonify({"error": "プロンプト名が指定されていません。"}), 400

    content = None
    confidential = False
    rag_enabled = False
    rag_mode = None
    persona_id_for_rag = None
    icon_data = None

    if is_personal_str == 'true':
        if not user_id: return jsonify({"error": "個人用プロンプトの取得にはログインが必要です。"}), 401
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                # ★修正: スラッシュを置換してIDを生成
                safe_prompt_id_name = prompt_name.replace('/', '__SLASH__')
                prompt_id = f"systemprompt_{user_id}_{safe_prompt_id_name}"
                
                try:
                    item = sessions_container.read_item(item=prompt_id, partition_key=user_id)
                except cosmos_exceptions.CosmosResourceNotFoundError:
                    # 旧IDでのフォールバック
                    prompt_id_legacy = f"systemprompt_{user_id}_{prompt_name}"
                    item = sessions_container.read_item(item=prompt_id_legacy, partition_key=user_id)

                content = item.get('promptContent')
                confidential = item.get('system_instruction_conf', False)
                icon_data = item.get('iconData')
                rag_enabled = item.get('rag_enabled', False)
                if rag_enabled:
                    rag_mode = item.get('rag_mode')
                    persona_id_for_rag = item.get('persona_id_for_rag')

            except cosmos_exceptions.CosmosResourceNotFoundError:
                return jsonify({"error": "指定された個人用System Promptが見つかりません。"}), 404
            except Exception as e:
                logger.error(f"Failed to read personal system prompt {prompt_id}: {e}")
                return jsonify({"error": "個人用System Promptの読み込みに失敗しました。"}), 500
    else:
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if not gcs_bucket_name: return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500
        
        system_prompt_base_folder = get_system_prompt_base_folder()
        file_path = f"{system_prompt_base_folder.rstrip('/')}/{prompt_name}.txt"
        
        content, metadata = _load_gcs_prompt_content(gcs_bucket_name, file_path)
        
        if content is not None:
            confidential = metadata.get('confidential', 'false').lower() == 'true'
            rag_enabled = metadata.get('rag_enabled', 'false').lower() == 'true'
            icon_data = metadata.get('icon_data')

            if rag_enabled:
                rag_mode = metadata.get('rag_mode')
                persona_id_for_rag = metadata.get('persona_id_for_rag')

    if content is not None:
        return jsonify({
            "content": content, 
            "system_instruction_conf": confidential,
            "rag_enabled": rag_enabled,
            "rag_mode": rag_mode,
            "persona_id_for_rag": persona_id_for_rag,
            "icon_data": icon_data
        })
    else:
        return jsonify({"error": f"System Prompt「{prompt_name}」の内容読み込みに失敗しました。"}), 404


@app.route('/api/chat/prompts/delete', methods=['POST'])
def delete_personal_chat_prompt_endpoint():
    """個人用のチャットプロンプトを削除するAPIエンドポイント"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証されていません。"}), 401

    data = request.get_json()
    category = data.get('category')
    prompt_name = data.get('prompt_name')

    if not all([category, prompt_name]):
        return jsonify({"error": "カテゴリとプロンプト名が必要です。"}), 400

    sessions_container = get_sessions_container()
    if not sessions_container:
        return jsonify({"error": "データベースが利用できません。"}), 500

    try:
        prompt_id = f"chatprompt_{user_id}_{category}_{prompt_name}"
        sessions_container.delete_item(item=prompt_id, partition_key=user_id)
        logger.info(f"User '{user_id}' deleted personal chat prompt: '{prompt_name}' in category '{category}'")
        return jsonify({"success": True, "message": "個人用プロンプトを削除しました。"})
    except cosmos_exceptions.CosmosResourceNotFoundError:
        # 既に存在しない場合も成功として扱う
        logger.warning(f"Attempted to delete non-existent personal chat prompt: {prompt_id}")
        return jsonify({"success": True, "message": "プロンプトは既に削除されています。"})
    except Exception as e:
        logger.error(f"Failed to delete personal chat prompt {prompt_id}: {e}", exc_info=True)
        return jsonify({"error": "プロンプトの削除中にエラーが発生しました。"}), 500

def _delete_rag_blobs(persona_id, filename=None):
    """
    指定されたpersona_idに関連するBlobファイルを削除します。
    filenameが指定されている場合はそのファイルのみ、指定されていない場合はフォルダごと削除します。
    """
    try:
        connect_str = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        container_name = getattr(config, 'AZURE_STORAGE_CONTAINER_NAME', 'tempstorage') # configから取得、なければデフォルト
        
        if not connect_str:
            logger.warning("Azure Storage connection string not found. Skipping blob deletion.")
            return

        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        container_client = blob_service_client.get_container_client(container_name)
        
        if filename:
            # 単一ファイルの削除
            blob_name = f"rag_source_files/{persona_id}/{filename}"
            if container_client.get_blob_client(blob_name).exists():
                container_client.delete_blob(blob_name)
                logger.info(f"Deleted RAG source file from blob: {blob_name}")
            else:
                logger.warning(f"Blob not found for deletion: {blob_name}")
        else:
            # フォルダ（プレフィックス）配下の全ファイル削除
            prefix = f"rag_source_files/{persona_id}/"
            blobs = container_client.list_blobs(name_starts_with=prefix)
            for blob in blobs:
                container_client.delete_blob(blob.name)
                logger.info(f"Deleted RAG source file from blob: {blob.name}")

    except Exception as e:
        logger.error(f"Error deleting blobs for persona {persona_id}: {e}", exc_info=True)

@app.route('/api/chat/system_prompts/delete', methods=['POST'])
def delete_personal_system_prompt_endpoint():
    """個人用のシステムプロンプトを削除するAPIエンドポイント。RAG連携削除機能付き。"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証されていません。"}), 401

    data = request.get_json()
    prompt_name = data.get('prompt_name')

    if not prompt_name:
        return jsonify({"error": "プロンプト名が必要です。"}), 400

    sessions_container = get_sessions_container()
    if not sessions_container:
        return jsonify({"error": "データベースが利用できません。"}), 500

    try:
        # ID生成: スラッシュを置換
        safe_prompt_id_name = prompt_name.replace('/', '__SLASH__')
        prompt_id = f"systemprompt_{user_id}_{safe_prompt_id_name}"
        
        # 1. 削除する前に、まずドキュメントを読み込む（RAG情報の確認のため）
        prompt_doc = None
        try:
            prompt_doc = sessions_container.read_item(item=prompt_id, partition_key=user_id)
        except cosmos_exceptions.CosmosResourceNotFoundError:
            # 新IDで見つからない場合、旧IDで試行
            try:
                prompt_id_legacy = f"systemprompt_{user_id}_{prompt_name}"
                prompt_doc = sessions_container.read_item(item=prompt_id_legacy, partition_key=user_id)
                prompt_id = prompt_id_legacy # 削除対象IDを旧IDに更新
            except cosmos_exceptions.CosmosResourceNotFoundError:
                logger.warning(f"Attempted to delete System Prompt, but document not found in Cosmos DB: {prompt_id}")
                return jsonify({"success": True, "message": "System Promptは既に削除されています。"})

        if prompt_doc:
            persona_id_for_rag = prompt_doc.get("persona_id_for_rag")

            # 2. RAG用のIDがあれば、Azure AI SearchとBlob Storageのデータを削除
            if persona_id_for_rag:
                logger.info(f"System Prompt '{prompt_name}' is RAG-enabled. Deleting associated knowledge base (persona_id: {persona_id_for_rag})...")
                
                # Search Index削除
                delete_success = delete_documents_by_persona_id(persona_id_for_rag)
                if not delete_success:
                    logger.warning(f"Failed to delete some documents from Azure AI Search for persona_id '{persona_id_for_rag}'.")
                
                # Blob Storage削除
                _delete_rag_blobs(persona_id_for_rag)

        # 3. Cosmos DBからドキュメントを削除
        sessions_container.delete_item(item=prompt_id, partition_key=user_id)

        logger.info(f"User '{user_id}' deleted personal system prompt: '{prompt_name}' and its associated RAG data if existed.")
        return jsonify({"success": True, "message": "個人用System Promptを削除しました。"})
    except Exception as e:
        logger.error(f"Failed to delete personal system prompt {prompt_id}: {e}", exc_info=True)
        return jsonify({"error": "System Promptの削除中にエラーが発生しました。"}), 500

@app.route('/api/chat/system_prompts/delete_shared', methods=['POST'])
def delete_shared_system_prompt_endpoint():
    """共有のシステムプロンプトと、それに紐づくRAGデータを削除するAPIエンドポイント"""
    data = request.get_json()
    prompt_name = data.get('prompt_name')

    if not prompt_name:
        return jsonify({"error": "プロンプト名が必要です。"}), 400

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500
    
    system_prompt_base_folder = get_system_prompt_base_folder()
    file_path_on_gcs = f"{system_prompt_base_folder.rstrip('/')}/{prompt_name}.txt"

    try:
        # 1. 削除する前に、まずGCSからメタデータを読み込む
        _, metadata = _load_gcs_prompt_content(gcs_bucket_name, file_path_on_gcs)
        
        # 2. RAG用のIDがあれば、Azure AI SearchとBlob Storageのデータを削除
        if metadata and metadata.get('rag_enabled', 'false').lower() == 'true':
            persona_id_for_rag = metadata.get('persona_id_for_rag')
            if persona_id_for_rag:
                logger.info(f"共有System Prompt '{prompt_name}' はRAGが有効です。関連ナレッジベース (persona_id: {persona_id_for_rag}) を削除します...")
                
                # Search Index削除
                delete_success = delete_documents_by_persona_id(persona_id_for_rag)
                if not delete_success:
                    logger.warning(f"Azure AI Searchのデータ削除に一部失敗しました (persona_id: {persona_id_for_rag})。")
                
                # 【追加】Blob Storage削除
                _delete_rag_blobs(persona_id_for_rag)
        
        # 3. GCSからプロンプトファイル本体を削除
        gcs_delete_success = _delete_gcs_blob(gcs_bucket_name, file_path_on_gcs)
        
        if gcs_delete_success:
            logger.info(f"共有System Promptを削除しました: '{file_path_on_gcs}'")
            return jsonify({"success": True, "message": "共有System Promptを削除しました。"})
        else:
            if not _gcs_blob_exists(gcs_bucket_name, file_path_on_gcs):
                 return jsonify({"success": True, "message": "共有System Promptは既に削除されています。"})
            else:
                 raise Exception("GCSからのファイル削除に失敗しました。")

    except Exception as e:
        logger.error(f"共有System Prompt '{prompt_name}' の削除中にエラー: {e}", exc_info=True)
        return jsonify({"error": "System Promptの削除中にエラーが発生しました。"}), 500

@app.route('/api/chat/system_prompts/delete_shared_rag_file', methods=['POST'])
def delete_shared_rag_file_endpoint():
    """共有System Promptのナレッジベースから特定のファイルを削除する"""
    data = request.get_json()
    prompt_name = data.get('prompt_name')
    filename_to_delete = data.get('filename')

    if not prompt_name or not filename_to_delete:
        return jsonify({"error": "プロンプト名とファイル名が必要です。"}), 400

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    system_prompt_base_folder = get_system_prompt_base_folder()
    file_path_on_gcs = f"{system_prompt_base_folder.rstrip('/')}/{prompt_name}.txt"

    try:
        # 1. GCSからメタデータを読み込み、persona_idを取得
        _, metadata = _load_gcs_prompt_content(gcs_bucket_name, file_path_on_gcs)
        
        if not (metadata and metadata.get('rag_enabled', 'false').lower() == 'true' and metadata.get('persona_id_for_rag')):
            return jsonify({"error": "このSystem PromptはRAGが有効でないか、設定情報が不足しています。"}), 400
        
        persona_id_for_rag = metadata.get('persona_id_for_rag')

        # 2. Azure AI Searchから指定されたファイル名のドキュメントを削除
        success = delete_documents_by_filename(persona_id_for_rag, filename_to_delete)
        
        if success:
            # 【追加】Blob Storageからファイルを削除
            _delete_rag_blobs(persona_id_for_rag, filename_to_delete)
            
            logger.info(f"共有プロンプト'{prompt_name}'のナレッジからファイル'{filename_to_delete}'を削除しました。")
            return jsonify({"success": True, "message": f"ファイル「{filename_to_delete}」をナレッジベースから削除しました。"})
        else:
            raise Exception("Azure AI Searchからのファイル削除に失敗しました。")

    except Exception as e:
        logger.error(f"共有RAGファイル'{filename_to_delete}'の削除中にエラー: {e}", exc_info=True)
        return jsonify({"error": "ファイルの削除中にエラーが発生しました。"}), 500

@app.route('/api/knowledge_base/download', methods=['GET'])
def download_knowledge_base_file():
    """
    【改訂版】
    指定されたpersona_idとファイル名に一致するナレッジベースの「元のファイル」を
    Azure Blob Storageから直接ダウンロードさせる。
    """
    persona_id = request.args.get('persona_id')
    filename = request.args.get('filename')
    if not persona_id or not filename:
        return jsonify({"error": "必要なパラメータ（persona_id, filename）が不足しています。"}), 400

    try:
        # 1. Azure AI Searchに問い合わせて、元のファイルのBlob名を取得する
        credential = AzureKeyCredential(os.environ["AZURE_SEARCH_ADMIN_KEY"])
        search_client = SearchClient(
            endpoint=os.environ["AZURE_SEARCH_SERVICE_ENDPOINT"], 
            index_name=os.environ["AZURE_SEARCH_INDEX_NAME"], 
            credential=credential
        )

        safe_filename = filename.replace("'", "''") # ODataフィルターのエスケープ
        filter_query = f"persona_id eq '{persona_id}' and original_filename eq '{safe_filename}'"
        
        # 1件だけ取得すれば十分
        results = search_client.search(
            search_text="*", 
            filter=filter_query, 
            select=["original_file_blob_name"], # 取得したいのはBlob名だけ
            top=1 
        )
        
        results_list = list(results)
        if not results_list:
            logger.warning(f"ナレッジベースにファイルが見つかりませんでした。Persona ID: {persona_id}, Filename: {filename}")
            return jsonify({"error": "ナレッジベースに該当するファイルが見つかりませんでした。"}), 404
        
        original_file_blob_name = results_list[0].get("original_file_blob_name")

        if not original_file_blob_name:
            logger.error(f"ナレッジベースにファイルのBlob参照が見つかりませんでした。Persona ID: {persona_id}, Filename: {filename}")
            return jsonify({"error": "ナレッジベースのデータが不完全で、元のファイルを見つけられませんでした。"}), 500

        # 2. 取得したBlob名を使って、Azure Blob Storageからファイルをダウンロード
        logger.info(f"Blob Storageからファイル '{original_file_blob_name}' のダウンロードを開始します。")
        file_bytes = download_blob_to_bytes(original_file_blob_name)
        
        if file_bytes is None:
            logger.error(f"Blob '{original_file_blob_name}' のダウンロードに失敗しました。")
            return jsonify({"error": "ストレージからのファイルのダウンロードに失敗しました。"}), 500

        # 3. ファイル名からMIMEタイプを推測し、ファイルを送信
        mimetype, _ = mimetypes.guess_type(filename)
        mimetype = mimetype or 'application/octet-stream'

        return send_file(
            io.BytesIO(file_bytes),
            mimetype=mimetype,
            as_attachment=True,
            download_name=filename
        )

    except Exception as e:
        logger.error(f"ナレッジベースファイルのダウンロード中に予期せぬエラー: {e}", exc_info=True)
        return jsonify({"error": "ファイルのダウンロード中にサーバーエラーが発生しました。"}), 500

# --- エンドポイント: ファイルとプロンプトを処理 (/process_file_and_prompt) (変更なし) ---
@app.route('/process_file_and_prompt', methods=['POST'])
def process_file_and_prompt_endpoint():
    try:
        headers_for_log = dict(request.headers)
        logger.info(f"Received Headers: {json.dumps(headers_for_log, indent=2)}")
    except Exception as e:
        logger.error(f"Error logging headers: {e}")

    if 'prompt' not in request.form or not request.form['prompt'].strip():
        return jsonify({"error": "プロンプトが空か、リクエストに含まれていません"}), 400
    user_prompt = request.form['prompt']

    uploaded_files = request.files.getlist('files')
    uploaded_files_references_json = request.form.get('uploaded_files_references')
    try:
        # このエンドポイントで使用されるモデルでトークン数をチェック
        validate_token_limit(uploaded_files, user_prompt, uploaded_files_references_json, model_name=config.FILE_PROCESS_MODEL_NAME)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    extract_images_flag = request.form.get('extract_images') == 'true'

    uploaded_files = request.files.getlist('files')
    file_parts = []
    log_filenames = []
    extracted_pdf_images = []

    if uploaded_files:
        logger.info(f"Received {len(uploaded_files)} file(s) and prompt for processing. Extract images flag: {extract_images_flag}")
        for uploaded_file in uploaded_files:
            if uploaded_file and uploaded_file.filename != '':
                log_filenames.append(uploaded_file.filename)
                current_filename = uploaded_file.filename
                logger.info(f"Processing file: {current_filename}")
                
                # テキスト抽出用のPartを作成
                # extract_file_content_to_part の中で seek(0) されているはず
                file_part_for_text = extract_file_content_to_part(uploaded_file)
                if file_part_for_text:
                    file_parts.append(file_part_for_text)
                    logger.info(f"Successfully created Part for text content of file: {current_filename}")
                else:
                    logger.warning(f"Failed to create Part for text content of file '{current_filename}'. Skipping text content for this file.")
                
                uploaded_file.seek(0) # ★重要: ストリームを再度先頭に戻す

                # ★ 画像抽出処理 (PDFファイルかつフラグがオンの場合)
                if current_filename.lower().endswith('.pdf') and extract_images_flag:
                    logger.info(f"Attempting to extract images from PDF: {current_filename}")
                    # extract_images_from_pdf はストリームを引数にとる
                    extracted_images_from_pdf_result = extract_images_from_pdf(io.BytesIO(uploaded_file.read()))
                    if extracted_images_from_pdf_result:
                        extracted_pdf_images.extend(extracted_images_from_pdf_result)
                        logger.info(f"Added {len(extracted_images_from_pdf_result)} images from {current_filename} to the list.")
                    else:
                        logger.info(f"No images were extracted from {current_filename} or an error occurred.")
                
                uploaded_file.seek(0) # ★重要: 他の処理のために再度ストリームを先頭に戻す
            else:
                 logger.info("Skipping empty file entry.")
    else:
        logger.info("No files provided. Processing prompt only.")

    try:
        prompt_part = types.Part.from_text(text=user_prompt)
        logger.info("Successfully created Part for prompt.")
    except Exception as e:
        logger.error(f"Failed to create Part object for prompt: {e}", exc_info=True)
        return jsonify({"error": "内部サーバーエラー (プロンプトPart作成失敗)"}), 500

    parts_for_gemini = []
    if file_parts: # テキスト抽出されたファイル内容があれば追加
        parts_for_gemini.extend(file_parts)
    parts_for_gemini.append(prompt_part) # ユーザープロンプトは必須

    contents = [types.Content(role="user", parts=parts_for_gemini)]

    FILE_PROCESS_SYSTEM_INSTRUCTION = """あなたは、ユーザーの指示に基づき、提供されたファイルの内容を分析・要約・抽出し、厳格なルールに従って構造化されたプレーンテキストを生成する、高度な情報処理AIアシスタントです。

### あなたの役割とタスク
1.  **意図の理解:** ユーザーの指示（プロンプト）の**背景や真の意図**を理解するよう努めます。提供されたファイル群を総合的に分析し、ユーザーが何を達成したいのかを正確に把握します。
2.  **タスクの実行:** 指示されたタスク（要約、情報抽出、分析、質問応答など）を、ファイルの内容に基づいて**正確かつ誠実**に実行します。不確かな情報や誤解を招く表現は避けます。
3.  **厳格な出力:** 以下の【出力形式の絶対厳守ルール】に従い、ユーザーが**次のアクション**に進めるような、実用的で分かりやすいプレーンテキストを生成します。

---

### 【出力形式の絶対厳守ルール】
あなたの応答は、**必ず**以下の3つのルールに従った**プレーンテキスト**でなければなりません。

1.  **Markdownの抑制:**
    *   応答は、原則として**プレーンテキスト**で生成してください。
    *   見出し (`#`)、箇条書き (`*`, `-`)、太字 (`**`) などのMarkdown装飾は、**表形式での出力が明確に要求されている場合や、情報の構造化が不可欠な場合を除き、絶対に使用しないでください。**
    *   通常の文章や要約を生成する場合は、自然な段落を持つプレーンテキストで応答してください。

2.  **階層構造の表現:**
    *   情報の階層構造や親子関係は、**インデント（半角スペース4つ）**で表現してください。
    *   親項目に対して、子項目はインデントを1つ深くします。

3.  **番号体系の使用:**
    *   各項目には、必ず階層に応じた番号（例: `1.`, `(1)`、`①`、`ア.`など）を付けてください。
    *   インデントと番号体系を組み合わせて、情報の構造を明確に示してください。

#### 出力例：
1.主要な発見
  (1)製品Aについて
     ①利点
         コストパフォーマンスが高い
     ②欠点
         デザインが古い
  (2)市場動向
      競合B社の新製品が脅威となっている

2.結論
  (1)製品Aのデザインを刷新し、若年層へのアピールを強化すべき。

### その他の指示
*   **前置き不要:** 「以下に出力します」のような前置きや、後書きは一切含めないでください。
"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(g.user_info.get("userId"))
    final_system_instruction = FILE_PROCESS_SYSTEM_INSTRUCTION + glossary_instruction

    generated_text, metadata = generate_with_gemini(
        model_name=config.FILE_PROCESS_MODEL_NAME,
        contents=contents,
        system_instruction=final_system_instruction,
        max_output_tokens=config.FILE_PROCESS_MAX_TOKENS,
        temperature=config.FILE_PROCESS_TEMPERATURE,
        user_info=user_info,
        log_prompt_text=user_prompt,
        log_filenames=log_filenames,
        feature_category="ファイルとプロンプト処理（画像抽出対応）" # ★変更: カテゴリ名
    )

    # --- レスポンス構成 ---
    response_data = {}
    if generated_text and not generated_text.startswith("[エラー:") and not generated_text.startswith("[APIエラー:"):
        response_data["result"] = generated_text.strip()
    elif generated_text:
        response_data["error"] = f"AIエラー: {generated_text}"
    else:
        response_data["error"] = "AI応答が空"
    
    if extracted_pdf_images: # ★追加: 抽出画像があればレスポンスに含める
        response_data["extracted_images"] = extracted_pdf_images

    if "error" in response_data:
        return jsonify(response_data), 500
    else:
        return jsonify(response_data)

# --- ヘルパー関数: 応答からコード抽出 (変更なし) ---
def extract_code_from_response(response_text: str, language: str) -> str:
    pattern = rf"```{language}\s*([\s\S]*?)\s*```"
    match = re.search(pattern, response_text, re.IGNORECASE)
    if match:
        return match.group(1).strip()
    else:
        pattern_generic = r"```\s*([\s\S]*?)\s*```"
        match_generic = re.search(pattern_generic, response_text, re.MULTILINE)
        if match_generic:
            extracted_code = match_generic.group(1).strip()
            logger.warning(f"Found generic code block '```...```' instead of specific '```{language}...```'. Returning its content.")
            return extracted_code
        else:
            logger.info(f"No code block found ('```{language}...```' or '```...```'). Returning original text as is.")
            return response_text.strip()

# --- Marp CLI 実行関数 (変更なし) ---
def run_marp_cli(md_file_path, output_file_path, options):
    if not config.MARP_CLI_PATH or not os.path.exists(config.MARP_CLI_PATH):
        logger.error(f"Marp CLIのパスが設定されていないか、無効です: {config.MARP_CLI_PATH}")
        return False, f"サーバーエラー: Marp CLIが見つかりません。管理者に連絡してください。"
    command = [config.MARP_CLI_PATH, md_file_path, "-o", output_file_path] + options
    logger.info(f"実行コマンド: {' '.join(command)}")
    use_shell = platform.system() == "Windows"
    try:
        result = subprocess.run(command, check=True, capture_output=True, text=True, shell=use_shell, encoding='utf-8')
        logger.info(f"Marp CLI の実行に成功しました: {output_file_path}")
        if result.stdout: logger.info(f"標準出力:\n{result.stdout}")
        if result.stderr: logger.warning(f"標準エラー出力:\n{result.stderr}")
        return True, None
    except FileNotFoundError:
        err_msg = f"エラー: 指定されたMarpコマンド '{config.MARP_CLI_PATH}' が見つかりません。"
        logger.error(err_msg)
        return False, f"サーバーエラー: Marp CLIが見つかりません。"
    except subprocess.CalledProcessError as e:
        stderr_output = e.stderr if e.stderr else "(標準エラー出力なし)"
        err_msg = f"Marp CLI の実行中にエラー (終了コード: {e.returncode})"
        logger.error(f"{err_msg}\nコマンド: {' '.join(e.cmd)}\nエラー詳細:\n{stderr_output}")
        return False, f"Marp CLI エラー: {e.returncode}。\n詳細: {stderr_output[:200]}..."
    except Exception as e:
        err_msg = f"Marp CLI変換中に予期せぬエラー: {e}"
        logger.error(err_msg, exc_info=True)
        return False, f"PPTX変換中に予期せぬサーバーエラーが発生しました。"

# --- エンドポイント: PPTX生成 (/generate_marp_markdown) (変更なし) ---
@app.route('/generate_marp_markdown', methods=['POST'])
def generate_marp_markdown_endpoint():
    if not request.json or 'text' not in request.json:
        return jsonify({"error": "リクエストボディに 'text' が必要です"}), 400
    input_text = request.json['text']
    regenerate_comment = request.json.get('comment', None)
    if not input_text or len(input_text.strip()) < 10:
         return jsonify({"error": "Marp Markdownを生成するにはテキストが短すぎます"}), 400

    logger.info(f"\nReceived request for Marp Markdown generation. Input length: {len(input_text)}")
    if regenerate_comment:
        logger.info(f"Regeneration requested with comment: {regenerate_comment}")

    # --- 1. GeminiでMarp Markdownを生成 ---
    # プロンプトを修正し、特定のテーマを指定せず多様な表現を促す
    marp_prompt = f"""以下のテキストの内容に基づいて、プレゼンテーション用のスライド原稿を **Marp 形式の Markdown** で生成してください。
    ターゲットとするパワポは、**モダンで視覚的にインパクトがあり(アイコン挿入、背景色、文字の色など)、かつ内容が分かりやすいプレゼンテーション**です。
    スライドのレイアウトとコンテンツの量に配慮してください。
    スライドの内容や役割に応じて多様な背景（色、グラデーション、画像、クラス指定など）を使用してください。

    **Marp Markdown のルールと考慮事項:**
    *   スライドは `---` で区切ります。
    *   各スライドは**一つの主要なアイデア**に絞り、情報を詰め込みすぎないでください。
    *   見出し (`#`, `##`) を明確に使用し、階層構造を示してください。
    *   **重要なポイントは箇条書き (`* ` や `- `) や番号付きリスト (`1. `) で整理**し、視覚的に分かりやすくしてください。
    *   必要に応じて、冒頭にテーマディレクティブ (`<!-- theme: ... -->`)、ページ番号 (`<!-- paginate: true -->`)、フッター (`<!-- footer: '...' -->`) などのディレクティブを含めてください。**標準で利用可能なテーマ (default, gaia, uncover) のいずれか**を使用するか、あるいはテーマディレクティブを省略し、`_class` ディレクティブや背景画像/色指定 (`![bg ...]`) を積極的に活用して視覚的な多様性を出してください。
    *   **画像を使用するスライドは、その画像が内容を補強し、視覚的に魅力的であるかを考慮**してください。（AIが直接画像を生成・埋め込むわけではありませんが、画像プレースホルダーの指示などで意識させます）
    *   コードブロックは ``` で囲みます。
    *   **テキストの量はスライドサイズに合わせて調整**し、読者が一目で理解できるように簡潔に記述してください。長文にならないように注意してください。
    *   **スライド構成は論理的**で、導入、本論、まとめの流れを意識してください。
    *   **箇条書きの各項目は短く、端的に**内容を伝わるように記述してください。

    **元のテキスト:**
    ---
    {input_text}
    ---
    """
    if regenerate_comment:
        marp_prompt += f"""
    **前回の生成結果を踏まえ、以下の指示に従って修正・再生成してください:**
    ---
    {regenerate_comment}
    ---
    """
    marp_prompt += """
    **生成する Marp Markdown:**
    ```markdown
    <!-- theme: uncover --> <!-- 例としてuncoverを使用 -->
    <!-- footer: 'Your Company Name | Confidential' -->
    <!-- paginate: true -->
    <!-- _class: lead -->
    <!-- ![bg left:30% filter:brightness(80%)](images/title_background.jpg) -->

    # ✨ テキストから抽出した魅力的なタイトル ✨
    ## *<span style="color: #0078D4;">内容を要約するサブタイトル</span>*
    ### プレゼンター名 / 日付

    ---

    <!-- _class: highlight -->
    ## :🎯: イントロダクション：現状と課題

    *   <span class="fa fa-exclamation-circle"></span> **現状の課題:** テキストが示す問題点 (簡潔に)
    *   <span class="fa fa-bullseye"></span> **本日のゴール:** このプレゼンで達成したいこと
    *   <span style="color: #DC143C;">なぜこれが重要か？</span> (インパクトを強調)

    ---

    ## :💡: 主要セクション１：提案内容

    ![right fit](images/diagram.png) <!-- 右側に図や画像を配置 -->

    1.  **提案 A:** 具体的なアクションやアイデア
        *   メリット１
        *   メリット２
    2.  **提案 B:** 別の角度からのアプローチ
        *   <span style="color: green;">期待される効果</span>

    ---

    <!-- _class: dark_bg -->
    ## :📊: データと分析結果

    <!-- ![bg opacity:.3](images/data_background.png) --> <!-- 背景に薄く画像 -->

    *   **主要な発見:** テキスト中のデータや分析結果の要点
        *   データポイント X: <span style="font-size: 1.2em; color: #FFD700;">XX%</span> 向上
        *   データポイント Y: 関連する統計値
    *   **洞察:** このデータが示す意味

    ---

    ## :🚀: 主要セクション２：実行計画とロードマップ

    *   **ステップ 1:** (具体的なタスク) - 担当:〇〇, 期限:YYYY/MM/DD
    *   **ステップ 2:** (次のタスク)
    *   **必要なリソース:** 人員、予算、ツールなど

    ---

    ## :✅: まとめとネクストステップ

    *   **キーメッセージ:**
        *   :star: ポイント１: (最も伝えたいこと)
        *   :star: ポイント２: (次に重要なこと)
    *   **次のアクション:**
        *   <span class="fa fa-arrow-right"></span> [ ] タスクA (担当者)
        *   <span class="fa fa-arrow-right"></span> [ ] タスクB (担当者)

    ---

    <!-- _class: lead dark_bg -->
    # ご清聴ありがとうございました

    **Q & A**

    [連絡先: email@example.com]
    [Webサイト: www.example.com]

    ```"""

    logger.info(f"Calling Gemini for Marp Markdown generation (model: {config.PPTX_GEN_MODEL_NAME})...")
    marp_prompt_part = types.Part.from_text(text=marp_prompt)
    contents = [types.Content(role="user", parts=[marp_prompt_part])]
    MARP_GEN_SYSTEM_INSTRUCTION = """あなたはプレゼンテーション資料作成のエキスパートAIです。特に、Marp形式のMarkdownを用いたスライド作成を得意としています。与えられたテキストの内容を構造化し、視覚的に魅力的で分かりやすいプレゼンテーションを構成するMarp Markdownコードを生成してください。モダンなデザイン（アイコン、色使い、レイアウト調整など）を意識し、指定されたMarpの構文ルール（スライド区切り、ディレクティブ、リスト、コードブロックなど）を厳守してください。**最重要: 応答はMarp Markdownコードそのもののみとし、説明文や ```markdown のようなコードブロックの囲み文字は絶対に含めないでください。**"""

    # user_info = get_entra_user_info(request)
    user_info = g.user_info

    marp_markdown_raw, metadata = generate_with_gemini(
        model_name=config.PPTX_GEN_MODEL_NAME,
        contents=contents,
        system_instruction=MARP_GEN_SYSTEM_INSTRUCTION,
        max_output_tokens=config.PPTX_GEN_MAX_TOKENS,
        temperature=config.PPTX_GEN_TEMPERATURE,
        user_info=user_info,
        log_prompt_text=marp_prompt,
        log_filenames=None,
        feature_category="PPTX資料生成（Marp）"
    )

    if not marp_markdown_raw or marp_markdown_raw.startswith("[エラー:") or marp_markdown_raw.startswith("[APIエラー:"):
        error_msg = f"Marp Markdownの生成に失敗しました: {marp_markdown_raw}"
        logger.error(error_msg)
        return jsonify({"error": error_msg}), 500

    marp_markdown = extract_code_from_response(marp_markdown_raw, 'markdown')
    if marp_markdown == marp_markdown_raw.strip():
        logger.warning("Could not extract Markdown block. Using raw response.")
        marp_markdown = marp_markdown_raw.strip()
    if not "---" in marp_markdown:
         logger.warning("Generated Markdown might miss '---' slide separators.")

    logger.info("Marp Markdown generated successfully.")
    return jsonify({"marp_markdown": marp_markdown})

# --- エンドポイント: MarkdownからPPTXへの変換 (/export_pptx_from_md) (変更なし) ---
@app.route('/export_pptx_from_md', methods=['POST'])
def export_pptx_from_md_endpoint():
    if not request.json or 'marp_markdown' not in request.json:
        return jsonify({"error": "リクエストボディに 'marp_markdown' が必要です"}), 400
    marp_markdown = request.json['marp_markdown']
    if not marp_markdown or len(marp_markdown.strip()) < 10 or not "---" in marp_markdown:
        return jsonify({"error": "有効なMarp Markdownが提供されていません。"}), 400

    logger.info(f"\nReceived request for PPTX export from Markdown. Markdown length: {len(marp_markdown)}")
    tmp_dir = None
    try:
        tmp_dir = tempfile.TemporaryDirectory()
        dir_path = tmp_dir.name
        md_filename = f"marp_export_{uuid.uuid4()}.md"
        md_file_path = os.path.join(dir_path, md_filename)
        pptx_filename = f"slides_export_{uuid.uuid4()}.pptx"
        pptx_file_path = os.path.join(dir_path, pptx_filename)

        with open(md_file_path, 'w', encoding='utf-8') as f: f.write(marp_markdown)
        logger.info(f"一時Markdownファイルを保存しました: {md_file_path}")

        logger.info("Marp CLIによるPPTX変換を開始します...")
        success, error_msg = run_marp_cli(md_file_path, pptx_file_path, ["--pptx", "--allow-local-files"])
        #success, error_msg = run_marp_cli(md_file_path, pptx_file_path, ["--pptx-editable", "--allow-local-files"])

        if not success: return jsonify({"error": error_msg}), 500
        if not os.path.exists(pptx_file_path) or os.path.getsize(pptx_file_path) == 0:
             logger.error("Marp CLIは成功しましたが、有効なPPTXファイルが生成されませんでした。")
             return jsonify({"error": "PPTXファイルの生成に失敗しました(ファイルが空か存在しません)。"}), 500

        logger.info(f"PPTXファイルが正常に生成されました: {pptx_file_path}")
        return send_file(pptx_file_path, mimetype='application/vnd.openxmlformats-officedocument.presentationml.presentation', as_attachment=True, download_name='presentation.pptx')
    except Exception as e:
        logger.error(f"PPTXエクスポート処理中に予期せぬエラー: {e}", exc_info=True)
        return jsonify({"error": "PPTXエクスポート中にサーバーエラーが発生しました。"}), 500
    finally:
        if tmp_dir:
            try: tmp_dir.cleanup(); logger.info(f"一時ディレクトリ {tmp_dir.name} をクリーンアップしました。")
            except Exception as e: logger.error(f"一時ディレクトリのクリーンアップ中にエラー: {e}", exc_info=True)

# --- 重複除去関数 (変更なし) ---
def remove_overlap(original_text: str, generated_text: str) -> str:
    cleaned_text = generated_text
    if original_text and generated_text:
        original_compare = original_text.strip().lower()
        generated_compare = generated_text.strip().lower()
        overlap_len = 0
        max_check_len = min(len(original_compare), len(generated_compare))
        for i in range(max_check_len, 0, -1):
            if original_compare.endswith(generated_compare[:i]): overlap_len = i; break
        if overlap_len > 0: cleaned_text = generated_text[overlap_len:]
        else: print("No significant overlap detected in post-processing.")
    return cleaned_text

# --- エンドポイント: テキスト補完 (/suggest) (変更なし) ---
@app.route('/suggest', methods=['POST'])
def suggest_text_endpoint():
    if not request.json or 'text' not in request.json or 'cursor_pos' not in request.json: return jsonify({"error": "リクエストボディに 'text' と 'cursor_pos' が必要です"}), 400
    input_text = request.json['text']
    cursor_pos = request.json['cursor_pos']
    if not isinstance(cursor_pos, int) or cursor_pos < 0 or cursor_pos > len(input_text): cursor_pos = len(input_text)
    text_before_cursor = input_text[:cursor_pos]
    suggest_prompt = f"""以下のテキストの続きとして、**自然で文脈に合った、次の文や一節となるような、ある程度の内容を持つ文章**を生成してください。単語レベルの補完ではなく、思考を少し先まで進めるような、**適切な長さの**提案をお願いします。生成する続きの文章のみを出力し、元の文章や追加の説明は含めないでください。\n\nテキスト:\n{text_before_cursor}\n\n補完:"""
    suggest_prompt_part = types.Part.from_text(text=suggest_prompt)
    contents = [types.Content(role="user", parts=[suggest_prompt_part])]

    SUGGEST_SYSTEM_INSTRUCTION = """あなたは文章の続きを提案するAIアシスタントです。ユーザーが入力中のテキストの文脈に自然に続く、**意味のある文章**を生成してください。単なる単語やフレーズの補完ではなく、**次の文や一節として適切な内容と長さ**を持つ提案を目指してください。ただし、不必要に長すぎる文章は避け、文脈に応じた**適度な長さ**で応答してください。応答は提案するテキストのみとし、前置きや説明は一切含めないでください。"""

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(g.user_info.get("userId"))
    final_instruction = SUGGEST_SYSTEM_INSTRUCTION + glossary_instruction

    suggestion_raw, metadata = generate_with_gemini(
        model_name=config.DEFAULT_MODEL_NAME,
        contents=contents,
        system_instruction=final_instruction,
        max_output_tokens=config.SUGGEST_MAX_TOKENS,
        temperature=config.SUGGEST_TEMPERATURE,
        user_info=user_info,
        log_prompt_text=suggest_prompt,
        log_filenames=None,
        feature_category="テキスト補完"
    )
    if suggestion_raw and not suggestion_raw.startswith("[エラー:") and not suggestion_raw.startswith("[APIエラー:"):
        cleaned_suggestion = remove_overlap(text_before_cursor, suggestion_raw)
        return jsonify({"suggestion": cleaned_suggestion})
    else: return jsonify({"suggestion": ""})

