@app.route('/generate_continuation', methods=['POST'])
def generate_continuation_endpoint():
    if not request.json or 'text' not in request.json: return jsonify({"error": "リクエストボディに 'text' が必要です"}), 400
    input_text = request.json['text']
    continuation_prompt = f"""以下の文章に続く、自然で文脈に合った文章を生成してください。できるだけ長く、豊かな内容になるように続けてください。生成する続きの文章のみを出力し、元の文章や追加の説明は含めないでください。\n\n元の文章:\n---\n{input_text}\n---\n\n続きの文章:"""
    continuation_prompt_part = types.Part.from_text(text=continuation_prompt)
    contents = [types.Content(role="user", parts=[continuation_prompt_part])]
    GENERATE_CONTINUATION_SYSTEM_INSTRUCTION = """あなたは創造性に富んだライターアシスタントです。与えられた文章の文脈、トーン、スタイルを引き継ぎ、自然で論理的な続きの文章を生成してください。できるだけ長く、内容豊かになるように続けることを目指してください。応答は生成した続きの文章のみとし、元の文章の繰り返しや追加の説明、前置きは含めないでください。"""

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(g.user_info.get("userId"))
    final_instruction = GENERATE_CONTINUATION_SYSTEM_INSTRUCTION + glossary_instruction
    
    continuation_raw, metadata = generate_with_gemini(
        model_name=config.DEFAULT_MODEL_NAME,
        contents=contents,
        system_instruction=final_instruction,
        max_output_tokens=config.GENERATE_CONTINUATION_MAX_TOKENS,
        temperature=config.GENERATE_CONTINUATION_TEMPERATURE,
        user_info=user_info,
        log_prompt_text=continuation_prompt,
        log_filenames=None,
        feature_category="文章の続きを生成"
    )
    if continuation_raw and not continuation_raw.startswith("[エラー:") and not continuation_raw.startswith("[APIエラー:"):
        cleaned_continuation = remove_overlap(input_text, continuation_raw)
        return jsonify({"continuation": cleaned_continuation})
    elif continuation_raw: return jsonify({"error": f"続き生成エラー: {continuation_raw}"}), 500
    else: return jsonify({"error": "続きの文章を生成できませんでした。"}), 500

