    # --- gemini_parts の構築 (★修正) ---
    # 1. プロンプトヘッダー + ユーザープロンプト + 形式指示
    gemini_parts.append(types.Part.from_text(text=prompt_header + "\n--- ユーザープロンプト ---\n" + prompt + "\n" + format_specific_instruction))
