# --- API: アップロードされた構造化ファイルから列名を取得 ---
@app.route('/get_file_columns', methods=['POST'])
def get_file_columns():
    if 'file' not in request.files:
        return jsonify({"error": "ファイルがリクエストに含まれていません"}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "ファイルが選択されていません"}), 400

    filename = file.filename.lower()
    df = None
    try:
        if filename.endswith('.csv'):
            # chardetでエンコーディングを推定 (既存のextract_file_content_to_partのロジックを参考に)
            csv_content = file.read()
            file.seek(0) # ストリームポインタを先頭に戻す
            detected_encoding_info = chardet.detect(csv_content)
            encoding = detected_encoding_info.get('encoding', 'utf-8')
            logger.info(f"CSV file detected. Attempting to read with encoding: {encoding}")
            df = pd.read_csv(io.BytesIO(csv_content), encoding=encoding)
        elif filename.endswith(('.xls', '.xlsx')):
            logger.info("Excel file detected. Reading with openpyxl engine.")
            df = pd.read_excel(file, engine='openpyxl')
        else:
            return jsonify({"error": "未対応のファイル形式です。CSVまたはExcelファイルをアップロードしてください。"}), 400

        if df is not None and not df.empty:
            if len(df) > config.MAX_PROCESSING_ROWS:
                return jsonify({"error": f"ファイルが長すぎます。処理できるのは最大{config.MAX_PROCESSING_ROWS}行までです。"}), 400
            return jsonify({"columns": df.columns.tolist(), "rowCount": len(df)})
        else:
            return jsonify({"error": "ファイルが空か、列を読み取れませんでした。"}), 400
    except pd.errors.EmptyDataError:
        logger.error(f"Pandas EmptyDataError for file: {filename}")
        return jsonify({"error": "ファイルが空であるか、データが含まれていません。"}), 400
    except UnicodeDecodeError as ude:
        logger.error(f"UnicodeDecodeError for CSV file {filename} with detected encoding. Error: {ude}")
        return jsonify({"error": f"CSVファイルのエンコーディングエラー。ファイルが破損しているか、エンコーディングが標準的でない可能性があります。UTF-8でお試しください。詳細: {str(ude)}"}), 400
    except ValueError as ve: # 例: Excelファイルが破損している場合など
        logger.error(f"ValueError during pandas read for file {filename}: {ve}")
        return jsonify({"error": f"ファイルの読み取り中にエラーが発生しました。ファイル形式が正しいか、破損していないか確認してください。詳細: {str(ve)}"}), 400
    except Exception as e:
        logger.error(f"Error reading columns from file {filename}: {e}", exc_info=True)
        return jsonify({"error": f"ファイルの列読み取り中に予期しないエラーが発生しました: {type(e).__name__}"}), 500


# --- API: 構造化データの処理 (要約・分類など) ---
@app.route('/process_structured_data', methods=['POST'])
def process_structured_data_endpoint():

    if 'file' not in request.files:
        return jsonify({"error": "処理対象のファイルがありません。"}), 400
    if 'selected_columns' not in request.form:
        return jsonify({"error": "処理対象の列が選択されていません。"}), 400
    if 'prompt_text' not in request.form:
        return jsonify({"error": "処理のためのプロンプトがありません。"}), 400
    if 'output_format' not in request.form:
        return jsonify({"error": "出力形式が指定されていません。"}), 400

    file = request.files['file']
    try:
        selected_columns = json.loads(request.form['selected_columns'])
    except json.JSONDecodeError:
        return jsonify({"error": "選択列の形式が不正です。"}), 400
    
    user_prompt_template = request.form['prompt_text']
    output_format = request.form['output_format'].lower() # 'excel' or 'csv'
    new_column_name = request.form.get('new_column_name', '生成結果') # デフォルト名

    if not isinstance(selected_columns, list) or not selected_columns:
        return jsonify({"error": "処理対象の列を1つ以上選択してください。"}), 400
    if output_format not in ['excel', 'csv']:
        return jsonify({"error": "無効な出力形式です。'excel' または 'csv' を指定してください。"}), 400

    filename = file.filename.lower()
    df = None
    try:
        if filename.endswith('.csv'):
            csv_content = file.read()
            file.seek(0)
            detected_encoding_info = chardet.detect(csv_content)
            encoding = detected_encoding_info.get('encoding', 'utf-8')
            df = pd.read_csv(io.BytesIO(csv_content), encoding=encoding)
        elif filename.endswith(('.xls', '.xlsx')):
            df = pd.read_excel(file, engine='openpyxl')
        else:
            return jsonify({"error": "未対応のファイル形式です。"}), 400

        if df is None or df.empty:
            return jsonify({"error": "ファイルが空か、読み込めませんでした。"}), 400

        if len(df) > config.MAX_PROCESSING_ROWS:
            logger.warning(f"File '{filename}' exceeds max rows ({len(df)} > {config.MAX_PROCESSING_ROWS}). This should have been caught by get_file_columns.")
            return jsonify({"error": f"ファイルが長すぎます。処理できるのは最大{config.MAX_PROCESSING_ROWS}行までです。"}), 400

        # 選択された列がDataFrameに存在するか確認
        for col in selected_columns:
            if col not in df.columns:
                return jsonify({"error": f"指定された列 '{col}' がファイルに存在しません。"}), 400
        
        logger.info(f"Processing {len(df)} rows from '{filename}' for columns: {selected_columns}. Output: {output_format}")

    except Exception as e:
        logger.error(f"Error reading structured file '{filename}' for processing: {e}", exc_info=True)
        return jsonify({"error": f"ファイルの読み込み中にエラー: {type(e).__name__}"}), 500

    # --- Gemini API呼び出しと結果の追加 ---
    results = []
    # user_info = get_entra_user_info(request) # ユーザー情報取得
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))

    STRUCTURED_DATA_SYSTEM_INSTRUCTION = f"""あなたは構造化データ（表形式データ）の指定された列の内容を分析し、ユーザーの指示に基づいて新しい情報を生成するAIアシスタントです。
各行のデータは独立して処理されることもありますが、表全体の文脈を考慮する必要がある場合もあります。
ユーザープロンプトには、処理対象の列の値がプレースホルダー（例: `{{列名}}`）として含まれます。これを実際のデータで置き換え、指示に従ってください。
生成する結果は、簡潔かつ的確に、要求された情報のみを出力してください。余計な説明や前置きは不要です。
例えば、「以下の顧客レビュー（`{{レビュー本文}}`）を要約してください」というプロンプトに対しては、要約文のみを返します。
「製品カテゴリ（`{{製品名}}`）を分類してください」というプロンプトに対しては、分類結果のカテゴリ名のみを返します。
"""
    # モデルパラメータは既存のものを流用するか、専用のものを定義
    model_name = os.environ.get("STRUCTURED_DATA_MODEL_NAME", config.DEFAULT_MODEL_NAME)
    max_tokens = int(os.environ.get("STRUCTURED_DATA_MAX_TOKENS", 500))
    temperature = float(os.environ.get("STRUCTURED_DATA_TEMPERATURE", 0.5))

    for index, row in df.iterrows():
        prompt_for_row = user_prompt_template # ユーザーが入力したプロンプトテンプレート
        row_data_context_parts = [] # AIに追加で渡す列データの文字列
        
        for col_name in selected_columns:
            cell_value = str(row[col_name]) if pd.notna(row[col_name]) else ""
            # プロンプトテンプレート内のプレースホルダーを実際のデータで置換
            prompt_for_row = prompt_for_row.replace(f"{{{col_name}}}", cell_value)
            # ログやAIへの追加コンテキスト用に整形
            row_data_context_parts.append(f"「{col_name}」: '{cell_value}'")
        
        # 最終的なプロンプト (デバッグ用、またはAIにより多くのコンテキストを与えるために調整可能)
        # full_prompt_for_gemini = f"以下の行データについて、指示を実行してください:\n{', '.join(row_data_str_parts)}\n\n指示プロンプト:\n{prompt_for_row}"
        # 今回はユーザーが作成したテンプレートがそのままプロンプトになる
        target_data_info = f"以下のデータについて、指示を実行してください。\nデータ: {', '.join(row_data_context_parts)}\n\n指示:\n"
        full_prompt_for_gemini = prompt_for_row

        log_combined_row_data = "; ".join([f"{col}: {str(row[col])[:50]}..." for col in selected_columns if pd.notna(row.get(col))])

        logger.debug(f"Row {index}: Final Gemini Prompt: '{full_prompt_for_gemini[:300]}...'") # ログ出力文字数調整

        gemini_contents = [types.Content(role="user", parts=[types.Part.from_text(text=full_prompt_for_gemini)])]
        
        # ログ用のプロンプトは、テンプレートと実際の行データの両方が分かると良い
        log_prompt_for_call = f"Template: {user_prompt_template[:100]}...\nRowData: {', '.join(row_data_context_parts)[:150]}...\nActualPromptToModel: {full_prompt_for_gemini[:100]}..."

        generated_text, metadata = generate_with_gemini(
            model_name=model_name,
            contents=gemini_contents,
            system_instruction=STRUCTURED_DATA_SYSTEM_INSTRUCTION + glossary_instruction, # これは「AIへの役割指示」
            max_output_tokens=max_tokens,
            temperature=temperature,
            user_info=user_info,
            log_prompt_text=log_prompt_for_call, # ★ 修正: より詳細なログ用プロンプト
            log_filenames=[filename],
            feature_category="構造化データ処理（行ごと）"
        )

        if generated_text and not generated_text.startswith("[エラー:") and not generated_text.startswith("[APIエラー:"):
            results.append(generated_text.strip())
        else:
            logger.warning(f"Row {index}: Failed to get valid response from Gemini. Error: {generated_text}")
            results.append(f"エラー: {generated_text}" if generated_text else "エラー: AI応答なし") # エラー時も何かしら記録

    df[new_column_name] = results # 新しい列として結果を追加

    # --- 結果をファイルとして出力 ---
    output_stream = io.BytesIO()
    original_filename_base = os.path.splitext(file.filename)[0]
    file_extension = ""
    if output_format == 'excel':
        file_extension = ".xlsx"
    elif output_format == 'csv':
        file_extension = ".csv"
    output_filename = f"{original_filename_base}_processed{file_extension}"

    try:
        if output_format == 'excel':
            df.to_excel(output_stream, index=False, engine='openpyxl')
            mimetype = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        elif output_format == 'csv':
            df.to_csv(output_stream, index=False, encoding='utf-8-sig')
            mimetype = 'text/csv'
        else: # 通常は到達しない
            return jsonify({"error": "内部エラー: 不明な出力形式です。"}), 500
        
        output_stream.seek(0)
        logger.info(f"Successfully processed and generated {output_format} file: {output_filename}")
        return send_file(
            output_stream,
            mimetype=mimetype,
            as_attachment=True,
            download_name=output_filename
        )
    except Exception as e:
        logger.error(f"Error writing processed data to {output_format} for file '{filename}': {e}", exc_info=True)
        return jsonify({"error": f"結果のファイル書き出し中にエラー: {type(e).__name__}"}), 500

# === GCSプロンプト読み込み用ヘルパー関数 ===
def _list_gcs_prompts_in_folder(bucket_name: str, folder_path: str) -> list[str] | None:
    """指定されたGCSフォルダ内のテキストファイル名をリストして返す"""
    if not bucket_name:
        logger.error("GCSバケット名が環境変数に設定されていません (プロンプト一覧取得)。")
        return None
    try:
        storage_client = get_main_gcs_client()
        if not storage_client:
            logger.error("メインGCSクライアントの初期化に失敗したため、プロンプト一覧を取得できません。")
            return None
        blobs = storage_client.list_blobs(bucket_name, prefix=folder_path)
        prompt_filenames = []
        for blob in blobs:
            if blob.name.lower().endswith(".txt") and blob.name != folder_path: # フォルダ自体を除外し、.txtファイルのみ
                # フルパスからファイル名のみを抽出
                filename = blob.name.split('/')[-1]
                if filename: # 空のファイル名でないことを確認
                    prompt_filenames.append(filename)
        logger.info(f"GCSフォルダ '{folder_path}' から {len(prompt_filenames)} 個のプロンプトファイルをリストしました。")
        return sorted(prompt_filenames) # ファイル名でソート
    except Exception as e:
        logger.error(f"GCSフォルダ '{folder_path}' からのプロンプト一覧取得中にエラー: {e}", exc_info=True)
        return None


# === 新しいAPIエンドポイント: GCSプロンプト一覧取得 ===
@app.route('/list_gcs_prompts', methods=['GET'])
def list_gcs_prompts_endpoint():
    prompt_type = request.args.get('type')
    if not prompt_type or prompt_type not in ['pdf', 'video', 'video_long']:
        return jsonify({"error": "無効なプロンプトタイプです。"}), 400

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    # 1. 共有プロンプトの取得 (既存ロジック)
    folder_map = {
        'pdf': "prompts/PDFデータ抽出/",
        'video': "prompts/動画データ抽出/",
        'video_long': "prompts/動画データ抽出（長編）/"
    }
    folder_path = folder_map.get(prompt_type)
    
    shared_prompts = []
    gcs_prompt_files = _list_gcs_prompts_in_folder(gcs_bucket_name, folder_path)
    if gcs_prompt_files:
        shared_prompts = [{
            "name": os.path.splitext(filename)[0], # 拡張子.txtを除去
            "filename": filename, # .txt付きの元のファイル名も保持
            "isPersonal": False,
            "type": prompt_type,
            "category": "共有プロンプト" # フロントでの表示用
        } for filename in gcs_prompt_files]

    # 2. 個人用プロンプトの取得 (AIチャット用)
    personal_prompts = []
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if user_id:
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                # AIチャット用に登録された個人用プロンプトを取得
                query = "SELECT c.promptName, c.category FROM c WHERE c.userId = @userId AND c.type = 'PersonalChatPrompt'"
                params = [{"name": "@userId", "value": user_id}]
                items = sessions_container.query_items(query=query, parameters=params, partition_key=user_id)
                
                # 重複を排除しつつリスト化
                unique_personal_prompts = {}
                for item in items:
                    if item.get('promptName') and item.get('category'):
                        # 複合キーでユニーク性を担保
                        unique_key = f"{item['category']}_{item['promptName']}"
                        if unique_key not in unique_personal_prompts:
                             unique_personal_prompts[unique_key] = {
                                "name": item['promptName'],
                                "isPersonal": True,
                                "type": "personal_chat", # 識別用タイプ
                                "category": item['category']
                            }
                personal_prompts = list(unique_personal_prompts.values())

            except Exception as e:
                logger.error(f"Failed to fetch personal chat prompts for data extract page: {e}")

    # 3. 結合して返す
    all_prompts = shared_prompts + sorted(personal_prompts, key=lambda x: (x['category'], x['name']))
    return jsonify({"prompts": all_prompts})

# === 新しいAPIエンドポイント: GCSプロンプト内容取得 ===
@app.route('/load_gcs_prompt', methods=['GET'])
def load_gcs_prompt_endpoint():
    prompt_type = request.args.get('type')
    filename_or_prompt_name = request.args.get('filename') # 共有の場合は.txt付き、個人用の場合は名前
    is_personal_str = request.args.get('isPersonal', 'false').lower()
    category = request.args.get('category') # 個人用の場合に必要

    if not filename_or_prompt_name:
        return jsonify({"error": "ファイル名またはプロンプト名が指定されていません。"}), 400

    # 個人用プロンプトの読み込み
    if is_personal_str == 'true':
        # user_info = get_entra_user_info(request)
        user_info = g.user_info
        user_id = user_info.get("userId")
        if not user_id:
            return jsonify({"error": "個人用プロンプトの取得にはログインが必要です。"}), 401
        if not category:
             return jsonify({"error": "個人用プロンプトのカテゴリが指定されていません。"}), 400
        
        sessions_container = get_sessions_container()
        if sessions_container:
            try:
                # AIチャット機能と同様のロジックで取得
                prompt_id = f"chatprompt_{user_id}_{category}_{filename_or_prompt_name}"
                item = sessions_container.read_item(item=prompt_id, partition_key=user_id)
                content = item.get('promptContent')
                if content is not None:
                    return jsonify({"content": content})
                else:
                    return jsonify({"error": "プロンプト内容が見つかりません。"}), 404
            except cosmos_exceptions.CosmosResourceNotFoundError:
                return jsonify({"error": "指定された個人用プロンプトが見つかりません。"}), 404
            except Exception as e:
                logger.error(f"Failed to read personal chat prompt for data extract: {e}")
                return jsonify({"error": "個人用プロンプトの読み込みに失敗しました。"}), 500
        else:
            return jsonify({"error": "データベースに接続できません。"}), 500

    # 共有プロンプトの読み込み (既存ロジック)
    else:
        if not prompt_type or prompt_type not in ['pdf', 'video', 'video_long']:
            return jsonify({"error": "無効なプロンプトタイプです。"}), 400

        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if not gcs_bucket_name:
            return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

        folder_map = {
            'pdf': "prompts/PDFデータ抽出/",
            'video': "prompts/動画データ抽出/",
            'video_long': "prompts/動画データ抽出（長編）/"
        }
        base_folder = folder_map.get(prompt_type)
        
        if '/' in filename_or_prompt_name or '\\' in filename_or_prompt_name or '..' in filename_or_prompt_name:
            return jsonify({"error": "不正なファイル名です。"}), 400
        
        file_path = f"{base_folder}{filename_or_prompt_name}" 

        content = _load_gcs_prompt_content(gcs_bucket_name, file_path)
        if content is not None:
            return jsonify({"content": content})
        else:
            return jsonify({"error": "プロンプト内容の読み込みに失敗しました。"}), 404


# --- PDFデータ抽出 ---
@app.route('/extract_pdf_data', methods=['POST'])
def extract_pdf_data_endpoint():

    main_pdf_files = request.files.getlist('files')
    sample_pdf_files = request.files.getlist('sample_pdfs')
    sample_json_strings = request.form.getlist('sample_jsons')
    user_prompt_text = request.form.get('prompt')

    if not main_pdf_files:
        return jsonify({"error": "メインPDFファイルが指定されていません。"}), 400
    if not user_prompt_text:
        return jsonify({"error": "抽出指示プロンプトが指定されていません。"}), 400
    if len(sample_pdf_files) != len(sample_json_strings):
        return jsonify({"error": "サンプルPDFとサンプルJSONの数が一致しません。"}), 400

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    parts_for_gemini = []
    log_filenames = []

    # ユーザープロンプト
    parts_for_gemini.append(types.Part.from_text(text=f"ユーザー指示プロンプト:\n{user_prompt_text}"))

    # メインPDFファイル
    main_pdf_placeholders = []
    for i, pdf_file in enumerate(main_pdf_files):
        if pdf_file and pdf_file.filename:
            filename = secure_filename(pdf_file.filename)
            log_filenames.append(f"main_{filename}")
            main_pdf_placeholders.append(f"[メインPDF {i+1}: {filename}]")
            pdf_file.seek(0)
            pdf_part = extract_file_content_to_part(pdf_file) # 既存関数を利用
            if pdf_part:
                parts_for_gemini.append(pdf_part)
            else:
                logger.warning(f"メインPDF '{filename}' の処理に失敗しました。")
    parts_for_gemini.append(types.Part.from_text(text=f"処理対象のメインPDFファイル群: {', '.join(main_pdf_placeholders)}"))


    # サンプルデータ (もしあれば)
    if sample_pdf_files:
        parts_for_gemini.append(types.Part.from_text(text="--- 出力形式と抽出の参考情報 (サンプル) ---"))
        for i, (sample_pdf, sample_json_str) in enumerate(zip(sample_pdf_files, sample_json_strings)):
            if sample_pdf and sample_pdf.filename and sample_json_str:
                sample_filename = secure_filename(sample_pdf.filename)
                log_filenames.append(f"sample_{sample_filename}")
                
                parts_for_gemini.append(types.Part.from_text(text=f"\nサンプル {i+1}:"))
                parts_for_gemini.append(types.Part.from_text(text=f"  - サンプルPDFファイル名: [{sample_filename}]"))
                sample_pdf.seek(0)
                sample_pdf_part = extract_file_content_to_part(sample_pdf)
                if sample_pdf_part:
                    parts_for_gemini.append(sample_pdf_part)
                
                # サンプルJSONを検証・整形して追加
                try:
                    parsed_sample_json = json.loads(sample_json_str)
                    formatted_sample_json = json.dumps(parsed_sample_json, indent=2, ensure_ascii=False)
                    parts_for_gemini.append(types.Part.from_text(text=f"  - 期待される抽出結果 (JSON形式):\n```json\n{formatted_sample_json}\n```"))
                except json.JSONDecodeError:
                    parts_for_gemini.append(types.Part.from_text(text=f"  - (警告) サンプルJSONのパースに失敗: {sample_json_str[:100]}..."))
                    logger.warning(f"サンプルJSONのパース失敗 for {sample_filename}")
            else:
                logger.info(f"サンプルセット {i+1} はファイルまたはJSONが不足しているためスキップ。")
        parts_for_gemini.append(types.Part.from_text(text="--- サンプルここまで ---"))


    pdf_extract_system_instruction = """あなたは、PDFファイルから構造化されたデータを抽出する、極めて正確で忠実なAIアシスタントです。
    与えられた複数のPDFファイルの内容、ユーザーからの詳細な指示プロンプト、そして特に重要な**サンプルとして提供されたPDFとその期待されるJSON出力**を深く理解し、以下のルールを厳密に守って作業してください。

    1.  **指示プロンプトへの厳密な遵守:** ユーザーの指示プロンプトは、抽出する具体的な情報、条件、そしてJSON出力の構造に関する主要な規定です。ここに書かれた抽出対象やルールに最大限従ってください。
    2.  **サンプルJSONの完全な模倣:** サンプルPDFとその対応する期待されるJSON出力が提供されている場合、**そのJSONの構造（ネスト、キー名、配列の使用方法、値のデータ型など）を最も重要な手本とし、厳密に模倣してください。** 抽出対象の情報が見つかった場合、その値をサンプルの同じキーに対応付けてください。サンプルJSONは、抽出対象そのものよりも、**どのように抽出・表現すべきか**を示すものです。
    3.  **抽出結果の正確性:** 抽出対象の情報は、提供されたPDFファイルの内容に基づいている必要があります。意図しない内容を抽出したり、存在しない情報を捏造したりしないでください。
    4.  **情報の欠落への対応:** 指示された情報、またはサンプルJSONに存在するキーに対応する情報が、メインのPDFファイルから見つからなかった場合は、対応するJSONの値を `null` または空文字 (`""`) としてください（サンプルに指示やパターンがあればそれに従う）。キー自体を省略しないでください。
    5.  **出力形式:** 最終的な応答は、生成されたJSONオブジェクトの文字列**のみ**としてください。前後の説明文、挨拶、感謝の言葉、補足説明、または ```json ```のようなマークダウンの囲み文字は**絶対に含めないでください**。

    あなたの任務は、与えられた指示とサンプルという「仕様書」に忠実に従い、PDFからデータを「読み取って」JSONという「データ形式」で出力することです。創造性よりも正確性と指示遵守が求められます。
    """
    
    model_name = os.environ.get("PDF_EXTRACT_MODEL_NAME") # 専用モデル名を定義可能に
    max_tokens = int(os.environ.get("PDF_EXTRACT_MAX_TOKENS", 65535))
    temperature = float(os.environ.get("PDF_EXTRACT_TEMPERATURE", 0.0))
    top_p_for_extract = 0.0

    log_prompt_parts_summary = [f"Main Prompt: {user_prompt_text[:100]}..."]
    if main_pdf_placeholders: log_prompt_parts_summary.append(f"Main PDFs: {len(main_pdf_placeholders)}")
    if sample_pdf_files: log_prompt_parts_summary.append(f"Sample Sets: {len(sample_pdf_files)}")

    generated_json_str, metadata = generate_with_gemini(
        model_name=model_name,
        contents=[types.Content(role="user", parts=parts_for_gemini)],
        system_instruction=pdf_extract_system_instruction,
        max_output_tokens=max_tokens,
        temperature=temperature,
        top_p=top_p_for_extract,
        user_info=user_info,
        log_prompt_text="; ".join(log_prompt_parts_summary),
        log_filenames=log_filenames,
        feature_category="PDFデータ抽出",
        generation_config_override={"response_mime_type": "application/json"}
    )

    # # --- ここから追加 ---
    # if generated_json_str:
    #     # 標準出力にAIからの生の応答文字列を出力
    #     print("--- BEGIN RAW AI RESPONSE (JSON STRING) ---")
    #     print(generated_json_str)
    #     print("--- END RAW AI RESPONSE (JSON STRING) ---")
        
    #     # Flaskのロガー経由でも出力しておくと、Azure App Serviceなどのログにも残りやすい
    #     logger.info("Raw AI Response (first 500 chars for log): %s", generated_json_str[:500])
    #     if len(generated_json_str) > 500:
    #         logger.info("Raw AI Response (last 500 chars for log): %s", generated_json_str[-500:])
    # else:
    #     print("--- RAW AI RESPONSE WAS EMPTY OR NONE ---")
    #     logger.info("Raw AI Response was empty or None.")
    # # --- 追加ここまで ---

    if generated_json_str and not generated_json_str.startswith("[エラー:") and not generated_json_str.startswith("[APIエラー:"):
        try:
            # API応答の前後に余計な文字がある場合を考慮し、主要なJSON部分を抽出する試み
            # ただし、AIが完全にJSON文字列のみを返すことを期待している
            json_match = re.search(r'^\s*(\{.*\}|\[.*\])\s*$', generated_json_str, re.DOTALL) # ^\s* と \s*$ で文字列全体のJSONを期待
            if json_match:
                json_to_parse_for_validation = json_match.group(1)
            else:
                # もしAIの応答が純粋なJSONでない場合に備え、主要なJSONブロックを探す
                # これは以前のロジックに近いが、最終的には生の文字列を返すことが目標
                deep_json_match = re.search(r'\{.*\}|\[.*\]', generated_json_str, re.DOTALL)
                if deep_json_match:
                    json_to_parse_for_validation = deep_json_match.group(0)
                else:
                    json_to_parse_for_validation = generated_json_str # マッチしなかった場合はそのまま試す

            # json.loads() は、AIの応答が本当に有効なJSONかのバリデーションのために行う
            # ただし、クライアントには生の文字列 (generated_json_str) を返す
            json.loads(json_to_parse_for_validation.strip()) # バリデーション目的

            # ★★★ 変更点: クライアントにはAIが生成した生のJSON文字列をそのまま返す ★★★
            # jsonifyではなく、直接Responseオブジェクトを生成し、コンテントタイプを指定する
            # AIが生成した生の文字列の先頭・末尾の空白や余計な文字は除去しておくことが望ましい
            # AIのプロンプトで「JSON文字列のみ」を強調しているため、基本的には純粋なJSONが返ることを期待
            
            # AIの応答が完全にJSON文字列のみであることをより確実にするため、
            # `json_to_parse_for_validation` (ある程度整形されたJSON文字列) を使用する
            # ただし、最も確実なのは AI からの `generated_json_str` が完璧なこと。
            # ここでは、バリデーションに使用した `json_to_parse_for_validation.strip()` を返す。
            # もしAIの応答に不要なプレフィックス/サフィックスが多く含まれる場合は、
            # `generated_json_str` をより積極的にクリーニングする必要がある。
            
            response_payload_str = json_to_parse_for_validation.strip()

            # --- 画面表示のため、この文字列をさらに整形 (インデント) ---
            # これは必須ではないが、画面で見やすくするため
            try:
                temp_parsed = json.loads(response_payload_str)
                pretty_response_payload_str = json.dumps(temp_parsed, indent=2, ensure_ascii=False)
            except json.JSONDecodeError:
                # 整形に失敗しても、元の文字列を返す
                pretty_response_payload_str = response_payload_str
            # --- 整形ここまで ---


            return app.response_class(
                response=pretty_response_payload_str, # 整形されたJSON文字列を返す
                # response=response_payload_str, # 整形しない場合はこちら
                status=200,
                mimetype='application/json' # コンテントタイプはJSON
            )
            # 以前の jsonify の代わりに上記を使用
            # return jsonify({"success": True, "data": extracted_data}) # この行は削除またはコメントアウト

        except json.JSONDecodeError as e:
            logger.error(f"PDF抽出結果のJSONパース失敗(バリデーション時): {e}. Raw response (from log): {generated_json_str[:500]}...")
            return jsonify({"error": f"AIの応答をJSONとして解釈できませんでした(バリデーション失敗)。応答: {generated_json_str[:200]}..."}), 500
    else:
        return jsonify({"error": generated_json_str or "AIからの応答がありませんでした。"}), 500

# --- 新しいエンドポイント: PDFから画像を抽出 ---
@app.route('/api/pptx/extract_images_from_pdf', methods=['POST'])
def extract_images_from_pdf_for_pptx_gen():
    if 'pdf_file' not in request.files:
        return jsonify({"error": "PDFファイルがリクエストに含まれていません。"}), 400
    
    pdf_file = request.files['pdf_file']
    
    if not pdf_file.filename.lower().endswith('.pdf'):
        return jsonify({"error": "無効なファイル形式です。PDFファイルを指定してください。"}), 400

    try:
        pdf_file.seek(0)
        # 既存のヘルパー関数を呼び出す
        # この関数はBase64エンコードされた画像のリストを返す
        extracted_images_base64 = extract_images_from_pdf(io.BytesIO(pdf_file.read()))

        if extracted_images_base64:
            logger.info(f"Successfully extracted {len(extracted_images_base64)} images from '{pdf_file.filename}' for PPTX generator.")
            return jsonify({"success": True, "images": extracted_images_base64})
        else:
            logger.info(f"No images were extracted from '{pdf_file.filename}' for PPTX generator.")
            return jsonify({"success": True, "images": []}) # 画像がなくても成功レスポンス

    except Exception as e:
        logger.error(f"Error extracting images from PDF for PPTX generator: {e}", exc_info=True)
        return jsonify({"error": f"サーバー側での画像抽出中にエラーが発生しました: {type(e).__name__}"}), 500

# === GCSへのアップロードと削除 ===
def _upload_to_gcs(file_stream, destination_blob_name: str, bucket_name: str) -> str | None:
    """ファイルストリームをGCSにアップロードし、GCS URIを返す"""
    if not bucket_name:
        logger.error("GCSバケット名が環境変数に設定されていません。")
        return None
    try:
        storage_client = get_main_gcs_client()
        if not storage_client:
            logger.error("メインGCSクライアントの初期化に失敗したため、ファイルをアップロードできません。")
            return None
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(destination_blob_name)

        file_stream.seek(0)
        blob.upload_from_file(file_stream)
        
        gcs_uri = f"gs://{bucket_name}/{destination_blob_name}"

        logger.info(_format_gcs_log_message(f"ファイル '{destination_blob_name}' をGCS ({gcs_uri}) にアップロードしました。"))
        return gcs_uri
        
    except Exception as e:
        logger.error(f"GCSへのファイル '{destination_blob_name}' アップロード中にエラー: {e}", exc_info=True)
        return None

def _schedule_result_blob_cleanup(blob_names: list, delay_seconds: int = 86400):
    """
    指定された Azure Blob のリストを delay_seconds 秒後にバックグラウンドで削除する。
    デフォルトは 24 時間後。サーバー再起動時にはタイマーが失われるため、
    長期保存が不要な一時成果物（ZIPパッケージ・PPTXスライド）の自動クリーンアップ用。
    """
    def _do_cleanup():
        for name in blob_names:
            try:
                delete_blob(name)
                logger.info(f"結果Blobを自動削除しました: {name}")
            except Exception as e:
                logger.warning(f"結果Blob自動削除に失敗しました: {name} - {e}")

    timer = threading.Timer(delay_seconds, _do_cleanup)
    timer.daemon = True  # サーバーシャットダウンをブロックしない
    timer.start()
    logger.info(
        f"結果Blobの自動削除を {delay_seconds // 3600} 時間後にスケジュールしました: {blob_names}"
    )


def _delete_from_gcs(bucket_name: str, blob_name: str) -> bool:
    """GCSから指定されたblobを削除する"""
    if not bucket_name:
        logger.warning("GCSバケット名が未設定のため、ファイル削除をスキップします。")
        return False
    try:
        storage_client = get_main_gcs_client()
        if not storage_client:
            logger.error("メインGCSクライアントの初期化に失敗したため、ファイル削除を行えません。")
            return False
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        if blob.exists():
            blob.delete()
            logger.info(_format_gcs_log_message(f"GCSファイル gs://{bucket_name}/{blob_name} を削除しました。"))
            return True
        else:
            logger.info(_format_gcs_log_message(f"削除対象のGCSファイル gs://{bucket_name}/{blob_name} は存在しませんでした。"))
            return False # 存在しない場合もエラーではない
    except Exception as e:
        logger.error(_format_gcs_log_message(f"GCSファイル gs://{bucket_name}/{blob_name} の削除中にエラー: {e}"), exc_info=True)
        return False

# --- 動画抽出用非同期タスク実行関数 ---
def _run_video_extraction_task(task_id, user_info, gcs_uri, gcs_blob_name, original_video_filename, user_prompt_text, video_duration_seconds):
    """
    通常動画データ抽出処理を行う非同期タスク関数。
    既にアップロードされたGCS URIを使用して処理を行う。
    """
    update_task_in_cosmos(task_id, {
        "status": "PROCESSING",
        "status_message": "動画をAIで分析中...",
        "progress_percent": 10
    })
    logger.info(f"Task {task_id}: Starting video extraction for '{original_video_filename}'. GCS URI: {gcs_uri}")

    try:
        # 1. Gemini API 呼び出し (GCS URIを直接使用)
        mime_type = _get_video_mime_type(original_video_filename)
        video_part = types.Part(file_data=types.FileData(file_uri=gcs_uri, mime_type=mime_type))
        
        prompt_for_model = f"""以下のユーザーの指示プロンプトに従い、提供された動画の内容を分析し、要求される情報を抽出してJSON形式で構造化して出力してください。
動画の総再生時間は約 {video_duration_seconds:.1f} 秒です。
時間に関する情報（作業開始、作業終了、作業時間など）を抽出する際は、この総再生時間を考慮し、秒単位で正確に記述してください。

ユーザー指示プロンプト:
---
{user_prompt_text}
---

最終的な応答は、生成されたJSONオブジェクトまたはJSON配列を含む文字列**のみ**としてください。前後の説明文、挨拶、感謝の言葉、補足説明、または ```json ```のようなマークダウンの囲み文字は**絶対に含めないでください**。
該当する情報が動画から見つからなかった場合は、対応するJSONの値を null または空文字にしてください。
"""
        prompt_part = types.Part.from_text(text=prompt_for_model)
        contents_for_gemini = [video_part, prompt_part]

        video_extract_system_instruction = "あなたは動画分析に特化したAIアシスタントです。提供された動画とユーザーの指示（抽出内容）に基づき、情報を正確に抽出し、JSON形式で構造化して出力する任務を負っています。常にJSON文字列のみを出力し、他の文字列は一切含めないでください。"
        model_name = os.environ.get("VIDEO_EXTRACT_MODEL_NAME")
        max_tokens = int(os.environ.get("VIDEO_EXTRACT_MAX_TOKENS", 65535))
        temperature = float(os.environ.get("VIDEO_EXTRACT_TEMPERATURE", 0.0))
        top_p_for_extract = float(os.environ.get("VIDEO_EXTRACT_TOP_P", 0.0))

        log_prompt_text_for_gemini = f"Async Video Extract (Task {task_id}): OrigFile='{original_video_filename}', GCS='{gcs_uri}', Duration={video_duration_seconds:.1f}s. User Prompt: '{user_prompt_text[:100]}...'"
        
        logger.info(f"Task {task_id}: Calling Gemini for video data extraction (model: {model_name})...")
        generated_json_str, metadata = generate_with_gemini(
            model_name=model_name,
            contents=[types.Content(role="user", parts=contents_for_gemini)],
            system_instruction=video_extract_system_instruction,
            max_output_tokens=max_tokens, temperature=temperature, top_p=top_p_for_extract,
            user_info=user_info,
            log_prompt_text=log_prompt_text_for_gemini,
            log_filenames=[original_video_filename],
            feature_category="動画データ抽出（非同期実処理）",
            skip_cosmos_log=False,
            generation_config_override={"response_mime_type": "application/json"}
        )
        
        update_task_in_cosmos(task_id, {"status_message": "抽出結果を処理中...", "progress_percent": 80})

        if generated_json_str and not generated_json_str.startswith("[エラー:") and not generated_json_str.startswith("[APIエラー:"):
            parsed_json_data = None
            try:
                json_block_match = re.search(r"```json\s*([\s\S]+?)\s*```", generated_json_str)
                json_to_parse = json_block_match.group(1) if json_block_match else generated_json_str.strip()
                parsed_json_data = json.loads(json_to_parse)
                
                update_task_in_cosmos(task_id, {
                    "status": "SUCCESS",
                    "result": {"extracted_json_data": parsed_json_data},
                    "status_message": "動画データの抽出が完了しました。",
                    "progress_percent": 100
                })
                logger.info(f"Task {task_id}: Successfully extracted and parsed JSON data for video.")
            except json.JSONDecodeError as e_json:
                error_msg = f"AIの応答をJSONとして解釈できませんでした。エラー: {e_json}. 応答抜粋: {generated_json_str[:200]}..."
                logger.error(f"Task {task_id}: {error_msg}")
                update_task_in_cosmos(task_id, {"status": "FAILURE", "error": error_msg, "status_message": error_msg, "progress_percent": 100})
        else:
            error_msg = generated_json_str or "AIからの応答がありませんでした。"
            logger.error(f"Task {task_id}: Gemini returned an error or empty response: {error_msg}")
            update_task_in_cosmos(task_id, {"status": "FAILURE", "error": error_msg, "status_message": error_msg, "progress_percent": 100})

    except Exception as e:
        error_msg_exc = f"動画データ抽出処理中に予期せぬエラー: {type(e).__name__} - {e}"
        logger.error(f"Task {task_id}: {error_msg_exc}", exc_info=True)
        update_task_in_cosmos(task_id, {"status": "FAILURE", "error": error_msg_exc, "status_message": error_msg_exc, "progress_percent": 100})
    finally:
        # クリーンアップ: GCSの一時ファイル
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if gcs_blob_name and gcs_bucket_name:
            _delete_from_gcs(gcs_bucket_name, gcs_blob_name)
        
        update_task_in_cosmos(task_id, {"progress_percent": 100})

# --- 動画データ抽出 ---
@app.route('/extract_video_data', methods=['POST'])
def extract_video_data_endpoint():
    logger.info("extract_video_data_endpoint (async): Received request.")

    if 'video_file' not in request.files:
        return jsonify({"error": "動画ファイルがありません。"}), 400
    
    video_file_storage = request.files['video_file']
    user_prompt_text = request.form.get('prompt')
    video_duration_seconds_str = request.form.get('video_duration_seconds')

    if not video_file_storage.filename:
        return jsonify({"error": "動画ファイル名がありません。"}), 400
    if not user_prompt_text:
        return jsonify({"error": "抽出指示プロンプトがありません。"}), 400
    if not video_duration_seconds_str:
        return jsonify({"error": "動画の長さ情報が指定されていません。"}), 400

    try:
        video_duration_seconds = float(video_duration_seconds_str)
        if video_duration_seconds <= 0:
            return jsonify({"error": "動画の長さは正の値である必要があります。"}), 400
    except ValueError:
        return jsonify({"error": "動画の長さ情報の形式が不正です。"}), 400

    try:
        validate_token_limit(
            [video_file_storage], 
            user_prompt_text, 
            None, 
            model_name=config.VIDEO_EXTRACT_MODEL_NAME
        )
        video_file_storage.seek(0)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    user_info = g.user_info
    original_video_filename = secure_filename(video_file_storage.filename)
    task_id = str(uuid.uuid4())

    # --- GCSへの直接アップロード (ストリーム処理) ---
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    file_extension = os.path.splitext(original_video_filename)[1].lower()
    # 一時ファイルとして保存するためのパス
    gcs_blob_name = f"temp_video_uploads/{task_id}_{uuid.uuid4().hex}{file_extension}"
    gcs_uri = None

    try:
        # ポインタを先頭に戻す
        video_file_storage.seek(0)
        
        # ユーティリティ関数を使ってGCSへ直接ストリームアップロード
        # _upload_to_gcs は内部で upload_from_file を使用するためメモリ効率が良い
        gcs_uri = _upload_to_gcs(video_file_storage, gcs_blob_name, gcs_bucket_name)

        if not gcs_uri:
            raise Exception("GCSへのアップロードに失敗しました。")
            
        logger.info(f"Directly uploaded video to GCS: {gcs_uri}")

    except Exception as e:
        logger.error(f"Failed to upload video directly to GCS: {e}", exc_info=True)
        return jsonify({"error": "動画ファイルのアップロードに失敗しました。"}), 500
    # -----------------------------------------------------------

    # Cosmos DBとメモリにタスクの初期状態を保存
    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "video_extraction",
        "user_info": user_info,
        "original_filename": original_video_filename,
        "status_message": "動画抽出タスクを受付ました。",
        "progress_percent": 0
    }
    
    if create_task_in_cosmos(task_initial_data) is None:
        return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500
    
    # 非同期タスクをサブミット
    # 動画の実体ではなく、GCSのURIとBlob名を渡す
    _submit_with_request_id(
        _run_video_extraction_task,
        task_id,
        user_info,
        gcs_uri,       # GCS URI (gs://...)
        gcs_blob_name, # 削除用Blob名
        original_video_filename,
        user_prompt_text,
        video_duration_seconds,
    )
    
    logger.info(f"Task {task_id} for video '{original_video_filename}' submitted for asynchronous processing.")

    # ログ記録
    log_container_for_task = get_cosmos_container()
    if log_container_for_task:
        call_time = datetime.now(timezone.utc)
        model_name_for_log = os.environ.get("VIDEO_EXTRACT_MODEL_NAME")
        log_gemini_call_to_cosmos(
            container=log_container_for_task,
            call_timestamp=call_time, 
            user_info=user_info, 
            model_name=model_name_for_log,
            system_instruction="N/A (Async Video Extraction task enqueued)",
            log_prompt_text=f"Async Video Task Enqueued (ID: {task_id}): File='{original_video_filename}', Duration={video_duration_seconds:.1f}s, Prompt='{user_prompt_text[:100]}...'",
            log_filenames=[original_video_filename],
            max_output_tokens=0,
            temperature=0.0,
            feature_category="動画データ抽出（非同期タスク受付）",
            additional_params={
                "task_id": task_id,
                "video_duration_seconds": video_duration_seconds,
                "processing_mode": "async_threadpool"
            }
        )
    
    return jsonify({"task_id": task_id}), 202

def ensure_temp_upload_dir_exists():
    """一時アップロードディレクトリが存在することを確認し、なければ作成する"""
    if not config.TEMP_UPLOAD_DIR_PPTX:
        os.makedirs(config.TEMP_Uconfig.LOAD_DIR_PPTX)
        logger.info(f"一時アップロードディレクトリを作成しました: {config.TEMP_UPLOAD_DIR_PPTX}")

def save_uploaded_files_temporarily(files, subfolder_id):
    """アップロードされた複数のファイルを一時ディレクトリに保存し、ファイル情報リストを返す"""
    ensure_temp_upload_dir_exists()
    saved_files_info = []
    # subfolder_id が None や空文字列の場合、ルートディレクトリを指してしまうのを防ぐ
    if not subfolder_id:
        logger.error("save_uploaded_files_temporarily に無効な subfolder_id が渡されました。")
        return [], None

    session_upload_path = os.path.join(config.TEMP_UPLOAD_DIR_PPTX, subfolder_id)
    
    abs_session_upload_path = os.path.abspath(session_upload_path)
    logger.info(f"一時保存セッションパスとして {abs_session_upload_path} を使用/作成試行します。")

    if not os.path.exists(session_upload_path):
        try:
            os.makedirs(session_upload_path)
            logger.info(f"一時保存セッションフォルダを作成しました: {abs_session_upload_path}")
        except OSError as e:
            logger.error(f"一時保存セッションフォルダの作成に失敗しました ({abs_session_upload_path}): {e}", exc_info=True)
            return [], None # フォルダ作成失敗時は空リストとNoneを返す
    else:
        logger.info(f"一時保存セッションフォルダは既に存在します: {abs_session_upload_path}")

    for file_storage in files:
        if file_storage and file_storage.filename:
            original_filename = secure_filename(file_storage.filename)
            temp_file_path = os.path.join(session_upload_path, original_filename)
            try:
                file_storage.save(temp_file_path)
                saved_files_info.append({
                    "original_filename": original_filename, # secure_filename 適用後の名前
                    "saved_path": temp_file_path,
                    "size": os.path.getsize(temp_file_path)
                })
                logger.info(f"一時ファイルを保存しました: {temp_file_path}")
            except Exception as e_save:
                logger.error(f"一時ファイル '{temp_file_path}' の保存中にエラー: {e_save}", exc_info=True)
                # 一部ファイルの保存に失敗しても処理を続けるが、saved_files_info には追加しない

    # ファイル保存後にフォルダが存在するか最終確認 (デバッグ用)
    if not os.path.exists(session_upload_path):
        logger.error(f"ファイル保存処理後、一時保存セッションフォルダが存在しません: {abs_session_upload_path}")
        # この場合、既に保存されたファイル情報があっても、フォルダ自体がないので問題
        return [], None
        
    return saved_files_info, session_upload_path

def save_uploaded_files_to_blob(files, session_id):
    """
    アップロードされた複数のファイルをBlob Storageの一時フォルダ(temp_pptx_uploads/{session_id}/)に保存し、
    ファイル情報リストを返す。
    """
    saved_files_info = []
    if not session_id:
        logger.error("save_uploaded_files_to_blob: session_id is required.")
        return []

    # Blob内の保存先プレフィックス
    blob_prefix = f"temp_pptx_uploads/{session_id}/"

    for file_storage in files:
        if file_storage and file_storage.filename:
            raw_original_name = file_storage.filename  # 元のファイル名（表示・ログ用）
            safe_name = secure_filename(raw_original_name) or "file"
            # UUID プレフィックスで日本語ファイル名などの衝突を完全に防ぐ
            unique_blob_filename = f"{uuid.uuid4().hex}_{safe_name}"
            blob_name = f"{blob_prefix}{unique_blob_filename}"

            try:
                # ストリームを直接アップロード（全量メモリ読み込みを回避）
                file_storage.seek(0)
                file_size = file_storage.seek(0, 2)  # ファイルサイズ取得（末尾まで移動）
                file_storage.seek(0)

                if upload_stream_to_blob(file_storage, blob_name):
                    saved_files_info.append({
                        "original_filename": raw_original_name,  # 元のファイル名を保持
                        "blob_name": blob_name,
                        "size": file_size
                    })
                    logger.info(f"Saved temp PPTX asset to blob (stream): {blob_name}")
                else:
                    logger.error(f"Failed to upload temp PPTX asset to blob: {blob_name}")

                # 後続処理のためにストリームをリセット
                file_storage.seek(0)
            except Exception as e_save:
                logger.error(f"Error saving temp PPTX asset '{raw_original_name}' to blob: {e_save}", exc_info=True)

    return saved_files_info


def cleanup_temp_folder(folder_path):
    """指定された一時フォルダとその内容を削除する"""
    abs_folder_path = os.path.abspath(folder_path) # 絶対パスで比較
    abs_temp_upload_dir_root = config.TEMP_UPLOAD_DIR_PPTX

    logger.info(f"クリーンアップ対象の一時フォルダパス (絶対パス): {abs_folder_path}")
    logger.info(f"ルート一時フォルダパス (絶対パス): {abs_temp_upload_dir_root}")

    if not folder_path or abs_folder_path == abs_temp_upload_dir_root:
        logger.error(f"致命的エラーの可能性: クリーンアップ対象がルート一時フォルダまたは無効なパス ({folder_path}) です。削除をスキップします。")
        return

    if os.path.exists(folder_path): # folder_path は os.path.join で作られた相対パスのまま渡される想定
        try:
            shutil.rmtree(folder_path)
            logger.info(f"一時フォルダを削除しました: {folder_path} (絶対パス: {abs_folder_path})")
        except Exception as e:
            logger.error(f"一時フォルダの削除に失敗しました ({folder_path}, 絶対パス: {abs_folder_path}): {e}", exc_info=True)
    else:
        logger.info(f"クリーンアップ対象の一時フォルダ {folder_path} (絶対パス: {abs_folder_path}) は既に存在しません。")

def cleanup_temp_blobs(session_id):
    """指定されたセッションIDに関連する一時Blobファイルを削除する"""
    if not session_id:
        return

    prefix = f"temp_pptx_uploads/{session_id}/"
    try:
        # utils.storage の delete_blob は単一ファイル用なので、
        # ここでコンテナクライアントを取得してリスト＆削除を行う
        connect_str = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        container_name = getattr(config, 'AZURE_STORAGE_CONTAINER_NAME', 'tempstorage')
        
        if not connect_str:
            return

        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        container_client = blob_service_client.get_container_client(container_name)
        
        blobs = container_client.list_blobs(name_starts_with=prefix)
        for blob in blobs:
            container_client.delete_blob(blob.name)
            logger.info(f"Deleted temp PPTX blob: {blob.name}")
            
    except Exception as e:
        logger.error(f"Error cleaning up temp PPTX blobs for session {session_id}: {e}", exc_info=True)

def remove_ansi_escape_sequences(text):
    if not text or not isinstance(text, str):
        return text
    # ANSIエスケープシーケンスの正規表現
    # \x1B または \u001B で始まり、[ で続き、0-9 と ; で構成され、m で終わるパターン
    ansi_escape_pattern = re.compile(r'\x1B\[[0-9;]*[mK]') # K (行末まで削除)も考慮
    # _x001B_ のようなXMLエンコードされたエスケープシーケンスも考慮
    xml_encoded_escape_pattern = re.compile(r'_x001B_\[[0-9;]*[mK]')
    
    text_no_ansi = ansi_escape_pattern.sub('', text)
    text_no_xml_ansi = xml_encoded_escape_pattern.sub('', text_no_ansi)
    return text_no_xml_ansi.strip() # 前後の空白も除去

