@app.route('/api/chat/multi_agent/start', methods=['POST'])
def start_multi_agent_session():
    """マルチエージェントセッションを開始する"""
    data = request.get_json()
    if not data or 'final_objective' not in data:
        return jsonify({"error": "最終目的が指定されていません。"}), 400

    task_id = str(uuid.uuid4())
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    
    chat_settings_from_request = data.get('chatSettings', {})
    attachments_from_request = data.get('attachments', []) 

    is_data_analysis_regen_flag = data.get('is_data_analysis_regen', False)

    agent_team_prompts = data.get('agent_team_prompts', []) 

    initial_history = [{"role": "user", "content": f"最終目的: {data['final_objective']}"}]
    history_blob_path = f"{task_id}/history.json"   # コンテナ: multi-agent-tasks
    _save_task_history_to_blob(task_id, initial_history)

    task_initial_data = {
        "id": task_id, # Cosmos DBのパーティションキー/ID用
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "multi_agent_chat",
        "final_objective": data['final_objective'],
        "history_blob_path": history_blob_path,
        "user_info": user_info,
        "iteration": 0,
        "chat_settings": chat_settings_from_request,
        "attachments": attachments_from_request,
        "agent_mode": chat_settings_from_request.get('agentMode', 'autonomous'),
        "max_iterations": int(chat_settings_from_request.get('maxIterations', 3)),
        "is_data_analysis_regen": is_data_analysis_regen_flag,
        "status_message": "タスクを受付ました。",
        "agent_team_prompts": agent_team_prompts
    }

    if create_task_in_cosmos(task_initial_data) is None:
        return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500
    else:
        logger.info(f"タスク {task_id} をCosmos DBに正常に作成しました。")

    _submit_with_request_id(_run_multi_agent_task, task_id)
    
    log_container = get_cosmos_container()
    if log_container:
        log_gemini_call_to_cosmos(
            container=log_container,
            call_timestamp=datetime.now(timezone.utc),
            user_info=user_info,
            model_name="Multi-Agent Orchestrator",
            system_instruction=None,
            log_prompt_text=f"Multi-Agent Task Start: {data['final_objective'][:100]}...",
            log_filenames=[att.get('name') for att in attachments_from_request],
            max_output_tokens=0,
            temperature=0.0,
            feature_category="マルチエージェント（タスク受付）",
            additional_params={
                "task_id": task_id,
                "agent_mode": data.get('agentMode', 'autonomous'),
                "max_iterations": data.get('maxIterations', 3),
                "chat_settings_used": chat_settings_from_request,
                "agent_team_prompts": [p['name'] for p in agent_team_prompts]
            }
        )

    logger.info(f"Multi-agent task {task_id} submitted.")
    return jsonify({"task_id": task_id}), 202



@app.route('/api/chat/multi_agent/continue', methods=['POST'])
def continue_multi_agent_session():
    """ユーザーからの入力でマルチエージェントセッションを再開する"""
    data = request.get_json()
    task_id = data.get('task_id')
    user_input = data.get('user_input')

    if not task_id:
        return jsonify({"error": "タスクIDが指定されていません。"}), 400

    task_info = get_task_from_cosmos(task_id)

    if not task_info:
        return jsonify({"error": "無効なタスクID、またはタスクの有効期限が切れました。"}), 404
    
    if task_info.get('status') != 'AWAITING_USER_INPUT':
        return jsonify({"error": "タスクはユーザーの入力を待機していません。"}), 400

    blob_path = task_info.get("history_blob_path")
    history = _load_task_history_from_blob(task_id, blob_path) if blob_path else task_info.get("history", [])
    history.append({"role": "user", "content": user_input})
    _save_task_history_to_blob(task_id, history)

    update_task_in_cosmos(task_id, {"status": "PROCESSING", "status_message": "処理を再開しています..."})

    # 非同期でタスクを再開
    _submit_with_request_id(_run_multi_agent_task, task_id)
    
    logger.info(f"Multi-agent task {task_id} continued with user input.")
    return jsonify({"success": True})



def cleanup_old_temp_files(days=1):
    """
    指定された日数より古い一時ファイルをクリーンアップする。
    アプリケーション起動時に実行される。
    """
    logger.info(f"Starting cleanup of temporary session files older than {days} day(s)...")
    
    # 既存のコードで使われている一時ディレクトリ名をリスト化
    # "temp_storage" は save_to_temp_storage() でハードコードされている
    # TEMP_UPLOAD_DIR_PPTX はグローバルスコープで定義されている
    target_base_dir_names = [
        "temp_storage",
        config.TEMP_UPLOAD_DIR_PPTX 
    ]
    
    now = datetime.now()
    cutoff_time = now - timedelta(days=days)

    for base_dir_name in target_base_dir_names:
        if not base_dir_name: continue # 空のディレクトリ名はスキップ
        
        # ディレクトリのフルパスを構築
        base_dir_path = os.path.join(os.path.dirname(__file__), base_dir_name)

        if not os.path.isdir(base_dir_path):
            logger.info(f"Temporary directory '{base_dir_path}' does not exist, skipping.")
            continue

        logger.info(f"Scanning directory: '{base_dir_path}'")
        try:
            # base_dir_path の直下にあるディレクトリ（セッションIDごとのディレクトリ）を走査
            for item_name in os.listdir(base_dir_path):
                item_path = os.path.join(base_dir_path, item_name)
                
                # サブディレクトリのみを対象とする
                if os.path.isdir(item_path):
                    try:
                        # ディレクトリの最終更新日時を取得
                        item_mtime_ts = os.path.getmtime(item_path)
                        item_mtime_dt = datetime.fromtimestamp(item_mtime_ts)

                        if item_mtime_dt < cutoff_time:
                            logger.info(f"Deleting old temporary session directory: '{item_path}' (Last modified: {item_mtime_dt.strftime('%Y-%m-%d %H:%M:%S')})")
                            shutil.rmtree(item_path)
                        else:
                            # デバッグレベルでログを残す
                            logger.debug(f"Keeping recent temporary directory: '{item_path}'")
                    except FileNotFoundError:
                        # 削除処理中に別プロセスで削除された可能性
                        logger.warning(f"Directory '{item_path}' was not found during cleanup, it might have been deleted already.")
                    except Exception as e_inner:
                        logger.error(f"Error processing or deleting directory '{item_path}': {e_inner}", exc_info=False)
        except Exception as e_outer:
            logger.error(f"Error scanning base directory '{base_dir_path}': {e_outer}", exc_info=True)
            
    logger.info("Temporary file cleanup process finished.")

def _format_history_for_prompt(context_history: list) -> str:
    """What-if分析プロンプト用に、会話履歴を整形するヘルパー関数"""
    text_parts = []
    for msg in context_history:
        role = msg.get('role', 'unknown').capitalize()
        content_raw = msg.get('content', '')
        content_str = ""
        # フロントエンドから渡されるcontentは常に文字列化されている前提だが、安全のためチェック
        if isinstance(content_raw, str):
            try:
                # 文字列がJSONオブジェクトや配列であるか試す (ファシリテーターの思考など)
                parsed_json = json.loads(content_raw)
                if isinstance(parsed_json, dict) and 'thought' in parsed_json:
                    thought = parsed_json.get('thought', '...')
                    action = parsed_json.get('action', 'unknown action')
                    content_str = f"[Thought: {thought[:100]}...] [Action: {action}]"
                else: # JSONだが未知の形式
                    content_str = content_raw[:300] + ('...' if len(content_raw) > 300 else '')
            except json.JSONDecodeError:
                # JSONでなければ通常の文字列として扱う
                content_str = content_raw[:300] + ('...' if len(content_raw) > 300 else '')
        else: # 文字列でない場合 (基本的には起こらないはず)
            content_str = str(content_raw)[:300]

        text_parts.append(f"{role}: {content_str}")
    return "\n---\n".join(text_parts)

@app.route('/api/chat/what_if_analysis', methods=['POST'])
def what_if_analysis_endpoint():
    """What-if分析を実行し、3つのシナリオを生成するエンドポイント"""
    data = request.get_json()
    if not data:
        return jsonify({"error": "リクエストボディがJSON形式ではありません。"}), 400
    
    context_history = data.get('contextHistory')
    hypothesis = data.get('whatIfHypothesis')

    if not context_history or not isinstance(context_history, list):
        return jsonify({"error": "分析の起点となる会話履歴が必要です。"}), 400
    if not hypothesis or not hypothesis.strip():
        return jsonify({"error": "分析のための仮説が必要です。"}), 400
        
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    history_for_prompt = _format_history_for_prompt(context_history)

    # LLMへの指示プロンプト
    prompt = f"""
あなたは、与えられた情報から未来を予測し、戦略的な洞察を提供する優秀な戦略コンサルタント兼リスクアナリストです。
以下の「これまでの会話の文脈」と、ユーザーから提示された「仮説（What-if）」を深く理解し、未来のシナリオを3つ生成してください。

## これまでの会話の文脈
{history_for_prompt}

## 仮説 (What-if)
「{hypothesis}」

## あなたのタスク
上記の文脈と仮説に基づき、以下の3つのシナリオを、それぞれの観点から具体的に生成してください。
1.  **ベストケース:** 仮説が導入された結果、考えうる最も良い未来のシナリオ。
2.  **ワーストケース:** 仮説が導入された結果、考えうる最悪の未来のシナリオ。
3.  **最も可能性の高いケース:** バイアスを排除し、現実的に最も起こりうると客観的に判断できるシナリオ。

各シナリオについて、以下の項目を必ず含めてください。
- **シナリオ概要 (`scenario`):** そのシナリオがどのような未来かを、具体的な出来事や状況を含めて記述してください。
- **潜在的なリスク (`risks`):** そのシナリオに至る過程や、その結果として新たに生じる可能性のあるリスクや課題。Markdownの箇条書き形式で記述してください。
- **新たな機会 (`opportunities`):** そのシナリオによって生まれる可能性のある新たなチャンスや利点。Markdownの箇条書き形式で記述してください。

## 出力形式
応答は、以下のキーを持つ単一のJSONオブジェクトで返してください。
- `bestCase`
- `worstCase`
- `mostLikelyCase`

各キーの値は、`scenario` (文字列), `risks` (Markdown文字列), `opportunities` (Markdown文字列) の3つのキーを持つオブジェクトです。

**【最重要】** 応答は、指示されたJSON形式の文字列のみとし、他の説明や ` ```json ` のような囲み文字は絶対に含めないでください。
"""
    
    system_instruction = """あなたは、未来予測と戦略立案に特化したAIです。ユーザーの仮説に基づき、複数のシナリオを客観的かつ多角的に分析し、その結果を構造化されたJSON形式で出力します。創造性と論理的思考を両立させ、意思決定に資する具体的な情報を提供してください。"""

    model_name = os.environ.get("CHAT_MODEL_NAME") # または専用モデル
    max_tokens = 65535
    temperature = 0.6 # 創造性と具体性のバランス

    # Gemini API呼び出し
    what_if_result_str, metadata = generate_with_gemini(
        model_name=model_name,
        contents=[types.Content(role="user", parts=[types.Part.from_text(text=prompt)])],
        system_instruction=system_instruction,
        max_output_tokens=max_tokens,
        temperature=temperature,
        user_info=user_info,
        log_prompt_text=f"What-if Analysis: {hypothesis[:100]}...",
        log_filenames=[],
        feature_category="What-if分析",
        generation_config_override={"response_mime_type": "application/json"}
    )

    if not what_if_result_str or what_if_result_str.startswith(("[エラー:", "[APIエラー:")):
        return jsonify({"error": f"シナリオ生成に失敗しました: {what_if_result_str}"}), 500
    
    try:
        # LLMの応答からJSONを抽出
        json_match = re.search(r'\{.*\}', what_if_result_str, re.DOTALL)
        if not json_match:
            raise json.JSONDecodeError("No JSON object found in the response.", what_if_result_str, 0)
        
        parsed_json = json.loads(json_match.group(0))
        # 形式バリデーション (簡易)
        if not all(k in parsed_json for k in ['bestCase', 'worstCase', 'mostLikelyCase']):
             raise ValueError("応答に必要なキーが不足しています。")

        return jsonify(parsed_json)
    except (json.JSONDecodeError, ValueError) as e:
        logger.error(f"What-if分析の応答JSONパースに失敗: {e}. Raw Response: {what_if_result_str[:500]}...")
        return jsonify({"error": f"AIの応答をJSONとして解釈できませんでした。詳細: {e}"}), 500

