@app.route('/api/diff/compare_files', methods=['POST'])
def compare_files_endpoint():
    if 'file1' not in request.files or 'file2' not in request.files:
        return jsonify({"error": "2つのファイルが必要です。"}), 400

    file1 = request.files['file1']
    file2 = request.files['file2']

    if file1.filename == '' or file2.filename == '':
        return jsonify({"error": "両方のファイルを選択してください。"}), 400

    try:
        content1 = _get_text_from_file_for_diff(file1)
        content2 = _get_text_from_file_for_diff(file2)

        if content1 is None or content2 is None:
            return jsonify({"error": "ファイルのテキスト抽出に失敗しました。対応していない形式か、ファイルが破損している可能性があります。"}), 400

        if not content1.strip() or not content2.strip():
            return jsonify({"error": "ファイルの内容が空か、テキストを抽出できませんでした。"}), 400

        custom_prompt = request.form.get('custom_prompt', '').strip()
        custom_prompt_section = f"""
**追加の確認観点（ユーザー指定）:**
{custom_prompt}
上記の観点も含めて、不一致点・懸念点を漏れなく抽出してください。
""" if custom_prompt else ""

        # ★★★ ここからプロンプトを全面的に変更 ★★★
        user_prompt = f"""以下の2つのテキスト（テキスト1、テキスト2）を比較し、意味内容における本質的な不一致点を特定してください。

**タスクの目的:**
単純な文字単位の差分ではなく、**意味内容が異なる箇所、追加された情報、削除された情報、矛盾する主張**を構造化された形式で抽出すること。フォーマットの違いや軽微な表現の揺れは無視してください。
また、テキストに「行番号」が付与されている場合は、**一方にしか存在しない行番号を「行の削除」または「行の追加」として必ず検出**してください。{custom_prompt_section}

**出力形式の厳格な指示:**
応答は、以下の構造を持つ**単一のJSONオブジェクト**のみとしてください。
説明文やマークダウン、```jsonの囲み文字は**絶対に含めないでください**。

```json
{{
  "summary": "（2つの文書の全体的な違いに関する簡潔なサマリー）",
  "comparison_pairs": [
    {{
      "file1_content": "（テキスト1の関連する段落や部分）",
      "file2_content": "（テキスト2の対応する段落や部分）",
      "comment": "（このペアの具体的な不一致点に関する簡潔な解説）"
    }},
    {{
      "file1_content": "（テキスト1にのみ存在する主要な情報）",
      "file2_content": null,
      "comment": "この情報はテキスト1にのみ存在します。"
    }},
    {{
      "file2_content": "（テキスト2にのみ存在する主要な情報）",
      "file1_content": null,
      "comment": "この情報はテキスト2にのみ存在します。"
    }}
  ]
}}
```

**JSONの各キーの説明:**
- **`summary`**: (必須, 文字列) 全体の違いを一言で要約。
- **`comparison_pairs`**: (必須, 配列) 比較ペアのリスト。
  - **`file1_content`**: (文字列 or `null`) テキスト1から抽出した関連部分。対応する部分がなければ`null`。
  - **`file2_content`**: (文字列 or `null`) テキスト2から抽出した関連部分。対応する部分がなければ`null`。
  - **`comment`**: (必須, 文字列) このペアがなぜ不一致なのかを説明する簡潔なコメント。

**実行手順:**
1.  両方のテキストを全体的に読み、意味的な構造（章、節、段落など）を把握する。
2.  対応する部分をペアリングしながら、意味が大きく異なる箇所を特定する。
3.  一方にしか存在しない重要な情報を特定する。
4.  行番号が付与されたデータ（表形式データ）の場合、一方にしか存在しない行番号を「削除された行」または「追加された行」として必ず検出し、`comparison_pairs`に含める。
5.  特定した不一致点ごとに、上記のJSONオブジェクトを生成し、`comparison_pairs`配列に追加する。
6.  最後に`summary`を生成する。
7.  最終的なJSONオブジェクトのみを出力する。

--- テキスト1: {file1.filename} ---
{content1}
--- テキスト1ここまで ---

--- テキスト2: {file2.filename} ---
{content2}
--- テキスト2ここまで ---
"""
        
        model_name = os.environ.get("DIFF_CHECKER_MODEL_NAME")
        try:
            validate_token_limit(None, user_prompt, None, model_name=model_name)
        except ValueError as e:
            return jsonify({"error": str(e)}), 400

        system_prompt = "あなたは、2つの文書を比較し、意味内容における本質的な不一致点を特定し、その結果を厳密なJSON形式で出力する、非常に優秀な差分分析エキスパートです。"

        # user_info = get_entra_user_info(request)
        user_info = g.user_info

        model_name = os.environ.get("DIFF_CHECKER_MODEL_NAME")

        diff_result_str, metadata = generate_with_gemini(
            model_name=model_name,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=user_prompt)])],
            system_instruction=system_prompt,
            max_output_tokens=65535,
            temperature=0.2,
            user_info=user_info,
            log_prompt_text=f"File Diff (JSON): {file1.filename} vs {file2.filename}",
            log_filenames=[file1.filename, file2.filename],
            feature_category="ドキュメント比較 (JSON出力)",
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not diff_result_str or diff_result_str.startswith("[エラー:") or diff_result_str.startswith("[APIエラー:"):
            return jsonify({"error": f"AIによる比較処理に失敗しました: {diff_result_str}"}), 500
        
        try:
            # AIが ```json ... ``` で囲んでくる可能性を考慮
            json_match = re.search(r'\{.*\}', diff_result_str, re.DOTALL)
            if not json_match:
                raise json.JSONDecodeError("応答にJSONオブジェクトが見つかりません。", diff_result_str, 0)
            
            parsed_json = json.loads(json_match.group(0))
            
            # 形式の簡易バリデーション
            if not isinstance(parsed_json, dict) or "summary" not in parsed_json or "comparison_pairs" not in parsed_json:
                 raise ValueError("JSONの形式が正しくありません。'summary'または'comparison_pairs'キーがありません。")

            return jsonify({"success": True, "diff_data": parsed_json})

        except (json.JSONDecodeError, ValueError) as e:
            logger.error(f"AI応答のJSONパースに失敗: {e}. Raw Response: {diff_result_str[:500]}...")
            return jsonify({"error": f"AIの応答をJSONとして解釈できませんでした。エラー: {e}"}), 500

    except Exception as e:
        logger.error(f"ファイル比較処理中にエラー: {e}", exc_info=True)
        return jsonify({"error": "サーバー内部でエラーが発生しました。"}), 500

@app.route('/api/diff/export_excel_from_json', methods=['POST'])
def export_diff_to_excel_from_json_endpoint():
    """
    クライアントから受け取った比較結果のJSONデータからExcelファイルを生成する。
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "JSONデータが必要です。"}), 400

        parsed_json = data.get('diff_data')
        file1_name = data.get('file1_name', 'file1.txt')
        file2_name = data.get('file2_name', 'file2.txt')

        if not parsed_json:
            return jsonify({"error": "比較データ (diff_data) がJSONに含まれていません。"}), 400

        # Excelファイルを生成
        wb = openpyxl.Workbook()
        
        # --- サマリーシート ---
        summary_sheet = wb.active
        summary_sheet.title = "サマリー"
        summary_sheet['A1'] = "比較サマリー"
        summary_sheet['A1'].font = Font(bold=True, size=14)
        summary_sheet['A2'] = parsed_json.get("summary", "サマリー情報がありません。")
        summary_sheet['A2'].alignment = Alignment(wrap_text=True, vertical='top')
        summary_sheet.column_dimensions['A'].width = 100

        # --- 詳細シート ---
        details_sheet = wb.create_sheet("比較詳細")
        
        # ヘッダースタイル
        header_font = Font(bold=True, color="FFFFFF")
        header_fill = PatternFill(start_color="4F81BD", end_color="4F81BD", fill_type="solid")
        
        # ヘッダー書き込み
        headers = [f"ファイル1の内容 ({file1_name})", f"ファイル2の内容 ({file2_name})", "AIによるコメント"]
        for col_idx, header_title in enumerate(headers, 1):
            cell = details_sheet.cell(row=1, column=col_idx, value=header_title)
            cell.font = header_font
            cell.fill = header_fill
        
        # データ書き込み
        alignment_wrap = Alignment(wrap_text=True, vertical='top')
        for row_idx, pair in enumerate(parsed_json.get("comparison_pairs", []), 2):
            details_sheet.cell(row=row_idx, column=1, value=pair.get("file1_content", ""))
            details_sheet.cell(row=row_idx, column=2, value=pair.get("file2_content", ""))
            details_sheet.cell(row=row_idx, column=3, value=pair.get("comment", ""))
            
            # 全てのセルに折り返しスタイルを適用
            for col_idx in range(1, 4):
                details_sheet.cell(row=row_idx, column=col_idx).alignment = alignment_wrap

        # 列幅の調整
        for col_letter in ['A', 'B', 'C']:
            details_sheet.column_dimensions[col_letter].width = 60

        # ファイルをストリームに保存して送信
        output_stream = io.BytesIO()
        wb.save(output_stream)
        output_stream.seek(0)
        
        output_filename = f"diff_report_{os.path.splitext(file1_name)[0]}.xlsx"

        return send_file(
            output_stream,
            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
            as_attachment=True,
            download_name=output_filename
        )

    except Exception as e:
        logger.error(f"Excelエクスポート処理中にエラー (from JSON): {e}", exc_info=True)
        return jsonify({"error": "サーバー内部でExcel生成エラーが発生しました。"}), 500

# --- Text-to-Speechクライアントの初期化ヘルパー --- (新規追加)
tts_client = None
def get_tts_client():
    """
    TextToSpeechClientをシングルトンとして初期化・取得する。
    """
    global tts_client
    if tts_client is None:
        try:
            # 環境に認証情報が設定されていることを前提とします。
            print("Attempting to initialize Text-to-Speech client...")
            tts_client = texttospeech.TextToSpeechClient()
            print("Text-to-Speech client initialized successfully.")
        except Exception as e:
            logger.error(f"Failed to initialize Text-to-Speech client: {e}", exc_info=True)
            return None
    return tts_client

# --- 音声合成ヘルパー関数 (Gemini TTSからStandard/Neural2へ戻す修正) ---
def generate_speech_for_pptx(text: str, language_code: str = 'ja', voice_name: str | None = None, user_info: dict | None = None) -> bytes | None:
    """
    指定されたテキストからナレーション用の音声データ（MP3形式）を生成する。
    Google Cloud Text-to-Speech (Neural2/WaveNet/Standard) を使用する旧ロジックに戻しました。
    ※ user_info引数は互換性維持のために残していますが、この関数内ではログ記録に使用しません。
    """
    if not text or not text.strip():
        return None

    # クライアントの取得
    client = get_tts_client()
    if not client:
        # フォールバック
        try:
            client = texttospeech.TextToSpeechClient()
        except Exception as e:
            logger.error(f"Failed to create TextToSpeechClient: {e}")
            return None

    try:
        synthesis_input = texttospeech.SynthesisInput(text=text)
        
        lang_code_map = {'ja': 'ja-JP', 'en': 'en-US', 'zh': 'cmn-CN'}
        api_language_code = lang_code_map.get(language_code, 'ja-JP')

        # ボイス設定
        if voice_name:
            voice = texttospeech.VoiceSelectionParams(
                language_code=api_language_code,
                name=voice_name
            )
        else:
            # デフォルトボイス設定
            default_voice_map = {
                'ja-JP': "ja-JP-Neural2-B",
                'en-US': "en-US-Neural2-A",
                'cmn-CN': "cmn-CN-Standard-A"
            }
            voice = texttospeech.VoiceSelectionParams(
                language_code=api_language_code,
                name=default_voice_map.get(api_language_code, "ja-JP-Neural2-B")
            )
        
        audio_config = texttospeech.AudioConfig(
            audio_encoding=texttospeech.AudioEncoding.MP3
        )

        response = client.synthesize_speech(
            input=synthesis_input,
            voice=voice,
            audio_config=audio_config
        )
        return response.audio_content

    except Exception as e:
        logger.error(f"Text-to-Speech API呼び出し失敗: {e}", exc_info=True)
        return None

# --- 【新規追加】Gemini TTS (単一話者) 音声合成ヘルパー ---
def generate_gemini_speech(text: str, voice_name: str = "Kore", language_code: str = "ja-JP", user_info: dict | None = None) -> bytes | None:
    """
    指定されたテキストからナレーション用の音声データ（MP3形式）を生成する。
    Gemini TTSとして振る舞うが、ライブラリの互換性を保つため、内部的にNeural2音声を使用する。
    """
    if not text or not text.strip():
        return None

    # クライアントの初期化 (v1安定版を使用)
    client = get_tts_client()
    if not client:
        try:
            client = texttospeech.TextToSpeechClient()
        except Exception as e:
            logger.error(f"Failed to initialize Text-to-Speech client: {e}", exc_info=True)
            return None

    # 言語コードのマッピング
    lang_code_map = {'ja': 'ja-JP', 'en': 'en-US', 'zh': 'cmn-CN'}
    api_language_code = lang_code_map.get(language_code, 'ja-JP')

    # スタイル指示（Neural2向けには効果は限定的だが残す）
    if api_language_code.startswith('ja'):
        style_prompt = "次の文章を、プレゼンテーションのナレーションとして、明瞭かつ自然に、落ち着いたトーンで話してください"
    else:
        style_prompt = "Speak the following naturally"

    # 音声名のマッピング (Gemini音声をNeural2音声に安全に置換)
    # これにより "This voice requires a model name" エラーを回避します
    safe_voice_map = {
        # 日本語
        "Kore": "ja-JP-Neural2-B",
        "Aoede": "ja-JP-Neural2-A",
        "Fenrir": "ja-JP-Neural2-C",
        "Charon": "ja-JP-Neural2-D",
        # 英語
        "en-US-Kore": "en-US-Neural2-F",
        # デフォルト
        "default": "ja-JP-Neural2-B"
    }
    
    # 指定されたvoice_nameがマッピングにあればそれを使用、なければデフォルトまたは指定値を試行
    target_voice_name = safe_voice_map.get(voice_name, voice_name)
    
    # もし安全なマッピングになく、かつGeminiっぽい名前なら強制的にNeural2に倒す
    if target_voice_name in ["Kore", "Aoede", "Fenrir", "Charon", "Leda", "Orus", "Puck", "Zephyr"]:
        if api_language_code == "ja-JP":
             target_voice_name = "ja-JP-Neural2-B"
        elif api_language_code == "en-US":
             target_voice_name = "en-US-Neural2-F"

    # 音声パラメータの設定 (modelパラメータは削除してエラーを回避)
    voice = texttospeech.VoiceSelectionParams(
        language_code=api_language_code,
        name=target_voice_name
        # model_name=... はライブラリが対応していないため削除
    )

    # オーディオ設定
    audio_config = texttospeech.AudioConfig(
        audio_encoding=texttospeech.AudioEncoding.MP3
    )

    # テキスト入力の設定
    synthesis_input = texttospeech.SynthesisInput(text=text)

    # --- ログ記録: 開始 ---
    log_blob_name = None
    try:
        current_user_info = user_info if user_info else {}
        log_container = get_cosmos_container()
        log_blob_name = log_gemini_call_to_cosmos(
            container=log_container,
            call_timestamp=datetime.now(timezone.utc),
            user_info=current_user_info,
            model_name="google-tts-neural2-fallback", # 実際はNeural2を使用
            system_instruction=style_prompt,
            log_prompt_text=text[:500] + ("..." if len(text) > 500 else ""),
            log_filenames=[],
            max_output_tokens=0, 
            temperature=0.0,
            feature_category="音声合成 (Gemini TTS互換)",
            additional_params={
                "requested_voice": voice_name,
                "used_voice": target_voice_name,
                "language_code": api_language_code
            }
        )
    except Exception: pass

    try:
        # 分割処理 (4000バイト制限対策)
        import textwrap
        chunks = textwrap.wrap(text, 800, break_long_words=False, replace_whitespace=False)
        if not chunks: chunks = [text]
        
        combined_audio = b""
        
        logger.info(f"Synthesizing speech (Safe Mode): {len(chunks)} chunks. Voice: {target_voice_name}")
        
        for chunk in chunks:
            chunk_input = texttospeech.SynthesisInput(text=chunk)
            response = client.synthesize_speech(
                input=chunk_input,
                voice=voice,
                audio_config=audio_config
            )
            combined_audio += response.audio_content
        
        # --- ログ更新 ---
        if log_blob_name and combined_audio:
            try:
                import librosa
                with io.BytesIO(combined_audio) as audio_buffer:
                    y, sr = librosa.load(audio_buffer, sr=None)
                    duration_sec = librosa.get_duration(y=y, sr=sr)
                output_tokens = int(duration_sec * 25)
                usage_data = {
                    "prompt_tokens": len(text),
                    "completion_tokens": output_tokens,
                    "total_tokens": len(text) + output_tokens,
                    "audio_duration_seconds": round(duration_sec, 2)
                }
                update_gemini_log_usage(log_blob_name, usage_data)
            except Exception: pass

        return combined_audio
        
    except Exception as e:
        logger.error(f"Text-to-Speech API call failed: {e}", exc_info=True)
        return None

# --- 複数話者音声合成ヘルパー (これはGemini機能として残す) ---
def generate_multispeaker_audio(text: str, speaker_configs: list[dict], language_code: str = "ja-JP", user_info: dict | None = None) -> bytes | None:
    """
    Gemini TTSを使用して複数話者の音声を生成する。
    (この関数は音声解説機能で必要なため、変更せずに維持します)
    """
    log_blob_name = None
    try:
        client = get_tts_client()
        if not client:
            client = texttospeech.TextToSpeechClient()

        # --- ログ記録開始 ---
        try:
            current_user_info = user_info if user_info else {}
            log_container = get_cosmos_container()
            model_name_log = "gemini-2.5-flash-tts" # Geminiモデル固定
            
            log_blob_name = log_gemini_call_to_cosmos(
                container=log_container,
                call_timestamp=datetime.now(timezone.utc),
                user_info=current_user_info,
                model_name=model_name_log,
                system_instruction="Multi-speaker TTS generation",
                log_prompt_text=text[:500] + "..." if len(text) > 500 else text,
                log_filenames=[], max_output_tokens=0, temperature=0.0,
                feature_category="音声合成 (Multi-speaker)",
                additional_params={
                    "speaker_configs": str(speaker_configs), 
                    "language_code": language_code,
                    "text_length": len(text)
                }
            )
        except Exception as log_err:
            logger.warning(f"Failed to create initial log for multi-speaker TTS: {log_err}")

        # プロンプト（スタイル指示）
        style_prompt = "次の会話を、ポッドキャストのように自然で聞き取りやすいトーンで話してください。"

        # 音声設定の準備 (Gemini TTS固有の設定)
        speaker_voice_configs = [
            texttospeech.MultispeakerPrebuiltVoice(
                speaker_alias=conf["speaker_alias"],
                speaker_id=conf["speaker_id"]
            )
            for conf in speaker_configs
        ]
        multi_speaker_voice_config = texttospeech.MultiSpeakerVoiceConfig(
            speaker_voice_configs=speaker_voice_configs
        )
        
        # Geminiモデルを指定
        target_model = "gemini-2.5-flash-002" # config.TTS_MODEL_NAME が geminiならそれを使うが、ここでは明示的に動くように記述推奨
        if config.TTS_MODEL_NAME and "gemini" in config.TTS_MODEL_NAME:
             target_model = config.TTS_MODEL_NAME

        voice = texttospeech.VoiceSelectionParams(
            language_code=language_code,
            model_name=target_model,
            multi_speaker_voice_config=multi_speaker_voice_config
        )
        audio_config = texttospeech.AudioConfig(
            audio_encoding=texttospeech.AudioEncoding.MP3
        )

        # --- テキスト分割ロジック ---
        lines = text.split('\n')
        chunks = []
        current_chunk = []
        current_length = 0
        MAX_CHARS_PER_CHUNK = 800 

        for line in lines:
            line_len = len(line)
            if current_length + line_len > MAX_CHARS_PER_CHUNK:
                if current_chunk:
                    chunks.append("\n".join(current_chunk))
                    current_chunk = []
                    current_length = 0
            current_chunk.append(line)
            current_length += line_len + 1

        if current_chunk:
            chunks.append("\n".join(current_chunk))

        combined_audio = b""
        
        for i, chunk_text in enumerate(chunks):
            if not chunk_text.strip(): continue
            
            synthesis_input = texttospeech.SynthesisInput(
                text=chunk_text,
                prompt=style_prompt
            )

            response = client.synthesize_speech(
                input=synthesis_input,
                voice=voice,
                audio_config=audio_config
            )
            combined_audio += response.audio_content
            time.sleep(0.1) 

        # --- ログ更新 ---
        if log_blob_name and combined_audio:
            try:
                import librosa
                with io.BytesIO(combined_audio) as audio_buffer:
                    y, sr = librosa.load(audio_buffer, sr=None)
                    duration_sec = librosa.get_duration(y=y, sr=sr)
                output_tokens = int(duration_sec * 25)
                usage_data = {
                    "prompt_tokens": len(text),
                    "completion_tokens": output_tokens,
                    "total_tokens": len(text) + output_tokens,
                    "audio_duration_seconds": round(duration_sec, 2)
                }
                update_gemini_log_usage(log_blob_name, usage_data)
            except Exception: pass

        return combined_audio

    except Exception as e:
        logger.error(f"Multi-speaker TTS failed: {e}", exc_info=True)
        return None


# --- 【新規追加】音声解説生成エンドポイント ---
@app.route('/api/audio/generate_explanation', methods=['POST'])
def generate_audio_explanation_endpoint():
    """
    チャット履歴から音声解説（ポッドキャスト風）を生成する。
    """
    try:
        data = request.get_json()
        conversation_history = data.get('conversation_history', [])
        mode = data.get('mode', 'single') # 'single' or 'multi'
        length_type = data.get('length', 'short') # 'short' (1min) or 'long' (3min)
        
        if not conversation_history:
            return jsonify({"error": "会話履歴がありません。"}), 400

        # user_info = get_entra_user_info(request)
        user_info = g.user_info

        # 1. チャット履歴のテキスト化
        history_text = "\n".join([f"{msg.get('role', 'unknown')}: {str(msg.get('content', ''))[:500]}" for msg in conversation_history])

        # 2. スクリプト生成用のプロンプト作成
        target_chars = "400字程度" if length_type == 'short' else "1200字程度"
        
        if mode == 'multi':
            # 複数話者（対談形式）
            script_prompt = f"""
あなたは人気テックポッドキャストの優秀な構成作家です。
以下の「会話履歴」の内容を分析し、その話題に最も適した**2人のパーソナリティ（名前と性別）を設定**した上で、彼らが内容を振り返り、重要ポイントを解説する対談台本を作成してください。

**制約事項:**
1.  **キャラクター設定:**
    *   会話の内容に合わせて、親しみやすい名前（英字表記、例: Ken, Yuki, Sarahなど）を2名設定してください。
    *   2人の性別は（男性・女性）、（男性・男性）、（女性・女性）いずれでも構いませんが、会話の雰囲気に合わせてください。
2.  **台本形式:**
    *   `SpeakerName: 発言内容` の形式で記述してください。
    *   長さは合計で{target_chars}。
    *   **【重要】自然な会話の演出:**
        *   機械的な読み上げにならないよう、**「えーっと」「んー」といったフィラー**や、**「なるほど！」「へえー」といった相槌**を適度に入れてください。
        *   文と文の間や、考え込む場面では、**三点リーダー（...）**を使って、**自然な「間」**を表現してください。
    *   履歴の要約だけでなく、そこから得られる洞察や次のアクションへの示唆を含めること。
3.  **出力形式:**
    *   以下のJSON形式のみを出力してください。
    ```json
    {{
      "speakers": [
        {{"name": "名前1(英字)", "gender": "Male"}},
        {{"name": "名前2(英字)", "gender": "Female"}}
      ],
      "script": "名前1: こんにちは！...\\n名前2: んー、今回は...そうですね..."
    }}
    ```

**会話履歴:**
---
{history_text}
---
"""
        else:
            # 一人話者（解説形式）
            script_prompt = f"""
あなたはプロのナレーターです。
以下の「会話履歴」の内容を元に、要点をまとめた解説ナレーション原稿を作成してください。

**制約事項:**
*   **長さ:** 合計で{target_chars}。
*   **トーン:** 知的で落ち着いたトーン。聞き取りやすい話し言葉。
*   **【重要】自然な「間」:**
    *   聞き手が情報を消化しやすいように、重要なポイントの前や段落の変わり目には、**三点リーダー（...）**を使って、**十分な「間」**を持たせてください。
    *   「さて、」「ここで重要なのは...」といった接続詞を使い、語りかけるようなリズムを作ってください。
*   **内容:** 会話の流れを整理し、結論を明確に伝える。
*   **出力形式:**
    *   以下のJSON形式のみを出力してください。
    ```json
    {{
      "script": "（ここに原稿テキスト）"
    }}
    ```

**会話履歴:**
---
{history_text}
---
"""

        # 3. Geminiで台本生成 (JSONモード)
        response_json_str, _ = generate_with_gemini(
            model_name=config.CHAT_MODEL_NAME,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=script_prompt)])],
            max_output_tokens=8192,
            temperature=0.7,
            user_info=user_info,
            feature_category="音声解説台本生成",
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not response_json_str:
            return jsonify({"error": "台本の生成に失敗しました。"}), 500
        
        try:
            cleaned_json_str = response_json_str.strip()
            if cleaned_json_str.startswith("```json"):
                cleaned_json_str = cleaned_json_str[7:]
            elif cleaned_json_str.startswith("```"):
                cleaned_json_str = cleaned_json_str[3:]
            if cleaned_json_str.endswith("```"):
                cleaned_json_str = cleaned_json_str[:-3]
            cleaned_json_str = cleaned_json_str.strip()

            result_data = json.loads(cleaned_json_str)
            script_text = result_data.get("script", "")
        except json.JSONDecodeError:
            return jsonify({"error": "AI応答の解析に失敗しました。"}), 500

        if not script_text:
             return jsonify({"error": "台本が空でした。"}), 500

        # 4. 音声合成
        audio_bytes = None
        
        if mode == 'multi':
            # 複数話者（Gemini TTS Multi-speaker）
            speakers_info = result_data.get("speakers", [])
            if len(speakers_info) < 2:
                speakers_info = [{"name": "Host", "gender": "Male"}, {"name": "Guest", "gender": "Female"}]

            male_voices = ["Charon", "Fenrir", "Puck", "Orus", "Enceladus"]
            female_voices = ["Aoede", "Kore", "Leda", "Erinome"]
            import random
            random.shuffle(male_voices)
            random.shuffle(female_voices)
            m_idx, f_idx = 0, 0
            speaker_configs = []

            for sp in speakers_info:
                name = sp.get("name", "Speaker")
                gender = sp.get("gender", "Female")
                if gender.lower() == "male":
                    voice_id = male_voices[m_idx % len(male_voices)]; m_idx += 1
                else:
                    voice_id = female_voices[f_idx % len(female_voices)]; f_idx += 1
                speaker_configs.append({"speaker_alias": name, "speaker_id": voice_id})

            audio_bytes = generate_multispeaker_audio(script_text, speaker_configs, user_info=user_info)
        else:
            # 一人話者（Gemini TTS Single Speaker）
            # ★★★ ここを修正: 新しい関数 generate_gemini_speech を使用 ★★★
            audio_bytes = generate_gemini_speech(script_text, voice_name="Kore", user_info=user_info)

        if not audio_bytes:
            return jsonify({"error": "音声データの生成に失敗しました。"}), 500

        # 5. Base64エンコードして返却
        audio_base64 = base64.b64encode(audio_bytes).decode('utf-8')
        
        return jsonify({
            "success": True,
            "audio_base64": audio_base64,
            "script": script_text
        })

    except Exception as e:
        logger.error(f"Audio explanation generation error: {e}", exc_info=True)
        return jsonify({"error": str(e)}), 500


# --- 新API: 利用可能な音声リストを取得 ---
# --- 音声リスト取得API (Google Cloud TTSのStandard/Neural2リストに戻す修正) ---
@app.route('/api/tts/voices', methods=['GET'])
@lru_cache(maxsize=1)
def get_available_voices():
    """
    【改善版】Google Cloud Text-to-Speechで利用可能な音声をカテゴリ分けして返す。
    Neural2, WaveNet, Standard 音声を対象とする。
    """
    tts_client = get_tts_client()
    if not tts_client:
        return jsonify({"error": "音声合成サービスが利用できません。"}), 503

    try:
        response = tts_client.list_voices()
        
        voices_by_lang = {
            "ja": {"name": "日本語", "voices": []},
            "en": {"name": "英語 (米国)", "voices": []},
            "zh": {"name": "中国語 (簡体字)", "voices": []},
        }
        
        gender_map = {
            texttospeech.SsmlVoiceGender.MALE: "男性",
            texttospeech.SsmlVoiceGender.FEMALE: "女性",
            texttospeech.SsmlVoiceGender.NEUTRAL: "中性",
            texttospeech.SsmlVoiceGender.SSML_VOICE_GENDER_UNSPECIFIED: "指定なし"
        }

        for voice in response.voices:
            category = None
            short_name = voice.name
            
            if "Neural2" in voice.name:
                category = "Neural2"
                short_name = voice.name.split("-Neural2-")[-1]
            elif "Wavenet" in voice.name:
                category = "WaveNet"
                short_name = voice.name.split("-Wavenet-")[-1]
            elif "Standard" in voice.name:
                category = "Standard"
                short_name = voice.name.split("-Standard-")[-1]
            
            if not category: continue

            lang_code = voice.language_codes[0]
            if lang_code == 'ja-JP': lang_key = 'ja'
            elif lang_code == 'en-US': lang_key = 'en'
            elif lang_code == 'cmn-CN': lang_key = 'zh'
            else: continue

            display_name = f"{category}-{short_name} ({gender_map.get(voice.ssml_gender, '不明')})"

            voices_by_lang[lang_key]["voices"].append({
                "name": voice.name,
                "gender": gender_map.get(voice.ssml_gender, "不明"),
                "display_name": display_name,
                "category": category
            })

        for lang_key in voices_by_lang:
            category_order = {"Neural2": 0, "WaveNet": 1, "Standard": 2}
            voices_by_lang[lang_key]["voices"].sort(key=lambda x: (category_order.get(x["category"], 99), x["name"]))

        return jsonify(voices_by_lang)

    except Exception as e:
        logger.error(f"音声リストの取得中にエラー: {e}", exc_info=True)
        return jsonify({"error": "サーバー側で音声リストの取得に失敗しました。"}), 500


@app.route('/api/document/upload_asset', methods=['POST'])
def upload_document_asset_endpoint():
    if 'file' not in request.files:
        return jsonify({"success": False, "error": "ファイルがリクエストに含まれていません。"}), 400
    
    file_storage = request.files['file']
    session_id_from_request = request.form.get('session_id')

    if not file_storage.filename:
        return jsonify({"success": False, "error": "ファイル名がありません。"}), 400
    if not session_id_from_request:
        return jsonify({"success": False, "error": "セッションIDが不足しています。"}), 400

    raw_filename = file_storage.filename 
    
    try:
        # ファイルをメモリに読み込む
        file_bytes = file_storage.read()
        
        # --- 改定箇所: ローカル保存を廃止し Blob Storage へアップロード ---
        # local_path = save_to_temp_storage(file_storage, session_id_from_request, original_filename) # 廃止
        
        from .utils.storage import upload_chat_attachment_to_blob
        blob_url = upload_chat_attachment_to_blob(file_bytes, session_id_from_request, raw_filename)
        
        if blob_url:
            mime_type, _ = mimetypes.guess_type(raw_filename)
            mime_type = mime_type or 'application/octet-stream'
            
            logger.info(f"アセット '{raw_filename}' を保存しました。")
 
            return jsonify({
                "success": True,
                "filename": raw_filename,
                "gcs_uri": blob_url, # フロントエンドとの互換性のためキー名は維持し、値をBlob URLにする
                "mime_type": mime_type
            })
        else:
            logger.error(f"アセット '{raw_filename}' の Blob アップロード失敗。")
            return jsonify({"success": False, "error": "ストレージへの保存に失敗しました。"}), 500
            
    except Exception as e:
        logger.error(f"アセット '{raw_filename}' のアップロード中にエラー: {e}", exc_info=True)
        return jsonify({"success": False, "error": f"サーバー内部エラー: {type(e).__name__}"}), 500

# --- 新規APIエンドポイント: フロントエンドからアーティファクト(グラフ画像)をGCSにアップロード ---
@app.route('/api/chat/upload_artifact', methods=['POST'])
def upload_chat_artifact():
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"success": False, "error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    if not request.json or 'base64_data' not in request.json:
        return jsonify({"success": False, "error": "アップロードするデータがありません。"}), 400

    base64_string = request.json['base64_data']
    
    if base64_string.startswith('http') or base64_string.startswith('gs://'):
        logger.info("Image data is already a URL/URI. Skipping upload.")
        return jsonify({"success": True, "gcs_uri": base64_string})

    try:
        # Data URL形式 (data:image/png;base64,...) からヘッダーとデータ本体を分離
        if "," in base64_string:
            header, encoded = base64_string.split(",", 1)
        else:
            # ヘッダーがない場合（純粋なBase64）のフォールバック
            header = "data:image/png;base64"
            encoded = base64_string
            
        mime_type = header.split(";")[0].split(":")[1]
        extension = mime_type.split('/')[1] if '/' in mime_type else 'bin'
        
        padding = '=' * (4 - len(encoded) % 4)
        image_bytes = base64.b64decode(encoded + padding)
        image_stream = io.BytesIO(image_bytes)
        
        # GCSに保存するファイル名を生成
        unique_filename = f"{uuid.uuid4().hex}.{extension}"
        destination_blob_name = f"{config.GCS_CHAT_ARTIFACT_FOLDER}{unique_filename}"
        
        # 既存のヘルパー関数を流用してアップロード
        gcs_uri = _upload_to_gcs(image_stream, destination_blob_name, gcs_bucket_name)

        if gcs_uri:
            return jsonify({"success": True, "gcs_uri": gcs_uri})
        else:
            return jsonify({"success": False, "error": "GCSへのアップロードに失敗しました。"}), 500

    except Exception as e:
        logger.error(f"アーティファクトのアップロード処理中にエラー: {e}", exc_info=True)
        return jsonify({"success": False, "error": f"サーバー内部エラー: {type(e).__name__}"}), 500


# --- 新規APIエンドポイント: GCS URIから署名付きURLを取得 ---
@app.route('/api/chat/get_artifact_url', methods=['GET'])
def get_artifact_url():
    gcs_uri = request.args.get('gcs_uri')
    if not gcs_uri or not gcs_uri.startswith("gs://"):
        return jsonify({"success": False, "error": "無効なGCS URIです。"}), 400

    try:
        bucket_name, blob_name = gcs_uri.replace("gs://", "").split("/", 1)

        storage_client = get_main_gcs_client()
        if not storage_client:
            logger.error("メインGCSクライアントの初期化に失敗したため、署名付きURLを生成できません。")
            return jsonify({"success": False, "error": "サーバー設定エラー: GCSクライアント初期化に失敗しました。"}), 500
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(blob_name)

        if not blob.exists():
            return jsonify({"success": False, "error": "指定されたファイルがGCSに存在しません。"}), 404
        
        # 1時間有効な署名付きURLを生成
        expiration_time = timedelta(days=3)
        signed_url = blob.generate_signed_url(version="v4", expiration=expiration_time, method="GET")
        
        return jsonify({"success": True, "signed_url": signed_url})

    except Exception as e:
        logger.error(f"署名付きURLの生成中にエラー ({gcs_uri}): {e}", exc_info=True)
        return jsonify({"success": False, "error": f"URLの生成中にサーバー内部エラーが発生しました: {type(e).__name__}"}), 500

def _run_video_extraction_long_task(task_id, user_info, source_gcs_uri, source_gcs_blob_name, original_video_filename, user_prompt_text, split_video_flag):
    """
    長編動画のデータ抽出（分割・要約・結合）を行う非同期タスク。
    GCS上のソース動画をローカル一時ファイルにダウンロードして処理する。
    """
    update_task_in_cosmos(task_id, {
        "status": "PROCESSING", "status_message": "長編動画の処理を開始しています...", "progress_percent": 5
    })
    logger.info(f"Task {task_id}: Starting long video extraction for '{original_video_filename}'. Split flag: {split_video_flag}")

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        error_msg = "サーバー設定エラー: 動画処理に必要なGCSバケットが設定されていません。"
        update_task_in_cosmos(task_id, {"status": "FAILURE", "error": error_msg})
        return
        
    temp_dir = None
    gcs_blobs_to_delete = [source_gcs_blob_name] # ソース動画も最後に削除対象
    
    try:
        temp_dir = tempfile.mkdtemp()
        
        # 1. GCSからソース動画をローカル一時ファイルにダウンロード
        update_task_in_cosmos(task_id, {"status_message": "動画を作業領域に準備中...", "progress_percent": 8})
        
        local_source_path = os.path.join(temp_dir, secure_filename(original_video_filename))
        
        # GCSクライアント取得
        storage_client = get_main_gcs_client()
        bucket = storage_client.bucket(gcs_bucket_name)
        blob = bucket.blob(source_gcs_blob_name)
        
        # ディスクへダウンロード (メモリ展開しない)
        blob.download_to_filename(local_source_path)
        logger.info(f"Downloaded source video to: {local_source_path}")

        # 2. 動画の分割処理 (またはそのまま使用)
        video_files_to_process = [] # (local_path, is_temp_split_file)
        
        if split_video_flag:
            update_task_in_cosmos(task_id, {"status_message": "動画を分割中...", "progress_percent": 10})
            # _split_video_ffmpeg はローカルパスを受け取り、分割後のファイルパスリストを返す
            split_files = _split_video_ffmpeg(local_source_path, temp_dir, num_parts=2)
            if split_files:
                video_files_to_process = split_files
            else:
                raise Exception("動画の分割に失敗しました。ffmpegのログを確認してください。")
        else:
            # 分割しない場合はソース動画をそのまま使用
            video_files_to_process.append(local_source_path)

        # 3. 各パートの処理ループ
        all_summaries = []
        num_videos = len(video_files_to_process)
        
        for i, video_path in enumerate(video_files_to_process):
            progress = 20 + int(60 * (i / num_videos))
            update_task_in_cosmos(task_id, {
                "status_message": f"動画パート {i+1}/{num_videos} を分析中...", "progress_percent": progress
            })

            # パート動画をGCSにアップロード (Geminiに渡すため)
            # 分割しない場合でも、GeminiにはGCS URIで渡す必要があるためアップロードする
            # (ソース動画のURIを再利用することも可能だが、処理の統一性と安全性のためにアップロードフローを通す)
            file_ext = os.path.splitext(video_path)[1]
            part_blob_name = f"temp_long_videos/{task_id}_part{i+1}{file_ext}"
            gcs_blobs_to_delete.append(part_blob_name)
            
            with open(video_path, "rb") as f_video:
                part_gcs_uri = _upload_to_gcs(f_video, part_blob_name, gcs_bucket_name)
            
            if not part_gcs_uri:
                raise Exception(f"動画パート {i+1} のGCSアップロードに失敗しました。")

            mime_type = _get_video_mime_type(video_path)
            video_part = types.Part(file_data=types.FileData(file_uri=part_gcs_uri, mime_type=mime_type))
            
            prompt_for_part = f"""
あなたは、長編動画の一部を分析する専門家です。
この動画は、長編動画全体のパート {i+1}/{num_videos} です。

**あなたのタスク:**
以下の「ユーザーの最終目的」を達成するために、この動画パートから抽出できる情報を要約・分析してください。
出力は、箇条書きなどを用いて分かりやすくまとめてください。

**もしこの動画パートから抽出できる有益な情報が何もない場合（例: 無音、意味のない映像など）は、必ず「このパートからは特筆すべき情報を抽出できませんでした。」とだけ出力してください。**

**ユーザーの最終目的:**
---
{user_prompt_text}
---

**この動画パートの分析結果:**
"""
            
            model_name = config.VIDEO_EXTRACT_LONG_MODEL_NAME
            summary_part_str, _ = generate_with_gemini(
                model_name=model_name,
                contents=[video_part, types.Part.from_text(text=prompt_for_part)],
                max_output_tokens=65535, temperature=0.3, user_info=user_info,
                feature_category="動画データ抽出（長編パート処理）", skip_cosmos_log=False
            )
            
            if summary_part_str and not summary_part_str.startswith("[エラー:"):
                if summary_part_str.strip():
                    all_summaries.append(f"【動画パート {i+1}/{num_videos} の分析結果】\n{summary_part_str.strip()}")
                else:
                    all_summaries.append(f"【動画パート {i+1}/{num_videos} の分析結果】\nこのパートからは特筆すべき情報を抽出できませんでした。（AIからの応答が空でした）")
            else:
                all_summaries.append(f"【動画パート {i+1}/{num_videos} の分析でエラーが発生】: {summary_part_str}")

        # 4. 最終要約の生成
        update_task_in_cosmos(task_id, {"status_message": "最終的な要約を生成中...", "progress_percent": 90})
        
        final_summary_prompt = f"""
あなたは、複数のレポートを統合して一つの最終報告書を作成する編集長です。
以下は、一つの長編動画を分割して分析した、各パートのレポートです。

**あなたのタスク:**
これらのレポート全体を読み、内容を統合・再構成し、動画全体の包括的な最終要約を作成してください。
最終要約は、ユーザーが元の指示で求めていた内容に沿ったものにしてください。
各パートのレポートヘッダー（【動画パート...】）は最終要約に含めず、自然な一つの文章またはレポートとしてまとめてください。

**ユーザーの元の指示:**
---
{user_prompt_text}
---

**各パートのレポート:**
---
{''.join(all_summaries)}
---

**動画全体の最終要約:**
"""
        
        final_summary, _ = generate_with_gemini(
            model_name=config.DOC_GEN_MODEL_NAME,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=final_summary_prompt)])],
            max_output_tokens=65535, temperature=0.5, user_info=user_info,
            feature_category="動画データ抽出（長編最終結合）", skip_cosmos_log=False
        )

        # 5. 結果の整形と保存
        excel_friendly_result = []
        final_summary_text = "動画全体から有益な情報を抽出できませんでした。"
        if final_summary and final_summary.strip():
            final_summary_text = final_summary.strip()
        
        excel_friendly_result.append({
            "種別": "動画全体の要約",
            "内容": final_summary_text
        })

        for summary_text in all_summaries:
            parts = summary_text.split('\n', 1)
            summary_type = parts[0].strip()
            summary_content = parts[1].strip() if len(parts) > 1 else ""
            excel_friendly_result.append({
                "種別": summary_type,
                "内容": summary_content
            })

        update_task_in_cosmos(task_id, {
            "status": "SUCCESS", 
            "result": {"extracted_json_data": excel_friendly_result},
            "status_message": "長編動画の抽出が完了しました。", 
            "progress_percent": 100
        })

    except Exception as e:
        error_msg = f"長編動画の抽出処理中にエラーが発生しました: {e}"
        logger.error(f"Task {task_id}: {error_msg}", exc_info=True)
        update_task_in_cosmos(task_id, {"status": "FAILURE", "error": error_msg})
    finally:
        # クリーンアップ
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir)
            logger.info(f"Task {task_id}: 一時ディレクトリ {temp_dir} をクリーンアップしました。")
        if gcs_blobs_to_delete:
            for blob in gcs_blobs_to_delete:
                _delete_from_gcs(gcs_bucket_name, blob)
        update_task_in_cosmos(task_id, {"progress_percent": 100})


@app.route('/extract_video_data_long', methods=['POST'])
def extract_video_data_long_endpoint():
    logger.info("extract_video_data_long_endpoint (async): Received request.")

    if 'video_file' not in request.files:
        return jsonify({"error": "動画ファイルがありません。"}), 400
    
    video_file = request.files['video_file']
    user_prompt = request.form.get('prompt')
    split_video_flag = request.form.get('split_video', 'false').lower() == 'true'
    
    video_duration_seconds_str = request.form.get('video_duration_seconds')

    if not video_file.filename:
        return jsonify({"error": "動画ファイル名がありません。"}), 400
    if not user_prompt:
        return jsonify({"error": "抽出・要約指示プロンプトがありません。"}), 400
    if not video_duration_seconds_str:
        return jsonify({"error": "動画の長さ情報が指定されていません。"}), 400

    try:
        video_duration_seconds = float(video_duration_seconds_str)
    except ValueError:
        return jsonify({"error": "動画の長さ情報の形式が不正です。"}), 400

    try:
        validate_token_limit(
            [video_file], 
            user_prompt, 
            None, 
            model_name=config.VIDEO_EXTRACT_LONG_MODEL_NAME
        )
        video_file.seek(0)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    user_info = g.user_info
    original_filename = secure_filename(video_file.filename)
    task_id = str(uuid.uuid4())

    # --- GCSへの直接アップロード (ストリーム処理) ---
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    file_extension = os.path.splitext(original_filename)[1].lower()
    # 一時ファイルとして保存するためのパス
    gcs_blob_name = f"temp_long_videos_source/{task_id}_{uuid.uuid4().hex}{file_extension}"
    gcs_uri = None

    try:
        # ポインタを先頭に戻す
        video_file.seek(0)
        
        # ユーティリティ関数を使ってGCSへ直接ストリームアップロード
        gcs_uri = _upload_to_gcs(video_file, gcs_blob_name, gcs_bucket_name)

        if not gcs_uri:
            raise Exception("GCSへのアップロードに失敗しました。")
            
        logger.info(f"Directly uploaded long video to GCS: {gcs_uri}")

    except Exception as e:
        logger.error(f"Failed to upload long video directly to GCS: {e}", exc_info=True)
        return jsonify({"error": "動画ファイルのアップロードに失敗しました。"}), 500
    
    # Cosmos DBとメモリにタスクの初期状態を保存
    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "video_extraction_long",
        "user_info": user_info,
        "original_filename": original_filename,
        "status_message": "長編動画抽出タスクを受付ました。",
        "progress_percent": 0
    }

    if create_task_in_cosmos(task_initial_data) is None:
        return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500
    
    # 非同期タスクをサブミット (bytesではなくGCS情報を渡す)
    _submit_with_request_id(
        _run_video_extraction_long_task,
        task_id,
        user_info,
        gcs_uri,       # ソース動画のURI
        gcs_blob_name, # 削除用Blob名
        original_filename,
        user_prompt,
        split_video_flag,
    )
    
    logger.info(f"Task {task_id} for long video '{original_filename}' submitted for asynchronous processing.")

    # ログ記録
    log_container = get_cosmos_container()
    if log_container:
        call_time = datetime.now(timezone.utc)
        log_gemini_call_to_cosmos(
            container=log_container,
            call_timestamp=call_time, 
            user_info=user_info, 
            model_name=config.VIDEO_EXTRACT_LONG_MODEL_NAME,
            system_instruction="N/A (Async Long Video task enqueued)",
            max_output_tokens=0,
            temperature=0.0,
            log_prompt_text=f"Async Long Video Task (ID: {task_id}): File='{original_filename}', Split={split_video_flag}, Prompt='{user_prompt[:100]}...'",
            log_filenames=[original_filename],
            feature_category="動画データ抽出（長編タスク受付）",
            additional_params={
                "task_id": task_id, 
                "split_video": split_video_flag
            }
        )
    
    return jsonify({"task_id": task_id}), 202


# --- 新APIエンドポイント: サーバーサイドでHTMLからPDFを生成 (xhtml2pdf版) ---
@app.route('/api/download_report_pdf', methods=['POST'])
def download_report_pdf_endpoint():
    """
    クライアントから送信されたHTMLコンテンツを、xhtml2pdfライブラリを使用して
    サーバーサイドでPDFに変換するエンドポイント。(文字重なり・ページまたぎ根本対策版)
    """
    try:
        data = request.get_json()
        if not data or 'html_content' not in data:
            return jsonify({"error": "PDFに変換するHTMLコンテンツがありません。"}), 400

        html_content = data.get('html_content')
        is_dark_mode = data.get('is_dark_mode', False)

        # --- フォントファイルのBase64エンコード (日本語対応に必須) ---
        font_base64_data = _get_base64_font_data()
        if not font_base64_data:
            logger.warning("日本語フォントデータが見つからないため、PDFで文字化けする可能性があります。")
            font_face_rule = "font-family: sans-serif;"
        else:
            font_face_rule = f"""
                @font-face {{
                    font-family: 'ipaexg';
                    src: url(data:font/truetype;charset=utf-8;base64,{font_base64_data});
                }}
                body {{
                    font-family: 'ipaexg', sans-serif;
                }}
            """

        # ▼▼▼【ここからが修正箇所です】▼▼▼
        # --- スタイルの定義 (ページまたぎ防止 と 行間調整 を追加) ---
        if is_dark_mode:
            css_styles = f"""
                {font_face_rule}
                body {{ 
                    background-color: #0d1117; 
                    color: #c9d1d9; 
                    line-height: 1.7; /* 行間を少し広げる */
                }}
                p {{ margin-bottom: 0.5em; }} /* 段落間のスペース */
                h1, h2, h3, h4, h5, h6 {{ 
                    color: #58a6ff; 
                    border-bottom: 1px solid #30363d; 
                    page-break-after: avoid; /* 見出しの後で改ページされにくくする */
                }}
                table {{ border-collapse: collapse; width: 100%; margin-bottom: 1em; }}
                th, td {{ border: 1px solid #444c56; padding: 8px; text-align: left; }}
                th {{ background-color: #161b22; font-weight: bold; }}
                tr {{ 
                    page-break-inside: avoid; /* テーブルの行がページで分割されるのを防ぐ */
                }}
                ul, ol {{ page-break-inside: avoid; }} /* リスト全体が分割されるのを防ぐ */
                li {{ page-break-inside: avoid; }} /* リストの項目が分割されるのを防ぐ */
                strong, b {{ color: #e6edf3; }}
            """
        else: # ライトモード
            css_styles = f"""
                {font_face_rule}
                body {{ 
                    background-color: #ffffff; 
                    color: #24292e; 
                    line-height: 1.7; /* 行間を少し広げる */
                }}
                p {{ margin-bottom: 0.5em; }} /* 段落間のスペース */
                h1, h2, h3, h4, h5, h6 {{ 
                    color: #0366d6; 
                    border-bottom: 1px solid #eaecef;
                    page-break-after: avoid; /* 見出しの後で改ページされにくくする */
                }}
                table {{ border-collapse: collapse; width: 100%; margin-bottom: 1em; }}
                th, td {{ border: 1px solid #dfe2e5; padding: 8px; text-align: left; }}
                th {{ background-color: #f6f8fa; font-weight: bold; }}
                tr {{ 
                    page-break-inside: avoid; /* テーブルの行がページで分割されるのを防ぐ */
                }}
                ul, ol {{ page-break-inside: avoid; }} /* リスト全体が分割されるのを防ぐ */
                li {{ page-break-inside: avoid; }} /* リストの項目が分割されるのを防ぐ */
            """
        # ▲▲▲【修正はここまでです】▲▲▲
        
        # --- HTML全体を構築 ---
        full_html = f"""
        <!DOCTYPE html>
        <html>
        <head>
            <meta charset="UTF-8">
            <style>{css_styles}</style>
        </head>
        <body>
            <h1>チャット結果レポート</h1>
            {html_content}
        </body>
        </html>
        """

        # --- PDFの生成 ---
        buffer = BytesIO()
        pisa_status = pisa.CreatePDF(
            src=full_html,
            dest=buffer,
            encoding='utf-8'
        )

        if pisa_status.err:
            logger.error(f"xhtml2pdfでのPDF生成に失敗: {pisa_status.err}")
            return jsonify({"error": f"PDFの生成に失敗しました。エラーコード: {pisa_status.err}"}), 500

        buffer.seek(0)
        logger.info("サーバーサイドでのPDF生成に成功しました (xhtml2pdf, ページまたぎ・行間対策版)。")

        return send_file(
            buffer,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f"report_{datetime.now().strftime('%Y%m%d')}.pdf"
        )

    except Exception as e:
        logger.error(f"サーバーサイドPDF生成中に予期せぬエラー (xhtml2pdf): {e}", exc_info=True)
        return jsonify({"error": f"サーバー側でPDF生成中に予期しないエラーが発生しました: {type(e).__name__}"}), 500


def classify_user_intent(last_user_prompt: str, user_info: dict) -> str:
    """
    ユーザーの最新のプロンプトに基づき、その意図が「コード生成」か「自然言語応答」かを分類する。
    """
    if not last_user_prompt:
        return "natural_language_response" # プロンプトが空なら対話とみなす

    # 軽量なモデルで高速に意図を判別する
    classification_prompt = f"""
あなたはユーザーの意図を分類するAIです。以下のユーザーからのテキストが、「Pythonコードの生成・実行」を要求しているか、「自然言語での説明・考察・対話」を要求しているかを判断してください。

- 「グラフ作成」「データ加工」「分析実行」などの具体的な指示は 'code_generation' です。
- 「これはどういう意味？」「考察を教えて」「次のステップは？」などの質問や相談は 'natural_language_response' です。

応答は必ず `code_generation` または `natural_language_response` のいずれか一言のみとしてください。

ユーザーのテキスト:
---
{last_user_prompt}
---

分類結果:
"""

    try:
        # 意図判別には高速なモデルを使用
        intent_model = config.DEFAULT_MODEL_NAME
        
        intent_response, _ = generate_with_gemini(
            model_name=intent_model,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=classification_prompt)])],
            max_output_tokens=100,
            temperature=0.0,
            user_info=user_info,
            skip_cosmos_log=False # この内部的な呼び出しはログ不要
        )

        if intent_response:
            cleaned_response = intent_response.strip().lower()
            if "code_generation" in cleaned_response:
                logger.info(f"User intent classified as: code_generation (Prompt: '{last_user_prompt[:50]}...')")
                return "code_generation"
    
    except Exception as e:
        logger.error(f"User intent classification failed: {e}. Defaulting to natural_language_response.")

    # デフォルトまたはエラー時は自然言語応答とみなす
    logger.info(f"User intent classified as: natural_language_response (Prompt: '{last_user_prompt[:50]}...')")
    return "natural_language_response"

