def _process_files_for_gemini(request_files):
    """リクエストからファイルを取得し、Gemini用のPartオブジェクトとファイル名リストを返す"""
    parts = []
    log_filenames = []
    for file_storage in request_files:
        if file_storage and file_storage.filename:
            log_filenames.append(file_storage.filename)
            file_storage.seek(0)
            part = extract_file_content_to_part(file_storage)
            if part:
                parts.append(part)
    return parts, log_filenames



# --- 新規追加: 図解ツールをSVGに変換するヘルパー関数 ---
def _render_graphviz_to_svg(dot_code: str) -> str | None:
    """Graphviz (DOT言語) のコードをSVG文字列に変換する"""
    if not shutil.which("dot"):
        logger.error("Graphviz 'dot' command not found. Please install Graphviz and ensure it's in the system's PATH.")
        return None
    try:
        process = subprocess.run(
            ["dot", "-Tsvg"],
            input=dot_code,
            capture_output=True,
            text=True,
            encoding='utf-8',
            check=True
        )
        return process.stdout
    except subprocess.CalledProcessError as e:
        logger.error(f"Graphviz rendering failed: {e.stderr}")
        return f'<svg width="1600" height="900" xmlns="http://www.w3.org/2000/svg"><text x="10" y="40" font-family="sans-serif" font-size="30" fill="red">Graphviz Error: {e.stderr[:100]}</text></svg>'
    except Exception as e:
        logger.error(f"An unexpected error occurred during Graphviz rendering: {e}")
        return None

def _render_plantuml_to_svg(puml_code: str) -> str | None:
    """PlantUMLコードをSVG文字列に変換する"""
    if not all([os.path.exists(config.PLANTUML_JAR_PATH), shutil.which('java'), os.path.exists(config.DOT_PATH)]):
        logger.error("PlantUML rendering requirements not met (plantuml.jar, java, or dot is missing).")
        return None
    try:
        with tempfile.NamedTemporaryFile(mode='w+', delete=False, suffix='.puml', encoding='utf-8') as tmp_in:
            tmp_in.write(puml_code)
            in_filename = tmp_in.name
        
        command = [
            'java', '-Djava.awt.headless=true', '-jar', config.PLANTUML_JAR_PATH,
            '-graphvizdot', config.DOT_PATH, '-tsvg', in_filename
        ]
        subprocess.run(command, check=True, capture_output=True)
        
        out_filename = os.path.splitext(in_filename)[0] + ".svg"
        if os.path.exists(out_filename):
            with open(out_filename, 'r', encoding='utf-8') as f_svg:
                svg_content = f_svg.read()
            os.remove(in_filename)
            os.remove(out_filename)
            return svg_content
        return None
    except Exception as e:
        logger.error(f"PlantUML rendering failed: {e}")
        return f'<svg width="1600" height="900" xmlns="http://www.w3.org/2000/svg"><text x="10" y="40" font-family="sans-serif" font-size="30" fill="red">PlantUML Error: Could not render diagram.</text></svg>'

def _render_mermaid_to_svg_server_side(mermaid_code: str) -> str | None:
    """MermaidコードをSVG文字列に変換する (Mermaid CLIが必要)"""
    mmdc_path = os.environ.get("MMDC_PATH", "mmdc") # 環境変数から mmdc のパスを取得
    if not shutil.which(mmdc_path):
        logger.warning(f"Mermaid CLI ('{mmdc_path}') not found. Server-side Mermaid rendering is disabled.")
        # MermaidコードをそのままSVG内の<foreignObject>に入れて返し、クライアント側でレンダリングさせるフォールバック
        escaped_code = html.escape(mermaid_code)
        return f"""<svg width="1600" height="900" xmlns="http://www.w3.org/2000/svg">
            <foreignObject width="100%" height="100%">
                <div xmlns="http://www.w3.org/1999/xhtml" class="mermaid">{escaped_code}</div>
            </foreignObject>
            <script xmlns="http://www.w3.org/1999/xhtml" src="https://cdn.jsdelivr.net/npm/mermaid@10/dist/mermaid.min.js"></script>
            <script xmlns="http://www.w3.org/1999/xhtml">mermaid.initialize({{startOnLoad:true}});</script>
        </svg>"""

    try:
        with tempfile.NamedTemporaryFile(mode='w+', delete=False, suffix='.mmd', encoding='utf-8') as tmp_in:
            tmp_in.write(mermaid_code)
            in_filename = tmp_in.name
        
        out_filename = os.path.splitext(in_filename)[0] + ".svg"
        command = [mmdc_path, '-i', in_filename, '-o', out_filename, '-w', '1600', '-H', '900']

        subprocess.run(command, check=True, capture_output=True, text=True)
        
        if os.path.exists(out_filename):
            with open(out_filename, 'r', encoding='utf-8') as f_svg:
                svg_content = f_svg.read()
            os.remove(in_filename)
            os.remove(out_filename)
            return svg_content
        return None
    except Exception as e:
        logger.error(f"Mermaid rendering failed: {e}")
        return f'<svg width="1600" height="900" xmlns="http://www.w3.org/2000/svg"><text x="10" y="40" font-family="sans-serif" font-size="30" fill="red">Mermaid Error: {str(e)[:100]}</text></svg>'

def _process_files_for_gemini_with_placeholders(request_files):
    """
    リクエストからファイルを取得し、Gemini用のPartオブジェクト、
    プレースホルダーとBase64データのマップ、ファイル名リストを返す。
    """
    parts = []
    log_filenames = []
    placeholder_map = {}
    
    for i, file_storage in enumerate(request_files):
        if file_storage and file_storage.filename:
            filename = file_storage.filename
            log_filenames.append(filename)
            file_storage.seek(0)
            
            # Geminiに渡すPartオブジェクトを作成
            part = extract_file_content_to_part(file_storage)
            if part:
                parts.append(part)
                
                # 画像の場合、Base64エンコードしてプレースホルダーマップを作成
                file_storage.seek(0)
                file_bytes = file_storage.read()
                try:
                    mime_type = magic.from_buffer(file_bytes, mime=True)
                    if mime_type.startswith("image/"):
                        base64_data = base64.b64encode(file_bytes).decode('utf-8')
                        placeholder = f"[IMAGE_PLACEHOLDER_{i+1}]"
                        placeholder_map[placeholder] = f"data:{mime_type};base64,{base64_data}"
                except Exception as e:
                    logger.warning(f"画像 '{filename}' のBase64エンコード中にエラー: {e}")

    return parts, placeholder_map, log_filenames

def _prepare_query_for_iconify(raw_query: str) -> str:
    """AIが生成したクエリをIconify検索に適した形式に前処理する。"""
    if not raw_query:
        return ""
    
    # 1. 小文字に変換
    query = raw_query.lower()
    # 2. ハイフンやアンダースコアをスペースに置換
    query = query.replace('-', ' ').replace('_', ' ')
    # 3. 複数のスペースを1つにまとめる
    query = ' '.join(query.split())
    
    # (オプション) "icon"のような検索に不要な単語を削除
    stop_words = {'icon', 'icons', 'for', 'a', 'an', 'the'}
    query_parts = [word for word in query.split() if word not in stop_words]
    
    cleaned_query = ' '.join(query_parts)
    
    if raw_query != cleaned_query:
        logger.info(f"Iconify query pre-processed: '{raw_query}' -> '{cleaned_query}'")
        
    return cleaned_query



def search_iconify_icons(query: str, limit: int = 5, strategy_name: str = "Initial") -> list[str]:
    """
    Iconify Search APIを叩いて、クエリに一致するアイコン名のリストを返す。
    どの検索戦略で成功したかをログに出力する。
    """
    if not query or not query.strip():
        return []

    def _perform_search(search_query: str) -> list[str] | None:
        if not search_query: return None
        try:
            api_url = f"https://api.iconify.design/search?query={requests.utils.quote(search_query)}&limit={limit}"
            response = requests.get(api_url, timeout=5)
            response.raise_for_status()
            data = response.json()
            
            icons = data.get('icons', [])
            if isinstance(icons, list) and icons:
                filtered_icons = [
                    icon_name for icon_name in icons 
                    if not any(icon_name.startswith(prefix + ':') for prefix in config.ANIMATED_ICON_SETS_BLOCKLIST)
                ]
                
                if filtered_icons:
                    logger.info(f"Iconify search SUCCEEDED with strategy '{strategy_name}' for query '{search_query}'. Top result: '{filtered_icons[0]}'")
                    return filtered_icons[:limit] # 上位N件だけを返す
            return None
        except requests.exceptions.RequestException as e:
            logger.error(f"Iconify Search API request failed for query '{search_query}': {e}")
            return None
        except json.JSONDecodeError as e:
            logger.error(f"Failed to parse JSON from Iconify Search API for query '{search_query}': {e}")
            return None

    processed_query = _prepare_query_for_iconify(query)
    
    results = _perform_search(processed_query)
    if results:
        return results
    
    logger.warning(f"Initial Iconify search for '{query}' (processed as '{processed_query}') failed. Attempting fallback.")

    query_parts = processed_query.split()
    if len(query_parts) > 1:
        last_word_query = query_parts[-1]
        results = _perform_search(last_word_query)
        if results:
            return results
        
        first_word_query = query_parts[0]
        results = _perform_search(first_word_query)
        if results:
            return results

    logger.warning(f"All fallback searches for '{query}' also failed. No icons found.")
    return []



def _embed_icons_into_svg(svg_string: str, user_info_for_translation: dict) -> str:
    """
    SVG文字列内のアイコンプレースホルダーを実際のアイコンデータに置換する。
    【根本対策版】LLMが指定した目標サイズ(data-icon-size)とアイコンの本来のサイズから、
    Python側で正確なscale値を計算して適用する。
    """
    try:
        soup = BeautifulSoup(svg_string, 'xml')
        placeholders = soup.find_all('g', attrs={'data-iconify-query': True})

        if not placeholders:
            return svg_string

        for holder in placeholders:
            query = holder.get('data-iconify-query')
            text_context = holder.get('data-text-context')
            
            # ▼▼▼【ここからが修正箇所】▼▼▼
            # 1. LLMからの指示（目標サイズ）を取得
            target_size_str = holder.get('data-icon-size')
            target_size = None
            if target_size_str and target_size_str.isdigit():
                target_size = int(target_size_str)
            else:
                logger.warning(f"アイコン '{query}' の目標サイズ(data-icon-size)が不正または未指定です。デフォルトサイズで描画します。")
                target_size = 24 # フォールバック値

            # 2. アイコン検索（既存ロジック）
            found_icons = []
            if query:
                found_icons = search_iconify_icons(query, limit=1, strategy_name="AI Query")
            
            if not found_icons and text_context:
                logger.info(f"Icon search failed for query '{query}'. Trying fallback with text context: '{text_context}'")
                translated_context = translate_text_content(text_context, "en", user_info_for_translation)
                if translated_context:
                    found_icons = search_iconify_icons(translated_context, limit=1, strategy_name="Translated Context")

            if not found_icons:
                logger.warning(f"All icon search strategies failed for query='{query}', context='{text_context}'. Skipping.")
                continue
                
            icon_full_name = found_icons[0]
            icon_set, icon_name = icon_full_name.split(':', 1)
            
            # 3. 実際のアイコンSVGデータを取得し、本来のサイズを解析
            color = holder.get('data-icon-color')
            # get_icon_svg にはサイズを指定せずに呼び出し、生のSVGを取得する
            icon_svg_str = get_icon_svg(icon_set, icon_name, color, size=None)

            if not icon_svg_str:
                logger.warning(f"アイコン '{icon_full_name}' のSVGデータ取得に失敗しました。")
                continue

            icon_soup = BeautifulSoup(icon_svg_str, 'xml')
            icon_svg_tag = icon_soup.find('svg')
            if not icon_svg_tag:
                logger.warning(f"アイコン '{icon_full_name}' のSVGデータに<svg>タグがありません。")
                continue
            
            # アイコンの本来のサイズをviewBoxまたはwidth/height属性から取得
            native_width, native_height = 24, 24 # デフォルト
            if icon_svg_tag.has_attr('viewBox'):
                try:
                    _, _, native_width, native_height = map(float, icon_svg_tag['viewBox'].split())
                except ValueError: pass
            elif icon_svg_tag.has_attr('width') and icon_svg_tag.has_attr('height'):
                native_width = float(icon_svg_tag['width'])
                native_height = float(icon_svg_tag['height'])
            
            if native_height <= 0: native_height = native_width # 0除算を避ける

            # 4. 正確なscale値を計算
            scale_factor = target_size / native_height
            
            # 5. 計算したscale値を適用して、プレースホルダーを置換
            # 元の<g>タグのtransformからtranslate部分のみを維持する
            original_transform = holder.get('transform', '')
            translate_match = re.search(r'translate\([^)]+\)', original_transform)
            translate_part = translate_match.group(0) if translate_match else ''
            
            # 新しいtransform文字列を生成
            new_transform = f"{translate_part} scale({scale_factor:.4f})"
            
            # プレースホルダー<g>の内容をクリアし、新しいtransformを適用
            holder.clear()
            holder['transform'] = new_transform
            
            # 取得したアイコンのSVG要素をプレースホルダー内に挿入
            for child in icon_svg_tag.children:
                holder.append(child)
            
            logger.info(f"アイコン '{icon_full_name}' を置換。目標サイズ: {target_size}, 本来の高さ: {native_height:.1f}, 計算scale: {scale_factor:.4f}")
            # ▲▲▲【修正ここまで】▲▲▲

        return str(soup)

    except Exception as e:
        logger.error(f"アイコンの埋め込み処理中にエラーが発生しました: {e}", exc_info=True)
        return svg_string

def _run_slide_generation_task(task_id, objective, ref_parts, img_parts, img_placeholder_map, user_info, design_concept_key, ref_filenames, img_filenames, outline_json_str, target_languages, confidentiality_level_ja, aspect_ratio='16:9', generation_mode='normal'):
    """
    スライド生成の全プロセスを非同期で実行するワーカー関数。
    generation_mode ('normal' or 'image') に応じて処理を分岐。
    【改修】画像モード時の完全多言語化（言語ごとに画像生成）、ノートの文脈考慮、デザイン統一強化。
    """
    try:
        # SVGサイズ決定
        svg_width = 1600
        svg_height = 900
        if aspect_ratio == '4:3':
            svg_width = 1200
            svg_height = 900
        
        def _update_status(message, percent):
            update_task_in_cosmos(task_id, {"status_message": message, "progress_percent": percent})

        _update_status(f"プレゼンテーションのアウトラインを解析中 (モード: {generation_mode})...", 10)
        outline_slides = json.loads(outline_json_str)
        if not isinstance(outline_slides, list) or not outline_slides:
            raise ValueError("生成されたアウトラインが空か、不正な形式です。")

        final_multilingual_slides = []

        # ==========================================
        # 分岐: 画像生成モード (Slide Images)
        # ==========================================
        if generation_mode == 'image':
            total_slides = len(outline_slides)
            
            # 言語名のマッピング
            lang_name_map = {'ja': 'JAPANESE', 'en': 'ENGLISH', 'zh': 'CHINESE (Simplified)'}
            
            # デザイン統一のためのスタイル参照用変数（最初のスライドの画像を保持）
            master_style_image_bytes = None
            
            # ノートの文脈維持用変数（言語ごとに直前のノートを保持）
            previous_notes_context = {lang: "" for lang in target_languages}

            for i, slide_outline in enumerate(outline_slides):
                progress = 15 + int(80 * (i / total_slides))
                _update_status(f"スライド画像とノートを生成中 ({i+1}/{total_slides})...", progress)
                
                title = slide_outline.get("title", "")
                content_items = slide_outline.get("content", [])
                content_str = "\n".join([f"- {item}" for item in content_items])
                
                slide_id = f"slide-{i}-{uuid.uuid4().hex}"
                multilingual_data = {'id': slide_id, 'type': 'image'}

                # 【改修】言語ごとにループして画像とノートを生成
                for lang_code in target_languages:
                    lang_name = lang_name_map.get(lang_code, 'JAPANESE')
                    is_primary_lang = (lang_code == target_languages[0]) # 最初の言語かどうか

                    # 1. コンテンツの翻訳（画像生成用）
                    # 日本語以外の場合、タイトルとコンテンツをその言語に翻訳してから画像生成プロンプトに埋め込む
                    current_title = title
                    current_content_str = content_str
                    
                    if lang_code != 'ja':
                        # 簡易翻訳（本来はLLMで翻訳すべきだが、ここではプロンプト内で指示する形をとるか、
                        # あるいは生成モデル自体に「この言語で作れ」と指示すれば中身も翻訳してくれることを期待する）
                        # Geminiはプロンプトで指示すれば出力画像の文字言語を調整してくれるため、
                        # 入力が日本語でも "Output text in English" で通じることが多いが、
                        # 精度を高めるためにテキスト自体も翻訳しておくのがベスト。
                        # ここでは処理時間短縮のため、プロンプトでの強力な言語指定に頼る。
                        pass 

                    # 2. 画像生成プロンプト構築
                    style_instruction = ""
                    reference_image_part = None

                    # スタイル参照のロジック:
                    # - 1枚目の最初の言語: ユーザー提供画像があればそれを使う
                    # - それ以外（2枚目以降 or 1枚目の他言語）: 「1枚目の最初の言語で生成した画像」をスタイル参照にする
                    if master_style_image_bytes:
                        style_instruction = "IMPORTANT: Use the provided 'Style Reference Image' to strictly maintain consistency in color palette, font style, layout vibe, and character design. The new slide must look like it belongs to the same deck as the reference."
                        reference_image_part = types.Part(inline_data=types.Blob(mime_type="image/png", data=master_style_image_bytes))
                    elif img_parts:
                        # まだマスタ画像がない（＝最初の生成）かつユーザー画像がある場合
                        reference_image_part = img_parts[0]

                    image_prompt = f"""
                    SYSTEM COMMAND: Create a high-quality, complete presentation slide image.
                    
                    **OBJECTIVE:** Visualize a slide for a presentation about: "{objective}"
                    **SLIDE TITLE:** "{current_title}"
                    **SLIDE CONTENT SUMMARY:**
                    {current_content_str}
                    
                    **DESIGN STYLE:** {config.DESIGN_CONCEPTS.get(design_concept_key, {}).get('name', 'Professional Business')}
                    **ASPECT RATIO:** {aspect_ratio}
                    
                    **REQUIREMENTS:**
                    - The image must look like a finished PowerPoint slide.
                    - Include the Title and key points visually (text in image).
                    - **LANGUAGE CONSTRAINT:** ALL text inside the image MUST be in **{lang_name}**. Translate the content if necessary.
                    - Ensure high legibility and professional layout.
                    {style_instruction}
                    """
                    
                    image_gen_contents = [types.Part.from_text(text=image_prompt)]
                    if reference_image_part:
                        image_gen_contents.append(types.Part.from_text(text="Style Reference Image:"))
                        image_gen_contents.append(reference_image_part)

                    generated_image_base64 = None
                    current_image_bytes = None
                    
                    try:
                        # 画像生成API呼び出し
                        response_iterator = generate_with_gemini(
                            model_name=config.IMAGE_GENERATION_MODEL_NAME,
                            contents=[types.Content(role="user", parts=image_gen_contents)],
                            stream=True, user_info=user_info, skip_cosmos_log=False,
                            feature_category=f"PPTXスライド画像生成({lang_code})", aspect_ratio=aspect_ratio,
                            temperature=0.8
                        )
                        
                        full_base64 = ""
                        for chunk in response_iterator:
                            if hasattr(chunk, 'image_data_url') and chunk.image_data_url:
                                if "," in chunk.image_data_url:
                                    _, b64 = chunk.image_data_url.split(",", 1)
                                else:
                                    b64 = chunk.image_data_url
                                full_base64 += b64
                        
                        if full_base64:
                            generated_image_base64 = f"data:image/png;base64,{full_base64}"
                            current_image_bytes = base64.b64decode(full_base64)
                            
                            # 最初のスライドの最初の言語の画像をマスタースタイルとして保存
                            if i == 0 and is_primary_lang:
                                master_style_image_bytes = current_image_bytes
                                logger.info("1枚目のスライド画像をスタイル参照として保存しました。")
                    
                    except Exception as e_img:
                        logger.error(f"スライド {i+1} ({lang_code}) の画像生成に失敗: {e_img}")

                    # 3. ノート生成 (テキストモデル)
                    # 【改修】直前のノート内容を踏まえる指示を追加
                    prev_context_str = ""
                    if i > 0 and previous_notes_context[lang_code]:
                        prev_context_str = f"""
                        **Previous Slide's Note (Context):**
                        "{previous_notes_context[lang_code]}"
                        
                        **Instruction:** Continue naturally from the previous note. Do NOT repeat greetings like "Hello" or "Welcome". Connect the topic smoothly.
                        """
                    else:
                        # 1枚目の場合
                        prev_context_str = "**Instruction:** This is the first slide. You may start with a brief greeting and introduction."

                    notes_prompt = f"""
                    You are a professional presenter. Create "Speaker Notes" (script) for this slide in **{lang_name}**.
                    
                    **Slide Title:** {current_title}
                    **Slide Content:**
                    {current_content_str}
                    
                    {prev_context_str}
                    
                    **Output Constraints:**
                    - **Output ONLY the spoken words.** No meta-text like "Speaker Note:", "Slide 1:", or "Here is the script".
                    - Tone: Natural, engaging, and professional spoken language.
                    - Length: 150-250 characters (or equivalent words).
                    """
                    
                    notes_text = ""
                    try:
                        notes_resp, _ = generate_with_gemini(
                            model_name=config.DEFAULT_MODEL_NAME,
                            contents=[types.Content(role="user", parts=[types.Part.from_text(text=notes_prompt)])],
                            max_output_tokens=1024, temperature=0.7, user_info=user_info,
                            feature_category=f"PPTXスライド画像ノート生成({lang_code})"
                        )
                        if notes_resp:
                            notes_text = notes_resp.strip()
                            # クリーニング
                            notes_text = re.sub(r'^(Here is|Sure|Okay|はい|承知).*?\n', '', notes_text, flags=re.IGNORECASE).strip()
                            notes_text = re.sub(r'^(\*\*|#|---).*?(\*\*|#|---)?\n', '', notes_text).strip()
                            
                            # コンテキスト更新
                            previous_notes_context[lang_code] = notes_text
                    except Exception as e_notes:
                        logger.error(f"スライド {i+1} ({lang_code}) のノート生成に失敗: {e_notes}")
                        notes_text = "（ノートの生成に失敗しました）"

                    # 4. データ構築 (SVGでラップ)
                    if generated_image_base64:
                        svg_content = f'<svg width="{svg_width}" height="{svg_height}" viewBox="0 0 {svg_width} {svg_height}" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice"><image href="{generated_image_base64}" x="0" y="0" width="{svg_width}" height="{svg_height}" preserveAspectRatio="xMidYMid slice"/></svg>'
                    else:
                        svg_content = f'<svg width="{svg_width}" height="{svg_height}" xmlns="http://www.w3.org/2000/svg"><rect width="100%" height="100%" fill="#eee"/><text x="50%" y="50%" font-size="40" text-anchor="middle" fill="red">Image Generation Failed</text></svg>'

                    level_text = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang_code, 'None')
                    svg_content = _add_confidentiality_to_svg(svg_content, level_text, svg_width=svg_width)

                    multilingual_data[lang_code] = {
                        'svg': svg_content,
                        'notes': notes_text
                    }

                final_multilingual_slides.append(multilingual_data)

        # ==========================================
        # 分岐: 通常モード (SVG Generation)
        # ==========================================
        else:
            # (既存のSVG生成ロジック - 変更なし)
            _update_status("デザインの基準となる表紙スライドを生成中...", 15)
            first_slide_outline = outline_slides[0]
            
            master_slide_data = _generate_single_slide_svg_from_files(
                objective, first_slide_outline.get("title", ""), first_slide_outline.get("content", []),
                ref_parts, img_parts, img_placeholder_map, user_info, design_concept_key,
                svg_width=svg_width, svg_height=svg_height
            )
            
            if not master_slide_data:
                raise Exception("最初のスライド（デザインマスター）の生成に失敗しました。処理を続行できません。")

            master_svg = master_slide_data['svg']
            final_slides_list = [master_slide_data]

            remaining_slides = outline_slides[1:]
            
            if remaining_slides:
                BATCH_SIZE = 5 
                slide_batches = list(_chunk_list(remaining_slides, BATCH_SIZE))
                total_batches = len(slide_batches)
                max_workers = 3 
                temp_results = {}
                
                with ThreadPoolExecutor(max_workers=max_workers) as executor:
                    future_to_batch_idx = {}
                    for batch_idx, batch in enumerate(slide_batches):
                        future = executor.submit(
                            _generate_slide_batch_svg, 
                            objective, batch, ref_parts, img_parts, img_placeholder_map, 
                            user_info, design_concept_key, master_svg,
                            svg_width, svg_height
                        )
                        future_to_batch_idx[future] = batch_idx

                    completed_batches = 0
                    for future in as_completed(future_to_batch_idx):
                        batch_idx = future_to_batch_idx[future]
                        completed_batches += 1
                        current_percent = 20 + int(60 * (completed_batches / total_batches))
                        _update_status(f"スライドを一括生成中 ({completed_batches}/{total_batches} バッチ完了)...", current_percent)
                        
                        try:
                            batch_result_list = future.result()
                            if batch_result_list:
                                for i, slide_data in enumerate(batch_result_list):
                                    global_idx = batch_idx * BATCH_SIZE + i
                                    temp_results[global_idx] = slide_data
                            else:
                                logger.warning(f"タスク {task_id}: バッチ {batch_idx} の結果が空でした。")
                        except Exception as e:
                            logger.error(f"タスク {task_id}: バッチ {batch_idx} の生成中にエラー: {e}", exc_info=True)

                for i in range(len(remaining_slides)):
                    if i in temp_results:
                        final_slides_list.append(temp_results[i])
                    else:
                        fallback_title = remaining_slides[i].get("title", f"Slide {i+2}")
                        logger.warning(f"タスク {task_id}: スライド '{fallback_title}' の生成データが見つからないため、フォールバックを使用します。")
                        final_slides_list.append({
                            "title": fallback_title,
                            "svg": f'<svg width="{svg_width}" height="{svg_height}" xmlns="http://www.w3.org/2000/svg"><rect width="{svg_width}" height="{svg_height}" fill="#f0f0f0"/><text x="{svg_width/2}" y="{svg_height/2}" font-family="sans-serif" font-size="40" text-anchor="middle" fill="red">Generation Failed: {fallback_title}</text></svg>',
                            "notes": "このスライドの生成に失敗しました。"
                        })
            
            if not final_slides_list:
                raise Exception("スライドの生成に失敗しました。")

            _update_status("デザインを最終化・翻訳中...", 85)
            
            for i, slide_ja in enumerate(final_slides_list):
                multilingual_slide_data = {'id': f"slide-{i}-{uuid.uuid4().hex}", 'type': 'normal'}
                
                svg_with_icons = _embed_icons_into_svg(slide_ja['svg'], user_info)
                svg_ja_raw = svg_with_icons
                
                for placeholder, base64_data in img_placeholder_map.items():
                    svg_ja_raw = svg_ja_raw.replace(placeholder, base64_data)
                
                level_text_ja = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get('ja', 'なし')
                svg_ja_processed = _add_confidentiality_to_svg(svg_ja_raw, level_text_ja, svg_width=svg_width)
                
                multilingual_slide_data['ja'] = { "svg": svg_ja_processed, "notes": slide_ja.get('notes', '') }
                
                languages_to_translate = [lang for lang in target_languages if lang != 'ja']
                if languages_to_translate:
                    svg_texts_dict, _ = _extract_translatable_texts_from_svg(svg_ja_processed)
                    notes_text = slide_ja.get('notes', '')
                    all_texts_to_translate = {**svg_texts_dict, **({'notes_text': notes_text} if notes_text.strip() else {})}
                    
                    soup_for_template = BeautifulSoup(svg_ja_processed, 'xml')
                    text_nodes = soup_for_template.find_all(['text', 'tspan'])
                    for idx, node in enumerate(text_nodes):
                        parent_g = node.find_parent('g')
                        if not (parent_g and parent_g.get('id') == 'confidentiality-marking') and node.string and node.string.strip():
                            node['data-translate-id'] = f"svg_text_{idx}"
                            node.string = ''
                    svg_template_with_ids = str(soup_for_template)
                    
                    for lang in languages_to_translate:
                        translated_all = _translate_text_batch(all_texts_to_translate, lang, user_info)
                        translated_svg_texts = {k: v for k, v in translated_all.items() if k.startswith('svg_text_')}
                        translated_notes = translated_all.get('notes_text', f"[{lang.upper()}] {notes_text}")
                        
                        final_svg_lang_no_level = _replace_texts_in_svg(svg_template_with_ids, translated_svg_texts)
                        
                        level_text_lang = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang, 'None')
                        final_svg_lang_with_level = _add_confidentiality_to_svg(final_svg_lang_no_level, level_text_lang, svg_width=svg_width)
                        
                        multilingual_slide_data[lang] = { "svg": final_svg_lang_with_level, "notes": translated_notes }
                
                final_multilingual_slides.append(multilingual_slide_data)

        # ==========================================
        # 共通: 履歴保存と完了処理 (データサイズ対策)
        # ==========================================

        # --- STEP 5: 履歴として保存 ---
        try:
            user_id = user_info.get("userId")
            if user_id:
                history_data = {
                    "id": task_id,
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                    "objective": objective,
                    "design_concept": design_concept_key,
                    "slides_data": final_multilingual_slides,
                    "target_languages": target_languages,
                    "confidentiality_level": confidentiality_level_ja,
                    "aspect_ratio": aspect_ratio,
                    "generation_mode": generation_mode
                }
                upload_pptx_history_to_blob(user_id, task_id, history_data)
                logger.info(f"タスク {task_id}: スライド生成結果を履歴として保存しました。")
        except Exception as e_history:
            logger.error(f"タスク {task_id}: 履歴保存に失敗しましたが、タスクは成功とします: {e_history}")

        # --- タスク完了と結果保存 ---
        result_data = {"multilingual_slides": final_multilingual_slides}
        result_json_str = json.dumps(result_data)
        result_size_bytes = len(result_json_str.encode('utf-8'))
        
        THRESHOLD_BYTES = 1.5 * 1024 * 1024 
        
        if result_size_bytes > THRESHOLD_BYTES:
            logger.info(f"タスク {task_id}: 結果データサイズ ({result_size_bytes} bytes) が閾値を超えています。Blob Storageに保存します。")
            
            result_blob_name = f"results/{task_id}_result_data.json"
            if upload_bytes_to_blob(result_json_str.encode('utf-8'), result_blob_name):
                update_task_in_cosmos(task_id, {
                    "status": "SUCCESS",
                    "status_message": "スライド生成が完了しました。",
                    "progress_percent": 100,
                    "result": {
                        "is_large_result": True,
                        "result_blob_name": result_blob_name
                    }
                })
            else:
                raise Exception("結果データのBlob Storageへの保存に失敗しました。")
        else:
            update_task_in_cosmos(task_id, {
                "status": "SUCCESS",
                "status_message": "スライド生成が完了しました。",
                "progress_percent": 100,
                "result": result_data
            })

    except Exception as e:
        logger.error(f"非同期スライド生成タスク {task_id} でエラー: {e}", exc_info=True)
        update_task_in_cosmos(task_id, {
            "status": "FAILURE",
            "error": f"サーバー内部でエラーが発生しました: {str(e)}",
            "status_message": "エラーが発生しました。",
            "progress_percent": 100
        })

    except Exception as e:
        logger.error(f"非同期スライド生成タスク {task_id} でエラー: {e}", exc_info=True)
        update_task_in_cosmos(task_id, {
            "status": "FAILURE",
            "error": f"サーバー内部でエラーが発生しました: {str(e)}",
            "status_message": "エラーが発生しました。",
            "progress_percent": 100
        })

@app.route('/api/pptx/history', methods=['GET'])
def get_pptx_history_list():
    """ユーザーのスライド生成履歴一覧を取得する"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証が必要です。"}), 401

    histories = list_pptx_histories_from_blob(user_id)
    return jsonify({"histories": histories})

@app.route('/api/pptx/history/<history_id>', methods=['GET'])
def get_pptx_history_detail(history_id):
    """指定されたIDのスライド生成履歴詳細を取得する"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証が必要です。"}), 401

    history_data = get_pptx_history_from_blob(user_id, history_id)
    if history_data:
        return jsonify({"success": True, "history_data": history_data})
    else:
        return jsonify({"error": "履歴が見つかりません。"}), 404

@app.route('/api/pptx/history/<history_id>', methods=['DELETE'])
def delete_pptx_history(history_id):
    """指定されたIDのスライド生成履歴を削除する"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証が必要です。"}), 401

    success = delete_pptx_history_blob(user_id, history_id)
    if success:
        return jsonify({"success": True, "message": "履歴を削除しました。"})
    else:
        return jsonify({"error": "履歴の削除に失敗しました。"}), 500

@app.route('/api/pptx/history/<history_id>/update', methods=['POST'])
def update_pptx_history_endpoint(history_id):
    """
    クライアント側での編集内容（スライド追加など）を反映して、履歴データを更新する。
    """
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証が必要です。"}), 401

    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "更新データがありません。"}), 400

        # 既存の履歴データを取得してベースにする（メタデータの維持などのため）
        # ※ 存在確認も兼ねる
        existing_history = get_pptx_history_from_blob(user_id, history_id)
        if not existing_history:
            return jsonify({"error": "指定された履歴が見つかりません。"}), 404

        # 更新用データを構築
        # クライアントから送られてきた最新のスライドデータ等を反映
        updated_history_data = {
            "id": history_id,
            "timestamp": datetime.now(timezone.utc).isoformat(), # 更新日時を現在に
            "objective": data.get("objective", existing_history.get("objective")),
            "design_concept": data.get("design_concept", existing_history.get("design_concept")),
            "slides_data": data.get("slides_data", existing_history.get("slides_data")),
            "target_languages": data.get("target_languages", existing_history.get("target_languages")),
            "confidentiality_level": data.get("confidentiality_level", existing_history.get("confidentiality_level"))
        }

        # Blob Storageを上書き保存
        upload_pptx_history_to_blob(user_id, history_id, updated_history_data)
        
        logger.info(f"User {user_id} updated history {history_id} successfully.")
        return jsonify({"success": True, "message": "履歴を更新しました。"})

    except Exception as e:
        logger.error(f"履歴更新中にエラーが発生しました: {e}", exc_info=True)
        return jsonify({"error": f"履歴の更新に失敗しました: {str(e)}"}), 500

def _get_detailed_pptx_system_instruction(width=1600, height=900):
    """
    PowerPoint詳細生成（SVG形式）のための、役割定義と技術仕様を統合した
    システムインストラクションを返す。
    サイズ（width, height）を動的に指定可能。
    """
    
    # ユーザーから提案された「役割」と「ゴール」を思考プロセスとして組み込む
    thinking_process_and_role = """
### 思考プロセスと役割
あなたは、ユーザーからの様々な質問や指示に対して、丁寧かつ正確に応答する対話型アシスタントであり、同時に世界トップクラスのプレゼンテーションデザイナーです。
あなたの思考は、以下のステップで進めてください。

1.  **意図の理解:** まず、ユーザーの指示や提供された資料の背景や真の意図を深く理解するよう努めます。必要であれば、明確化のための質問をすることなく、最も効果的だと考えられる解釈を自ら立てて進めます。
2.  **構成と物語性の考案:** 次に、ユーザーが抱える疑問や問題を解消し、満足度の高い対話体験を提供することをゴールとします。単に情報を並べるだけでなく、ユーザーが次のアクションに進めるような実用的で具体的な支援となるよう、論理的で分かりやすい物語性のある構成を考案します。
3.  **デザインと視覚化の実行:** 考案した構成に基づき、情報をどのように配置するかを計画し、SVGコードを生成します。その際、後述の「絶対厳守のデザイン原則」と「ツールキット」を常にチェックしてください。

**【重要】あなたの思考プロセス（上記1、2）は最終的な出力には含めず、指示されたJSON形式のデータのみを応答として返してください。**
"""

    # 既存の技術的な指示
    # width, height をフォーマット文字列に埋め込む
    technical_specifications = f"""
### 【クリエイティブ・デザインツールキット】
- **背景:** 単色塗りだけでなく、`<linearGradient>`や`<radialGradient>`を定義し、繊細なグラデーション背景を積極的に使用してください。SVGの`<defs>`内に`<pattern>`を定義し、ドットやライプなどの背景パターンを作成することも有効です。
- **奥行きと立体感:** `<filter>`と`<feGaussianBlur>`、`<feOffset>`を使い、カード型レイアウトの要素に自然なドロップシャドウを適用して奥行きを表現してください。
- **タイポグラフィ:** `font-weight`（例: "bold", "light"）や`font-size`を使い分け、情報の階層構造を視覚的に明確にしてください。
- ** **`font-family`属性には、'Meiryo'や'MS PGothic'のような、日本語環境で一般的に利用可能なフォント名を指定してください。**
- **アイコン:** 重要なリスト項目や概念の横に、後述の**アイコンプレースホルダー**を使用してください。

### 【絶対厳守のデザイン原則】

    ### 【最重要】XML/SVG構文の絶対厳守ルール
    あなたの生成するSVGコードは、厳格なXMLパーサーで解釈されます。以下のルールを絶対に守ってください。
    1.  **整形式 (Well-formed):** すべてのタグは正しく閉じられている必要があります。例: `<tag>...</tag>` または `<tag/>`。
    2.  **文字のエスケープ:** SVG内のテキストコンテンツや属性値に以下の特殊文字が含まれる場合は、必ずXMLエンティティにエスケープしてください。
        - `&` は `&amp;` に
        - `<` は `&lt;` に
        - `>` は `&gt;` に
    3.  **自己検証:** 最終的なSVGコードを出力する前に、これらの構文ルールが守られているか、あなた自身で必ず再確認してください。軽微な構文エラーは、後続の処理全体を停止させる致命的なエラーとなります。

#### 0. フォントサイズと可読性 (最重要)
*   **【絶対厳守】フォントサイズの最小値:** スライドは遠くからでも読める必要があります。
    *   **タイトル (h1相当):** `font-size="48"` 以上
    *   **見出し (h2相当):** `font-size="36"` 以上
    *   **本文・リスト (body):** `font-size="24"` 以上（**絶対に20px未満にしないでください。** 16pxや14pxはWeb用であり、スライドでは小さすぎます。）
    *   **注釈・キャプション:** `font-size="18"` 以上
*   **テキスト描画:** テキストは必ず `<text>` と `<tspan>` を使用し、`<foreignObject>` は使用しないでください。改行は `<tspan dy="...">` で行い、図形からはみ出さないよう注意してください。
    
#### 1. レイアウトと包含関係 (最重要)
*   **コンテナ内の余白:** 背景となる図形（コンテナ）の中に他の要素を配置する場合、**必ず十分な内側の余白（パディング）**を設け、コンテンツが**はみ出さない**ようにしてください。
*   **要素の重なり回避:** テキスト、図形、線など、**いかなる要素同士も互いに重ならない**ように配置してください。特に、**線や矢印がテキストや図形の上を通過することは絶対に避けてください。**
*   **セーフエリアの確保:** 生成されるスライドの上部と下部は、PowerPointテンプレートのロゴ等で隠れる可能性があります。**タイトル、主要なテキスト、図などの重要な情報は、必ず上下の端から少し離れた中央のエリアに配置してください。**

#### 2. 線とコネクタの論理性
*   矢印や線は、**必ず図形の境界線上や明確な接続点から始まり、別の図形の境界線上や接続点に終わる**ようにしてください。意味のない線は**絶対に生成しないでください。**

#### 3. タイポグラフィと可読性
*   **【超重要】テキスト描画の厳格なルール:**
    *   テキストは必ず **`<text>`** タグと、その子要素としての **`<tspan>`** タグのみを使用して記述してください。
    *   **`<foreignObject>`, `<p>`, `<div>` のようなHTMLタグをSVG内に埋め込むことは固く禁止します。**
    *   改行は **`<br/>` タグを使わず**、必ず **`<tspan>` タグの `dy` 属性**（例: `dy="1.2em"`）で行ってください。
*   **テキストのはみ出し禁止:** **図形内にテキストを配置する場合、テキストが図形の境界からはみ出さないように、フォントサイズを小さくする、文章を要約する、または前述の `<tspan>` で改行する、のいずれかの方法を必ず実行してください。**
*   **色のコントラスト:** テキストと背景色の**コントラスト**を十分に確保してください。

#### 4. 配色とスタイル
*   **背景のデザイン:** **選択したデザインコンセプトに基づいて、創造的で美しい背景を自由にデザインしてください。**
*   **スタイルの一貫性:** プレゼンテーション全体で、選択したデザインコンセプトに沿った統一感のあるカラーパレットとフォントスタイルを使用してください。

#### 5. 技術仕様
*   **SVGサイズとビューボックス (最重要):** SVGがコンテナに合わせて正しく拡大縮小されるように、**必ず**以下の属性を`<svg>`タグに含めてください。
    `width="{width}" height="{height}" viewBox="0 0 {width} {height}"`
*   **画像の挿入:** ユーザーから画像が提供された場合、その画像を**再描画するのではなく**、指示された**プレースホルダー** (`[IMAGE_PLACEHOLDER_...]`) を使って `<image>` タグで挿入してください。
*   **アイコンの挿入 (最重要):**
    *   アイコンを配置したい場所には、以下の形式で**プレースホルダーグループ (`<g>`)** を記述してください。
    *   **`<g data-iconify-query="[アイコン検索クエリ]" data-text-context="[隣接テキスト]" transform="translate(x, y)" data-icon-size="[目標サイズ]" data-icon-color="[色]"></g>`**
    *   **`transform`**: 必須。`translate(x, y)`で正確な座標を指定してください。**`scale(...)`は絶対に含めないでください。**
    *   **`data-icon-size`**: 必須。アイコンの**目標とすべき最終的なサイズ（高さ）をピクセル単位の数値で**指定してください。**隣接するテキストの`font-size`とほぼ同じ値を指定するのが基本です。** (例: `"24"`)
    *   **`data-iconify-query`**: 必須。原則として**`[コレクション名]:[アイコン名]`形式**を使用し、空白はハイフンに置換する。
        - 推奨例: `"mdi:account"`, `"fa-solid:arrow-right"`, `"ph:chart-line"`
        - 簡易キーワードを使う場合は1〜2語まで（空白はハイフン推奨）。
    *   **`data-text-context`**: 必須。関連するテキスト内容（日本語可）をそのまま指定。
    *   **`data-icon-color`**: 推奨。テーマカラーパレットに従い指定（例: `"#3B82F6"`）。
*   **出力形式:** 応答は、指示されたJSON形式の文字列**のみ**とします。
"""

    return thinking_process_and_role + technical_specifications


def _generate_single_slide_svg_from_files(objective: str, slide_title: str, slide_content: list, ref_parts: list, img_parts: list, img_placeholder_map: dict, user_info: dict, design_concept_key: str, previous_slide_svg: str = None, previous_slide_notes: str = None, svg_width=1600, svg_height=900) -> dict | None:
    """
    【改修版・デザイン引きずり対策・サイズ指定対応】
    プレゼンテーションの目的、単一スライドの構成案、参考ファイル、デザインコンセプト、そして直前のスライド情報を基に、
    そのスライドのSVGとノートを生成するヘルパー関数。
    """
    design_concept_info = config.DESIGN_CONCEPTS.get(design_concept_key, config.DESIGN_CONCEPTS["auto"])
    design_concept_name_for_prompt = design_concept_info["name"]

    # AIに「直前のスライドのデザインに厳密に合わせる」よう指示すると、
    # 1枚目（表紙）のデザインにすべてのスライドが引きずられてしまう問題への対策。
    # 指示を「参考にする」に弱め、「今回の内容を表現すること」を最優先するよう明確化します。

    prompt = f"""
あなたは、与えられた構成案に基づいて、プレゼンテーションの単一のスライドをデザインする専門家です。

**プレゼンテーション全体の目的:**
{objective}

**【最重要】デザインコンセプト:**
**`{design_concept_name_for_prompt}`**
このコンセプトに厳密に従い、プレゼンテーション全体で統一感のあるデザインを維持してください。
"""

    if previous_slide_svg:
        prompt += f"""
**【参考】直前のスライドのデザインと内容 (これを参考に、デザインの一貫性を保ってください):**
---
**SVGコード:**
```xml
{previous_slide_svg}
```
**スピーカーノート:**
{previous_slide_notes or "（なし）"}
---
"""

    prompt += f"""
**【今回生成するスライドの内容】:**
- **タイトル:** {slide_title}
- **コンテンツ（箇条書き）:**
{"".join([f"  - {item}\\n" for item in slide_content])}

**【あなたのタスク】:**
1.  **最優先事項:** 上記の「今回生成するスライドの内容」を、最も効果的に視覚化するSVGスライドをデザインしてください。
2.  **二次的な考慮事項:** その際、「直前のスライド」のデザイン（配色、フォント、全体的な雰囲気）を参考にし、プレゼンテーション全体で一貫性が保たれるようにしてください。
3.  **注意:** 直前のスライドがタイトルページのようなシンプルなレイアウトであっても、今回のコンテンツが詳細な情報を含む場合は、それに適したレイアウト（例：箇条書き、図解など）を新たに考案してください。
4.  最終的に、SVGコードとナレーション原稿（スピーカーノート）を生成してください。
"""

    if img_placeholder_map:
        prompt += f"""
**【重要】添付画像の利用:**
以下の画像プレースホルダーを利用して、スライド内に画像を配置してください。
**利用可能な画像プレースホルダー:** {', '.join(img_placeholder_map.keys())}
"""

    prompt += """
**出力形式:**
*   SVGコード (`svg`) とスピーカーノート (`notes`) を含む、単一のJSONオブジェクトを生成してください。
*   応答は、このJSONオブジェクトの文字列のみとし、他の説明やマークダウン、コードブロックの囲み文字は絶対に含めないでください。
"""
    
    parts_for_api = [types.Part.from_text(text=prompt)]
    if ref_parts:
        parts_for_api.append(types.Part.from_text(text="--- 参考資料 ---"))
        parts_for_api.extend(ref_parts)
    if img_parts:
        parts_for_api.append(types.Part.from_text(text="--- 参考画像 ---"))
        parts_for_api.extend(img_parts)

    contents = [types.Content(role="user", parts=parts_for_api)]
    
    # サイズ引数を渡す
    system_instruction = _get_detailed_pptx_system_instruction(width=svg_width, height=svg_height)
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))
    
    # 自己修正ループのための設定
    max_retries = 2
    for attempt in range(max_retries + 1):
        try:
            response_text, _ = generate_with_gemini(
                model_name=os.environ.get("PPTX_GEN_MODEL_NAME"),
                contents=contents, # historyをcontentsで渡す
                system_instruction=system_instruction + glossary_instruction,
                max_output_tokens=65535,
                temperature=0.6,
                user_info=user_info,
                log_prompt_text=f"PPTX Slide Gen (Attempt {attempt+1}): {slide_title}",
                feature_category="PPTX詳細生成(単一スライド)",
                skip_cosmos_log=False,
                generation_config_override={"response_mime_type": "application/json"}
            )

            if not response_text or response_text.startswith(("[エラー:", "[APIエラー:")):
                raise ValueError(f"AI API returned an error: {response_text}")

            json_match = re.search(r'\{.*\}', response_text, re.DOTALL)
            if not json_match:
                raise json.JSONDecodeError("AIの応答からJSONオブジェクトを抽出できませんでした。", response_text, 0)
            
            json_to_parse = json_match.group(0)
            parsed_json = json.loads(json_to_parse)

            svg_code = parsed_json['svg']
            # '&' が '&amp;' や '&lt;' などの既存のエンティティの一部でない場合のみ '&amp;' に置換
            sanitized_svg_code = re.sub(r'&(?!amp;|lt;|gt;|quot;|apos;)', '&amp;', svg_code)
            if svg_code != sanitized_svg_code:
                logger.info("SVG内の不正な'&'を自動的にサニタイズしました。")
                parsed_json['svg'] = sanitized_svg_code

            try:
                ET.fromstring(parsed_json['svg'])
            except ET.ParseError as e_parse_svg:
                # 検証に失敗した場合、自己修正のために例外を発生させる
                raise ValueError(f"生成されたSVGの構文が不正です。Error: {e}")

            # すべて成功した場合、ループを抜けて結果を返す
            return parsed_json

        except (json.JSONDecodeError, ValueError, Exception) as e:
            logger.warning(f"スライド「{slide_title}」の生成/検証に失敗 (試行 {attempt + 1}/{max_retries + 1})。エラー: {e}")
            if attempt < max_retries:
                # 最後の試行でなければ、AIに修正を促すプロンプトを会話履歴に追加
                correction_prompt = f"""
                あなたの直前の応答は以下のエラーにより処理できませんでした。
                エラー内容: {str(e)}
                
                このエラーを修正し、必ず有効なJSONオブジェクト（SVGの構文エラーも解消すること）のみを再度出力してください。
                説明は一切不要です。
                """
                # 既存の履歴にAIの応答と修正指示を追加して次のループへ
                if response_text:
                    contents.append(types.Content(role="model", parts=[types.Part.from_text(text=response_text)]))
                contents.append(types.Content(role="user", parts=[types.Part.from_text(text=correction_prompt)]))
                logger.info(f"AIに自己修正を要求します...")
            else:
                # 最終試行でも失敗した場合
                logger.error(f"スライド「{slide_title}」の生成が最終的に失敗しました。")
                return None # 失敗としてNoneを返す
    
    return None # ループが正常に完了しなかった場合

@app.route('/api/pptx/generate_slides', methods=['POST'])
def generate_slides_endpoint():
    """
    【非同期タスク対応・改訂版】
    目的と参考資料からアウトラインを生成し、バックグラウンドで各スライドを生成するタスクを開始する。
    アスペクト比と生成モード（通常/画像）の選択に対応。
    """
    if 'objective' not in request.form:
        return jsonify({"error": "目的が指定されていません。"}), 400
    
    objective = request.form.get('objective')
    use_grounding = request.form.get('use_grounding', 'false').lower() == 'true'
    confidentiality_level_ja = request.form.get('confidentiality_level', 'なし')
    design_concept_key = request.form.get('design_concept', 'auto')
    languages_str = request.form.get('languages', 'ja')
    aspect_ratio = request.form.get('aspect_ratio', '16:9') # アスペクト比を取得
    generation_mode = request.form.get('generation_mode', 'normal') # 生成モードを取得 (normal / image)

    target_languages = [lang.strip() for lang in languages_str.split(',') if lang.strip()]
    if not target_languages:
        return jsonify({"error": "生成する言語が選択されていません。"}), 400

    reference_files = request.files.getlist('reference_files')
    image_files = request.files.getlist('image_files') 

    try:
        # 参照ファイルと画像ファイルを合わせてチェック
        all_files_for_check = reference_files + image_files
        validate_token_limit(all_files_for_check, objective, None, model_name=config.PPTX_GEN_MODEL_NAME)
        
        # チェックでファイルストリームが読み込まれる可能性があるため、ポインタを先頭に戻す
        for f in all_files_for_check:
            f.seek(0)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))

    ref_parts, _, ref_filenames = _process_files_for_gemini_with_placeholders(reference_files)
    img_parts, img_placeholder_map, img_filenames = _process_files_for_gemini_with_placeholders(image_files)
    
    task_id = str(uuid.uuid4())
    create_task_in_cosmos({
        "id": task_id, "task_id": task_id, "status": "PENDING",
        "task_type": "ppt_detailed_generation", "user_info": user_info,
        "status_message": "タスクを受付ました。", "progress_percent": 0,
        "aspect_ratio": aspect_ratio,
        "generation_mode": generation_mode # タスク情報にも保存
    })

    try:
        # --- ステップ0: デザインコンセプトの決定 (同期処理) ---
        final_design_concept_key = design_concept_key
        if design_concept_key == 'auto':
            logger.info("デザインコンセプトがお任せに設定されているため、AIが最適なコンセプトを決定します。")
            
            design_concepts_list_str = "\n".join([f"- `{key}`: {info['name']} ({info['description']})" for key, info in config.DESIGN_CONCEPTS.items() if key != 'auto'])
            concept_prompt_parts = []
            
            pdf_ref_parts = [part for i, part in enumerate(ref_parts) if ref_filenames[i].lower().endswith('.pdf')]
            
            if pdf_ref_parts:
                concept_decision_prompt = f"""あなたはデザインコンサルタントです。
提供された「プレゼンテーションの目的」と「参考PDF資料」のデザインを分析し、以下の選択肢の中から最も雰囲気が近いデザインコンセプトの**キー名（例: `modern_corporate`）のみ**を回答してください。
**プレゼンテーションの目的:** {objective}
**デザインコンセプトの選択肢:**\n{design_concepts_list_str}\n**最適なデザインコンセプトのキー名 (1つだけ):**"""
                concept_prompt_parts.append(types.Part.from_text(text=concept_decision_prompt))
                concept_prompt_parts.append(types.Part.from_text(text="\n--- 参考PDF資料 ---"))
                concept_prompt_parts.extend(pdf_ref_parts)
            else:
                concept_decision_prompt = f"""あなたはデザインコンサルタントです。
以下の「プレゼンテーションの目的」に最も適したデザインコンセプトを、提示された選択肢の中から**キー名（例: `modern_corporate`）のみ**で回答してください。
**プレゼンテーションの目的:** {objective}
**デザインコンセプトの選択肢:**\n{design_concepts_list_str}\n**最適なデザインコンセプトのキー名 (1つだけ):**"""
                concept_prompt_parts.append(types.Part.from_text(text=concept_decision_prompt))

            determined_key, _ = generate_with_gemini(
                model_name=config.DEFAULT_MODEL_NAME, max_output_tokens=50,
                contents=[types.Content(role="user", parts=concept_prompt_parts)],
                user_info=user_info, feature_category="PPTX詳細生成(コンセプト決定)", skip_cosmos_log=False
            )
            
            if determined_key and determined_key.strip().replace('`', '') in config.DESIGN_CONCEPTS:
                final_design_concept_key = determined_key.strip().replace('`', '')
            else:
                logger.warning(f"AIが不正なデザインコンセプトキー '{determined_key}' を生成。'modern_corporate'にフォールバック。")
                final_design_concept_key = 'modern_corporate'
            logger.info(f"AIがお任せモードでデザインコンセプト '{final_design_concept_key}' を選択しました。")
        
        # --- ステップ1: アウトライン生成 (同期処理) ---
        update_task_in_cosmos(task_id, {"status_message": "プレゼンテーションの構成案を生成中...", "progress_percent": 5})
        
        outline_prompt = f"""あなたはプレゼンテーションの構成作家です。
以下の「目的」と「参考資料」に基づき、プレゼンテーション全体の詳細なアウトラインをJSON形式で生成してください。
**目的:** {objective}"""
        if ref_filenames: outline_prompt += f"\n**参考資料リスト:** {', '.join(ref_filenames)}"
        if img_filenames: outline_prompt += f"\n**参考画像リスト:** {', '.join(img_filenames)}"
        outline_prompt += """
**出力形式:**
各スライドの「タイトル」と「主要コンテンツ（箇条書きのリスト）」を持つオブジェクトの配列としてください。
```json
[
  { "title": "...", "content": ["...", "..."] }
]
```
応答はJSON配列の文字列のみとし、他の説明は含めないでください。"""
        
        outline_parts = [types.Part.from_text(text=outline_prompt)]
        if ref_parts:
            outline_parts.append(types.Part.from_text(text="--- 参考資料 ---"))
            outline_parts.extend(ref_parts)
        if img_parts:
             outline_parts.append(types.Part.from_text(text="--- 参考画像 ---"))
             outline_parts.extend(img_parts)

        outline_json_str, _ = generate_with_gemini(
            model_name=config.PPTX_OUTLINE_MODEL_NAME, max_output_tokens=65535,
            system_instruction=glossary_instruction,
            contents=[types.Content(role="user", parts=outline_parts)], user_info=user_info,
            log_prompt_text=f"PPTX Outline Gen: {objective[:100]}...",
            log_filenames=ref_filenames + img_filenames, feature_category="PPTX詳細生成(アウトライン)",
            generation_config_override={"response_mime_type": "application/json"}
        )
        if not outline_json_str or outline_json_str.startswith("[エラー:"):
            raise Exception(f"AIによるアウトライン生成に失敗: {outline_json_str}")

        # --- ステップ2: バックグラウンドタスクの起動（request_id を伝播） ---
        # generation_mode を引数に追加
        _submit_with_request_id(
            _run_slide_generation_task,
            task_id, objective, ref_parts, img_parts, img_placeholder_map,
            user_info, final_design_concept_key, ref_filenames, img_filenames,
            outline_json_str, target_languages, confidentiality_level_ja,
            aspect_ratio,
            generation_mode # 追加
        )
        
        # すぐにタスクIDを返却
        return jsonify({"task_id": task_id}), 202

    except Exception as e:
        logger.error(f"PPTX詳細生成タスクの開始に失敗 (タスクID: {task_id}): {e}", exc_info=True)
        update_task_in_cosmos(task_id, {
            "status": "FAILURE", "error": f"タスク開始時にエラーが発生しました: {str(e)}",
            "status_message": "エラーが発生しました。", "progress_percent": 100
        })
        return jsonify({"error": f"スライド生成タスクの開始に失敗しました: {str(e)}"}), 500

# ヘルパー関数: SVGが「画像スライド」かどうかを判定する
def _is_image_slide_svg(svg_string):
    try:
        soup = BeautifulSoup(svg_string, 'xml')
        
        # 1. 画像タグの存在確認
        images = soup.find_all('image')
        if not images:
            return False, None
        
        # 2. テキストタグのカウント（等級表示などは除外）
        text_count = 0
        for text in soup.find_all(['text', 'tspan']):
            # 等級表示のグループ内にあるテキストは無視
            parent = text.find_parent('g')
            if parent and parent.get('id') == 'confidentiality-marking':
                continue
            # 空白以外のテキストがあればカウント
            if text.get_text(strip=True):
                text_count += 1
        
        # 判定基準: 画像があり、かつコンテンツテキストが非常に少ない（例: 2個以下）
        # ※ 通常スライドでも画像を使うことはあるが、テキストが極端に少ない場合は画像主体のスライドとみなす
        if text_count <= 2:
            # 最初の画像のhref (Base64) を返す
            return True, images[0].get('href')
            
        return False, None
    except Exception as e:
        logger.error(f"画像スライド判定中にエラー: {e}")
        return False, None

@app.route('/api/pptx/regenerate_slide', methods=['POST'])
def regenerate_slide_endpoint():
    objective = request.form.get('objective')
    slide_svg = request.form.get('slide_svg')
    slide_notes = request.form.get('slide_notes')
    prompt = request.form.get('prompt')
    use_grounding = request.form.get('use_grounding', 'false').lower() == 'true'
    confidentiality_level_ja = request.form.get('confidentiality_level', 'なし')
    files = request.files.getlist('files')
    languages_str = request.form.get('languages', 'ja')
    target_languages = [lang.strip() for lang in languages_str.split(',') if lang.strip()]
    if not target_languages:
        return jsonify({"error": "生成する言語が選択されていません。"}), 400
    if not objective or not slide_svg:
        return jsonify({"error": "目的と元のスライドSVGが必要です。"}), 400

    try:
        # プロンプト、SVG、ノートを結合してテキストとしてチェック
        combined_text = f"{prompt}\n{slide_svg}\n{slide_notes}"
        validate_token_limit(files, combined_text, None, model_name=config.PPTX_GEN_MODEL_NAME)
        
        # チェックでファイルストリームが読み込まれる可能性があるため、ポインタを先頭に戻す
        for f in files:
            f.seek(0)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))

    is_image_slide, base64_image_data = _is_image_slide_svg(slide_svg)
    
    if is_image_slide and base64_image_data and base64_image_data.startswith('data:image/'):
        logger.info("入力SVGを「画像スライド」と判定しました。画像編集モードで再生成します。")
        try:
            # 1. Base64画像をデコード
            header, encoded = base64_image_data.split(",", 1)
            image_bytes = base64.b64decode(encoded)
            mime_type = header.split(';')[0].split(':')[1]
            
            # 2. 画像編集プロンプトの構築
            edit_prompt = f"""
            SYSTEM COMMAND: Perform a targeted EDIT on the provided image based on the user's instruction.
            
            **THE GOAL:** Modify ONLY the specific parts mentioned in the instruction. Preserve the rest of the image exactly as is.
            
            **SOURCE IMAGE:** The attached image is the absolute reference for layout, style, and language.
            
            **USER INSTRUCTION (in Japanese):** "{prompt}"
            
            **STRICT EXECUTION RULES:**
            1.  **Interpret the Instruction:** Understand the user's Japanese instruction (e.g., "remove text", "change color").
            2.  **Apply to Image:** Apply this change to the visual elements in the image.
            3.  **LANGUAGE LOCK:** **Do NOT change the language of the text in the image.** 
                - If the image text is in **English**, KEEP it in **English**.
                - If the image text is in **Japanese**, KEEP it in **Japanese**.
                - Do NOT translate the slide content back to Japanese just because the prompt is in Japanese.
            4.  **NO RE-GENERATION:** Do NOT generate a completely new slide design. Maintain the original composition, background, and fonts.
            """
            
            # 3. Gemini API (画像生成/編集) を呼び出し
            # 画像を入力として渡す
            image_part = types.Part(inline_data=types.Blob(mime_type=mime_type, data=image_bytes))
            prompt_part = types.Part.from_text(text=edit_prompt)
            
            # 画像編集はストリーミングで受け取る（generate_image_endpointと同様）
            response_iterator = generate_with_gemini(
                model_name=config.IMAGE_GENERATION_MODEL_NAME,
                contents=[types.Content(role="user", parts=[prompt_part, image_part])],
                stream=True, user_info=user_info, skip_cosmos_log=False,
                feature_category="PPTXスライド画像再生成(自動検知)",
                temperature=0.8
            )
            
            full_base64 = ""
            for chunk in response_iterator:
                if hasattr(chunk, 'image_data_url') and chunk.image_data_url:
                    if "," in chunk.image_data_url:
                        _, b64 = chunk.image_data_url.split(",", 1)
                    else:
                        b64 = chunk.image_data_url
                    full_base64 += b64
            
            if not full_base64:
                raise Exception("画像の生成（編集）に失敗しました。")

            new_image_href = f"data:image/png;base64,{full_base64}"
            
            # 4. 新しい画像を埋め込んだSVGを構築
            # 元のSVGの構造（viewBoxなど）を維持しつつ、画像だけ差し替えるのがベストだが、
            # 簡易的に新規SVGを作っても良い。ここでは元のSVGの属性をパースして画像だけ入れ替える。
            soup = BeautifulSoup(slide_svg, 'xml')
            img_tag = soup.find('image')
            if img_tag:
                img_tag['href'] = new_image_href
                new_svg_content = str(soup)
            else:
                # 万が一imageタグが見つからない場合（判定ロジックと矛盾するが念のため）
                svg_width = 1600; svg_height = 900
                new_svg_content = f'<svg width="{svg_width}" height="{svg_height}" viewBox="0 0 {svg_width} {svg_height}" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice"><image href="{new_image_href}" x="0" y="0" width="{svg_width}" height="{svg_height}" preserveAspectRatio="xMidYMid slice"/></svg>'

            # 5. レスポンス構築
            # 画像スライドの場合、ノートは変更しない（またはノート修正も必要なら別途APIを呼ぶ必要があるが、今回は画像修正が主目的と仮定）
            multilingual_slide = {'id': f"slide-regen-img-{uuid.uuid4().hex}", 'type': 'image'}
            
            # 等級表示の更新
            level_text_ja = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get('ja', 'なし')
            svg_ja_processed = _add_confidentiality_to_svg(new_svg_content, level_text_ja)
            multilingual_slide['ja'] = {"svg": svg_ja_processed, "notes": slide_notes}

            # 他言語データの構築
            for lang in target_languages:
                if lang != 'ja':
                    level_text_lang = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang, 'None')
                    svg_lang = _add_confidentiality_to_svg(new_svg_content, level_text_lang)
                    multilingual_slide[lang] = {"svg": svg_lang, "notes": slide_notes}

            return jsonify({"multilingual_slide": multilingual_slide})

        except Exception as e:
            logger.error(f"画像スライドの自動再生成中にエラー: {e}", exc_info=True)
            return jsonify({"error": f"画像の編集に失敗しました: {str(e)}"}), 500

    uploaded_image_parts = []
    log_filenames = []
    uploaded_image_base64 = None
    
    if files:
        image_file = files[0]
        if image_file and image_file.filename:
            log_filenames.append(image_file.filename)
            image_file.seek(0)
            img_bytes = image_file.read()
            mime_type = magic.from_buffer(img_bytes, mime=True)
            if mime_type.startswith("image/"):
                uploaded_image_base64 = f"data:{mime_type};base64,{base64.b64encode(img_bytes).decode('utf-8')}"
            image_file.seek(0)
            part = extract_file_content_to_part(image_file)
            if part:
                uploaded_image_parts.append(part)

    # 1. SVG内のBase64画像をプレースホルダーに置換
    original_images_map = {}
    cleaned_svg_for_llm = slide_svg
    try:
        soup_pre = BeautifulSoup(slide_svg, 'xml')
        image_tags = soup_pre.find_all('image')
        for i, img_tag in enumerate(image_tags):
            href = img_tag.get('href', '')
            if href.startswith('data:image/'):
                placeholder = f"[EXISTING_IMAGE_{i+1}]"
                original_images_map[placeholder] = href
                img_tag['href'] = placeholder
        cleaned_svg_for_llm = str(soup_pre)
        logger.info(f"{len(original_images_map)}件の埋め込み画像をプレースホルダーに置換しました。")
    except Exception as e_pre:
        logger.error(f"SVGの前処理中にエラー: {e_pre}")
        # エラーが発生しても、元のSVGで処理を続行（ただし失敗する可能性が高い）
        cleaned_svg_for_llm = slide_svg

    # 2. AIへの指示プロンプトを修正
    regeneration_prompt = f"""
あなたはプロのプレゼンテーションデザイナーです。
以下の「元のSVGスライド」と「元のノート」を、指定された「全体の目的」「追加の指示」「添付ファイル」に基づいて編集し、更新されたSVGコードとスピーカーノートを生成してください。

**【最重要】デザイン編集のルール:**
1.  **スタイルの厳格な維持:** ユーザーから「デザインを変更して」等の明示的な指示がない限り、**元のSVGの配色、フォント、図形スタイル、背景デザインを維持**してください。勝手にデザインテーマを刷新しないでください。
2.  **レイアウトの調整:** コンテンツの増減に合わせてレイアウトを微調整する際は、元のスライドの構成ルール（余白、配置のバランスなど）に従ってください。
3.  **部分修正の原則:** 指示された箇所以外は、むやみに変更しないでください。

**全体の目的:**
{objective}

**元のSVGスライド (画像はプレースホルダーに置換済み):**
```xml
{cleaned_svg_for_llm}
```
**元のスピーカーノート:**
{slide_notes}

**追加の指示:**
{prompt if prompt else "特に追加の指示はありません。現在のデザインスタイルを保ったまま、内容の微調整や改善を行ってください。"}
"""
    
    if original_images_map:
        regeneration_prompt += f"""
**【重要】既存画像の維持:**
元のスライドには、`{', '.join(original_images_map.keys())}` というプレースホルダーで示される既存の画像が含まれています。
これらの画像は**必ず維持**し、修正後のSVGにも同じプレースホルダーを含めてください。レイアウト変更の指示がある場合は、プレースホルダーを含む`<image>`タグ全体を移動させてください。
"""

    if uploaded_image_parts:
        regeneration_prompt += f"""
**【最重要・絶対厳守】添付画像の取り扱い:**
ユーザーから新しい画像が添付されました。この画像の内容を理解し、**スライド内の最も適切な場所に配置してください。**
画像を配置する場所には、以下の形式で**目印となるプレースホルダー図形を必ず挿入してください。**
<rect id="image-placeholder-for-upload" x="..." y="..." width="..." height="..." fill="lightgray" />
**あなた自身が画像をSVGで描画する必要はありません。** 上記の`<rect>`タグを配置するだけで結構です。後続の処理で、この`<rect>`が実際の画像に置き換えられます。
"""
    
    regeneration_prompt += """
**出力形式:**
*   修正後のSVGとノートを含むJSONオブジェクト {{"svg": "...", "notes": "..."}} を返してください。(配列ではない)
*   応答は、生成したJSONオブジェクトの文字列**のみ**を出力してください。他の文字列は一切含めないでください。
"""

    parts_for_api = [types.Part.from_text(text=regeneration_prompt)]
    if uploaded_image_parts:
        parts_for_api.extend(uploaded_image_parts)
    contents_for_api = [types.Content(role="user", parts=parts_for_api)]
    
    system_instruction = _get_detailed_pptx_system_instruction()

    response_text, _ = generate_with_gemini(
        model_name=os.environ.get("PPTX_GEN_MODEL_NAME"),
        contents=contents_for_api,
        system_instruction=system_instruction + glossary_instruction,
        max_output_tokens=65535,
        temperature=0.7,
        user_info=user_info,
        log_prompt_text=f"PPTX Slide Regenerate: {prompt[:100]}...",
        log_filenames=log_filenames,
        feature_category="PPTX詳細版_スライド再生成",
        use_grounding=use_grounding,
        generation_config_override={"response_mime_type": "application/json"}
    )

    if not response_text or response_text.startswith("[エラー:"):
        return jsonify({"error": f"AIからの応答エラー: {response_text}"}), 500
    try:
        start = response_text.find('{')
        end = response_text.rfind('}')
        if start != -1 and end != -1:
            slide_data_ja = json.loads(response_text[start:end+1])
            if 'svg' in slide_data_ja and 'notes' in slide_data_ja:
                multilingual_slide = {'id': f"slide-regen-{uuid.uuid4().hex}"}
                svg_with_icons = _embed_icons_into_svg(slide_data_ja['svg'], user_info)
                svg_ja_raw = svg_with_icons

                # 3. AIが返したSVGのプレースホルダーを元のBase64に戻す
                for placeholder, original_base64 in original_images_map.items():
                    svg_ja_raw = svg_ja_raw.replace(placeholder, original_base64)
                
                # (以降の新規アップロード画像の処理は変更なし)
                if uploaded_image_base64:
                    try:
                        soup = BeautifulSoup(svg_ja_raw, 'xml')
                        placeholder_rect = soup.find('rect', id='image-placeholder-for-upload')
                        if placeholder_rect:
                            image_tag = soup.new_tag('image',
                                x=placeholder_rect.get('x', '0'), y=placeholder_rect.get('y', '0'),
                                width=placeholder_rect.get('width', '100'), height=placeholder_rect.get('height', '100'),
                                href=uploaded_image_base64
                            )
                            placeholder_rect.replace_with(image_tag)
                            svg_ja_raw = str(soup)
                            logger.info("SVG内の画像プレースホルダーをアップロードされた画像に正常に置換しました。")
                        else:
                            logger.warning("AIがSVG内に画像プレースホルダー(rect with id='image-placeholder-for-upload')を生成しませんでした。")
                    except Exception as e_soup:
                        logger.error(f"SVGの画像プレースホルダー置換中にエラー: {e_soup}")

                level_text_ja = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get('ja', 'なし')
                svg_ja_processed = _add_confidentiality_to_svg(svg_ja_raw, level_text_ja)
                multilingual_slide['ja'] = {"svg": svg_ja_processed, "notes": slide_data_ja['notes']}

                # (以降の多言語翻訳処理は変更なし)
                languages_to_translate = [lang for lang in target_languages if lang != 'ja']
                if languages_to_translate:
                    svg_texts_dict, _ = _extract_translatable_texts_from_svg(svg_ja_processed)
                    notes_text = slide_data_ja.get('notes', '')
                    all_texts_to_translate = {**svg_texts_dict, **({'notes_text': notes_text} if notes_text.strip() else {})}
                    
                    soup_for_template = BeautifulSoup(svg_ja_processed, 'xml')
                    text_nodes_for_template = soup_for_template.find_all(['text', 'tspan'])
                    for idx, node in enumerate(text_nodes_for_template):
                        parent_g = node.find_parent('g')
                        if not (parent_g and parent_g.get('id') == 'confidentiality-marking') and node.string and node.string.strip():
                            node['data-translate-id'] = f"svg_text_{idx}"
                            node.string = ''
                    svg_template_with_ids = str(soup_for_template)

                    for lang in languages_to_translate:
                        translated_all = _translate_text_batch(all_texts_to_translate, lang, user_info)
                        translated_svg_texts = {k: v for k, v in translated_all.items() if k.startswith('svg_text_')}
                        translated_notes = translated_all.get('notes_text', f"[{lang.upper()}] {notes_text}")
                        final_svg_lang_no_level = _replace_texts_in_svg(svg_template_with_ids, translated_svg_texts)
                        level_text_lang = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang, 'None')
                        final_svg_lang_with_level = _add_confidentiality_to_svg(final_svg_lang_no_level, level_text_lang)
                        multilingual_slide[lang] = {"svg": final_svg_lang_with_level, "notes": translated_notes}
                
                return jsonify({"multilingual_slide": multilingual_slide})

        raise ValueError("適切なJSONオブジェクト({svg, notes}キーを含む)が見つかりません。")
    except (json.JSONDecodeError, ValueError) as e:
        logger.error(f"スライド再生成後のJSONパース失敗: {e}\nRaw: {response_text[:300]}")
        svg_match = re.search(r'<svg.*?</svg>', response_text, re.DOTALL)
        if svg_match:
            svg_content_raw = svg_match.group(0)
            
            # 【重要】フォールバック時も、退避しておいた画像を必ず復元する
            for placeholder, original_base64 in original_images_map.items():
                svg_content_raw = svg_content_raw.replace(placeholder, original_base64)

            # 新規アップロード画像の処理（フォールバック）
            if uploaded_image_base64:
                try:
                    soup = BeautifulSoup(svg_content_raw, 'xml')
                    placeholder_rect = soup.find('rect', id='image-placeholder-for-upload')
                    if placeholder_rect:
                        image_tag = soup.new_tag('image', x=placeholder_rect.get('x'), y=placeholder_rect.get('y'), width=placeholder_rect.get('width'), height=placeholder_rect.get('height'), href=uploaded_image_base64)
                        placeholder_rect.replace_with(image_tag)
                        svg_content_raw = str(soup)
                except Exception: pass

            fallback_slide = {'id': f"slide-fallback-{uuid.uuid4().hex}"}
            for lang in target_languages:
                 level_text = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang, 'None')
                 svg_content_with_level = _add_confidentiality_to_svg(svg_content_raw, level_text)
                 fallback_slide[lang] = {"svg": svg_content_with_level, "notes": slide_notes}
            
            return jsonify({"multilingual_slide": fallback_slide})
        
        return jsonify({"error": "AIの応答から有効なデータを抽出できませんでした。"}), 500

@app.route('/api/pptx/generate_new_slide', methods=['POST'])
def generate_new_slide_endpoint():
    objective = request.form.get('objective')
    prompt = request.form.get('prompt')
    use_grounding = request.form.get('use_grounding', 'false').lower() == 'true'
    confidentiality_level_ja = request.form.get('confidentiality_level', 'なし')
    files = request.files.getlist('files')
    
    # --- 【修正】アスペクト比の取得とSVGサイズの決定 ---
    aspect_ratio = request.form.get('aspect_ratio', '16:9')
    svg_width = 1600
    svg_height = 900
    if aspect_ratio == '4:3':
        svg_width = 1200
    # --------------------------------------------------

    if not objective or not prompt:
        return jsonify({"error": "目的と指示プロンプトが必要です。"}), 400

    try:
        # 目的、プロンプト、直前のスライド情報を結合してテキストとしてチェック
        previous_slide_svg = request.form.get('previous_slide_svg', '')
        previous_slide_notes = request.form.get('previous_slide_notes', '')
        combined_text = f"{objective}\n{prompt}\n{previous_slide_svg}\n{previous_slide_notes}"
        
        validate_token_limit(files, combined_text, None, model_name=config.PPTX_GEN_MODEL_NAME)
        
        # チェックでファイルストリームが読み込まれる可能性があるため、ポインタを先頭に戻す
        for f in files:
            f.seek(0)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))
    file_parts, file_placeholder_map, log_filenames = _process_files_for_gemini_with_placeholders(files)

    previous_slide_svg = request.form.get('previous_slide_svg')
    previous_slide_notes = request.form.get('previous_slide_notes')

    languages_str = request.form.get('languages', 'ja')
    target_languages = [lang.strip() for lang in languages_str.split(',') if lang.strip()]
    if not target_languages:
        return jsonify({"error": "生成する言語が選択されていません。"}), 400

    new_slide_prompt = f"""
あなたはプロのプレゼンテーションデザイナーです。
以下の「全体の目的」と「このスライドの指示」に基づいて、新しいスライドを1枚生成してください。
生成するスライドのスピーカーノートには、スライド内容を補足するためのナレーション原稿を記述してください。
**デザインの一貫性を保ちつつ、このスライドの内容に最適な表現を追求してください。例えば、重要なメッセージを伝えるスライドではアクセントカラーを大胆に使うなど、単調にならないように工夫してください。**
生成にあたっては、あなたの思考プロセスとデザイン原則（システムインストラクションで提供）に厳密に従ってください。

**全体の目的:**
{objective}
"""

    if previous_slide_svg:
        new_slide_prompt += f"""
**【最重要】直前のスライドの内容 (この内容の続きとして新しいスライドを作成してください):**
- **直前のスライドのビジュアル:**
```xml
{previous_slide_svg}
```
- **直前のスライドのスピーカーノート:**
{previous_slide_notes}
"""

    new_slide_prompt += f"""
**この新しいスライドに対する指示:**
{prompt}
"""

    if file_placeholder_map:
        new_slide_prompt += f"""
**【重要】添付画像の利用:**
以下の画像プレースホルダーを利用して、スライド内に画像を配置してください。
**利用可能な画像プレースホルダー:** {', '.join(file_placeholder_map.keys())}
"""
    new_slide_prompt += """
**出力形式:**
*   SVGコード (`svg`) とスピーカーノート (`notes`) を含むJSONオブジェクト `{"svg": "...", "notes": "..."}` を返してください。
*   応答は、生成したJSONオブジェクトの文字列**のみ**を出力してください。
"""
    
    parts_for_api = [types.Part.from_text(text=new_slide_prompt)]
    if file_parts:
        parts_for_api.extend(file_parts)
        
    contents_for_api = [types.Content(role="user", parts=parts_for_api)]
    
    # --- 【修正】動的なサイズを渡す ---
    system_instruction = _get_detailed_pptx_system_instruction(width=svg_width, height=svg_height)
    # --------------------------------

    response_text, _ = generate_with_gemini(
        model_name=os.environ.get("PPTX_GEN_MODEL_NAME"),
        contents=contents_for_api,
        system_instruction=system_instruction + glossary_instruction,
        max_output_tokens=65535,
        temperature=0.7,
        user_info=user_info,
        log_prompt_text=f"PPTX New Slide: {prompt[:100]}...",
        log_filenames=log_filenames,
        feature_category="PPTX詳細版_スライド追加",
        use_grounding=use_grounding,
        generation_config_override={"response_mime_type": "application/json"}
    )
    if not response_text or response_text.startswith("[エラー:"):
        return jsonify({"error": f"AIからの応答エラー: {response_text}"}), 500
    try:
        start = response_text.find('{')
        end = response_text.rfind('}')
        if start != -1 and end != -1:
            slide_data_ja = json.loads(response_text[start:end+1])
            if 'svg' in slide_data_ja and 'notes' in slide_data_ja:
                multilingual_slide = {'id': f"slide-new-{uuid.uuid4().hex}"}
                svg_with_icons = _embed_icons_into_svg(slide_data_ja['svg'], user_info)
                svg_ja_raw = svg_with_icons
                for placeholder, base64_data in file_placeholder_map.items():
                    svg_ja_raw = svg_ja_raw.replace(placeholder, base64_data)
                
                level_text_ja = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get('ja', 'なし')
                
                # --- 【修正】動的なサイズを渡す ---
                svg_ja_processed = _add_confidentiality_to_svg(svg_ja_raw, level_text_ja, svg_width=svg_width)
                # --------------------------------
                
                multilingual_slide['ja'] = {"svg": svg_ja_processed, "notes": slide_data_ja['notes']}

                languages_to_translate = [lang for lang in target_languages if lang != 'ja']
                if languages_to_translate:
                    svg_texts_dict, _ = _extract_translatable_texts_from_svg(svg_ja_processed)
                    notes_text = slide_data_ja.get('notes', '')
                    all_texts_to_translate = {**svg_texts_dict, **({'notes_text': notes_text} if notes_text.strip() else {})}
                    
                    soup_for_template = BeautifulSoup(svg_ja_processed, 'xml')
                    text_nodes_for_template = soup_for_template.find_all(['text', 'tspan'])
                    for idx, node in enumerate(text_nodes_for_template):
                        parent_g = node.find_parent('g')
                        if not (parent_g and parent_g.get('id') == 'confidentiality-marking') and node.string and node.string.strip():
                            node['data-translate-id'] = f"svg_text_{idx}"
                            node.string = ''
                    svg_template_with_ids = str(soup_for_template)
                    
                    for lang in languages_to_translate:
                        translated_all = _translate_text_batch(all_texts_to_translate, lang, user_info)
                        translated_svg_texts = {k: v for k, v in translated_all.items() if k.startswith('svg_text_')}
                        translated_notes = translated_all.get('notes_text', f"[{lang.upper()}] {notes_text}")
                        final_svg_lang_no_level = _replace_texts_in_svg(svg_template_with_ids, translated_svg_texts)
                        level_text_lang = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang, 'None')
                        
                        # --- 【修正】動的なサイズを渡す ---
                        final_svg_lang_with_level = _add_confidentiality_to_svg(final_svg_lang_no_level, level_text_lang, svg_width=svg_width)
                        # --------------------------------
                        
                        multilingual_slide[lang] = {"svg": final_svg_lang_with_level, "notes": translated_notes}
                
                return jsonify({"multilingual_slide": multilingual_slide})
        raise ValueError("JSONが見つかりません")
    except (json.JSONDecodeError, ValueError):
        svg_match = re.search(r'<svg.*?</svg>', response_text, re.DOTALL)
        if svg_match:
            svg_content_raw = svg_match.group(0)
            fallback_slide = {'id': f"slide-fallback-{uuid.uuid4().hex}"}
            for lang in target_languages:
                level_text = config.CONFIDENTIALITY_MAP.get(confidentiality_level_ja, {}).get(lang, 'None')
                # --- 【修正】動的なサイズを渡す ---
                svg_content_with_level = _add_confidentiality_to_svg(svg_content_raw, level_text, svg_width=svg_width)
                # --------------------------------
                fallback_slide[lang] = {"svg": svg_content_with_level, "notes": ""}
            return jsonify({"multilingual_slide": fallback_slide})
        return jsonify({"error": "AIの応答から有効なデータを抽出できませんでした。"}), 500


@lru_cache(maxsize=1)
def _get_base64_font_data():
    """日本語フォントファイルを読み込み、Base64エンコードして返す。"""
    # このパスは、既存のPDF生成機能で使われているフォントファイルを指します
    font_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), 'static', 'fonts', 'ipaexg.ttf')
    if not os.path.exists(font_path):
        logger.error("日本語フォントファイル 'ipaexg.ttf' が見つかりません。SVG -> PNG 変換で文字化けする可能性があります。")
        return None
    try:
        with open(font_path, 'rb') as f:
            font_data = f.read()
        return base64.b64encode(font_data).decode('utf-8')
    except Exception as e:
        logger.error(f"フォントファイルの読み込みまたはBase64エンコードに失敗: {e}")
        return None

def _add_confidentiality_to_svg(svg_string: str, level_text: str, svg_width=1600) -> str:
    """
    SVG文字列の右上に、指定された等級表示テキストを追加する。
    【改修】svg_widthを引数で受け取り、動的に位置を計算する。
    """
    if not level_text or level_text.lower() in ['なし', 'none']:
        return svg_string

    try:
        soup = BeautifulSoup(svg_string, 'xml')
        svg_tag = soup.find('svg')
        if not svg_tag:
            return svg_string

        # --- 1. 既存の等級表示を検出して削除 ---
        existing_marking = soup.find(id="confidentiality-marking")
        if existing_marking:
            existing_marking.decompose()
        
        # (既存の削除ロジック省略 - 必要であれば維持)
        # ...

        # --- 2. 新しい等級表示を追加 ---
        text = level_text
        
        font_size = 28
        padding = 20
        
        full_width_chars = len(re.findall(r'[^\x00-\x7F]', text))
        half_width_chars = len(text) - full_width_chars
        
        estimated_text_width = (full_width_chars * font_size) + (half_width_chars * font_size * 0.6)
        
        rect_width = estimated_text_width + (padding * 2)

        rect_height = 50
        # svg_width を使って右端の位置を計算
        rect_x = svg_width - rect_width - 20
        rect_y = 20
        
        confidentiality_g_tag = soup.new_tag(
            "g", id="confidentiality-marking", transform=f"translate({rect_x}, {rect_y})"
        )
        rect_tag = soup.new_tag(
            "rect", x="0", y="0", width=str(rect_width), height=str(rect_height),
            fill="none", stroke="red", **{'stroke-width': "3"}, rx="5"
        )
        text_tag = soup.new_tag(
            "text", x=str(rect_width / 2), y=str(rect_height / 2), dy=".3em",
            **{'font-family': "sans-serif", 'font-size': str(font_size), 'font-weight': "bold"},
            fill="red", **{'text-anchor': "middle"}
        )
        text_tag.string = text
        
        confidentiality_g_tag.append(rect_tag)
        confidentiality_g_tag.append(text_tag)
        svg_tag.append(confidentiality_g_tag)
        
        return str(soup)

    except Exception as e:
        logger.error(f"SVGへの等級表示追加/置換処理に失敗: {e}", exc_info=True)
        return svg_string


def _apply_transparency_to_png_bytes(png_bytes: bytes) -> bytes | None:
    """
    PNG画像のバイトデータを受け取り、Pillowを使って上部と下部を透過させ、
    新しいPNGバイトデータを返す。
    ★★★ 修正点: フッターの透過範囲を30pxに縮小 ★★★
    """
    if not png_bytes:
        return None
    try:
        image = Image.open(io.BytesIO(png_bytes)).convert("RGBA")
        
        # 透過させる高さを定義
        header_height = 110  # 上部110pxを透過
        footer_height = 20   # ★★★ 修正: 下部70pxから20pxに変更 ★★★

        # アルファチャンネル用のマスクを作成 (黒=透明, 白=不透明)
        mask = Image.new('L', image.size, 255) # 最初は全体を不透明(白)にする
        draw = ImageDraw.Draw(mask)
        
        # ヘッダー部分を透明(黒)にする
        draw.rectangle([(0, 0), (image.width, header_height)], fill=0)
        
        # フッター部分を透明(黒)にする
        draw.rectangle([(0, image.height - footer_height), (image.width, image.height)], fill=0)

        # 元の画像のアルファチャンネルにマスクを適用
        image.putalpha(mask)

        # 結果をバイトデータとして保存
        output_buffer = io.BytesIO()
        image.save(output_buffer, format='PNG')
        logger.info(f"PNG画像の上部{header_height}pxと下部{footer_height}pxを正常に透過させました。")
        return output_buffer.getvalue()

    except Exception as e:
        logger.error(f"PillowによるPNGの透過処理中にエラー: {e}", exc_info=True)
        return png_bytes # エラー時は元の画像を返す

def _render_svg_background_to_png(svg_string: str, apply_transparency: bool = True) -> bytes | None:
    """
    【改訂版・不正なマーカー参照対策】
    SVG文字列からテキスト要素をすべて削除し、背景グラフィックのみをPNGバイトデータに変換する。
    apply_transparency が True の場合、ヘッダーとフッター部分を透過処理する。
    """
    if cairosvg is None:
        logger.error("cairosvgライブラリが未インストールのため、SVGをPNGに変換できません。")
        return None

    cleaned_svg_string = svg_string

    try:
        # --- 不正なマーカー参照のクリーンアップ (cairosvgクラッシュ対策) ---
        try:
            soup = BeautifulSoup(svg_string, 'xml')
            
            # 1. SVG内に定義されている全てのマーカーIDを収集
            defined_marker_ids = {
                marker.get('id') for marker in soup.find_all('marker') if marker.get('id')
            }

            # 2. マーカーを参照する可能性のある要素を走査
            elements_with_markers = soup.find_all(['path', 'line', 'polyline', 'polygon'])
            marker_attributes = ['marker-start', 'marker-mid', 'marker-end']

            for element in elements_with_markers:
                for attr in marker_attributes:
                    if element.has_attr(attr):
                        marker_ref_value = element[attr]
                        marker_id_ref = None
                        
                        # "url(#some-id)" や "url(some-id)" の形式からIDを抽出
                        match = re.search(r'url\((.*?)\)', marker_ref_value)
                        if match:
                            marker_id_ref = match.group(1).strip().lstrip('#')
                        # "#some-id" の形式（url()なし）も考慮
                        elif marker_ref_value.startswith('#'):
                            marker_id_ref = marker_ref_value.lstrip('#')

                        # 3. 抽出したIDが定義済みIDのセットに存在しない場合、その属性を削除
                        if not marker_id_ref or marker_id_ref not in defined_marker_ids:
                            logger.warning(f"未定義または不正な形式のマーカー参照 '{marker_ref_value}' を検出しました。属性を削除します。")
                            del element[attr]
            
            cleaned_svg_string = str(soup)
        except Exception as e_cleanup:
            logger.error(f"SVGのクリーンアップ中にエラーが発生しました: {e_cleanup}。元のSVGで処理を続行します。")
            cleaned_svg_string = svg_string

        # --- テキスト情報の抽出とSVGからの削除 ---
        soup = BeautifulSoup(cleaned_svg_string, 'xml')
        svg_tag = soup.find('svg')
        if not svg_tag:
            logger.warning("SVGタグが見つかりません。元のSVGを直接変換します。")
            png_bytes_fallback = cairosvg.svg2png(bytestring=cleaned_svg_string.encode('utf-8'))
            return _apply_transparency_to_png_bytes(png_bytes_fallback) if apply_transparency else png_bytes_fallback

        # テキスト要素を削除（背景のみにするため）
        for text_tag in soup.find_all('text'):
            text_tag.decompose()
        
        # 背景色がない場合の自動追加処理
        viewbox_str = svg_tag.get('viewBox', '0 0 1600 900')
        _, _, vb_width, vb_height = map(float, viewbox_str.split())
        
        has_background_rect = False
        for child in svg_tag.find_all('rect', recursive=False):
            try:
                rect_w = float(child.get('width', 0))
                rect_h = float(child.get('height', 0))
                if rect_w >= vb_width and rect_h >= vb_height:
                    has_background_rect = True
                    break
            except (ValueError, TypeError):
                continue
        
        if not has_background_rect:
            new_bg_rect = soup.new_tag("rect", width=str(vb_width), height=str(vb_height), x="0", y="0", fill="#ffffff")
            svg_tag.insert(0, new_bg_rect)

        # 等級表示などの不要な要素を削除
        confidentiality_marking_group = soup.find('g', id='confidentiality-marking')
        if confidentiality_marking_group:
            confidentiality_marking_group.decompose()
        for text_element in soup.find_all(['text', 'tspan']):
            text_element.decompose()
        
        background_svg_string = str(soup)

        png_width = 1600
        png_height = int(png_width * (vb_height / vb_width)) if vb_width > 0 else 900

        # --- PNG変換 ---
        png_bytes_opaque = cairosvg.svg2png(
            bytestring=background_svg_string.encode('utf-8'),
            output_width=png_width,
            output_height=png_height
        )
        if not png_bytes_opaque:
            raise ValueError("背景画像のPNG変換に失敗しました。")
        
        # --- 透過処理の分岐 ---
        if apply_transparency:
            png_bytes_with_transparency = _apply_transparency_to_png_bytes(png_bytes_opaque)
            if not png_bytes_with_transparency:
                logger.warning("PNGの透過処理に失敗しました。透過なしの画像を返します。")
                return png_bytes_opaque
            return png_bytes_with_transparency
        else:
            return png_bytes_opaque

    except Exception as e:
        logger.error(f"背景用PNG画像の生成中にエラーが発生しました: {e}", exc_info=True)
        try:
            logger.warning("フォールバックとして、元のSVGを直接PNGに変換します。")
            png_bytes_fallback = cairosvg.svg2png(bytestring=cleaned_svg_string.encode('utf-8'))
            return _apply_transparency_to_png_bytes(png_bytes_fallback) if apply_transparency else png_bytes_fallback
        except Exception as fallback_e:
            logger.error(f"フォールバックでのSVG変換も失敗しました: {fallback_e}")
            return None


def _subclip_compat(clip, t_start, t_end):
    """
    MoviePy v1: clip.subclip / v2: clip.subclipped に対応する互換ラッパー。
    """
    try:
        # MoviePy v1.x
        return clip.subclip(t_start, t_end)
    except AttributeError:
        # MoviePy v2.x
        return clip.subclipped(t_start, t_end)

def _get_audio_duration_seconds(audio_bytes: bytes, temp_dir: str) -> float | None:
    """音声バイトデータを受け取り、一時ファイル経由で再生時間を秒単位で取得する"""
    if AudioFileClip is None:
        logger.error("moviepy library is not installed, cannot get audio duration.")
        return None
    
    temp_audio_path = ""
    try:
        # 一時ファイルに音声データを書き出す
        temp_audio_path = os.path.join(temp_dir, f"temp_audio_{uuid.uuid4().hex}.mp3")
        with open(temp_audio_path, 'wb') as f:
            f.write(audio_bytes)
        
        # moviepyで読み込んで長さを取得
        with AudioFileClip(temp_audio_path) as audio_clip:
            duration = audio_clip.duration
        
        return duration
    except Exception as e:
        logger.error(f"Failed to get audio duration: {e}", exc_info=True)
        return None
    finally:
        # 一時ファイルは呼び出し元の finally ブロックでディレクトリごと削除されるので、ここでは削除しない
        pass

@app.route('/api/pptx/export_presentation', methods=['POST'])
def export_presentation_endpoint():
    """
    SVGスライド群から直接PPTXファイルを生成する。音声合成にも対応。
    """
    # 1. リクエストデータの取得 (FormData対応)
    json_data_str = request.form.get('json_data')
    request_data = {}
    
    if json_data_str:
        try:
            request_data = json.loads(json_data_str)
        except json.JSONDecodeError:
            return jsonify({"error": "JSONデータの形式が不正です。"}), 400
    elif request.is_json:
        request_data = request.json
    else:
        return jsonify({"error": "リクエストデータ(json_data)が見つかりません。"}), 400

    if not request_data or 'slides' not in request_data:
        return jsonify({"error": "スライドデータがありません。"}), 400

    slides = request_data['slides']
    add_narration = request_data.get('add_narration', False)
    apply_transparency = request_data.get('apply_transparency', True) # デフォルトは透過オン
    current_lang = request_data.get('language', 'ja')
    selected_voice = request_data.get('selected_voice', None)
    aspect_ratio = request_data.get('aspect_ratio', '16:9')
    
    temp_dir = tempfile.mkdtemp()
    
    try:
        def parse_transform(transform_str):
            tx, ty = 0, 0
            if transform_str:
                match = re.search(r'translate\(\s*([-\d.e]+)\s*,?\s*([-\d.e]+)?\s*\)', transform_str)
                if match:
                    tx = float(match.group(1) or 0)
                    ty = float(match.group(2) or 0)
            return tx, ty

        # --- 1. テンプレート PPTX を読み込む ---
        prs = None
        custom_template_file = request.files.get('template_file')
        using_template = False # テンプレート使用フラグ

        if custom_template_file:
            try:
                prs = Presentation(custom_template_file)
                using_template = True
                logger.info(f"カスタムテンプレートを使用します: {secure_filename(custom_template_file.filename)}")
            except Exception as e_custom:
                logger.error(f"カスタムテンプレートの読み込みに失敗: {e_custom}")
                return jsonify({"error": "カスタムテンプレートの読み込みに失敗しました。"}), 500
        else:
            # デフォルトテンプレートの選択
            template_path = config.PPTX_GENERATOR_DEFAULT_TEMPLATE
            
            if aspect_ratio == '4:3':
                if hasattr(config, 'PPTX_GENERATOR_TEMPLATE_4_3'):
                    template_path = config.PPTX_GENERATOR_TEMPLATE_4_3
                else:
                    base_dir = os.path.dirname(config.PPTX_GENERATOR_DEFAULT_TEMPLATE) if config.PPTX_GENERATOR_DEFAULT_TEMPLATE else 'static/pptx_templates'
                    template_path = os.path.join(base_dir, 'default_template_4_3.pptx')

            if template_path and os.path.exists(template_path):
                try:
                    prs = Presentation(template_path)
                    using_template = True
                    logger.info(f"テンプレート '{template_path}' ({aspect_ratio}) を読み込みました。")
                except Exception as e_template:
                    logger.error(f"テンプレートの読み込みに失敗: {e_template}。空のプレゼンテーションで開始します。")
                    prs = Presentation()
            else:
                logger.warning(f"テンプレート '{template_path}' が見つかりません。空のプレゼンテーションで開始します。")
                prs = Presentation()

        # --- スライドサイズの設定 (ロゴずれ対策) ---
        # テンプレートを使用している場合は、そのサイズを維持する（上書きしない）
        if not using_template:
            if aspect_ratio == '4:3':
                prs.slide_width = PptxInches(10)
                prs.slide_height = PptxInches(7.5)
            else:
                prs.slide_width = PptxInches(16)
                prs.slide_height = PptxInches(9)
        else:
            logger.info(f"テンプレートのスライドサイズを維持します: {prs.slide_width.inches}x{prs.slide_height.inches} inches")
        
        # --- 2. 使用するレイアウトを事前に検索・準備 ---
        title_layout_name = "Layout_2_Title_Subtitle_And_Footer"
        content_layout_name = "Layout_11_Blank_With_Footers"
        
        title_layout_to_use = None
        content_layout_to_use = None

        if prs.slide_layouts:
            for layout in prs.slide_layouts:
                if hasattr(layout, 'name'):
                    if layout.name == title_layout_name:
                        title_layout_to_use = layout
                    elif layout.name == content_layout_name:
                        content_layout_to_use = layout
            
            if not content_layout_to_use:
                # フォールバック
                fallback_indices = [6, len(prs.slide_layouts) - 1, 0] 
                for idx_try in fallback_indices:
                    if 0 <= idx_try < len(prs.slide_layouts):
                        content_layout_to_use = prs.slide_layouts[idx_try]
                        break
        
        if not content_layout_to_use:
            return jsonify({"error": "PPTX生成エラー: 利用可能なスライドレイアウトがありません。"}), 500

        # --- 3. 各スライドのコンテンツを生成 ---
        for i, slide_data in enumerate(slides):
            layout_for_this_slide = None
            if i == 0 and title_layout_to_use:
                layout_for_this_slide = title_layout_to_use
            else:
                layout_for_this_slide = content_layout_to_use
            
            slide = prs.slides.add_slide(layout_for_this_slide)
            svg_string = slide_data['svg']

            # 3-1. 背景用SVGをPNGに変換してスライドに挿入
            # 修正: apply_transparency フラグを渡す
            png_bytes = _render_svg_background_to_png(svg_string, apply_transparency=apply_transparency)
            
            if png_bytes:
                slide.shapes.add_picture(
                    io.BytesIO(png_bytes), 0, 0, 
                    width=prs.slide_width, height=prs.slide_height
                )
            else:
                txBox = slide.shapes.add_textbox(PptxInches(1), PptxInches(1), PptxInches(8), PptxInches(1))
                tf = txBox.text_frame
                tf.text = f"Slide {i+1}: SVG graphics conversion failed."

            # 3-2. 元のSVGからテキスト要素を抽出してネイティブテキストボックスとして追加
            _add_svg_text_elements_to_slide(slide, svg_string, prs.slide_width, prs.slide_height)

            # 3-3. 等級表示の追加 (省略 - 変更なし)
            try:
                soup_for_confidentiality = BeautifulSoup(svg_string, 'xml')
                conf_group = soup_for_confidentiality.find('g', id='confidentiality-marking')
                if conf_group:
                    conf_rect = conf_group.find('rect')
                    conf_text = conf_group.find('text')
                    if conf_rect and conf_text:
                        rect_x_px = float(conf_rect.get('x', 0)); rect_y_px = float(conf_rect.get('y', 0))
                        rect_w_px = float(conf_rect.get('width', 100)); rect_h_px = float(conf_rect.get('height', 30))
                        tx, ty = parse_transform(conf_group.get('transform', ''))
                        
                        svg_tag_conf = soup_for_confidentiality.find('svg')
                        vb_str = svg_tag_conf.get('viewBox', '0 0 1600 900')
                        vb_parts = vb_str.split()
                        vb_width = float(vb_parts[2]) if len(vb_parts) >= 4 else 1600
                        vb_height = float(vb_parts[3]) if len(vb_parts) >= 4 else 900
                        
                        scale_x = prs.slide_width / vb_width if vb_width > 0 else 1
                        scale_y = prs.slide_height / vb_height if vb_height > 0 else 1

                        final_x_emu = int((tx + rect_x_px) * scale_x); final_y_emu = int((ty + rect_y_px) * scale_y)
                        final_w_emu = int(rect_w_px * scale_x); final_h_emu = int(rect_h_px * scale_y)

                        shape = slide.shapes.add_textbox(final_x_emu, final_y_emu, final_w_emu, final_h_emu)
                        shape.text = conf_text.get_text(strip=True)
                        shape.fill.background()
                        line = shape.line; line.color.rgb = PptxRGBColor(255, 0, 0); line.width = Pt(1.5)

                        tf = shape.text_frame
                        tf.margin_bottom = tf.margin_left = tf.margin_right = tf.margin_top = 0
                        tf.vertical_anchor = MSO_VERTICAL_ANCHOR.MIDDLE
                        
                        para = tf.paragraphs[0]; para.alignment = PP_ALIGN.CENTER
                        para.font.color.rgb = PptxRGBColor(255, 0, 0); para.font.bold = True
                        
                        font_size_svg_px = float(re.findall(r'[\d.]+', conf_text.get('font-size', '28'))[0])
                        font_size_pt_scaled = font_size_svg_px * (72 / 96)
                        para.font.size = Pt(font_size_pt_scaled)
            except Exception as e_conf:
                logger.warning(f"スライド {i+1} の等級表示のネイティブ描画に失敗: {e_conf}")

            # 3-4. スピーカーノート
            notes_text = slide_data.get('notes')
            if notes_text and notes_text.strip():
                try:
                    notes_slide = slide.notes_slide
                    text_frame = notes_slide.notes_text_frame
                    text_frame.clear()
                    p = text_frame.paragraphs[0] if text_frame.paragraphs else text_frame.add_paragraph()
                    p.text = notes_text
                except Exception: pass

            # 3-5. 音声ナレーション
            if add_narration and slide_data.get('notes'):
                audio_bytes = generate_speech_for_pptx(slide_data['notes'], language_code=current_lang, voice_name=selected_voice)
                if audio_bytes:
                    temp_audio_path = os.path.join(temp_dir, f"narration_{i+1}.mp3")
                    with open(temp_audio_path, 'wb') as f_audio:
                        f_audio.write(audio_bytes)
                    
                    icon_size = PptxInches(0.3)
                    slide.shapes.add_movie(
                        temp_audio_path, 
                        prs.slide_width - icon_size - PptxInches(0.1), 
                        prs.slide_height - icon_size - PptxInches(0.1),
                        icon_size, icon_size,
                        mime_type='audio/mpeg'
                    )

        # --- 4. 最終ページとして「エンディング」スライドを追加 ---
        ending_layout = None
        if prs.slide_layouts:
            for layout in prs.slide_layouts:
                if hasattr(layout, 'name') and layout.name == "エンディング":
                    ending_layout = layout
                    logger.info("テンプレート内に「エンディング」という名前のレイアウトが見つかりました。")
                    break
        
        if ending_layout:
            try:
                ending_slide = prs.slides.add_slide(ending_layout)
                logger.info("最終ページとして「エンディング」スライドを追加しました。")
                
                text_shape_to_fill = None
                if ending_slide.shapes.title and ending_slide.shapes.title.has_text_frame:
                    text_shape_to_fill = ending_slide.shapes.title
                else:
                    for ph in ending_slide.placeholders:
                        if ph.has_text_frame and (ph.placeholder_format.type in [PP_PLACEHOLDER.TITLE, PP_PLACEHOLDER.CENTER_TITLE, PP_PLACEHOLDER.OBJECT]):
                            text_shape_to_fill = ph
                            break
                
                if text_shape_to_fill:
                    tf = text_shape_to_fill.text_frame; tf.clear()
                    p = tf.paragraphs[0] if tf.paragraphs else tf.add_paragraph(); p.clear()
                    p.alignment = PP_ALIGN.CENTER
                    run = p.add_run(); run.text = "ご清聴ありがとうございました"
                    run.font.bold = True; run.font.size = Pt(36)
                    tf.vertical_anchor = MSO_VERTICAL_ANCHOR.MIDDLE
                    logger.info(f"エンディングスライドのプレースホルダー '{getattr(text_shape_to_fill, 'name', 'N/A')}' にテキストを設定しました。")
                else:
                    logger.warning("エンディングスライドに適切なテキストプレースホルダーが見つかりませんでした。")
            except Exception as e_add_ending:
                logger.error(f"「エンディング」スライドの追加中にエラーが発生しました: {e_add_ending}", exc_info=True)
        else:
            logger.warning("テンプレートに「エンディング」という名前のレイアウトが見つからなかったため、最終ページは追加されませんでした。")
        
        # --- 5. 全スライドにページ番号を挿入 ---
        logger.info("全スライドにページ番号を挿入します...")
        for i, slide in enumerate(prs.slides):
            page_number_text = f"{i + 1}"
            page_number_shape = None
            for shape in slide.placeholders:
                if hasattr(shape, 'placeholder_format') and shape.placeholder_format.type == PP_PLACEHOLDER.SLIDE_NUMBER:
                    page_number_shape = shape
                    break
            
            if page_number_shape:
                tf = page_number_shape.text_frame; tf.clear()
                p = tf.paragraphs[0] if tf.paragraphs else tf.add_paragraph()
                p.text = page_number_text
                p.alignment = PP_ALIGN.RIGHT; p.font.size = Pt(10)
            else:
                try:
                    width = PptxInches(0.5); height = PptxInches(0.1)
                    left = prs.slide_width - width - PptxInches(0.1)
                    top = prs.slide_height - height - PptxInches(0.05)
                    txBox = slide.shapes.add_textbox(left, top, width, height)
                    tf = txBox.text_frame; tf.clear()
                    tf.margin_bottom = tf.margin_left = tf.margin_right = tf.margin_top = 0
                    p = tf.paragraphs[0]; p.text = page_number_text
                    p.font.size = Pt(10); p.alignment = PP_ALIGN.RIGHT
                except Exception as e_add_page_num:
                    logger.warning(f"スライド {i+1}: ページ番号の手動追加に失敗: {e_add_page_num}")

        # --- 6. ファイルを保存して送信 ---
        pptx_buffer = io.BytesIO()
        prs.save(pptx_buffer)
        pptx_buffer.seek(0)
        
        return send_file(
            pptx_buffer,
            as_attachment=True,
            download_name='presentation.pptx',
            mimetype='application/vnd.openxmlformats-officedocument.presentationml.presentation'
        )
    except Exception as e:
        logger.error(f"PPTX直接生成中にエラー: {e}", exc_info=True)
        return jsonify({"error": "PPTXファイルの生成中にサーバーでエラーが発生しました。"}), 500
    finally:
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir)

def _render_svg_to_png_for_video(svg_string: str) -> bytes | None:
    """
    【動画エクスポート専用・文字化け対策・堅牢化版】
    SVG文字列をPNGバイトデータに変換する。
    文字化けを回避するため、グラフィックとテキストを分離し、Pillowで再合成する。
    cairosvgがクラッシュする原因となる、定義されていないマーカーへの参照を事前に除去する。
    """
    if cairosvg is None:
        logger.error("cairosvgライブラリが未インストールのため、SVGをPNGに変換できません。")
        return None

    try:
        # --- 1. SVGのパースとクリーンアップ ---
        soup = BeautifulSoup(svg_string, 'xml')
        svg_tag = soup.find('svg')
        if not svg_tag:
            logger.warning("SVGタグが見つかりません。")
            # パースできない場合はそのまま渡してみる（エラーになる可能性が高いが）
            return cairosvg.svg2png(bytestring=svg_string.encode('utf-8'))

        # --- ▼▼▼ 不正なマーカー参照のクリーンアップ (cairosvgクラッシュ対策) ▼▼▼ ---
        try:
            # 1. SVG内に定義されている全てのマーカーIDを収集
            defined_marker_ids = {
                marker.get('id') for marker in soup.find_all('marker') if marker.get('id')
            }

            # 2. マーカーを参照する可能性のある要素を走査
            elements_with_markers = soup.find_all(['path', 'line', 'polyline', 'polygon'])
            marker_attributes = ['marker-start', 'marker-mid', 'marker-end']

            for element in elements_with_markers:
                for attr in marker_attributes:
                    if element.has_attr(attr):
                        marker_ref_value = element[attr]
                        marker_id_ref = None
                        
                        # "url(#some-id)" や "url(some-id)" の形式からIDを抽出
                        match = re.search(r'url\((.*?)\)', marker_ref_value)
                        if match:
                            # 抽出したIDから'#'と前後の空白を除去
                            marker_id_ref = match.group(1).strip().lstrip('#')
                        # "#some-id" の形式（url()なし）も考慮
                        elif marker_ref_value.startswith('#'):
                            marker_id_ref = marker_ref_value.lstrip('#')

                        # 3. 抽出したIDが定義済みIDのセットに存在しない場合、その属性を削除
                        if not marker_id_ref or marker_id_ref not in defined_marker_ids:
                            logger.warning(f"動画用PNG変換: 未定義または不正な形式のマーカー参照 '{marker_ref_value}' を検出しました。属性を削除します。")
                            del element[attr]
        except Exception as e_cleanup:
            logger.error(f"SVGのマーカークリーンアップ中にエラーが発生しました: {e_cleanup}。処理を続行します。")
        # --- ▲▲▲ クリーンアップここまで ▲▲▲ ---

        # --- 2. テキスト情報の抽出とSVGからの削除 ---
        viewbox_str = svg_tag.get('viewBox', '0 0 1600 900')
        _, _, vb_width, vb_height = map(float, viewbox_str.split())
        png_width = 1600
        png_height = int(png_width * (vb_height / vb_width)) if vb_width > 0 else 900
        scale_x = png_width / vb_width
        scale_y = png_height / vb_height
        
        text_elements_to_draw = []

        def parse_transform(transform_str):
            tx, ty = 0, 0
            if transform_str:
                match = re.search(r'translate\(\s*([-\d.e]+)\s*,?\s*([-\d.e]+)?\s*\)', transform_str)
                if match:
                    tx = float(match.group(1) or 0)
                    ty = float(match.group(2) or 0)
            return tx, ty

        all_text_tags = soup.find_all('text')
        
        for text_tag in all_text_tags:
            inherited_tx, inherited_ty = 0, 0
            parent = text_tag.find_parent()
            while parent and parent.name != 'svg':
                parent_tx, parent_ty = parse_transform(parent.get('transform'))
                inherited_tx += parent_tx
                inherited_ty += parent_ty
                parent = parent.find_parent()

            base_x = float(text_tag.get('x', 0))
            base_y = float(text_tag.get('y', 0))
            items_to_process = text_tag.find_all('tspan') if text_tag.find('tspan') else [text_tag]
            last_x, last_y = base_x, base_y

            for item in items_to_process:
                item_text = item.get_text(strip=True)
                if not item_text: continue
                
                font_size_str = item.get('font-size', text_tag.get('font-size', '12'))
                font_size_matches = re.findall(r'[\d.]+', str(font_size_str))
                font_size_px = float(font_size_matches[0]) if font_size_matches else 12.0

                def parse_length(length_str, font_size_for_em):
                    total_value = 0
                    for part in str(length_str).split():
                        try:
                            val_matches = re.findall(r'[-.\d]+', part)
                            if not val_matches: continue
                            val = float(val_matches[0])
                            if 'em' in part.lower(): total_value += val * font_size_for_em
                            else: total_value += val
                        except (ValueError, TypeError): pass
                    return total_value

                current_x = float(item.get('x', last_x)) if 'x' in item.attrs else last_x
                current_y = float(item.get('y', last_y)) if 'y' in item.attrs else last_y
                dx = parse_length(item.get('dx', '0'), font_size_px)
                dy = parse_length(item.get('dy', '0'), font_size_px)
                current_x += dx
                current_y += dy
                last_x, last_y = current_x, current_y
                
                final_x_svg = inherited_tx + current_x
                final_y_svg = inherited_ty + current_y

                font_weight_str = item.get('font-weight', text_tag.get('font-weight', 'normal'))
                
                text_elements_to_draw.append({
                    "text": item_text,
                    "x": final_x_svg * scale_x,
                    "y": final_y_svg * scale_y,
                    "size": int(font_size_px * scale_y),
                    "family": item.get('font-family', text_tag.get('font-family', 'sans-serif')).split(',')[0].strip(),
                    "weight": "bold" if font_weight_str in ['bold', 'bolder'] or (font_weight_str.isnumeric() and int(font_weight_str) >= 600) else "normal",
                    "fill": item.get('fill', text_tag.get('fill', '#000000')),
                    "anchor": item.get('text-anchor', text_tag.get('text-anchor', 'start'))
                })

        # テキスト要素を削除
        for text_tag in soup.find_all('text'):
            text_tag.decompose()
        
        # クリーンアップ済みのSVG文字列（テキストなし、マーカー修正済み）
        background_svg_string = str(soup)
        
        # --- 3. テキストなしのSVGをPNGに変換 ---
        png_bytes_background = cairosvg.svg2png(bytestring=background_svg_string.encode('utf-8'), output_width=png_width, output_height=png_height)
        if not png_bytes_background:
            raise ValueError("背景画像のPNG変換に失敗しました。")
        
        # --- 4. PillowでPNG画像にテキストを描画 (透過処理はなし) ---
        image = Image.open(io.BytesIO(png_bytes_background)).convert("RGBA")
        draw = ImageDraw.Draw(image)
        font_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), 'static', 'fonts', 'ipaexg.ttf')
        if not os.path.exists(font_path):
            logger.error("日本語フォントファイル 'ipaexg.ttf' が見つかりません。")
            # フォントがない場合はテキストなしの画像を返す
            output_buffer = io.BytesIO()
            image.save(output_buffer, format='PNG')
            return output_buffer.getvalue()

        for text_info in text_elements_to_draw:
            try:
                anchor_map = {'start': 'ls', 'middle': 'ms', 'end': 'rs'}
                anchor = anchor_map.get(text_info['anchor'], 'ls')
                font = ImageFont.truetype(font_path, size=text_info['size'])
                draw.text(
                    (text_info['x'], text_info['y']),
                    text_info['text'],
                    font=font,
                    fill=text_info['fill'],
                    anchor=anchor
                )
            except Exception as e_draw:
                logger.warning(f"テキスト '{text_info['text']}' の描画に失敗: {e_draw}")

        # --- 5. 最終的な画像をバイトデータとして返す ---
        final_buffer = io.BytesIO()
        image.save(final_buffer, format='PNG')
        logger.info("SVGから動画用PNGへの変換（Pillow再描画方式）が正常に完了しました。")
        return final_buffer.getvalue()

    except Exception as e:
        logger.error(f"SVGから動画用PNGへの変換でエラー: {e}", exc_info=True)
        # フォールバックとして元のSVGをそのまま変換してみる
        try:
            logger.warning("フォールバックとして、元のSVGを直接PNGに変換します。")
            # 元の文字列そのままではなく、最低限マーカークリーンアップ済みのものを使いたいが、
            # パース自体に失敗している可能性もあるため、安全策として元の文字列を使う
            return cairosvg.svg2png(bytestring=svg_string.encode('utf-8'))
        except Exception as fallback_e:
            logger.error(f"フォールバックでのSVG変換も失敗しました: {fallback_e}")
            return None

def _prepare_slide_assets(slide_data: dict, index: int, temp_dir: str, language: str, task_id: str, voice_name: str | None = None) -> dict | None:
    """
    【改訂版・堅牢化】
    1枚のスライドの素材（PNG画像、音声ファイル）を準備し、Azure Blobにアップロードする。
    音声処理の堅牢性を向上させ、各ステップでの失敗を適切に処理し、詳細なログを出力する。
    各スライドの表示時間に2秒の余白を追加する。
    """
    try:
        # 1. SVGをPNGに変換してBlobにアップロード
        png_bytes = _render_svg_to_png_for_video(slide_data['svg'])
        if not png_bytes:
            logger.warning(f"タスク {task_id}: スライド {index + 1} のSVGからPNGへの変換に失敗。")
            return None
        
        png_blob_name = f"{task_id}/slide_{index + 1}.png"
        if not upload_bytes_to_blob(png_bytes, png_blob_name):
            logger.error(f"タスク {task_id}: スライド {index + 1} のPNG blob '{png_blob_name}' のアップロードに失敗。")
            return None

        # --- 2. 音声合成とデュレーション決定、Blobへのアップロード ---
        pause_duration = 2.0
        content_duration = 5.0  # 音声がない場合のデフォルト表示時間
        audio_blob_name = None
        notes_text = slide_data.get('notes')
        
        # "All-or-Nothing"ロジック：ノートが存在する場合、音声処理を試みる
        if notes_text and notes_text.strip():
            # 処理ブロックを `while True` で囲み、失敗時に `break` することでネストを回避
            while True: 
                # ステップ1: 音声合成
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声合成を開始 (テキスト長: {len(notes_text)}文字)。")
                audio_bytes = generate_speech_for_pptx(notes_text, language_code=language, voice_name=voice_name)
                if not audio_bytes:
                    logger.warning(f"タスク {task_id}: スライド {index + 1} の音声合成に失敗。このスライドは音声なしになります。")
                    break # 失敗したため処理ブロックを抜ける

                # ステップ2: 音声長の取得
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声合成成功。音声長を取得します。")
                audio_duration = _get_audio_duration_seconds(audio_bytes, temp_dir)
                if not audio_duration:
                    logger.warning(f"タスク {task_id}: スライド {index + 1} の音声長取得に失敗。このスライドは音声なしになります。")
                    break # 失敗したため処理ブロックを抜ける

                # ステップ3: Blob Storageへのアップロード
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声長は {audio_duration:.2f}秒です。アップロードします。")
                temp_audio_blob_name = f"{task_id}/narration_{index + 1}.mp3"
                if not upload_bytes_to_blob(audio_bytes, temp_audio_blob_name):
                    logger.warning(f"タスク {task_id}: スライド {index + 1} の音声blobアップロード失敗。このスライドは音声なしになります。")
                    break # 失敗したため処理ブロックを抜ける

                # 全てのステップが成功した場合のみ、結果を反映
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声関連処理がすべて成功しました。")
                audio_blob_name = temp_audio_blob_name
                content_duration = audio_duration
                break # 成功したので処理ブロックを抜ける
        
        # 最終的なスライドの表示時間は「コンテンツの時間 + 間」
        total_duration = content_duration + pause_duration
        
        return {
            "png_blob_name": png_blob_name,
            "audio_blob_name": audio_blob_name,
            "duration": total_duration,
            "content_duration": content_duration
        }
    except Exception as e:
        logger.error(f"タスク {task_id}: スライド {index + 1} のアセット準備中に予期せぬエラー: {e}", exc_info=True)
        return None


def _prepare_slide_assets_with_request_id(
    slide_data: dict,
    index: int,
    temp_dir: str,
    language: str,
    task_id: str,
    voice_name: str | None,
    request_id: str | None,
) -> dict | None:
    """ThreadPoolExecutor用のラッパー。

    バックグラウンドのワーカースレッドでも request_id を引き継げるように、
    スレッドローカルに request_id をセットしてから _prepare_slide_assets を呼び出す。
    """

    customLogger.set_request_id_for_current_thread(request_id)
    return _prepare_slide_assets(slide_data, index, temp_dir, language, task_id, voice_name)

class FFMPEGProgressLogger:
    """
    moviepyのffmpeg処理の進捗を捕捉するための、tqdm互換のカスタムロガークラス（最適化版）。
    __call__, write, iter_bar の全てを正しく実装し、安定動作を保証する。
    Cosmos DBへの書き込み頻度を抑制し、RU消費を削減するロジックを追加。
    """
    def __init__(self, task_id):
        self.task_id = task_id
        self.last_update_time = 0
        self.last_progress_percent = -1 # 追加: 前回の進捗率を保持して頻度制御に使用
        self.server_logger = logging.getLogger("MoviePyLogger")
        self.tqdm_bar = None

    def __call__(self, *args, **kwargs):
        message = kwargs.get('message', '')
        if message:
            self.server_logger.info(f"Task {self.task_id}: MoviePy Status - {message}")

    def write(self, s):
        s = s.strip()
        if not s or 'it/s' not in s:
            return

        # 進捗率を解析して計算
        percent_match = re.search(r'(\d+)\s*%', s)
        percent = int(percent_match.group(1)) if percent_match else 0
        # 全体進捗の80%〜98%の範囲をエンコード処理として割り当て
        progress_percent = 80 + int(18 * (percent / 100.0))
        progress_percent = min(98, progress_percent)

        current_time = time.time()
        
        # 【修正】更新頻度の抑制ロジック (RU消費対策)
        # 1. 前回の更新から5秒以上経過している
        # 2. または、進捗率が前回より5%以上進んだ
        time_elapsed = current_time - self.last_update_time
        percent_changed = progress_percent - self.last_progress_percent

        if time_elapsed < 5.0 and percent_changed < 5:
            return

        # 更新条件を満たした場合のみ実行
        self.last_update_time = current_time
        self.last_progress_percent = progress_percent

        if "frame_index: " in s:
            s = s.split("frame_index: ", 1)[-1]
        
        s = re.sub(r',\s*now=None', '', s)
        status_message = f"エンコード中... {s}"

        update_payload = {
            "status_message": status_message,
            "progress_percent": progress_percent
        }
        
        # Cosmos DBを更新
        update_task_in_cosmos(self.task_id, update_payload)

    def flush(self):
        pass

    def iter_bar(self, **kwargs):
        """
        moviepyがプログレスバーの反復処理に使うメソッド。
        'chunk'や'frame_index'など、tqdmが知らない引数を取り除き、
        tqdmが理解できる'iterable'にマッピングする。
        """
        iterable_data = kwargs.pop('iterable', None)
        if iterable_data is None:
            iterable_data = kwargs.pop('chunk', None)
        if iterable_data is None:
            iterable_data = kwargs.pop('frame_index', None)
        
        # tqdmのコンストラクタを、安全な引数のみで呼び出す
        self.tqdm_bar = tqdm(iterable=iterable_data, file=self, **kwargs)
        return self.tqdm_bar


# --- 非同期動画エクスポートのワーカー関数 (voice_name引数を追加) ---
def _run_video_export_task(task_id: str, slides_data: list, user_info: dict, language: str, voice_name: str | None = None):
    """
    動画エクスポートの全プロセスを非同期で実行するワーカー関数。
    【最終修正版】tqdm互換のカスタムロガーを使用し、安定性を確保。
    """
    temp_dir = tempfile.mkdtemp(prefix=f"export_{task_id}_")
    clips_to_close = []
    blobs_to_delete = []
    
    def _update_status(status_message, progress_percent, status="PROCESSING"):
        update_payload = { "status": status, "status_message": status_message, "progress_percent": progress_percent }
        update_task_in_cosmos(task_id, update_payload)

    try:
        _update_status("動画素材の準備を開始...", 5)
        
        prepared_assets = [None] * len(slides_data)
        max_workers = min(4, (os.cpu_count() or 1) + 2)
        total_slides = len(slides_data)

        # この動画生成タスクに紐づく request_id を取得し、
        # 下流の ThreadPoolExecutor のワーカースレッドでも引き継げるようにする
        request_id_for_task = customLogger.get_request_id_for_current_thread()
        
        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            future_to_index = {
                executor.submit(
                    _prepare_slide_assets_with_request_id,
                    slide,
                    i,
                    temp_dir,
                    language,
                    task_id,
                    voice_name,
                    request_id_for_task,
                ): i
                for i, slide in enumerate(slides_data)
            }
            processed_count = 0
            for future in concurrent.futures.as_completed(future_to_index):
                index = future_to_index[future]
                try:
                    asset_data = future.result()
                    if asset_data:
                        prepared_assets[index] = asset_data
                        if asset_data.get("png_blob_name"): blobs_to_delete.append(asset_data["png_blob_name"])
                        if asset_data.get("audio_blob_name"): blobs_to_delete.append(asset_data["audio_blob_name"])
                except Exception as e:
                    logger.error(f"タスク {task_id}: スライド {index + 1} のアセット準備タスクで例外が発生: {e}", exc_info=True)
                processed_count += 1
                progress = 5 + int(35 * (processed_count / total_slides))
                _update_status(f"スライド素材を準備中 ({processed_count}/{total_slides})...", progress)

        _update_status("動画クリップを作成中...", 40)
        
        video_clips = []
        for i, asset in enumerate(prepared_assets):
            if not asset or not asset.get("png_blob_name"):
                logger.warning(f"タスク {task_id}: スライド {i + 1} の素材準備に失敗したため、このスライドは動画から除外されます。")
                continue
            clip = _create_moviepy_clip(asset, clips_to_close, temp_dir, task_id)
            if clip:
                if FadeIn and FadeOut:
                    video_clips.append(clip.with_effects([FadeIn(0.5), FadeOut(0.5)]))
                else:
                    video_clips.append(clip)
        
        if not video_clips:
            raise ValueError("有効な動画クリップを1つも生成できませんでした。")

        final_clip = concatenate_videoclips(video_clips, method="compose")
        final_clip.fps = 24
        clips_to_close.append(final_clip)
        
        output_filename = f"presentation_{task_id}.mp4"
        output_video_path = os.path.join(temp_dir, output_filename)
        
        _update_status("動画をエンコード中...", 80)
        
        # 完全に機能するカスタムロガークラスのインスタンスを渡す
        progress_logger = FFMPEGProgressLogger(task_id)
        
        final_clip.write_videofile(
            output_video_path, 
            codec='libx264', 
            audio_codec='aac', 
            preset='veryfast',
            threads=os.cpu_count() or 2,
            logger=progress_logger
        )

        _update_status("成果物をアップロード中...", 98)
        
        video_blob_name = f"results/{output_filename}"
        with open(output_video_path, "rb") as f_video:
            upload_bytes_to_blob(f_video.read(), video_blob_name)

        # 完了ステータスと結果を1つのペイロードにまとめて、一度だけDBを更新する
        success_payload = {
            "status": "SUCCESS",
            "status_message": "動画の生成が完了しました。",
            "progress_percent": 100,
            "result": {
                "files_data": {
                    "video": {
                        "blob_name": video_blob_name,
                        "filename": output_filename,
                        "mimetype": "video/mp4"
                    }
                }
            }
        }
        update_task_in_cosmos(task_id, success_payload)

        logger.info(f"タスク {task_id}: 動画生成成功。Blob: {video_blob_name}")

    except Exception as e:
        error_msg = f"動画生成タスク中にエラー: {e}"
        logger.error(f"タスク {task_id}: {error_msg}", exc_info=True)
        failure_payload = {
            "status": "FAILURE",
            "error": error_msg,
            "status_message": f"エラーが発生しました: {str(e)[:100]}...",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, failure_payload)
        
    finally:
        for clip in clips_to_close:
            try:
                if hasattr(clip, 'close') and callable(clip.close):
                    clip.close()
            except Exception: pass
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)
        for blob_name in blobs_to_delete:
            delete_blob(blob_name)


def _create_moviepy_clip(asset: dict | None, clips_to_close: list, temp_dir_local: str, task_id: str) -> Any | None:
    """
    Azure Blob Storageからアセットをダウンロードし、MoviePyクリップを作成するヘルパー。
    【最終確定版】正常に動作していた初期のロジックに戻す。
    """
    if not asset or not asset.get("png_blob_name"):
        return None

    try:
        # PNGをダウンロード
        png_blob_name = asset["png_blob_name"]
        png_bytes = download_blob_to_bytes(png_blob_name)
        if not png_bytes:
            logger.warning(f"タスク {task_id}: PNGデータダウンロードに失敗。スライドを除外します。 (Blob: {png_blob_name})")
            return None
        
        local_png_path = os.path.join(temp_dir_local, os.path.basename(png_blob_name))
        with open(local_png_path, "wb") as f:
            f.write(png_bytes)
        
        # ImageClipを作成
        video_clip = ImageClip(local_png_path, duration=asset["duration"])
        video_clip.fps = 24
        
        # 音声をダウンロードして適用
        audio_blob_name = asset.get("audio_blob_name")
        if audio_blob_name and AudioFileClip:
            audio_bytes = download_blob_to_bytes(audio_blob_name)
            if audio_bytes:
                local_audio_path = os.path.join(temp_dir_local, os.path.basename(audio_blob_name))
                with open(local_audio_path, "wb") as f:
                    f.write(audio_bytes)
                audio_clip = AudioFileClip(local_audio_path)
                # 最も基本的な .audio 属性への代入を使用
                video_clip.audio = audio_clip
                clips_to_close.append(audio_clip)
            else:
                logger.warning(f"タスク {task_id}: 音声データが見つかりません。 (Blob: {audio_blob_name})")
        
        clips_to_close.append(video_clip)
        return video_clip

    except Exception as e:
        logger.error(f"MoviePyクリップの作成中にエラー (Asset: {asset}): {e}", exc_info=True)
        return None


# --- 動画エクスポートAPI (selected_voiceを受け取るように修正) ---
@app.route('/api/pptx/export_video_async', methods=['POST'])
def export_video_async_endpoint():
    """
    SVGスライド群から動画生成タスクを非同期で開始するエンドポイント。(Cosmos DB対応版)
    """
    if ImageClip is None:
        return jsonify({"error": "動画生成機能はサーバーで無効化されています。"}), 503
    if not request.json or 'slides' not in request.json:
        return jsonify({"error": "スライドデータがありません。"}), 400

    slides = request.json['slides']
    language = request.json.get('language', 'ja')
    # ▼▼▼【ここからが修正箇所】▼▼▼
    selected_voice = request.json.get('selected_voice', None)
    # ▲▲▲【修正ここまで】▲▲▲
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    task_id = str(uuid.uuid4())

    task_initial_data = {
        "task_id": task_id,
        "id": task_id,
        "status": "PENDING",
        "task_type": "video_export",
        "user_info": user_info,
        "status_message": "動画生成タスクを受付ました。",
        "progress_percent": 0
    }
    
    if create_task_in_cosmos(task_initial_data) is None:
        # メモリへのフォールバックを削除し、常にエラーを返す
        return jsonify({"error": "タスクの初期化に失敗しました。データベースに接続できません。"}), 500

    # executor.submit に selected_voice を渡す（かつ request_id を伝播）
    _submit_with_request_id(
        _run_video_export_task,
        task_id,
        slides,
        user_info,
        language,
        selected_voice,
    )
    
    logger.info(f"動画生成タスク {task_id} をキューに追加しました。")
    return jsonify({"success": True, "task_id": task_id}), 202

# 新しいダウンロード用エンドポイントを app.py の末尾近くに追加
@app.route('/api/pptx/download_video_result/<task_id>', methods=['GET'])
def download_video_result_endpoint(task_id):
    """
    完了した動画生成タスクの結果（Blob Storage上のファイル）への署名付きURLを返す。
    """
    task_info = get_task_from_cosmos(task_id)
    if not task_info or task_info.get("status") != "SUCCESS":
        return jsonify({"error": "タスクが完了していないか、存在しません。"}), 404
    
    result_data = task_info.get("result", {})
    # 正しい階層をたどって blob_name を取得
    video_info = result_data.get("files_data", {}).get("video", {})
    video_blob_name = video_info.get("blob_name")

    if not video_blob_name:
        return jsonify({"error": "生成された動画ファイルの情報が見つかりません。"}), 404

    download_url = get_blob_sas_url(video_blob_name, expiration_minutes=10)

    if download_url:
        return jsonify({"success": True, "download_url": download_url})
    else:
        return jsonify({"error": "ダウンロードリンクの生成に失敗しました。"}), 500


def _add_svg_text_elements_to_slide(slide, svg_string, slide_width_emu, slide_height_emu):
    """
    SVG文字列からテキスト要素を抽出し、PPTXスライドにネイティブなテキストボックスとして追加する。
    ★★★ 再修正点 ★★★
    1. フォントサイズの変換係数をさらに積極的に調整し、見た目のサイズ感をSVGに近づける。
    2. テキストボックスの幅と高さの推定ロジックを改善し、不要なテキストの拡大・縮小を抑制。
    3. 係数やマジックナンバーを定数として定義し、可読性とメンテナンス性を向上。
    """
    try:
        # --- 定数定義 ---
        # SVGのピクセル(px)からPowerPointのポイント(pt)への変換係数。
        # 理論値(0.75)より小さく設定し、見た目のサイズ感を合わせるための経験的調整。
        SVG_PX_TO_PPTX_PT_SCALE_FACTOR = 0.60

        # SVGのY座標(ベースライン)をPowerPointテキストボックスの上端(top)に変換するための補正係数。
        SVG_Y_BASELINE_TO_PPTX_TOP_FACTOR = 1.0
        
        # SVGの名前空間宣言を除去
        svg_string_no_xmlns = re.sub(r'\sxmlns="[^"]+"', '', svg_string)
        soup = BeautifulSoup(svg_string_no_xmlns, 'xml')
        svg_tag = soup.find('svg')
        if not svg_tag: return

        viewbox_str = svg_tag.get('viewBox', f'0 0 {slide_width_emu} {slide_height_emu}')
        _, _, vb_width, vb_height = map(float, viewbox_str.split())
        
        scale_x = slide_width_emu / vb_width if vb_width > 0 else 1
        scale_y = slide_height_emu / vb_height if vb_height > 0 else 1

        def parse_transform(transform_str):
            tx, ty = 0, 0
            if transform_str:
                match = re.search(r'translate\(\s*([-\d.e]+)\s*,?\s*([-\d.e]+)?\s*\)', transform_str)
                if match:
                    tx = float(match.group(1) or 0)
                    ty = float(match.group(2) or 0)
            return tx, ty

        def process_element_recursively(element, inherited_tx, inherited_ty):
            current_tx, current_ty = parse_transform(element.get('transform'))
            total_tx = inherited_tx + current_tx
            total_ty = inherited_ty + current_ty

            for child in element.children:
                if not hasattr(child, 'name'): continue

                if child.name == 'text':
                    parent_g = child.find_parent('g')
                    if parent_g and parent_g.get('id') == 'confidentiality-marking':
                        continue

                    base_x = float(child.get('x', 0))
                    base_y = float(child.get('y', 0))
                    
                    items_to_process = child.find_all('tspan') if child.find('tspan') else [child]
                    last_x, last_y = base_x, base_y

                    for item in items_to_process:
                        try:
                            item_text = item.get_text(strip=True)
                            if not item_text: continue

                            font_size_str = item.get('font-size', child.get('font-size', '24'))
                            font_size_matches = re.findall(r'[\d.]+', str(font_size_str))
                            font_size_px = float(font_size_matches[0]) if font_size_matches else 24.0
                            
                            def parse_length(length_str, font_size_for_em):
                                total_value = 0
                                for part in str(length_str).split():
                                    try:
                                        val_matches = re.findall(r'[-.\d]+', part)
                                        if not val_matches: continue
                                        val = float(val_matches[0])
                                        if 'em' in part.lower(): total_value += val * font_size_for_em
                                        else: total_value += val
                                    except (ValueError, TypeError): pass
                                return total_value

                            current_x = float(item.get('x', last_x)) if 'x' in item.attrs else last_x
                            current_y = float(item.get('y', last_y)) if 'y' in item.attrs else last_y
                            
                            dx = parse_length(item.get('dx', '0'), font_size_px)
                            dy = parse_length(item.get('dy', '0'), font_size_px)
                            
                            current_x += dx; current_y += dy
                            last_x, last_y = current_x, current_y
                            
                            final_x_svg = total_tx + current_x
                            final_y_svg = total_ty + current_y
                            
                            # ★★★ 変更点1: 変換係数をより積極的に調整 ★★★
                            font_size_pt = font_size_px * SVG_PX_TO_PPTX_PT_SCALE_FACTOR
                            final_y_svg_adjusted = final_y_svg - (font_size_px * SVG_Y_BASELINE_TO_PPTX_TOP_FACTOR)

                            left_scaled = int(final_x_svg * scale_x)
                            top_scaled = int(final_y_svg_adjusted * scale_y)
                            
                            is_title = top_scaled < PptxInches(1.5) and font_size_pt > 28

                            if is_title:
                                left = PptxInches(0.5); top = PptxInches(0.25)
                                width = slide_width_emu - PptxInches(1.0); height = PptxInches(1.2)
                                alignment = PP_ALIGN.CENTER; vertical_anchor = MSO_VERTICAL_ANCHOR.MIDDLE
                            else:
                                # ★★★ 変更点2: テキストボックスのサイズ推定ロジックを改善 ★★★
                                # 文字数とフォントサイズから、より現実に近い幅と高さを推定
                                est_width_svg_px = len(item_text) * font_size_px * 1.2  # 平均的な文字幅を考慮
                                est_height_svg_px = font_size_px * 1.5 # 行の高さを考慮
                                
                                width = int(est_width_svg_px * scale_x) + PptxInches(0.1) # 少しだけ幅に余裕を持たせる
                                height = int(est_height_svg_px * scale_y)
                                
                                text_anchor = item.get('text-anchor', child.get('text-anchor', 'start'))
                                left = left_scaled
                                if text_anchor == 'middle': left -= int(width / 2)
                                elif text_anchor == 'end': left -= int(width)
                                top = top_scaled
                                alignment = {'start': PP_ALIGN.LEFT, 'middle': PP_ALIGN.CENTER, 'end': PP_ALIGN.RIGHT}.get(text_anchor, PP_ALIGN.LEFT)
                                vertical_anchor = MSO_VERTICAL_ANCHOR.TOP

                            txBox = slide.shapes.add_textbox(left, top, width, height)
                            tf = txBox.text_frame
                            tf.clear()
                            tf.margin_left = tf.margin_right = tf.margin_top = tf.margin_bottom = 0
                            tf.word_wrap = True
                            tf.auto_size = MSO_AUTO_SIZE.TEXT_TO_FIT_SHAPE
                            if is_title:
                                tf.vertical_anchor = vertical_anchor

                            p = tf.paragraphs[0]
                            p.text = item_text
                            p.alignment = alignment
                            
                            font = p.font

                            svg_font_family_raw = item.get('font-family', child.get('font-family', 'system-ui, sans-serif'))
                            # 引用符などを除去し、最初のフォント名を取得
                            svg_font_family = svg_font_family_raw.split(',')[0].strip().replace("'", "").replace('"', '')

                            # 汎用フォントファミリーを具体的な日本語フォントにマッピング
                            font_mapping = {
                                'sans-serif': 'メイリオ',
                                'serif': 'ＭＳ 明朝',
                                'monospace': 'ＭＳ ゴシック',
                                'system-ui': 'メイリオ'
                            }
                            # マッピングにない場合は、SVGで指定されたフォント名をそのまま使う
                            font.name = font_mapping.get(svg_font_family.lower(), svg_font_family)

                            font.size = PptxPt(font_size_pt)
                            font_weight_str = item.get('font-weight', child.get('font-weight', 'normal'))
                            font.bold = font_weight_str in ['bold', 'bolder'] or (font_weight_str.isnumeric() and int(font_weight_str) >= 600)
                            font.italic = item.get('font-style', child.get('font-style', 'normal')) == 'italic'
                            
                            fill_color_hex = item.get('fill', child.get('fill', '#000000'))
                            if fill_color_hex.startswith('#'):
                                try:
                                    rgb = tuple(int(fill_color_hex.lstrip('#')[i:i+2], 16) for i in (0, 2, 4))
                                    font.color.rgb = PptxRGBColor(*rgb)
                                except (ValueError, TypeError): pass

                        except Exception as e_item:
                            logger.warning(f"SVG内のテキスト/tspan要素の処理中にエラー: {e_item}")
                
                elif child.name == 'g':
                    process_element_recursively(child, total_tx, total_ty)

        process_element_recursively(svg_tag, 0, 0)

    except Exception as e_svg_parse:
        logger.error(f"SVG全体のパースに失敗: {e_svg_parse}", exc_info=True)


def _extract_translatable_texts_from_svg(svg_string: str) -> tuple[dict[str, str], list[str]]:
    """
    SVGから翻訳対象のテキストを抽出し、一意なIDを割り振る。
    ★★★ 修正版 v3 (Final) ★★★
    <text>と<tspan>を検索し、ノードに直接含まれるテキスト(node.string)のみを対象にすることで、
    重複を避けつつ、すべてのテキスト片を漏れなく抽出する。
    """
    texts_to_translate = {}
    ordered_ids = []
    try:
        soup = BeautifulSoup(svg_string, 'xml')
        text_nodes = soup.find_all(['text', 'tspan'])
        
        node_counter = 0
        for node in text_nodes:
            # node.string は、そのノードに直接含まれるテキストのみを返す (子要素のテキストは含まない)。
            # これにより、<text>親ノードと<tspan>子ノードのテキストが二重に抽出されるのを防ぐ。
            if node.string and node.string.strip():
                parent_g = node.find_parent('g')
                if parent_g and parent_g.get('id') == 'confidentiality-marking':
                    continue
                
                unique_id = f"svg_text_{node_counter}"
                texts_to_translate[unique_id] = node.string.strip()
                ordered_ids.append(unique_id)
                
                node['data-translate-id'] = unique_id
                node.string = ''
                node_counter += 1

    except Exception as e:
        logger.error(f"SVGからのテキスト抽出でエラー: {e}")
    
    return texts_to_translate, ordered_ids


def _translate_text_batch(texts_dict: dict, target_lang: str, user_info: dict) -> dict[str, str]:
    """
    【根本対策版】テキストの辞書を翻訳する。
    AIによる構造破壊を防ぐため、一括翻訳を完全に廃止し、
    内部で個別翻訳のフォールバック関数を直接呼び出す方式に変更。
    これにより、翻訳の正確性と堅牢性を最優先する。
    """
    if not texts_dict or not target_lang:
        return {}

    logger.info(f"Executing robust 1-to-1 translation for {len(texts_dict)} text items to '{target_lang}'. Batch processing is disabled to ensure accuracy.")

    # 常に個別翻訳のフォールバック関数を呼び出す
    return _translate_text_fallback(texts_dict, target_lang, user_info)

def _translate_text_fallback(texts_dict: dict, target_lang: str, user_info: dict) -> dict[str, str]:
    """
    テキストを1つずつ個別に翻訳する、堅牢なフォールバック関数。
    """
    translated_dict = {}
    
    # 翻訳が必要な（空でない）テキストのみをリストアップ
    items_to_translate = {text_id: text for text_id, text in texts_dict.items() if text and text.strip()}
    
    max_workers = 8  # APIへの同時リクエスト数を制限
    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        # 個別翻訳タスクをサブミット
        future_to_id = {
            executor.submit(translate_text_content, text, target_lang, user_info): text_id
            for text_id, text in items_to_translate.items()
        }
        
        # 完了したものから結果を収集
        for future in concurrent.futures.as_completed(future_to_id):
            text_id = future_to_id[future]
            try:
                translated_text = future.result()
                # 翻訳関数が失敗時にNoneを返すことを考慮
                if translated_text is not None:
                    translated_dict[text_id] = translated_text
                else:
                    # 翻訳に失敗した場合は、安全のため元のテキストを維持
                    translated_dict[text_id] = texts_dict[text_id]
                    logger.warning(f"Individual translation failed for ID '{text_id}'. Reverting to original text.")
            except Exception as exc:
                logger.error(f"Individual translation for ID '{text_id}' generated an exception: {exc}")
                translated_dict[text_id] = texts_dict[text_id] # エラー時も元のテキストを維持

    # 元の辞書にあり、翻訳対象外だった（空の）テキストも最終結果に含める
    final_result = texts_dict.copy()
    final_result.update(translated_dict)

    return final_result


def _replace_texts_in_svg(svg_string: str, translated_texts: dict[str, str]) -> str:
    """翻訳されたテキストをSVG内の対応するIDを持つ要素に挿入する"""
    try:
        soup = BeautifulSoup(svg_string, 'xml')
        for unique_id, translated_text in translated_texts.items():
            node = soup.find(attrs={'data-translate-id': unique_id})
            if node:
                node.string = translated_text
                del node['data-translate-id']
        return str(soup)
    except Exception as e:
        logger.error(f"SVGへのテキスト置換でエラー: {e}")
    return svg_string

@app.route('/render_d2', methods=['POST'])
def render_d2_endpoint():
    """
    POSTリクエストで受け取ったD2コードをSVG画像に変換し、Base64形式で返す。
    """
    if not request.json or 'code' not in request.json:
        return jsonify({"error": "D2コードがリクエストに含まれていません。"}), 400
    
    d2_code = request.json['code']

    # ▼▼▼ ここからが修正箇所 ▼▼▼
    # 設定ファイルからD2のパスを取得し、なければPATH環境変数から探す
    d2_path = config.D2_CLI_PATH or shutil.which('d2')

    # D2コマンドが利用可能か確認
    if not d2_path or not os.path.exists(d2_path):
        logger.error(f"サーバーエラー: D2コマンドラインツールが見つかりません。設定されたパス: {config.D2_CLI_PATH}")
        return jsonify({"error": "サーバーエラー: D2の実行に必要なコマンドが見つかりません。"}), 500
    # ▲▲▲ 修正ここまで ▲▲▲

    # 一時ファイルを使用してD2コマンドを実行
    tmp_dir = tempfile.mkdtemp()
    in_filename = os.path.join(tmp_dir, "input.d2")
    out_filename = os.path.join(tmp_dir, "output.svg")

    try:
        with open(in_filename, 'w', encoding='utf-8') as f:
            f.write(d2_code)
        
        # ▼▼▼ ここからが修正箇所 ▼▼▼
        # D2コマンドを実行 (-l elk でレイアウトエンジンを指定すると品質が向上)
        command = [d2_path, '-l', 'elk', in_filename, out_filename] # 引数に -t svg は不要
        logger.info(f"Executing D2 command: {' '.join(command)}")
        # ▲▲▲ 修正ここまで ▲▲▲
        
        timeout_seconds = 20
        result = subprocess.run(
            command,
            capture_output=True,
            text=True,
            timeout=timeout_seconds,
            encoding='utf-8',
            errors='ignore'
        )

        if result.returncode != 0 or not os.path.exists(out_filename):
            error_details = result.stderr if result.stderr.strip() else "D2から有効な出力が得られませんでした。"
            raise RuntimeError(f"D2 failed to generate SVG. Details: {error_details}")

        with open(out_filename, 'rb') as f_svg:
            svg_bytes = f_svg.read()
        
        encoded_svg = base64.b64encode(svg_bytes).decode('utf-8')
        
        return jsonify({
            "success": True,
            "svg_base64": encoded_svg
        })

    except (subprocess.TimeoutExpired, subprocess.CalledProcessError, RuntimeError) as e:
        error_message = str(e)
        logger.error(f"D2の実行に失敗しました: {error_message}", exc_info=True)
        return jsonify({"error": f"D2の描画に失敗しました。\n詳細: {error_message[:500]}..."}), 500
    except Exception as e:
        logger.error(f"D2のレンダリング中に予期せぬエラー: {e}", exc_info=True)
        return jsonify({"error": "サーバー内部で予期せぬエラーが発生しました。"}), 500
    finally:
        # 一時ディレクトリとファイルをクリーンアップ
        if os.path.exists(tmp_dir):
            shutil.rmtree(tmp_dir)

