# --- 要領書作成機能用ヘルパー関数 ---
def _add_hatching_to_image(image_path, hatch_rect, output_path, color_hex="#ff0000"):
    """
    画像に枠（ハッチング）を追加する。
    color_hex 引数を追加し、デフォルトを赤(#ff0000)に設定。
    """
    try:
        # HexカラーコードをRGBに変換
        color_hex = color_hex.lstrip('#')
        r, g, b = tuple(int(color_hex[i:i+2], 16) for i in (0, 2, 4))
        
        image = Image.open(image_path).convert("RGBA")
        overlay = Image.new("RGBA", image.size, (255, 255, 255, 0))
        draw = ImageDraw.Draw(overlay)

        x, y, w, h = hatch_rect['x'], hatch_rect['y'], hatch_rect['width'], hatch_rect['height']
        
        # 指定された色で枠を描画 (透過度 220)
        draw.rectangle([x, y, x + w, y + h], outline=(r, g, b, 220), width=3)
        
        # 指定された色で塗りつぶし (透過度 50)
        draw.rectangle([x, y, x + w, y + h], fill=(r, g, b, 50))

        combined = Image.alpha_composite(image, overlay)
        combined.convert("RGB").save(output_path, "JPEG")
        return True
    except Exception as e:
        logger.error(f"枠の描画エラー: {e}")
        return False

