@app.route('/api/video/waveform', methods=['POST'])
def get_video_waveform():
    """
    動画ファイルを受け取り、音声波形データを生成して返すAPI。
    音声がない動画にも対応。
    """
    if 'video_file' not in request.files:
        return jsonify({"error": "動画ファイルが見つかりません。"}), 400
    
    video_file = request.files['video_file']
    
    # 一時ファイルのパスを try ブロックの外で初期化
    audio_path = None
    video_path = None
    
    try:
        # 一時ビデオファイルを作成
        with tempfile.NamedTemporaryFile(delete=False, suffix=os.path.splitext(video_file.filename)[1]) as tmp_video_file:
            video_path = tmp_video_file.name
            video_file.save(video_path)

        # MoviePyで動画から音声を抽出
        with VideoFileClip(video_path) as video:
            # --- ▼▼▼【修正箇所】ここから ▼▼▼ ---
            if video.audio is None:
                logger.info(f"動画 '{video_file.filename}' には音声トラックがありません。空の波形を返します。")
                # 音声がない場合は、空のデータとメッセージを返す
                return jsonify({
                    "waveform": [], 
                    "message": "動画に音声が含まれていません。"
                })
            
            # 一時音声ファイルパスを生成
            with tempfile.NamedTemporaryFile(delete=False, suffix=".wav") as tmp_audio_file:
                audio_path = tmp_audio_file.name
            
            video.audio.write_audiofile(audio_path, codec='pcm_s16le')
            # --- ▲▲▲ 修正ここまで ▲▲▲ ---

        # Librosaで音声ファイルを読み込み、波形データを生成
        y, sr = librosa.load(audio_path, sr=None)
        
        # データ量を削減するために間引く（例: 1000点に）
        num_samples = 1000
        if len(y) > num_samples:
            y = y[::len(y) // num_samples]
        
        # 振幅を[-1, 1]の範囲に正規化
        y = y / np.max(np.abs(y)) if np.max(np.abs(y)) > 0 else y
        
        return jsonify({"waveform": y.tolist()})

    except Exception as e:
        logger.error(f"音声波形の生成に失敗しました: {e}", exc_info=True)
        return jsonify({"error": "音声波形の生成に失敗しました。"}), 500
    finally:
        # 一時ファイルを削除
        if audio_path and os.path.exists(audio_path):
            os.remove(audio_path)
        if video_path and os.path.exists(video_path):
            os.remove(video_path)

def _split_video_for_transcription(video_path, temp_dir, chunk_duration=45, overlap_duration=5):
    """動画を指定された長さのオーバーラップするチャンクに分割する"""
    from moviepy import VideoFileClip
    
    chunk_paths_with_start_time = []
    try:
        with VideoFileClip(video_path) as clip:
            total_duration = clip.duration
            start_time = 0
            
            while start_time < total_duration:
                end_time = min(start_time + chunk_duration, total_duration)
                
                chunk_filename = os.path.join(temp_dir, f"chunk_{start_time:.2f}_{end_time:.2f}.mp4")
                
                # moviepy v1/v2 互換の subclip を使用
                sub_clip = _subclip_compat(clip, start_time, end_time)
                sub_clip.write_videofile(chunk_filename, codec="libx264", audio_codec="aac")
                
                chunk_paths_with_start_time.append((chunk_filename, start_time))
                
                if end_time == total_duration:
                    break
                
                start_time += (chunk_duration - overlap_duration)
    except Exception as e:
        logger.error(f"動画の分割中にエラーが発生: {e}", exc_info=True)
        return []
        
    return chunk_paths_with_start_time

def _run_video_transcribe_task(task_id, video_bytes, original_filename, user_info, video_duration):
    """
    【分割統治法・堅牢化最終版 v3】
    動画チャンクの文字起こしでAIが失敗した場合でも、再試行とフォールバック処理で音声の取りこぼしを防ぐ。
    FileDataの引数名を `file_uri` に修正し、ライブラリの仕様に完全準拠。
    """
    update_task_in_cosmos(task_id, {"status": "PROCESSING", "status_message": "動画認識タスクを開始...", "progress_percent": 5})
    temp_dir = tempfile.mkdtemp(prefix=f"transcribe_{task_id}_")
    gcs_blobs_to_delete = []

    try:
        # 1. 動画を一時ファイルに保存し、チャンクに分割
        update_task_in_cosmos(task_id, {"status_message": "動画を解析・分割中...", "progress_percent": 15})
        original_video_path = os.path.join(temp_dir, "original_video.mp4")
        with open(original_video_path, "wb") as f:
            f.write(video_bytes)
        
        video_chunks = _split_video_for_transcription(original_video_path, temp_dir) if video_duration > 180 else [(original_video_path, 0)]
        if not video_chunks:
            raise Exception("動画の分割処理に失敗しました。")

        # 2. 各チャンクを並列で文字起こし
        all_telops_from_chunks = []
        
        def _transcribe_chunk_with_fallback(chunk_path, chunk_start_time):
            """
            【堅牢化版】1つのチャンクを文字起こしする。
            AIへの指示を厳格化し、出力タイムスタンプを必ず検証・補正する。
            """
            gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
            if not gcs_bucket_name: raise Exception("GCSバケットが設定されていません。")

            # チャンクのデュレーションを取得
            with VideoFileClip(chunk_path) as clip:
                chunk_duration = clip.duration

            chunk_filename = os.path.basename(chunk_path)
            gcs_blob_name = f"temp_transcribe_chunks/{task_id}/{chunk_filename}"
            gcs_blobs_to_delete.append(gcs_blob_name)
            
            with open(chunk_path, "rb") as f_chunk:
                gcs_uri = _upload_to_gcs(f_chunk, gcs_blob_name, gcs_bucket_name)
            if not gcs_uri: raise Exception(f"チャンク {chunk_filename} のアップロードに失敗。")
            
            video_part = types.Part(
                file_data=types.FileData(
                    file_uri=gcs_uri,
                    mime_type=_get_video_mime_type(chunk_path)
                )
            )

            main_prompt = f"""あなたはプロの映像編集者であり、文字起こしの専門家です。
提供された**長さ{chunk_duration:.2f}秒の短い動画クリップ**を視聴し、テロップ用のテキストとタイムスタンプを生成してください。

**【最重要・厳格なルール】**
- **音声の最優先:** 文字起こしの**主たる情報源は、人が話している音声**です。聞こえる会話を可能な限り正確にテキスト化してください。
- **映像内テキストの補助的利用:** 映像に表示されているテキストは、あくまで**話されている内容の補助**としてのみ利用してください。具体的には、音声で言及されている専門用語や固有名詞の**スペルを確認・補正するため**に使用します。
- **【絶対禁止】音声にない情報のテロップ化:** 音声で話されていないにも関わらず、映像に文字が表示されているだけの場合、その文字をテロップとして書き起こさないでください。ただし、話者が無言で、かつ映像内の文字が明らかにメッセージを伝えている場合（例：説明図のタイトル）を除きます。
- **タイムスタンプの絶対制約:** 生成するタイムスタンプは、このクリップの開始時間(0.0秒)からの相対時間とし、**絶対にこのクリップの長さ({chunk_duration:.2f}秒)を超えてはいけません。**
- **【絶対禁止】推測や解釈の禁止:** 映像の内容から意味を推測したり、背景を説明したり、発話されていない内容を補完したりすることは固く禁じられています。

**厳格な出力形式:**
- 文字起こし結果を、以下のキーを持つJSONオブジェクトの配列として出力してください。
  - `text`: (文字列) 認識された一文。句読点を含み、自然な文章になるようにしてください。
  - `start`: (数値) その文章の**発話が開始される瞬間**を秒単位で記述してください。(0.0から{chunk_duration:.2f}の範囲)
  - `end`: (数値) その文章の**発話が終了する瞬間**を秒単位で記述してください。(0.0から{chunk_duration:.2f}の範囲)
- 応答は、このJSON配列の文字列のみとし、他の説明や` ```json `のような囲み文字は絶対に含めないでください。

**文字起こしの詳細ルール:**
- **テロップの区切り:** 会話の自然な間や文の切れ目を重視し、1つのテロップが長くなりすぎないように（10〜25文字程度）適切に区切ってください。
- 「えー」「あのー」のような不要なフィラーワードは除去してください。

**JSON出力例:**
```json
[
  {{
    "text": "本日はお集まりいただきありがとうございます。",
    "start": 1.5,
    "end": 5.2
  }},
  {{
    "text": "それでは、早速ですが本題に入ります。",
    "start": 6.1,
    "end": 9.8
  }}
]```
"""
            
            for attempt in range(2): # 失敗時に1回リトライ
                try:
                    response_str, _ = generate_with_gemini(
                        model_name=config.VIDEO_TRANSCRIBE_MODEL_NAME, 
                        contents=[video_part, types.Part.from_text(text=main_prompt)],
                        max_output_tokens=65535, 
                        temperature=0.1, 
                        user_info=user_info,
                        feature_category="動画テロップ生成(チャンク)", 
                        skip_cosmos_log=False,
                        generation_config_override={"response_mime_type": "application/json"}
                    )
                    if response_str and not response_str.startswith("[エラー:"):
                        relative_telops = json.loads(response_str)
                        
                        corrected_telops = []
                        for telop in relative_telops:
                            # タイムスタンプがチャンクの長さを超えていないか検証・補正
                            telop['start'] = min(max(0, telop.get('start', 0)), chunk_duration)
                            telop['end'] = min(max(telop['start'], telop.get('end', 0)), chunk_duration)
                            
                            # グローバルタイムスタンプに変換
                            telop['start'] += chunk_start_time
                            telop['end'] += chunk_start_time
                            corrected_telops.append(telop)
                        return corrected_telops
                except (json.JSONDecodeError, ValueError, TypeError) as e:
                    logger.warning(f"チャンク {chunk_filename} のJSON解析または処理に失敗 (試行 {attempt + 1}): {e}")
                    if attempt == 1: # 2回目の試行でも失敗した場合
                        raise e
            
            return [] # 2回試行して失敗した場合は空リストを返す

        with ThreadPoolExecutor(max_workers=2) as executor:
            future_to_chunk_info = {
                executor.submit(_transcribe_chunk_with_fallback, path, start_t): (path, start_t) 
                for path, start_t in video_chunks
            }
            processed_count = 0
            for future in as_completed(future_to_chunk_info):
                processed_count += 1
                progress = 20 + int(70 * (processed_count / len(video_chunks)))
                update_task_in_cosmos(task_id, {"status_message": f"動画を並列で解析中 ({processed_count}/{len(video_chunks)})...", "progress_percent": progress})
                try:
                    all_telops_from_chunks.extend(future.result())
                except Exception as exc:
                    path, start_t = future_to_chunk_info[future]
                    logger.error(f"チャンク {os.path.basename(path)} の処理が2回失敗。このチャンクはスキップされます。エラー: {exc}")
                    # フォールバック処理は今回は省略し、エラーログに留めることで安定性を優先

        # 3. 結果の結合、ソート、重複排除
        update_task_in_cosmos(task_id, {"status_message": "認識結果を統合・整理中...", "progress_percent": 95})
        all_telops_from_chunks.sort(key=lambda x: x['start'])
        
        merged_telops = []
        if all_telops_from_chunks:
            last_telop = all_telops_from_chunks[0]
            for i in range(1, len(all_telops_from_chunks)):
                current_telop = all_telops_from_chunks[i]
                # 現在のテロップが前のテロップの終了時間より前に開始する場合（オーバーラップ）
                if current_telop['start'] < last_telop['end']:
                    # テキストが類似している場合、前のテロップに統合（より長い方を採用）
                    if current_telop['text'] in last_telop['text'] or last_telop['text'] in current_telop['text']:
                        last_telop['end'] = max(last_telop['end'], current_telop['end'])
                    else: # テキストが異なる場合は、新しいテロップとして追加
                        merged_telops.append(last_telop)
                        last_telop = current_telop
                else: # オーバーラップしていない場合は、前のテロップを確定し、現在のを次に
                    merged_telops.append(last_telop)
                    last_telop = current_telop
            merged_telops.append(last_telop) # 最後のテロップを追加

        final_telops = [{"id": f"telop-{i}", **t} for i, t in enumerate(merged_telops)]

        success_payload = {
            "status": "SUCCESS", 
            "result": {"telops": final_telops},
            "status_message": "テロップの自動生成が完了しました。",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, success_payload)

    except Exception as e:
        error_msg = f"音声認識タスクでエラーが発生しました: {e}"
        logger.error(f"タスク {task_id}: {error_msg}", exc_info=True)
        failure_payload = {"status": "FAILURE", "error": str(e)}
        update_task_in_cosmos(task_id, failure_payload)
    finally:
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir)
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if gcs_bucket_name:
            for blob_name in gcs_blobs_to_delete:
                _delete_from_gcs(gcs_bucket_name, blob_name)


@app.route('/api/video/transcribe_async', methods=['POST'])
def transcribe_video_async():
    """動画の音声認識タスクを非同期で開始するエンドポイント"""
    if 'video_file' not in request.files:
        return jsonify({"error": "動画ファイルが見つかりません。"}), 400
    
    video_file = request.files['video_file']

    try:
        # 動画ファイルはトークン消費が大きいためチェックを行う
        # プロンプトは内部で固定のものを使用するが、動画自体のトークン数が支配的なため空文字でチェック
        validate_token_limit([video_file], "", None, model_name=config.VIDEO_TRANSCRIBE_MODEL_NAME)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    video_bytes = video_file.read()

    video_duration_str = request.form.get('video_duration_seconds')
    if not video_duration_str:
        return jsonify({"error": "動画の長さ情報が不足しています。"}), 400
    try:
        video_duration = float(video_duration_str)
    except ValueError:
        return jsonify({"error": "動画の長さの形式が不正です。"}), 400

    task_id = str(uuid.uuid4())
    
    # Cosmos DBとメモリにタスクの初期状態を保存
    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "video_transcription",
        "user_info": user_info,
        "original_filename": video_file.filename,
        "status_message": "音声認識タスクを受付ました。",
        "progress_percent": 0
    }

    if create_task_in_cosmos(task_initial_data) is None:
        return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500

    _submit_with_request_id(
        _run_video_transcribe_task,
        task_id,
        video_bytes,
        video_file.filename,
        user_info,
        video_duration,
    )

    return jsonify({"task_id": task_id}), 202

def _subclip_compat(clip, t_start, t_end):
    """
    MoviePy v1: clip.subclip / v2: clip.subclipped に対応する互換ラッパー。
    """
    try:
        # MoviePy v1.x
        return clip.subclip(t_start, t_end)
    except AttributeError:
        # MoviePy v2.x
        return clip.subclipped(t_start, t_end)

@app.route('/api/video/process', methods=['POST'])
def process_video():
    """
    選択範囲をカットして返す（Windows のファイルロック対策済み）。
    """
    if 'video_file' not in request.files:
        return jsonify({"error": "動画ファイルが見つかりません。"}), 400

    video_file = request.files['video_file']
    action = request.form.get('action', 'cut')
    
    # 一時ファイルのパスを try ブロックの外で初期化
    in_path = None
    out_path = None

    try:
        # 一時入力ファイルを書き出し
        with tempfile.NamedTemporaryFile(delete=False, suffix=os.path.splitext(video_file.filename)[1]) as tmp_in:
            in_path = tmp_in.name
            video_file.save(in_path)

        if action != 'cut':
            return jsonify({"error": "不明な処理です。"}), 400

        start_time = float(request.form.get('start', 0))
        end_time   = float(request.form.get('end', 0))

        # 生成先は delete=False にして先に閉じてから bytes で返す（Win のロック回避）
        with tempfile.NamedTemporaryFile(delete=False, suffix=".mp4") as tmp_out:
            out_path = tmp_out.name

        
        from moviepy import VideoFileClip, concatenate_videoclips
        with VideoFileClip(in_path) as clip:
            dur = float(clip.duration or 0.0)
            start = max(0.0, min(start_time, dur))
            end   = max(0.0, min(end_time,   dur))
            if end <= start:
                return jsonify({"error": "開始と終了の指定が不正です。"}), 400

            parts = []
            if start > 0:
                parts.append(_subclip_compat(clip, 0, start))
            if end < dur:
                parts.append(_subclip_compat(clip, end, dur))
            if not parts:
                return jsonify({"error": "カット結果が空です。"}), 400

            final_clip = concatenate_videoclips(parts, method="compose") if len(parts) > 1 else parts[0]
            final_clip.write_videofile(out_path, codec="libx264", audio_codec="aac")
            
            # クリップを明示的に閉じる
            if isinstance(parts, list):
                for p in parts:
                    try: p.close()
                    except Exception: pass
            try: final_clip.close()
            except Exception: pass

        # ここで out_path を bytes に読んでから send_file(BytesIO)
        with open(out_path, "rb") as f:
            data = f.read()
        
        return send_file(
            io.BytesIO(data),
            mimetype="video/mp4",
            as_attachment=True,
            download_name=f"cut_{secure_filename(video_file.filename)}"
        )

    except Exception as e:
        logger.error("動画処理中にエラーが発生しました: %s", e, exc_info=True)
        return jsonify({"error": "動画処理に失敗しました。"}), 500
    finally:
        # 入力・出力の一時ファイルを確実に削除
        if in_path and os.path.exists(in_path):
            try: os.remove(in_path)
            except Exception as e: logger.warning(f"一時入力ファイル {in_path} の削除に失敗: {e}")
        if out_path and os.path.exists(out_path):
            try: os.remove(out_path)
            except Exception as e: logger.warning(f"一時出力ファイル {out_path} の削除に失敗: {e}")


def _identify_segments_to_keep(telops, total_duration, cut_silence, cut_fillers, silence_threshold=1.5):
    """
    【修正版】
    テロップデータから、カットすべきでない（残すべき）時間範囲のリストを生成する。
    発声区間のみを抽出し、無音区間は単純に除外するロジックに変更。
    """
    if not telops:
        return [] if cut_silence else [(0, total_duration)]

    filler_words = ['えー', 'あの', 'えーと', 'まあ', 'なんか', 'こう', 'そのー', 'えっと']
    
    # フィルタリングするテロップのリストを作成
    filtered_telops = [
        telop for telop in telops 
        if not (cut_fillers and telop.get('text', '').strip() in filler_words)
    ]

    if not filtered_telops:
        return []

    # 単純に、フィルタリングされたすべてのテロップの開始時間と終了時間を「残すべき区間」としてリストアップする
    segments_to_keep = [
        (telop['start'], telop['end']) 
        for telop in filtered_telops 
        if 'start' in telop and 'end' in telop and telop['end'] > telop['start']
    ]
    
    # 無音カットが有効でない場合は、動画全体を返す
    if not cut_silence:
        return [(0, total_duration)]

    # 開始時間でソート
    segments_to_keep.sort(key=lambda x: x[0])
    
    return segments_to_keep


def _run_auto_cut_task(task_id, video_bytes, telops, cut_silence, cut_fillers, user_info):
    """
    自動カット（無音間／フィラー除去）を実行するバックグラウンドタスク。
    - MoviePy v2 の subclipped 互換
    - タスク結果に result["video_blob_name"] も入れて /api/pptx/download_video_result に整合
    - 堅牢化されたセグメント抽出ロジックを使用
    """
    update_task_in_cosmos(task_id, {
        "status": "PROCESSING",
        "status_message": "動画を解析中...",
        "progress_percent": 10
    })

    temp_dir = tempfile.mkdtemp(prefix=f"autocut_{task_id}_")
    in_path  = os.path.join(temp_dir, f"in_{task_id}.mp4")
    out_name = f"autocut_{task_id}.mp4"
    out_path = os.path.join(temp_dir, out_name)

    try:
        # 入力 bytes をファイル化
        with open(in_path, "wb") as f:
            f.write(video_bytes)

        from moviepy import VideoFileClip, concatenate_videoclips
        with VideoFileClip(in_path) as clip:
            dur = float(clip.duration or 0.0)

            # --- 残すべき区間を新しいロジックで決定 ---
            update_task_in_cosmos(task_id, {"status_message": "カット区間を特定中...", "progress_percent": 30})
            keep_segments = _identify_segments_to_keep(telops, dur, cut_silence, cut_fillers)
            
            if not keep_segments:
                 failure_payload = {
                    "status": "FAILURE", "error": "カットの結果、動画の長さが0秒になりました。設定を見直してください。",
                    "status_message": "カットの結果、動画の長さが0秒になりました。"
                }
                 update_task_in_cosmos(task_id, failure_payload)
                 return

            update_task_in_cosmos(task_id, {"status_message": "動画を切り出し中...", "progress_percent": 60})

            # v1/v2 互換 subclip で切り出し→連結
            subclips = [_subclip_compat(clip, s, e) for (s, e) in keep_segments if e > s]
            
            if not subclips:
                raise ValueError("切り出す有効なクリップがありませんでした。")

            final_clip = concatenate_videoclips(subclips, method="compose") if len(subclips) > 1 else subclips[0]
            final_clip.write_videofile(out_path, codec="libx264", audio_codec="aac")

            for sc in subclips:
                try: sc.close()
                except Exception: pass
            try: final_clip.close()
            except Exception: pass

        update_task_in_cosmos(task_id, {"status_message": "成果物をアップロード中...", "progress_percent": 95})

        # BLOB へアップロード（SAS でダウンロードさせる）
        with open(out_path, "rb") as fv:
            blob_name = f"results/{out_name}"
            upload_bytes_to_blob(fv.read(), blob_name)

        success_payload = {
            "status": "SUCCESS",
            "status_message": "自動カットが完了しました。",
            "progress_percent": 100,
            "result": {
                "files_data": {
                    "video": {
                        "blob_name": blob_name,
                        "filename": out_name,
                        "mimetype": "video/mp4"
                    }
                }
            }
        }
        update_task_in_cosmos(task_id, success_payload)

    except Exception as e:
        logger.error(f"自動カットタスク {task_id} 失敗: {e}", exc_info=True)
        failure_payload = {
            "status": "FAILURE",
            "error": str(e),
            "status_message": "自動カットに失敗しました。"
        }
        update_task_in_cosmos(task_id, failure_payload)
    finally:
        try:
            shutil.rmtree(temp_dir, ignore_errors=True)
        except Exception:
            pass

def _run_summarize_task(task_id, transcript_text, user_info):
    """動画の文字起こしテキストを要約し、タグを生成する非同期タスク"""
    update_task_in_cosmos(task_id, {"status": "PROCESSING", "status_message": "AIによる要約を開始...", "progress_percent": 20})
    try:
        prompt = f"""あなたはプロの編集者です。以下の会議またはプレゼンテーションの文字起こしテキストを分析し、以下の2つの項目を生成してください。

1.  **要約:** 全体の内容を3〜5つの箇条書きで簡潔にまとめてください。
2.  **タグ:** この動画の内容を表す適切なキーワードを5つ抽出してください。

出力は、必ず以下のキーを持つJSON形式の文字列のみとしてください。
```json
{{
  "summary": "（ここに箇条書きの要約をMarkdown形式で記述）",
  "tags": ["（タグ1）", "（タグ2）", "（タグ3）", "（タグ4）", "（タグ5）"]
}}
```

--- 文字起こしテキスト ---
{transcript_text}
--- 文字起こしテキストここまで ---
"""
        summary_result_str, _ = generate_with_gemini(
            model_name=config.DOC_GEN_MODEL_NAME,
            contents=[types.Part.from_text(text=prompt)],
            max_output_tokens=4096,
            temperature=0.2,
            user_info=user_info,
            feature_category="動画要約・タグ生成(Gemini)",
            skip_cosmos_log=False,
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not summary_result_str or summary_result_str.startswith("[エラー:"):
            raise Exception(f"AIによる要約生成に失敗: {summary_result_str}")

        parsed_result = json.loads(summary_result_str)
        
        success_payload = {
            "status": "SUCCESS", 
            "result": parsed_result,
            "status_message": "要約とタグの生成が完了しました。",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, success_payload)

    except Exception as e:
        logger.error(f"要約タスク {task_id} 失敗: {e}", exc_info=True)
        failure_payload = {"status": "FAILURE", "error": str(e)}
        update_task_in_cosmos(task_id, failure_payload)


