@app.route('/api/video/ai_intelligent_cut_async', methods=['POST'])
def ai_intelligent_cut_async():
    if 'video_file' not in request.files: return jsonify({"error": "動画ファイルが見つかりません。"}), 400
    if 'telops' not in request.form: return jsonify({"error": "テロップデータが必要です。"}), 400
    if 'objective' not in request.form: return jsonify({"error": "動画の目的が指定されていません。"}), 400
    
    video_file = request.files['video_file']
    telops = json.loads(request.form['telops'])
    objective = request.form.get('objective')
    
    estimated_duration = 600.0
    if telops and isinstance(telops, list) and len(telops) > 0:
        try:
            last_telop = telops[-1]
            if 'end' in last_telop:
                estimated_duration = float(last_telop['end']) + 10.0 # マージン
        except:
            pass

    try:
        # Gemini動画: 約300 tokens/sec と仮定
        estimated_video_tokens = int(estimated_duration * 300)
        dummy_video_content = "a" * (estimated_video_tokens * 4)
        
        # プロンプト（目的）と結合してチェック
        combined_check_text = f"{objective}\n{dummy_video_content}"
        
        logger.info(f"AI Cut Token Estimation: Duration={estimated_duration}s, Est.Tokens={estimated_video_tokens}")
        
        validate_token_limit(
            [], # ファイル実体は渡さない
            combined_check_text, 
            None, 
            model_name=config.VIDEO_EXTRACT_MODEL_NAME
        )
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    original_filename = secure_filename(video_file.filename)
    task_id = str(uuid.uuid4())

    # --- GCSへの直接アップロード (ストリーム処理) ---
    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
    if not gcs_bucket_name:
        return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500

    file_extension = os.path.splitext(original_filename)[1].lower()
    gcs_blob_name = f"temp_ai_cut_video/{task_id}{file_extension}"
    gcs_uri = None

    try:
        # ポインタを先頭に戻す
        video_file.seek(0)
        
        # ストリームアップロード
        gcs_uri = _upload_to_gcs(video_file, gcs_blob_name, gcs_bucket_name)

        if not gcs_uri:
            raise Exception("GCSへのアップロードに失敗しました。")
            
        logger.info(f"Directly uploaded video for AI cut to GCS: {gcs_uri}")

    except Exception as e:
        logger.error(f"Failed to upload video to GCS: {e}", exc_info=True)
        return jsonify({"error": "動画ファイルのアップロードに失敗しました。"}), 500
    
    # Cosmos DBとメモリにタスクの初期状態を保存
    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "video_ai_intelligent_cut",
        "user_info": user_info,
        "original_filename": original_filename,
        "status_message": "AIおまかせカットタスクを受付ました。",
        "progress_percent": 0
    }

    if create_task_in_cosmos(task_initial_data) is None:
        return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500
    
    # 非同期タスクをサブミット (bytesではなくGCS情報を渡す)
    _submit_with_request_id(
        _run_ai_intelligent_cut_task,
        task_id,
        gcs_uri,       # GCS URI
        gcs_blob_name, # 削除用Blob名
        original_filename,
        telops,
        objective,
        user_info,
    )
    
    return jsonify({"task_id": task_id}), 202

def _run_ai_intelligent_cut_task(task_id, gcs_uri, gcs_blob_name, original_filename, telops, objective, user_info):
    """
    【改定版】AIが動画内容を判断し、重要シーンのみを抽出する非同期タスク。
    GCS上の動画をGeminiで解析し、編集のためにローカルへダウンロードする。
    """
    update_task_in_cosmos(task_id, {"status": "PROCESSING", "status_message": "AIによる編集判断を開始...", "progress_percent": 10})
    temp_dir = tempfile.mkdtemp(prefix=f"ai_cut_{task_id}_")
    
    # クリーンアップ用リスト
    gcs_blobs_to_delete = [gcs_blob_name]

    try:
        # 1. Geminiへのプロンプト構築
        # (動画は既にGCSにあるのでアップロード不要)
        update_task_in_cosmos(task_id, {"status_message": "AIが動画全体を分析中...", "progress_percent": 30})
        
        transcript_text = "\n".join([f"- 「{t['text']}」（開始: {t['start']:.1f}秒, 終了: {t['end']:.1f}秒)" for t in telops])

        prompt = f"""あなたは熟練の映像編集ディレクターです。
提供された動画全体とその文字起こし内容を分析し、以下の「ユーザーの目的」を達成するために、動画から「残すべき」部分の時間範囲を特定してください。

**ユーザーの目的:**
{objective}

**あなたのタスク:**
動画の中から「残すべき」と判断した部分の時間範囲（開始時間と終了時間）を特定し、そのリストをJSON形式で出力してください。

**編集の重要ルール:**
1.  **自然な「間」の確保:** 発話部分を抽出する際、各発話の開始時間の**0.3秒前**から、終了時間の**0.3秒後**までを範囲に含めてください。これにより、視聴者にとって自然な会話の間が生まれます。
2.  **目的の達成:** ユーザーの目的が単なる無音カット以上の意図（例：「製品紹介の重要な部分だけを残す」）を持つ場合、その目的に合致しない無関係な発言は大胆にカットしてください。
3.  **連続した発言の結合:** 複数の発言が1.5秒以内の短い間隔で連続している場合は、それらを1つの長い区間として結合してください。

**文字起こし内容（タイムスタンプ付き）:**
---
{transcript_text}
---

**厳格な出力形式:**
- 「残すべき」時間範囲のリストを、以下のキーを持つJSONオブジェクトの配列として出力してください。
  - `start`: (数値) 残すべき区間の開始時間（秒）
  - `end`: (数値) 残すべき区間の終了時間（秒）
- 応答は、このJSON配列の文字列のみとし、他の説明や` ```json `のような囲み文字は**絶対に含めないでください**。

**JSON出力例:**
```json
[
  {{ "start": 10.2, "end": 25.5 }},
  {{ "start": 44.8, "end": 62.3 }}
]
```
"""
        
        mime_type = _get_video_mime_type(original_filename)
        video_part = types.Part(file_data=types.FileData(file_uri=gcs_uri, mime_type=mime_type))
        prompt_part = types.Part.from_text(text=prompt)

        # 2. Gemini APIを呼び出し、残すべき区間リストを取得
        response_str, _ = generate_with_gemini(
            model_name=config.VIDEO_EXTRACT_MODEL_NAME, # 高度な判断が必要なためProモデルを推奨
            contents=[video_part, prompt_part],
            max_output_tokens=65535, temperature=0.1, user_info=user_info,
            feature_category="動画AIおまかせカット(判断)", skip_cosmos_log=False,
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not response_str or response_str.startswith("[エラー:"):
            raise Exception(f"AIによる編集判断に失敗: {response_str}")

        try:
            # JSONパース（マークダウン除去含む）
            json_str = response_str.strip()
            if json_str.startswith("```json"): json_str = json_str[7:]
            if json_str.endswith("```"): json_str = json_str[:-3]
            keep_segments = json.loads(json_str.strip())
        except json.JSONDecodeError as e:
            raise Exception(f"AI応答のJSON解析に失敗: {e}")

        # 3. 動画をローカルにダウンロードして編集 (MoviePy/FFmpeg)
        update_task_in_cosmos(task_id, {"status_message": "動画を編集・結合中...", "progress_percent": 60})
        
        local_video_path = os.path.join(temp_dir, "input.mp4")
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        
        # GCSからダウンロード
        storage_client = get_main_gcs_client()
        bucket = storage_client.bucket(gcs_bucket_name)
        blob = bucket.blob(gcs_blob_name)
        blob.download_to_filename(local_video_path)
        
        from moviepy import VideoFileClip, concatenate_videoclips
        with VideoFileClip(local_video_path) as clip:
            subclips = [_subclip_compat(clip, s['start'], s['end']) for s in keep_segments if s['end'] > s['start']]
            if not subclips: raise ValueError("AIが残すべき区間を抽出しませんでした。")
            
            final_clip = concatenate_videoclips(subclips, method="compose") if len(subclips) > 1 else subclips[0]
            out_name = f"ai_cut_{task_id}.mp4"
            out_path = os.path.join(temp_dir, out_name)
            
            # 処理状況をログ出力するカスタムロガーを使用
            progress_logger = FFMPEGProgressLogger(task_id)
            final_clip.write_videofile(out_path, codec="libx264", audio_codec="aac", logger=progress_logger)

            # メモリ解放
            for sc in subclips:
                try: sc.close()
                except Exception: pass
            try: final_clip.close()
            except Exception: pass

        # 4. 結果をアップロード
        update_task_in_cosmos(task_id, {"status_message": "成果物をアップロード中...", "progress_percent": 95})
        with open(out_path, "rb") as fv:
            blob_name = f"results/{out_name}"
            upload_bytes_to_blob(fv.read(), blob_name)

        success_payload = {
            "status": "SUCCESS", "status_message": "AIおまかせカットが完了しました。", "progress_percent": 100,
            "result": {
                "files_data": {
                    "video": {
                        "blob_name": blob_name,
                        "filename": out_name,
                        "mimetype": "video/mp4"
                    }
                }
            }
        }
        update_task_in_cosmos(task_id, success_payload)

    except Exception as e:
        logger.error(f"AIおまかせカットタスク {task_id} 失敗: {e}", exc_info=True)
        failure_payload = {"status": "FAILURE", "error": str(e)}
        update_task_in_cosmos(task_id, failure_payload)
    finally:
        # GCSとローカルの一時ファイルをクリーンアップ
        if gcs_blob_name and gcs_bucket_name: 
            _delete_from_gcs(gcs_bucket_name, gcs_blob_name)
        if temp_dir and os.path.exists(temp_dir): 
            shutil.rmtree(temp_dir)

def _run_video_editor_export_task(task_id: str, video_bytes: bytes, telops: list, user_info: dict, voice_name: str | None = None):
    """
    【フォントサイズ自動調整・改訂版】
    FFmpegを直接使用し、テロップを動画に焼き付ける。
    動画の高さに対する比率でフォントサイズを動的に計算し、常に適切な大きさのテロップを生成する。
    """
    update_task_in_cosmos(task_id, {"status": "PROCESSING", "status_message": "高速エクスポート処理を開始...", "progress_percent": 10})
    temp_dir = tempfile.mkdtemp(prefix=f"export_hardsub_{task_id}_")
    original_cwd = os.getcwd()

    try:
        # --- 1. SRT（字幕）ファイルとフォントを一時ディレクトリに準備 ---
        update_task_in_cosmos(task_id, {"status_message": "字幕ファイルとフォントを準備中...", "progress_percent": 20})
        
        def _create_srt_content(telops_data):
            srt_parts = []
            def format_srt_time(seconds):
                ms = int((seconds - int(seconds)) * 1000)
                s = int(seconds)
                m, s = divmod(s, 60)
                h, m = divmod(m, 60)
                return f"{h:02d}:{m:02d}:{s:02d},{ms:03d}"

            for i, telop in enumerate(telops_data, 1):
                start_time_str = format_srt_time(telop.get('start', 0))
                end_time_str = format_srt_time(telop.get('end', 0))
                text = telop.get('text', '').strip()
                if text:
                    srt_parts.append(f"{i}\n{start_time_str} --> {end_time_str}\n{text}\n")
            return "\n".join(srt_parts)

        srt_content = _create_srt_content(telops)

        if not srt_content:
            logger.info(f"タスク {task_id}: テロップデータがないため、元の動画をコピーして処理を完了します。")
            output_filename = f"exported_video_{task_id}.mp4"
            video_blob_name = f"results/{output_filename}"
            upload_bytes_to_blob(video_bytes, video_blob_name)
            
            success_payload = {
                "status": "SUCCESS",
                "result": {"files_data": {"video": {"blob_name": video_blob_name, "filename": output_filename, "mimetype": "video/mp4"}}},
                "status_message": "エクスポートが完了しました（字幕なし）。", "progress_percent": 100
            }
            update_task_in_cosmos(task_id, success_payload)
            return

        input_video_filename = "input_video.mp4"
        srt_filename = "subtitles.srt"
        font_filename = os.path.basename(config.FONT_PATH)

        input_video_path = os.path.join(temp_dir, input_video_filename)
        with open(input_video_path, "wb") as f: f.write(video_bytes)
        
        srt_path = os.path.join(temp_dir, srt_filename)
        with open(srt_path, "w", encoding='utf-8') as f: f.write(srt_content)

        font_path_in_temp = os.path.join(temp_dir, font_filename)
        shutil.copy(config.FONT_PATH, font_path_in_temp)
        
        # --- 2. FFmpegで字幕を映像に焼き付け ---
        update_task_in_cosmos(task_id, {"status_message": "字幕を動画に焼き付け中...", "progress_percent": 40})
        
        ffmpeg_path = config.FFMPEG_PATH or shutil.which('ffmpeg')
        if not ffmpeg_path or not os.path.exists(ffmpeg_path):
            raise FileNotFoundError(f"FFmpeg実行可能ファイルが見つかりません。設定パス: {config.FFMPEG_PATH}")

        from moviepy import VideoFileClip
        video_height = 720 # デフォルト値
        with VideoFileClip(input_video_path) as clip:
            video_height = clip.h
        logger.info(f"動画の高さを取得しました: {video_height}px")

        # 動画の高さの約1/24をフォントサイズとする。この分母の数値を調整することで、全体の文字サイズを変更できます。
        # (数値を大きくすると文字は小さく、小さくすると文字は大きくなります)
        FONT_SIZE_RATIO_DIVISOR = 50
        calculated_font_size = int(video_height / FONT_SIZE_RATIO_DIVISOR)
        
        # 極端な解像度の動画でも読みやすいように、フォントサイズに下限と上限を設ける
        final_font_size = max(16, min(calculated_font_size, 100))
        logger.info(f"解像度に合わせてフォントサイズを {final_font_size} に調整しました。 (基準: 高さ/{FONT_SIZE_RATIO_DIVISOR})")

        # 字幕のスタイルを指定 (FontSizeを動的に設定)
        subtitle_style = (
            f"FontName=MS Gothic,"
            f"FontSize={final_font_size},"  # 動的に計算したフォントサイズを使用
            f"PrimaryColour=&HFFFFFF,"
            f"BorderStyle=1,"
            f"OutlineColour=&H000000,"
            f"Outline=1.5,"
            f"Shadow=0.8,"
            f"Alignment=2," # 2は下部中央
            f"MarginV=25"   # 画面下からのマージン
        )
        
        video_filter_string = f"subtitles={srt_filename}:force_style='{subtitle_style}':fontsdir=."
        output_filename = f"exported_video_{task_id}.mp4"

        command = [
            ffmpeg_path, '-i', input_video_filename, '-vf', video_filter_string,
            '-c:v', 'libx264', '-preset', 'fast', '-crf', '23',
            '-c:a', 'copy', '-y', output_filename
        ]
        
        logger.info(f"タスク {task_id}: FFmpeg字幕焼き付けコマンドを実行 (CWD: {temp_dir}): {' '.join(command)}")
        os.chdir(temp_dir)
        
        result = subprocess.run(
            command, capture_output=True, text=True, check=True, 
            encoding='utf-8', errors='ignore', shell=(platform.system() == "Windows")
        )

        update_task_in_cosmos(task_id, {"status_message": "成果物をアップロード中...", "progress_percent": 95})
        
        output_video_path = os.path.join(temp_dir, output_filename)
        with open(output_video_path, "rb") as f_video:
            video_blob_name = f"results/{output_filename}"
            upload_bytes_to_blob(f_video.read(), video_blob_name)

        success_payload = {
            "status": "SUCCESS",
            "result": { "files_data": { "video": { "blob_name": video_blob_name, "filename": output_filename, "mimetype": "video/mp4" } } },
            "status_message": "動画のエクスポートが完了しました。",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, success_payload)

    except (subprocess.CalledProcessError, FileNotFoundError) as e:
        stderr_output = getattr(e, 'stderr', str(e))
        error_msg = f"動画のエクスポート処理に失敗しました。エラー: {stderr_output[:1000]}"
        logger.error(f"タスク {task_id}: {error_msg}")
        failure_payload = {"status": "FAILURE", "error": error_msg}
        update_task_in_cosmos(task_id, failure_payload)
    except Exception as e:
        logger.error(f"動画エクスポートタスク {task_id} 失敗: {e}", exc_info=True)
        failure_payload = {"status": "FAILURE", "error": str(e)}
        update_task_in_cosmos(task_id, failure_payload)
    finally:
        os.chdir(original_cwd)
        if os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)


