def _run_noise_removal_task(task_id, video_bytes, remove_wind, remove_reverb, remove_constant_noise, remove_low_freq_noise, user_info):
    """
    【改定版 v3 - Windowsファイルロック対策】
    noisereduceライブラリとFFmpegを組み合わせ、効果的なノイズ除去を行う非同期タスク。
    moviepyオブジェクトを明示的に閉じることで、リソースリークとファイルロックを防ぐ。
    """
    update_task_in_cosmos(task_id, {
        "status": "PROCESSING",
        "status_message": "ノイズ除去の準備中...",
        "progress_percent": 10
    })

    temp_dir = tempfile.mkdtemp(prefix=f"noise_removal_{task_id}_")
    current_video_bytes = video_bytes
    
    # moviepyオブジェクトを追跡するリスト
    clips_to_close = []

    try:
        # --- ステップ1: AIによる定常ノイズ除去 (noisereduceライブラリ) ---
        if remove_constant_noise:
            update_task_in_cosmos(task_id, {"status_message": "AIが定常ノイズを分析・除去中...", "progress_percent": 20})
            
            input_video_path = os.path.join(temp_dir, "input_step1.mp4")
            audio_path = os.path.join(temp_dir, "original_audio.wav")
            denoised_audio_path = os.path.join(temp_dir, "denoised_audio.wav")
            output_video_path_step1 = os.path.join(temp_dir, "output_step1.mp4")

            with open(input_video_path, "wb") as f:
                f.write(current_video_bytes)
            
            video_clip = VideoFileClip(input_video_path)
            clips_to_close.append(video_clip) # 追跡リストに追加

            if video_clip.audio is None:
                raise ValueError("動画に音声トラックが含まれていません。")
            
            video_clip.audio.write_audiofile(audio_path, codec='pcm_s16le')

            y, sr = librosa.load(audio_path, sr=None)
            noise_len_seconds = min(0.5, video_clip.duration / 2)
            noise_sample = y[0:int(noise_len_seconds * sr)]
            reduced_noise_y = nr.reduce_noise(y=y, y_noise=noise_sample, sr=sr, stationary=True)
            sf.write(denoised_audio_path, reduced_noise_y, sr)
            
            audio_clip = AudioFileClip(denoised_audio_path)
            clips_to_close.append(audio_clip) # 追跡リストに追加

            final_video_clip = video_clip.with_audio(audio_clip)
            clips_to_close.append(final_video_clip) # 追跡リストに追加

            final_video_clip.write_videofile(
                output_video_path_step1, 
                codec="libx264", 
                audio_codec="aac"
            )
            
            with open(output_video_path_step1, "rb") as f:
                current_video_bytes = f.read()
            logger.info(f"タスク {task_id}: AIによる定常ノイズ除去が完了しました。")

        # --- ステップ2: FFmpegによるその他のノイズ除去 ---
        ffmpeg_filters_to_apply = []
        if remove_wind:
            ffmpeg_filters_to_apply.append("afftdn=nr=15:nf=-25")
        if remove_reverb:
            ffmpeg_filters_to_apply.append("aecho=0.8:0.9:50:0.3")
        if remove_low_freq_noise:
            ffmpeg_filters_to_apply.append("highpass=f=80")

        if ffmpeg_filters_to_apply:
            update_task_in_cosmos(task_id, {"status_message": "FFmpegで追加フィルターを適用中...", "progress_percent": 70})
            
            input_video_path_step2 = os.path.join(temp_dir, "input_step2.mp4")
            output_video_path_step2 = os.path.join(temp_dir, "output_step2.mp4")
            with open(input_video_path_step2, "wb") as f:
                f.write(current_video_bytes)

            audio_filter_string = ",".join(ffmpeg_filters_to_apply)
            ffmpeg_path = config.FFMPEG_PATH or shutil.which('ffmpeg')
            if not ffmpeg_path: raise FileNotFoundError("FFmpegが見つかりません。")

            use_shell = platform.system() == "Windows"
            command = (
                f'"{ffmpeg_path}" -i "{input_video_path_step2}" -c:v copy '
                f'-af "{audio_filter_string}" -c:a aac -y "{output_video_path_step2}"'
            ) if use_shell else [
                ffmpeg_path, '-i', input_video_path_step2, '-c:v', 'copy',
                '-af', audio_filter_string, '-c:a', 'aac', '-y', output_video_path_step2
            ]
            
            subprocess.run(command, capture_output=True, text=True, check=True, shell=use_shell)
            
            with open(output_video_path_step2, "rb") as f:
                current_video_bytes = f.read()
            logger.info(f"タスク {task_id}: FFmpegによる追加フィルターの適用が完了しました。")
        
        # --- 最終成果物のアップロード ---
        update_task_in_cosmos(task_id, {"status_message": "成果物をアップロード中...", "progress_percent": 95})
        output_filename = f"noise_removed_{task_id}.mp4"
        blob_name = f"results/{output_filename}"
        upload_bytes_to_blob(current_video_bytes, blob_name)

        success_payload = {
            "status": "SUCCESS",
            "status_message": "ノイズ除去が完了しました。",
            "progress_percent": 100,
            "result": {
                "files_data": {
                    "video": {
                        "blob_name": blob_name,
                        "filename": output_filename,
                        "mimetype": "video/mp4"
                    }
                }
            }
        }
        update_task_in_cosmos(task_id, success_payload)

    except Exception as e:
        error_msg = f"ノイズ除去タスクでエラーが発生: {e}"
        if isinstance(e, subprocess.CalledProcessError):
            error_msg += f"\nFFmpeg Log: {e.stderr[:1000]}"
        logger.error(f"タスク {task_id}: {error_msg}", exc_info=True)
        failure_payload = {"status": "FAILURE", "error": error_msg}
        update_task_in_cosmos(task_id, failure_payload)
    finally:
        # 追跡リストにあるすべてのmoviepyオブジェクトを閉じる
        for clip in clips_to_close:
            try:
                if hasattr(clip, 'close') and callable(clip.close):
                    clip.close()
            except Exception as e_close:
                logger.warning(f"タスク {task_id}: moviepyクリップのクローズ中にエラー: {e_close}")
        if os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)


