@app.route('/api/video/translate_telops', methods=['POST'])
def translate_telops_endpoint():
    """
    受け取ったテロップデータのリストを、指定された言語に一括で翻訳して返す。
    """
    if not request.json or 'telops' not in request.json or 'target_language' not in request.json:
        return jsonify({"error": "必要なデータ（テロップ、ターゲット言語）が不足しています。"}), 400

    telops_to_translate = request.json['telops']
    target_language = request.json['target_language']
    # user_info = get_entra_user_info(request)
    user_info = g.user_info

    if not isinstance(telops_to_translate, list):
        return jsonify({"error": "テロップデータは配列である必要があります。"}), 400
    if not target_language:
        return jsonify({"error": "翻訳先の言語が指定されていません。"}), 400

    # 翻訳対象のテキストを抽出
    texts_to_translate = [telop.get('text', '') for telop in telops_to_translate]
    
    translated_texts = []
    # 既存の翻訳ヘルパーを並列実行して高速化
    with ThreadPoolExecutor(max_workers=8) as executor:
        # 翻訳タスクをサブミット
        future_to_text = {executor.submit(translate_text_content, text, target_language, user_info): text for text in texts_to_translate}
        
        # 元の順序を保持するための辞書
        results_map = {}
        for future in as_completed(future_to_text):
            original_text = future_to_text[future]
            try:
                translated_text = future.result()
                # 翻訳に失敗した場合は元のテキストを維持
                results_map[original_text] = translated_text if translated_text else original_text
            except Exception as e:
                logger.error(f"テロップ翻訳中にエラー: {e}")
                results_map[original_text] = original_text # エラー時も元のテキスト

        # 元の順序で結果を再構築
        for text in texts_to_translate:
            translated_texts.append(results_map.get(text, text))

    # 元のテロップデータのテキスト部分だけを翻訳後のものに置き換える
    translated_telops_result = []
    for i, original_telop in enumerate(telops_to_translate):
        new_telop = original_telop.copy()
        new_telop['text'] = translated_texts[i]
        translated_telops_result.append(new_telop)

    return jsonify({"translated_telops": translated_telops_result})

@app.route('/api/video/download_processed_video/<task_id>', methods=['GET'])
def download_processed_video_endpoint(task_id):
    """
    完了したタスクの成果物（動画ファイル）をBlob Storageから取得し、
    クライアントに直接ストリーミングするエンドポイント。
    """
    # 最初にメモリ上のDBからタスク情報を探す
    task_info = get_task_from_cosmos(task_id)

    if not task_info or task_info.get("status") != "SUCCESS":
        logger.error(f"ダウンロード要求がありましたが、タスク {task_id} が完了していないか、存在しません。")
        return jsonify({"error": "タスクが完了していないか、存在しません。"}), 404
    
    # result -> files_data -> video -> blob_name の階層を安全にたどる
    video_info = task_info.get("result", {}).get("files_data", {}).get("video", {})
    video_blob_name = video_info.get("blob_name")
    video_filename = video_info.get("filename", "processed_video.mp4")

    if not video_blob_name:
        logger.error(f"タスク {task_id} の成功結果に、動画のblob_nameが見つかりません。")
        return jsonify({"error": "生成された動画ファイルの情報が見つかりません。"}), 404

    try:
        # 既存のユーティリティ関数を使ってBlobからバイトデータをダウンロード
        video_bytes = download_blob_to_bytes(video_blob_name)
        if not video_bytes:
            logger.error(f"Blob '{video_blob_name}' のダウンロードに失敗しました（空のデータ）。")
            return jsonify({"error": "ストレージからのファイルのダウンロードに失敗しました。"}), 500

        logger.info(f"タスク {task_id} の成果物 ({video_blob_name}) をクライアントに送信します。")
        
        # Flaskのsend_fileを使って、バイトデータを動画ファイルとして返す
        return send_file(
            io.BytesIO(video_bytes),
            mimetype='video/mp4',
            as_attachment=True,
            download_name=video_filename
        )
    except Exception as e:
        logger.error(f"動画成果物 ({video_blob_name}) の送信中にエラー: {e}", exc_info=True)
        return jsonify({"error": "ファイルの送信中にサーバーエラーが発生しました。"}), 500

