# --- 新API: 画像生成・編集 ---
@app.route('/api/image/generate', methods=['POST'])
def generate_image_endpoint():
    """
    プロンプト、モード、および画像ファイルに基づいて、Gemini 2.5 Flash Image Previewモデルを使い画像を生成する。
    結果はServer-Sent Events (SSE)でストリーミングされる。
    """
    try:
        # フォームデータからパラメータを取得
        prompt = request.form.get('prompt', '')
        mode = request.form.get('mode', 'generate') # 'generate', 'edit', 'inpaint', 'outpaint', 'composite'
        num_images = int(request.form.get('num_images', 1))
        aspect_ratio = request.form.get('aspect_ratio', 'auto')
        
        if not prompt:
            return jsonify({"error": "プロンプトは必須です。"}), 400

        # user_info = get_entra_user_info(request)
        user_info = g.user_info
        
        # ファイルを取得
        base_image_file = request.files.get('base_image')
        mask_image_file = request.files.get('mask_image')
        reference_files = request.files.getlist('reference_images')
        
        final_prompt = "" # 変数を初期化

        # 編集モードの場合のプロンプト強化
        if mode == 'edit':
            log_feature_category = "画像編集"
            final_prompt = f"""
            SYSTEM COMMAND: Edit the provided image based on the user's instruction.
            
            **USER INSTRUCTION:** "{prompt}"
            
            **CONSTRAINTS:**
            - **Strictly maintain the original layout, background, and style.** Do not generate a completely new image.
            - Only modify the specific parts mentioned in the instruction (e.g., remove text, change object).
            - If removing text, use inpainting techniques to fill the background naturally.
            - **LANGUAGE:** If any new text is added, it MUST be in JAPANESE (or the target language if specified).
            """
            aspect_ratio = None # 編集時は元画像の比率を維持
        else:
            log_feature_category = "画像生成"
        
        text_to_send = final_prompt if final_prompt else prompt

        # SSEストリームを生成するジェネレータ関数
        def generate_image_stream(target_prompt):
            try:
                # --- AIへの入力(contents)を構築 ---
                # 引数で受け取った target_prompt を使用
                parts_for_gemini = [types.Part.from_text(text=target_prompt)]
                
                log_filenames = []
                if base_image_file:
                    log_filenames.append(base_image_file.filename)
                    base_image_file.seek(0)
                    parts_for_gemini.append(extract_file_content_to_part(base_image_file))
                if mask_image_file and mode in ['inpaint', 'erase']:
                    log_filenames.append(mask_image_file.filename)
                    mask_image_file.seek(0)
                    parts_for_gemini.append(extract_file_content_to_part(mask_image_file))
                for ref_file in reference_files:
                    if ref_file and ref_file.filename:
                        log_filenames.append(ref_file.filename)
                        ref_file.seek(0)
                        part = extract_file_content_to_part(ref_file)
                        if part: parts_for_gemini.append(part)
                contents = [types.Content(role="user", parts=parts_for_gemini)]

                generated_count = 0
                
                for i in range(num_images):
                    logger.info(f"Generating image {i+1}/{num_images}...")
                    
                    # --- Gemini APIをストリーミングで呼び出し ---
                    response_iterator = generate_with_gemini(
                        model_name=config.IMAGE_GENERATION_MODEL_NAME,
                        contents=contents, stream=True, user_info=user_info,
                        log_prompt_text=f"Image Gen ({mode}) [{i+1}/{num_images}]: {prompt[:50]}...",
                        log_filenames=log_filenames, feature_category=log_feature_category,
                        temperature=0.8,
                        aspect_ratio=aspect_ratio
                    )

                    for chunk in response_iterator:
                        if hasattr(chunk, 'image_data_url') and chunk.image_data_url:
                            # 巨大なBase64データをチャンクに分割して送信する
                            header, base64_data = chunk.image_data_url.split(",", 1)
                            mime_type = header.split(';')[0].split(':')[1]

                            # 1. 画像転送開始を通知 (index は通し番号)
                            start_event = {"type": "image_start", "mime_type": mime_type, "index": generated_count}
                            yield f"data: {json.dumps(start_event)}\n\n"
                            
                            # 2. Base64データを8KBずつのチャンクに分割して送信
                            chunk_size = 8192
                            for k in range(0, len(base64_data), chunk_size):
                                data_chunk = base64_data[k:k + chunk_size]
                                chunk_event = {"type": "image_chunk", "data": data_chunk}
                                yield f"data: {json.dumps(chunk_event)}\n\n"
                            
                            # 3. 画像転送終了を通知
                            end_event = {"type": "image_end"}
                            yield f"data: {json.dumps(end_event)}\n\n"
                            
                            # 画像が1枚完成したらカウントアップ
                            generated_count += 1

                        if hasattr(chunk, 'text') and chunk.text:
                            sse_data = {"type": "text", "content": chunk.text}
                            yield f"data: {json.dumps(sse_data)}\n\n"

            except Exception as e_stream:
                logger.error(f"画像生成ストリーム中にエラー: {e_stream}", exc_info=True)
                error_data = json.dumps({'type': 'error', 'error': str(e_stream)})
                yield f"data: {error_data}\n\n"
            finally:
                done_data = json.dumps({'type': 'done'})
                yield f"data: {done_data}\n\n"

        return Response(stream_with_context(generate_image_stream(text_to_send)), mimetype='text/event-stream')

    except Exception as e:
        logger.error(f"画像生成リクエスト受付中にエラー: {e}", exc_info=True)
        # ストリーミング開始前にエラーが発生した場合
        return jsonify({"error": f"サーバー側でエラーが発生しました: {str(e)}"}), 500

# --- 新API: ストーリーボードからPPTXをエクスポート ---
@app.route('/api/storyboard/export_pptx', methods=['POST'])
def export_storyboard_to_pptx():
    if not request.json or 'storyboard_data' not in request.json:
        return jsonify({"error": "ストーリーボードのデータがありません。"}), 400

    storyboard_data = request.json['storyboard_data']
    if not isinstance(storyboard_data, list) or len(storyboard_data) == 0:
        return jsonify({"error": "ストーリーボードのデータ形式が不正です。"}), 400

    try:
        prs = None
        if config.PPTX_GENERATOR_DEFAULT_TEMPLATE and os.path.exists(config.PPTX_GENERATOR_DEFAULT_TEMPLATE):
            try:
                prs = Presentation(config.PPTX_GENERATOR_DEFAULT_TEMPLATE)
                logger.info(f"テンプレート '{config.PPTX_GENERATOR_DEFAULT_TEMPLATE}' を読み込みました。")
            except Exception as e_template:
                logger.error(f"テンプレートの読み込みに失敗: {e_template}。空のプレゼンテーションで開始します。")
                prs = Presentation()
        else:
            prs = Presentation()

        prs.slide_width = PptxInches(10)
        prs.slide_height = PptxInches(5.625)

        target_layout_name = "Layout_11_Blank_With_Footers"
        export_layout = None
        if prs.slide_layouts:
            for layout in prs.slide_layouts:
                if hasattr(layout, 'name') and layout.name == target_layout_name:
                    export_layout = layout
                    logger.info(f"指定されたレイアウト '{target_layout_name}' を見つけました。")
                    break
        
        if not export_layout:
            logger.warning(f"レイアウト '{target_layout_name}' が見つかりません。デフォルトの空白レイアウト(インデックス6)にフォールバックします。")
            if len(prs.slide_layouts) > 6:
                export_layout = prs.slide_layouts[6]
            elif prs.slide_layouts:
                export_layout = prs.slide_layouts[-1]
            else:
                return jsonify({"error": "PPTX生成エラー: テンプレートに利用可能なレイアウトがありません。"}), 500

        for item in storyboard_data:
            slide = prs.slides.add_slide(export_layout)

            if item.get('image_data_url'):
                try:
                    header, encoded = item['image_data_url'].split(",", 1)
                    image_bytes = base64.b64decode(encoded)
                    image_stream = io.BytesIO(image_bytes)
                    
                    # ▼▼▼【ここからが修正箇所です (1/2)】▼▼▼
                    # 画像のY座標(top)を下にずらし、その分高さを調整
                    img_left = PptxInches(0.5)
                    img_top = PptxInches(1.0)  # 0.5 -> 1.0 に変更
                    img_height = PptxInches(4.125) # 4.625 -> 4.125 に変更
                    # ▲▲▲【修正はここまでです (1/2)】▲▲▲

                    with Image.open(image_stream) as img:
                        aspect = img.width / img.height if img.height > 0 else 1
                        img_width = img_height * aspect
                    
                    image_stream.seek(0)
                    slide.shapes.add_picture(image_stream, img_left, img_top, height=img_height, width=img_width)
                except Exception as e_img:
                    logger.error(f"ストーリーボードの画像追加に失敗: {e_img}")

            if item.get('text'):
                # ▼▼▼【ここからが修正箇所です (2/2)】▼▼▼
                # テキストボックスのY座標(top)も画像に合わせて下にずらし、高さを調整
                txt_left = PptxInches(5.5)
                txt_top = PptxInches(1.0) # 0.5 -> 1.0 に変更
                txt_width = PptxInches(4)
                txt_height = PptxInches(4.125) # 4.625 -> 4.125 に変更
                # ▲▲▲【修正はここまでです (2/2)】▲▲▲
                
                txBox = slide.shapes.add_textbox(txt_left, txt_top, txt_width, txt_height)
                tf = txBox.text_frame
                tf.word_wrap = True
                
                p = tf.add_paragraph()
                p.text = item['text']
                p.font.size = PptxPt(14)

        pptx_stream = io.BytesIO()
        prs.save(pptx_stream)
        pptx_stream.seek(0)
        
        return send_file(
            pptx_stream,
            mimetype='application/vnd.openxmlformats-officedocument.presentationml.presentation',
            as_attachment=True,
            download_name='storyboard.pptx'
        )

    except Exception as e:
        logger.error(f"ストーリーボードのPPTXエクスポート中にエラー: {e}", exc_info=True)
        return jsonify({"error": "サーバー内部でPPTXファイルの生成に失敗しました。"}), 500


# --- 新API: 複数フレームからGIFを作成 ---
@app.route('/api/image/create_gif', methods=['POST'])
def create_gif_from_frames():
    if not request.json or 'image_data_urls' not in request.json:
        return jsonify({"error": "GIFにする画像データがありません。"}), 400
    
    image_data_urls = request.json['image_data_urls']
    fps = int(request.json.get('fps', 2)) # フレームレート

    if not image_data_urls or len(image_data_urls) < 2:
        return jsonify({"error": "GIFを作成するには2枚以上の画像が必要です。"}), 400

    # 一時ファイルのパスを try/finally ブロックで管理
    temp_gif_path = None
    try:
        image_frames = []
        for data_url in image_data_urls:
            header, encoded = data_url.split(",", 1)
            image_bytes = base64.b64decode(encoded)
            img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
            image_frames.append(np.array(img))
        
        clip = ImageSequenceClip(image_frames, fps=fps)
        
        # 一時ファイルを作成して、そのパスを取得
        with tempfile.NamedTemporaryFile(delete=False, suffix=".gif") as tmp_file:
            temp_gif_path = tmp_file.name

        # 一時ファイルのパスを書き込み先として指定
        clip.write_gif(temp_gif_path, logger=None)
        
        # 書き出された一時ファイルを読み込む
        with open(temp_gif_path, 'rb') as f:
            gif_bytes = f.read()

        gif_base64 = base64.b64encode(gif_bytes).decode('utf-8')
        
        return jsonify({"success": True, "gif_data_url": f"data:image/gif;base64,{gif_base64}"})

    except Exception as e:
        logger.error(f"GIF作成中にエラー: {e}", exc_info=True)
        return jsonify({"error": "サーバー内部でGIFの生成に失敗しました。"}), 500
    finally:
        # 処理の最後に一時ファイルを削除
        if temp_gif_path and os.path.exists(temp_gif_path):
            os.remove(temp_gif_path)


# --- 新API: ストーリーボードの計画を生成 ---
@app.route('/api/storyboard/create_plan', methods=['POST'])
def create_storyboard_plan_endpoint():
    """
    【改訂版】ユーザーの目的とシーン数、参考画像に基づき、AIがストーリーボードの計画を生成する。
    """
    # ▼▼▼【ここからが修正箇所です】▼▼▼
    # JSONボディではなくフォームデータから取得
    if 'objective' not in request.form or 'num_scenes' not in request.form:
        return jsonify({"error": "目的とシーン数が指定されていません。"}), 400

    objective = request.form.get('objective')
    num_scenes = int(request.form.get('num_scenes'))
    reference_files = request.files.getlist('reference_images') # 参考画像を受け取る
    # user_info = get_entra_user_info(request)
    user_info = g.user_info

    prompt = f"""あなたはプロの脚本家であり、アートディレクターです。
ユーザーの「目的」と、提供された「参考画像」を分析し、物語を考え、それを**必ず{num_scenes}個のシーンに分割した**ストーリーボードを作成してください。

**あなたのタスク:**
1.  **Art Style Definition:** 全シーンを通して一貫させるべき「アートスタイル、画風、色使い、キャラクターの特徴」を定義した英語のプロンプトを作成してください。
2.  **Scenes:** 各シーンについて、以下の2つの要素を生成してください。
    - **image_prompt:** そのシーンの独自の状況（誰が、どこで、何をしているか）を描写する具体的な英語プロンプト。
    - **description_text:** そのシーンの状況説明（日本語）。

**【最重要】厳格な出力形式:**
- 応答は、以下のJSONオブジェクトの文字列**のみ**としてください。
```json
{{
  "art_style": "（全シーンに共通して適用する詳細なスタイル定義の英語プロンプト）",
  "plan": [
    {{
      "image_prompt": "（シーン1の具体的な状況描写の英語プロンプト）",
      "description_text": "（シーン1の日本語説明）"
    }},
    ... （合計{num_scenes}個）
  ]
}}
```
- 他の説明やマークダウンは含めないでください。
- 生成するplan配列の要素数は、指定されたシーン数({num_scenes})と完全に一致させてください。

**ユーザーの目的:**
---
{objective}
---
"""
    
    parts_for_gemini = [types.Part.from_text(text=prompt)]
    log_filenames = []
    
    # 参考画像をPartとして追加
    if reference_files:
        parts_for_gemini.append(types.Part.from_text(text="\n--- 以下は全体のスタイルや雰囲気の参考となる画像です ---"))
        for ref_file in reference_files:
            if ref_file and ref_file.filename:
                log_filenames.append(ref_file.filename)
                ref_file.seek(0)
                part = extract_file_content_to_part(ref_file)
                if part:
                    parts_for_gemini.append(part)

    try:
        model_name = os.environ.get("DEFAULT_MODEL_NAME")
        
        plan_str, _ = generate_with_gemini(
            model_name=model_name,
            contents=[types.Content(role="user", parts=parts_for_gemini)],
            max_output_tokens=8192,
            temperature=0.7,
            user_info=user_info,
            log_prompt_text=f"Storyboard Plan Gen: {objective[:50]}...",
            log_filenames=log_filenames, # ログにファイル名を記録
            feature_category="ストーリーボード計画生成",
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not plan_str or plan_str.startswith("[エラー:"):
            raise Exception(f"AIによる計画生成に失敗: {plan_str}")
        
        # JSONパース処理の強化
        cleaned_plan_str = plan_str.strip()
        if cleaned_plan_str.startswith("```json"):
            cleaned_plan_str = cleaned_plan_str[7:]
        if cleaned_plan_str.endswith("```"):
            cleaned_plan_str = cleaned_plan_str[:-3]
        
        parsed_data = json.loads(cleaned_plan_str)

        # レスポンス形式の変更に対応
        return jsonify({
            "success": True, 
            "plan": parsed_data.get("plan", []),
            "art_style": parsed_data.get("art_style", "") # アートスタイルを返す
        })

    except Exception as e:
        logger.error(f"ストーリーボード計画生成中にエラー: {e}", exc_info=True)
        return jsonify({"error": f"サーバー内部でエラーが発生しました: {str(e)}"}), 500


# --- 新API: バナー・アイコン生成 ---
@app.route('/api/image/generate_specialized', methods=['POST'])
def generate_specialized_image_endpoint():
    """
    【改訂版】バナーやアイコン、シナリオ画像など、特定の目的に特化した画像を生成する。
    日本語テキストの生成精度向上に伴い、バナー内の文字も含めてAIに一括生成させる方式に変更。
    バナー生成時は、指定サイズの透明画像をリファレンスとして渡すことでアスペクト比を制御する。
    スライド画像生成（16:9）を追加し、複数枚生成に対応。
    Blob Storage経由の画像URL返却に対応。
    """
    try:
        generation_type = request.form.get('generation_type')
        prompt = request.form.get('prompt', '')
        # user_info = get_entra_user_info(request)
        user_info = g.user_info
        aspect_ratio = request.form.get('aspect_ratio', 'auto')
        num_images = int(request.form.get('num_images', 1))

        if not generation_type or not prompt:
            return jsonify({"error": "生成タイプとプロンプトは必須です。"}), 400

        base_image_file = request.files.get('base_image')
        reference_files = request.files.getlist('reference_images')
        
        parts_for_gemini = []
        log_filenames = []
        final_prompt = ""
        log_feature_category = "特殊画像生成"
        
        if generation_type == 'banner':
            log_feature_category = "バナー生成"
            banner_text_to_add = request.form.get('banner_text', '')
            width_str = request.form.get('width', '1200')
            height_str = request.form.get('height', '630')
            
            try:
                width = int(width_str)
                height = int(height_str)
            except ValueError:
                width = 1200
                height = 630

            text_color = request.form.get('text_color', '')
            text_align = request.form.get('text_align', 'center')
            
            final_prompt = f"""
            SYSTEM COMMAND: Create a professional web banner image.
            
            **OBJECTIVE:** Generate a high-quality banner with integrated text.
            **DIMENSIONS:** The output image MUST strictly follow the aspect ratio of the provided transparent base image ({width}x{height}).
            
            **DESIGN CONTENT:**
            - **Visual Theme:** {prompt}
            - **Text Content:** "{banner_text_to_add}"
            
            **TEXT RENDERING RULES:**
            1.  **Render the text "{banner_text_to_add}" directly into the image.**
            2.  **LANGUAGE:** Japanese (Ensure correct kanji/kana rendering). This is CRITICAL.
            3.  **Style:** The typography should match the visual theme.
            4.  **Placement:** {text_align} alignment.
            5.  **Color:** {text_color if text_color else "Choose a color that contrasts well with the background"}.
            
            **OUTPUT:** A single, finished banner image with the Japanese text seamlessly integrated into the design.
            """

            transparent_canvas = Image.new('RGBA', (width, height), (0, 0, 0, 0))
            bytes_io = io.BytesIO()
            transparent_canvas.save(bytes_io, format='PNG')
            bytes_io.seek(0)
            
            parts_for_gemini.append(types.Part(
                inline_data=types.Blob(mime_type="image/png", data=bytes_io.getvalue())
            ))
            log_filenames.append(f"transparent_canvas_{width}x{height}.png")
            
            aspect_ratio = None 

        elif generation_type == 'icon':
            log_feature_category = "アイコン生成"
            transparent_bg = request.form.get('transparent_bg', 'false').lower() == 'true'
            background_instruction = "with a transparent background (PNG format)" if transparent_bg else "with a simple, solid color background"
            final_prompt = f"""
            Create a high-quality, modern icon.
            The main subject of the icon is: "{prompt}".
            Key requirements:
            - Style: Simple, clean, flat design or vector style.
            - Background: The icon MUST be generated {background_instruction}.
            - Composition: The subject should be centered and clearly recognizable.
            - Format: The output should be a square image.
            """
            aspect_ratio = "1:1"

        elif generation_type == 'scenario':
            log_feature_category = "シナリオ画像生成"
            panel_count = int(request.form.get('panel_count', 4))
            style_key = request.form.get('style', 'business_flat')
            panel_texts_json = request.form.get('panel_texts', '[]')
            try:
                panel_texts = json.loads(panel_texts_json)
            except:
                panel_texts = []

            style_prompts = {
                "business_flat": "Flat vector illustration, corporate Memphis style, clean lines, minimal shading, professional color palette (blue, grey, white).",
                "anime_style": "Anime style illustration, expressive characters, vibrant colors, clean cel-shading, high quality manga aesthetic.",
                "line_art": "Black and white line art, minimalist, sketch style, clear outlines, no fill or subtle monochrome shading.",
                "isometric": "3D Isometric illustration, clean geometric shapes, soft lighting, tech startup aesthetic."
            }
            selected_style_prompt = style_prompts.get(style_key, style_prompts["business_flat"])

            final_prompt = f"""
            SYSTEM COMMAND: Create a {panel_count}-panel sequential illustration (storyboard style).
            
            **OBJECTIVE:** Create a visual narrative explaining a business scenario or product flow.
            **LAYOUT:** A single image divided into {panel_count} distinct panels (grid layout).
            **STYLE:** {selected_style_prompt}
            **GLOBAL THEME:** {prompt}
            
            **PANEL DETAILS:**
            """
            
            for i, text in enumerate(panel_texts):
                panel_num = i + 1
                if text.strip():
                    final_prompt += f"\n- Panel {panel_num}: {text} (Ensure any text within the image is legible JAPANESE)"
                else:
                    final_prompt += f"\n- Panel {panel_num}: Continuation of the story."

            final_prompt += """
            
            **IMPORTANT CONSTRAINTS:**
            1. The output must be a SINGLE image containing all panels.
            2. Ensure visual consistency (characters, colors) across all panels.
            3. **LANGUAGE:** All speech bubbles, captions, and text inside the image MUST be in **JAPANESE**. Do not use English text.
            """
            
            if panel_count == 4:
                aspect_ratio = "1:1" 
            elif panel_count == 6:
                aspect_ratio = "3:2"
            elif panel_count == 8:
                aspect_ratio = "16:9" 
            else:
                aspect_ratio = "auto"

        elif generation_type == 'slide':
            log_feature_category = "スライド画像生成"
            
            # --- 【修正】アスペクト比の動的設定 ---
            # デフォルトは16:9だが、リクエストで4:3が指定されていればそれを使う
            target_ar = aspect_ratio if aspect_ratio and aspect_ratio != 'auto' else '16:9'
            
            ar_text = "16:9 (1600x900 equivalent)"
            if target_ar == '4:3':
                ar_text = "4:3 (1200x900 equivalent)"
            
            final_prompt = f"""
            SYSTEM COMMAND: Create a high-quality, complete presentation slide image.
            
            **OBJECTIVE:** Visualize a complete PowerPoint slide based on the user request.
            **ASPECT RATIO:** {ar_text}.
            **STYLE:** Professional, modern business presentation.
            
            **CONTENT REQUIREMENTS:**
            - The image must look like a **finished slide**, not just a background.
            - Include a **Title**, **Bullet points**, **Charts/Diagrams**, or **Infographics** relevant to the request.
            - Ensure the layout is balanced and professional.
            - **LANGUAGE CONSTRAINT:** ALL text (Titles, bullet points, labels) MUST be in **JAPANESE** unless the user explicitly requests another language. Do not generate English text.
            
            **USER REQUEST:** "{prompt}"
            """
            # Gemini APIに渡すアスペクト比パラメータを更新
            aspect_ratio = target_ar
            # ------------------------------------

        else:
            return jsonify({"error": "未対応の生成タイプです。"}), 400

        if base_image_file:
            final_prompt += "\n\nAn existing base image has been provided. Use its style, color palette, and overall aesthetic as a strong reference for the new generation."
            log_filenames.append(base_image_file.filename)
            base_image_file.seek(0)
            parts_for_gemini.append(extract_file_content_to_part(base_image_file))

        if reference_files:
            final_prompt += "\n\nAdditionally, reference images have been provided for inspiration."
            for ref_file in reference_files:
                if ref_file and ref_file.filename:
                    log_filenames.append(ref_file.filename)
                    ref_file.seek(0)
                    part = extract_file_content_to_part(ref_file)
                    if part: parts_for_gemini.append(part)
        
        parts_for_gemini.insert(0, types.Part.from_text(text=final_prompt))

        def generate_specialized_image_stream():
            try:
                contents = [types.Content(role="user", parts=parts_for_gemini)]

                gen_kwargs = {
                    "model_name": config.IMAGE_GENERATION_MODEL_NAME,
                    "contents": contents,
                    "stream": True,
                    "user_info": user_info,
                    "log_prompt_text": f"Specialized Gen ({generation_type}): {prompt[:50]}...",
                    "log_filenames": log_filenames,
                    "feature_category": log_feature_category,
                    "temperature": 0.8
                }
                
                if aspect_ratio:
                    gen_kwargs["aspect_ratio"] = aspect_ratio

                generated_count = 0
                for i in range(num_images):
                    if num_images > 1:
                        gen_kwargs["log_prompt_text"] = f"Specialized Gen ({generation_type}) [{i+1}/{num_images}]: {prompt[:50]}..."

                    response_iterator = generate_with_gemini(**gen_kwargs)

                    for chunk in response_iterator:
                        if hasattr(chunk, 'image_data_url') and chunk.image_data_url:
                            image_data = chunk.image_data_url
                            
                            # GeminiがBlob URLを返す場合 ("https://...")
                            if image_data.startswith("http"):
                                final_image_url = image_data
                                if "blob.core.windows.net" in image_data and "?" not in image_data:
                                    try:
                                        # URLからBlob名(コンテナ名以降のパス)を抽出
                                        # 例: https://<account>.blob.core.windows.net/<container>/<blob_name>
                                        # 正規表現で <container>/ 以降を取得する
                                        match = re.search(r'https?://[^/]+/[^/]+/(.+)', image_data)
                                        if match:
                                            blob_name = match.group(1)
                                            # SASトークン付きURLを取得
                                            sas_url = get_blob_sas_url(blob_name)
                                            if sas_url:
                                                final_image_url = sas_url
                                                logger.info(f"Azure Blob URLにSASトークンを付与しました: {blob_name}")
                                    except Exception as e_sas:
                                        logger.error(f"SASトークン生成中にエラーが発生しました: {e_sas}")

                                yield f"data: {json.dumps({'type': 'image_url', 'url': final_image_url})}\n\n"
                                generated_count += 1

                            else:
                                try:
                                    if "," in image_data:
                                        header, base64_data_raw = image_data.split(",", 1)
                                    else:
                                        header = "data:image/png;base64"
                                        base64_data_raw = image_data
                                        
                                    mime_type = header.split(';')[0].split(':')[1]
                                    base64_data_processed = base64_data_raw
                                    
                                    # チャンク送信
                                    yield f"data: {json.dumps({'type': 'image_start', 'mime_type': mime_type, 'index': generated_count})}\n\n"
                                    chunk_size = 8192
                                    for k in range(0, len(base64_data_processed), chunk_size):
                                        yield f"data: {json.dumps({'type': 'image_chunk', 'data': base64_data_processed[k:k + chunk_size]})}\n\n"
                                    yield f"data: {json.dumps({'type': 'image_end'})}\n\n"
                                    generated_count += 1
                                except Exception as e_img_proc:
                                    logger.error(f"画像データの処理中にエラー: {e_img_proc}")
                    
                    if hasattr(chunk, 'text') and chunk.text:
                        yield f"data: {json.dumps({'type': 'text', 'content': chunk.text})}\n\n"

            except Exception as e_stream:
                logger.error(f"{log_feature_category}ストリーム中にエラー: {e_stream}", exc_info=True)
                yield f"data: {json.dumps({'type': 'error', 'error': str(e_stream)})}\n\n"
            finally:
                yield f"data: {json.dumps({'type': 'done'})}\n\n"

        return Response(stream_with_context(generate_specialized_image_stream()), mimetype='text/event-stream')
    
    except Exception as e:
        logger.error(f"特殊画像生成リクエスト受付中にエラー: {e}", exc_info=True)
        return jsonify({"error": f"サーバー側でエラーが発生しました: {str(e)}"}), 500


@app.route('/video_analyzer_page')
def video_analyzer_page_route():
    """AI動画パフォーマンス分析ページのHTMLをレンダリングして返す"""
    return render_template('video_analyzer.html') # このHTMLファイルは別途作成が必要です

@app.route('/api/video/analyze_performance_async', methods=['POST'])
def analyze_performance_async_endpoint():
    """
    動画分析の非同期タスクを開始するAPIエンドポイント。
    動画ファイルをAzure Blob Storageに直接アップロードし、バックグラウンドタスクを開始する。
    """
    if 'video_file' not in request.files:
        return jsonify({"error": "動画ファイルがリクエストに含まれていません。"}), 400
    
    video_file = request.files['video_file']
    transcript_file = request.files.get('transcript_file') # 任意
    analysis_scenario = request.form.get('analysis_scenario')
    custom_perspective = request.form.get('custom_perspective', '')
    
    # 動画の長さ情報は必須ではないが、あればトークン見積もりに使用
    video_duration_str = request.form.get('video_duration_seconds', '600') # デフォルト10分

    if not video_file or not video_file.filename:
        return jsonify({"error": "動画ファイルが選択されていません。"}), 400
    if not analysis_scenario:
        return jsonify({"error": "分析シナリオが選択されていません。"}), 400

    try:
        combined_check_text = f"{analysis_scenario}\n{custom_perspective}"
        
        validate_token_limit(
            [video_file], 
            combined_check_text, 
            None, 
            model_name=config.VIDEO_ANALYSIS_MODEL_NAME
        )
        video_file.seek(0)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    user_info = g.user_info
    original_filename = secure_filename(video_file.filename)
    
    # トランスクリプトはテキストなのでメモリ読み込みでOK
    transcript_bytes = None
    original_transcript_filename = None
    if transcript_file and transcript_file.filename:
        transcript_bytes = transcript_file.read()
        original_transcript_filename = secure_filename(transcript_file.filename)

    task_id = str(uuid.uuid4())

    # --- 1. 動画再生用にAzure Blob Storageへ直接アップロード ---
    azure_blob_name = f"temp_video_playback/{uuid.uuid4().hex}_{original_filename}"
    video_sas_url = None
    
    try:
        connect_str = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        container_name = getattr(config, 'AZURE_STORAGE_CONTAINER_NAME', 'tempstorage')
        if not connect_str:
            raise Exception("Azure Storage Connection String is not set.")

        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        container_client = blob_service_client.get_container_client(container_name)
        blob_client = container_client.get_blob_client(azure_blob_name)

        # ポインタを先頭に戻してからストリームアップロード
        video_file.seek(0)
        blob_client.upload_blob(video_file, overwrite=True)
        
        # SAS URL生成
        sas_token = generate_blob_sas(
            account_name=blob_service_client.account_name,
            container_name=container_name,
            blob_name=azure_blob_name,
            account_key=blob_service_client.credential.account_key,
            permission=BlobSasPermissions(read=True),
            expiry=datetime.now(timezone.utc) + timedelta(minutes=180) # 3時間有効
        )
        video_sas_url = f"https://{blob_service_client.account_name}.blob.core.windows.net/{container_name}/{azure_blob_name}?{sas_token}"
        
        logger.info(f"Uploaded video to Azure Blob for playback: {azure_blob_name}")

    except Exception as e:
        logger.error(f"Failed to upload video to Azure Blob: {e}", exc_info=True)
        return jsonify({"error": "動画再生用URLの生成に失敗しました。ストレージ設定を確認してください。"}), 500

    # 2. 非同期タスクを登録
    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "video_performance_analysis",
        "user_info": user_info,
        "original_filename": original_filename,
        "analysis_scenario": analysis_scenario,
        "custom_perspective": custom_perspective,
        "azure_blob_name": azure_blob_name, # クリーンアップ用
        "status_message": "分析タスクを受付ました。",
        "progress_percent": 0
    }
    
    if create_task_in_cosmos(task_initial_data) is None:
         return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500

    # 3. バックグラウンドでワーカー関数を実行
    # video_bytes の代わりに azure_blob_name を渡す
    _submit_with_request_id(
        _run_video_analysis_task,
        task_id,
        azure_blob_name, # ここを変更
        transcript_bytes,
        original_filename,
        analysis_scenario,
        custom_perspective,
        user_info,
        original_transcript_filename,
    )

    logger.info(f"AI動画分析タスク {task_id} を開始しました (シナリオ: {analysis_scenario})。")
    return jsonify({"success": True, "task_id": task_id, "video_sas_url": video_sas_url}), 202

def _run_video_analysis_task(task_id, azure_blob_name, transcript_bytes, original_filename, 
                             analysis_scenario, custom_perspective, user_info, original_transcript_filename=None):
    """
    AI動画パフォーマンス分析を非同期で実行するワーカー関数。
    Azure Blob Storageにある動画をGCSに転送してGeminiで分析する。
    """
    gcs_blob_name = None
    
    def _update_status(message, percent):
        update_task_in_cosmos(task_id, {"status_message": message, "progress_percent": percent})

    try:
        # 1. Azure Blob -> GCS への転送 (AI分析用)
        _update_status("AI分析エンジンに動画を転送中...", 10)
        
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if not gcs_bucket_name:
            raise Exception("サーバー設定エラー: AI分析用のGCSバケットが設定されていません。")
        
        gcs_blob_name = f"temp_video_analysis/{task_id}_{original_filename}"
        
        # Azure Blob Clientの取得
        connect_str = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        container_name = getattr(config, 'AZURE_STORAGE_CONTAINER_NAME', 'tempstorage')
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=azure_blob_name)
        
        with tempfile.NamedTemporaryFile(delete=True) as temp_video_file:
            # Azure -> ローカル一時ファイル
            download_stream = blob_client.download_blob()
            download_stream.readinto(temp_video_file)
            temp_video_file.seek(0)
            
            # ローカル一時ファイル -> GCS
            gcs_uri = _upload_to_gcs(temp_video_file, gcs_blob_name, gcs_bucket_name)
        
        if not gcs_uri:
            raise Exception("AI分析エンジンへの動画転送に失敗しました。")

        # 2. プロンプト構築（トランスクリプト処理を含む）
        _update_status("AIが分析の準備をしています...", 20)
        transcript_text_section = ""
        if transcript_bytes and original_transcript_filename:
            parsed_text = ""
            try:
                if original_transcript_filename.lower().endswith('.vtt'):
                    detected = chardet.detect(transcript_bytes)
                    encoding = detected.get('encoding', 'utf-8')
                    vtt_content = transcript_bytes.decode(encoding)
                    parsed_text = parse_vtt_content(vtt_content)
                elif original_transcript_filename.lower().endswith('.docx'):
                    parsed_text = parse_docx_transcript(transcript_bytes)
                
                if parsed_text:
                    transcript_text_section = f"\n## 会議のトランスクリプト（補助情報）\n{parsed_text}\n"
            except Exception as e:
                logger.warning(f"タスク {task_id}: トランスクリプトファイル '{original_transcript_filename}' の解析に失敗: {e}")
                transcript_text_section = "\n## 会議のトランスクリプト（補助情報）\n(ファイルの解析に失敗しました)\n"

        analysis_perspective = custom_perspective if analysis_scenario == "custom" else config.VIDEO_ANALYSIS_PERSPECTIVES.get(analysis_scenario, "一般的な観点から動画を評価してください。")
        
        # フェーズ1: 構造とスコアの抽出
        prompt_phase1 = config.VIDEO_ANALYSIS_BASE_PROMPT.format(
            analysis_perspective=analysis_perspective,
            transcript_text_section=transcript_text_section,
            output_format_definition=config.VIDEO_ANALYSIS_JSON_OUTPUT_DEFINITION
        )

        # 3. Gemini API呼び出し (フェーズ1: 動画分析)
        _update_status("AIが動画全体を分析し、スコアを算出しています...", 40)
        
        mime_type = _get_video_mime_type(original_filename)
        video_part = types.Part(file_data=types.FileData(file_uri=gcs_uri, mime_type=mime_type))
        prompt_part_p1 = types.Part.from_text(text=prompt_phase1)
        
        analysis_result_str, metadata = generate_with_gemini(
            model_name=config.VIDEO_ANALYSIS_MODEL_NAME,
            contents=[video_part, prompt_part_p1],
            system_instruction=None, 
            max_output_tokens=65535,
            temperature=0.2,
            user_info=user_info,
            log_prompt_text=f"Video Analysis Phase 1: {analysis_scenario}",
            log_filenames=[original_filename],
            feature_category="AI動画パフォーマンス分析(Ph1)",
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not analysis_result_str or analysis_result_str.strip().startswith(("[エラー:", "[APIエラー:")):
            raise Exception(f"AIによる分析(フェーズ1)に失敗しました: {analysis_result_str}")
        
        parsed_result = None
        try:
            json_match = re.search(r'\{.*\}', analysis_result_str, re.DOTALL)
            if not json_match: raise ValueError("JSONが見つかりません")
            parsed_result = json.loads(json_match.group(0))
        except (json.JSONDecodeError, ValueError) as e:
             raise Exception(f"AI応答(フェーズ1)のJSON解析に失敗: {e}")

        # --- フェーズ2: 各話者のスコアに基づいた詳細アドバイス生成 ---
        speakers = parsed_result.get('speakers', [])
        if speakers:
            _update_status("各評価指標に対する詳細アドバイスを生成中...", 70)
            
            total_speakers = len(speakers)
            for idx, speaker in enumerate(speakers):
                speaker_id = speaker.get('speaker_id', f'Speaker {idx+1}')
                scores = speaker.get('performance_scores', {})
                
                if not scores: continue
                
                _update_status(f"詳細アドバイス生成中: {speaker_id} ({idx+1}/{total_speakers})...", 70 + int(20 * (idx / total_speakers)))

                scores_text = json.dumps(scores, ensure_ascii=False, indent=2)
                prompt_phase2 = f"""
あなたは、動画分析結果に基づいて具体的なフィードバックを行うプロのコーチです。
先ほどの動画分析の結果、話者「{speaker_id}」は以下の評価スコア（5点満点）を獲得しました。

**評価スコア:**
{scores_text}

**分析の観点:**
{analysis_perspective}

**あなたのタスク:**
各評価指標について、なぜそのスコアになったのか考えられる「課題」と、スコアを向上させるための具体的な「改善アドバイス」を作成してください。

**出力形式 (JSON):**
以下のキーを持つオブジェクトを生成してください。キー名は入力された評価指標と完全に一致させてください。
```json
{{
  "アドバイス詳細": {{
    "評価指標名A": {{
      "issue": "（想定される課題を1文で）",
      "advice": "（具体的な改善アクションを1〜2文で）"
    }},
    "評価指標名B": {{ ... }}
  }}
}}
```
"""
                try:
                    advice_response_str, _ = generate_with_gemini(
                        model_name=config.DEFAULT_MODEL_NAME,
                        contents=[types.Content(role="user", parts=[types.Part.from_text(text=prompt_phase2)])],
                        max_output_tokens=65535,
                        temperature=0.4,
                        user_info=user_info,
                        feature_category="AI動画パフォーマンス分析(Ph2:アドバイス)",
                        skip_cosmos_log=False,
                        generation_config_override={"response_mime_type": "application/json"}
                    )

                    if advice_response_str and not advice_response_str.startswith("[エラー:"):
                        advice_json = json.loads(advice_response_str)
                        detailed_advice = advice_json.get("アドバイス詳細", {})
                        speaker['detailed_feedback'] = detailed_advice
                        
                except Exception as e_phase2:
                    logger.warning(f"話者 {speaker_id} の詳細アドバイス生成に失敗しましたが、分析は続行します: {e_phase2}")
                    speaker['detailed_feedback'] = {}

        # 4. 結果を処理してDBに保存
        _update_status("分析結果を整形しています...", 95)
        
        if 'transcript' in parsed_result:
            del parsed_result['transcript']

        update_payload = {
            "status": "SUCCESS",
            "result": parsed_result,
            "status_message": "分析が完了しました。",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, update_payload)
        logger.info(f"タスク {task_id}: AI動画分析(2段階)が正常に完了しました。")

    except Exception as e:
        logger.error(f"AI動画分析タスク {task_id} でエラーが発生: {e}", exc_info=True)
        error_payload = {
            "status": "FAILURE",
            "error": str(e),
            "status_message": f"エラーが発生しました: {str(e)[:100]}...",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, error_payload)
    
    finally:
        # 5. 一時ファイルのクリーンアップ
        if gcs_blob_name and gcs_bucket_name:
            _delete_from_gcs(gcs_bucket_name, gcs_blob_name)
        
        update_task_in_cosmos(task_id, {"progress_percent": 100})

@app.route('/api/chat/system_prompts/details', methods=['GET'])
def get_system_prompt_details_endpoint():
    """RAGが有効なSystem Promptに紐づくファイル一覧とRAGモードを取得する"""
    user_info = g.user_info
    user_id = user_info.get("userId")
    prompt_name = request.args.get('prompt_name')
    is_personal_str = request.args.get('isPersonal', 'false').lower()
    
    if not prompt_name:
        return jsonify({"error": "必要な情報が不足しています。"}), 400

    persona_id_for_rag = None
    rag_mode = None 

    if is_personal_str == 'true':
        if not user_id: return jsonify({"error": "個人用プロンプトの取得にはログインが必要です。"}), 401
        container = get_sessions_container()
        if not container:
            return jsonify({"error": "データベースに接続できません。"}), 500
        try:
            # ★修正: スラッシュを置換してIDを生成
            safe_prompt_id_name = prompt_name.replace('/', '__SLASH__')
            prompt_id = f"systemprompt_{user_id}_{safe_prompt_id_name}"
            
            try:
                item = container.read_item(item=prompt_id, partition_key=user_id)
            except cosmos_exceptions.CosmosResourceNotFoundError:
                # 旧IDでのフォールバック検索
                prompt_id_legacy = f"systemprompt_{user_id}_{prompt_name}"
                item = container.read_item(item=prompt_id_legacy, partition_key=user_id)

            if item.get("rag_enabled"):
                persona_id_for_rag = item.get("persona_id_for_rag")
                rag_mode = item.get("rag_mode")
        except cosmos_exceptions.CosmosResourceNotFoundError:
            return jsonify({"files": [], "rag_mode": None})

    else: 
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if not gcs_bucket_name:
            return jsonify({"error": "サーバー設定エラー: GCSバケットが設定されていません。"}), 500
        
        system_prompt_base_folder = get_system_prompt_base_folder()
        file_path = f"{system_prompt_base_folder.rstrip('/')}/{prompt_name}.txt"
        
        _, metadata = _load_gcs_prompt_content(gcs_bucket_name, file_path)
        
        if metadata and metadata.get('rag_enabled', 'false').lower() == 'true':
            persona_id_for_rag = metadata.get('persona_id_for_rag')
            rag_mode = metadata.get('rag_mode')

    if not persona_id_for_rag:
        return jsonify({"files": [], "rag_mode": None})

    try:
        credential = AzureKeyCredential(os.environ["AZURE_SEARCH_ADMIN_KEY"])
        search_client = SearchClient(
            endpoint=os.environ["AZURE_SEARCH_SERVICE_ENDPOINT"], 
            index_name=os.environ["AZURE_SEARCH_INDEX_NAME"], 
            credential=credential
        )
        results = search_client.search(
            search_text="*", 
            filter=f"persona_id eq '{persona_id_for_rag}'",
            facets=["original_filename,count:1000"]
        )
        
        facets = results.get_facets()
        filenames = []
        if facets and "original_filename" in facets:
            filenames = sorted([f["value"] for f in facets["original_filename"]])
        
        return jsonify({"files": filenames, "rag_mode": rag_mode})

    except Exception as e:
        logger.error(f"Azure AI Searchからのファイルリスト取得に失敗: {e}", exc_info=True)
        return jsonify({"error": "ナレッジベースからのファイルリストの取得に失敗しました。"}), 500

@app.route('/api/chat/system_prompts/delete_rag_file', methods=['POST'])
def delete_rag_file_endpoint():
    """個人用System Promptのナレッジベースから特定のファイルを削除する"""
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    user_id = user_info.get("userId")
    if not user_id:
        return jsonify({"error": "認証されていません。"}), 401
    
    data = request.get_json()
    prompt_name = data.get('prompt_name')
    filename_to_delete = data.get('filename')
    
    if not prompt_name or not filename_to_delete:
        return jsonify({"error": "プロンプト名とファイル名が必要です。"}), 400
        
    sessions_container = get_sessions_container()
    if not sessions_container:
        return jsonify({"error": "データベースが利用できません。"}), 500

    try:
        # persona_idを取得
        prompt_id = f"systemprompt_{user_id}_{prompt_name}"
        item = sessions_container.read_item(item=prompt_id, partition_key=user_id)
        
        if not item.get("rag_enabled") or not item.get("persona_id_for_rag"):
             return jsonify({"error": "このSystem PromptはRAGが有効ではありません。"}), 400
             
        persona_id_for_rag = item.get("persona_id_for_rag")

        # 1. Azure AI Searchからドキュメントを削除
        success = delete_documents_by_filename(persona_id_for_rag, filename_to_delete)
        
        if success:
            # 2. Blob Storageからファイルを削除
            _delete_rag_blobs(persona_id_for_rag, filename_to_delete)
            
            return jsonify({"success": True, "message": f"ファイル「{filename_to_delete}」をナレッジベースから削除しました。"})
        else:
            return jsonify({"error": "Azure AI Searchからのファイル削除に失敗しました。"}), 500

    except cosmos_exceptions.CosmosResourceNotFoundError:
        return jsonify({"error": "指定されたSystem Promptが見つかりません。"}), 404
    except Exception as e:
        logger.error(f"個人用RAGファイル'{filename_to_delete}'の削除中にエラー: {e}", exc_info=True)
        return jsonify({"error": "ファイルの削除中にエラーが発生しました。"}), 500


