@app.route('/api/slides/analyze_pdf_for_video', methods=['POST'])
def analyze_pdf_for_video_endpoint():
    """PDFから各スライドの画像を抽出し、スピーカーノートを生成・翻訳する"""
    if 'pdf_file' not in request.files:
        return jsonify({"error": "PDFファイルがありません。"}), 400
    
    pdf_file = request.files['pdf_file']
    languages_str = request.form.get('languages', 'ja')
    languages = [lang.strip() for lang in languages_str.split(',') if lang.strip()]
    # user_info = get_entra_user_info(request)
    user_info = g.user_info

    try:
        pdf_bytes = pdf_file.read()
        pdf_doc = fitz.open(stream=pdf_bytes, filetype="pdf")
        
        multilingual_slides = []
        previous_notes_ja = "" # 直前のスライドの日本語ナレーションを保持する変数
        
        for page_num in range(len(pdf_doc)):
            page = pdf_doc.load_page(page_num)
            
            # 1. 画像の抽出とBase64化
            pix = page.get_pixmap(dpi=150)
            img_bytes = pix.tobytes("png")

            try:
                with Image.open(io.BytesIO(img_bytes)) as original_img:
                    sanitized_img = Image.new("RGBA", original_img.size)
                    sanitized_img.paste(original_img)
                    
                    output_buffer = io.BytesIO()
                    sanitized_img.save(output_buffer, format="PNG")
                    img_bytes = output_buffer.getvalue()
                    logger.info(f"Pillowライブラリを使って、PDFの {page_num + 1} ページ目の画像をディープノーマライズしました。")
            except Exception as e_sanitize:
                logger.warning(f"PDFの {page_num + 1} ページ目の画像のディープノーマライズに失敗しました: {e_sanitize}。元の画像データを使用します。")

            img_base64 = f"data:image/png;base64,{base64.b64encode(img_bytes).decode('utf-8')}"
            
            # 2. AIによるノート生成 (プロンプトを動的に構築)
            previous_notes_context = ""
            if page_num > 0 and previous_notes_ja:
                # 2ページ目以降、かつ前のナレーションが存在する場合、文脈としてプロンプトに追加
                previous_notes_context = f"""
**【重要】直前のスライドのナレーション内容:**
---
{previous_notes_ja}
---
上記のナレーションの続きとして、話の流れが自然に繋がるように、今回のスライドのナレーションを生成してください。
"""

            prompt = f"""あなたはプロのプレゼンテーションコーチです。
提供されたスライド画像を分析し、発表者が聴衆の前で話すべき、高品質なスピーカーノート（ナレーション原稿）を生成してください。
{previous_notes_context}
**厳格な指示:**
1.  **構成:** 生成するノートは、必ず以下の4つの要素で構成してください。
    - **【導入】:** 聴衆の関心を引くための、簡潔な問いかけや短いエピソード。
    - **【スライド内容の説明】:** スライドに表示されている図やテキストが何を意味しているのかを具体的に説明。
    - **【補足・背景】:** スライドには書かれていないが、聴衆の理解を深めるために重要な背景情報、データ、または考察。
    - **【次のスライドへの繋ぎ】:** 次のスライドの内容を簡潔に予告し、スムーズに話を繋げる一文。
2.  **文体:** 自然で聞き取りやすい「話し言葉」を使用してください。
3.  **長さ:** 全体で150〜250字程度の十分な長さを持たせてください。
4.  **出力形式:** 生成したナレーション原稿のテキストのみを出力し、他の説明や前置きは一切含めないでください。

**例:**
さて、皆様は普段の業務で「非効率だ」と感じる瞬間はありませんでしょうか？
こちらのグラフは、過去3年間の部署別残業時間の推移を示したものです。ご覧の通り、特に営業部門の残業時間が一貫して高い水準にあることが分かります。
この背景には、近年の顧客対応プロセスの複雑化があり、特に見積作成と承認フローに多くの時間が割かれているという現場の声が挙がっています。
では、具体的にどのような対策が考えられるのか、次のスライドで見ていきましょう。
"""

            image_part = types.Part(inline_data=types.Blob(mime_type="image/png", data=img_bytes))
            prompt_part = types.Part.from_text(text=prompt)
            gemini_contents = [types.Content(role="user", parts=[image_part, prompt_part])]

            notes_ja, _ = generate_with_gemini(
                model_name=config.DOC_GEN_MODEL_NAME,
                max_output_tokens=65535,
                contents=gemini_contents,
                user_info=user_info,
                feature_category="スライド動画ノート生成"
            )
            
            if not notes_ja or notes_ja.startswith(("[エラー:", "[APIエラー:")):
                notes_ja = f"（スライド {page_num + 1} のノート生成に失敗しました）"
            else:
                # 次のループのために、生成されたナレーションを保存
                notes_ja = notes_ja.strip()
            
            previous_notes_ja = notes_ja

            slide_data = {
                "id": f"slide-{page_num}-{uuid.uuid4().hex}",
                "ja": {
                    "image_base64": img_base64,
                    "notes": notes_ja
                }
            }

            # 3. 各言語への翻訳
            for lang in languages:
                if lang != 'ja':
                    translated_notes = translate_text_content(notes_ja, lang, user_info)
                    slide_data[lang] = {
                        "image_base64": img_base64,
                        "notes": translated_notes or f"[{lang.upper()}] {notes_ja}"
                    }
            
            multilingual_slides.append(slide_data)
            
        return jsonify({"multilingual_slides": multilingual_slides})

    except Exception as e:
        logger.error(f"PDF解析中にエラー: {e}", exc_info=True)
        return jsonify({"error": f"サーバー側でPDFの解析に失敗しました: {str(e)}"}), 500


@app.route('/api/slides/export_video_async', methods=['POST'])
def export_video_from_slides_async():
    """スライドデータから動画生成タスクを非同期で開始する"""
    if not request.json or 'slides' not in request.json:
        return jsonify({"error": "スライドデータがありません。"}), 400
        
    slides_data = request.json['slides']
    language = request.json.get('language', 'ja')
    selected_voice = request.json.get('selected_voice')
    add_telops = request.json.get('add_telops', False)
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    task_id = str(uuid.uuid4())

    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "slide_video_export",
        "user_info": user_info,
        "original_filename": "PDF_Slide_Video", # ファイル名がないため固定の文字列
        "status_message": "動画生成タスクを受付ました。",
        "progress_percent": 0
    }
    create_task_in_cosmos(task_initial_data)

    _submit_with_request_id(
        _run_slide_video_export_task,
        task_id,
        slides_data,
        user_info,
        language,
        selected_voice,
        add_telops,
    )
    
    return jsonify({"success": True, "task_id": task_id}), 202

def _prepare_slide_assets_from_base64(slide_data: dict, index: int, temp_dir: str, language: str, task_id: str, voice_name: str | None) -> dict | None:
    """
    【改訂版・堅牢化】
    Base64画像とノートからスライド素材を準備し、Blob Storageにアップロードする。
    音声処理の堅牢性を向上させ、各ステップでの失敗を適切に処理し、詳細なログを出力する。
    各スライドの表示時間に2秒の余白を追加する。
    """
    try:
        # --- 1. Base64画像データをデコードし、16:9のキャンバスに配置してPNGとしてBlobにアップロード ---
        header, encoded = slide_data['image_base64'].split(",", 1)
        png_bytes_from_pdf = base64.b64decode(encoded)
        
        with Image.open(io.BytesIO(png_bytes_from_pdf)) as original_img:
            canvas_width, canvas_height = 1600, 900
            canvas = Image.new("RGB", (canvas_width, canvas_height), "black")
            original_img.thumbnail((canvas_width, canvas_height), Image.Resampling.LANCZOS)
            paste_x = (canvas_width - original_img.width) // 2
            paste_y = (canvas_height - original_img.height) // 2
            canvas.paste(original_img, (paste_x, paste_y))
            output_buffer = io.BytesIO()
            canvas.save(output_buffer, format="PNG")
            image_bytes_for_upload = output_buffer.getvalue()
        
        image_blob_name = f"{task_id}/slide_{index + 1}.png"
        if not upload_bytes_to_blob(image_bytes_for_upload, image_blob_name):
            logger.error(f"タスク {task_id}: スライド {index + 1} の画像blob '{image_blob_name}' のアップロードに失敗。")
            return None

        # --- 2. 音声合成とデュレーション決定、Blobへのアップロード ---
        pause_duration = 2.0
        content_duration = 5.0  # 音声がない場合のデフォルト表示時間
        audio_blob_name = None
        notes_text = slide_data.get('notes')
        
        # ▼▼▼【ここからが修正箇所】▼▼▼
        # "All-or-Nothing"ロジック：ノートが存在する場合、音声処理を試みる
        if notes_text and notes_text.strip():
            # 処理ブロックを `while True` で囲み、失敗時に `break` することでネストを回避
            while True: 
                # ステップ1: 音声合成
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声合成を開始 (テキスト長: {len(notes_text)}文字)。")
                audio_bytes = generate_speech_for_pptx(notes_text, language_code=language, voice_name=voice_name)
                if not audio_bytes:
                    logger.warning(f"タスク {task_id}: スライド {index + 1} の音声合成に失敗。このスライドは音声なしになります。")
                    break # 失敗したため処理ブロックを抜ける

                # ステップ2: 音声長の取得
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声合成成功。音声長を取得します。")
                audio_duration = _get_audio_duration_seconds(audio_bytes, temp_dir)
                if not audio_duration:
                    logger.warning(f"タスク {task_id}: スライド {index + 1} の音声長取得に失敗。このスライドは音声なしになります。")
                    break # 失敗したため処理ブロックを抜ける

                # ステップ3: Blob Storageへのアップロード
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声長は {audio_duration:.2f}秒です。アップロードします。")
                temp_audio_blob_name = f"{task_id}/narration_{index + 1}.mp3"
                if not upload_bytes_to_blob(audio_bytes, temp_audio_blob_name):
                    logger.warning(f"タスク {task_id}: スライド {index + 1} の音声blobアップロード失敗。このスライドは音声なしになります。")
                    break # 失敗したため処理ブロックを抜ける

                # 全てのステップが成功した場合のみ、結果を反映
                logger.info(f"タスク {task_id}: スライド {index + 1} の音声関連処理がすべて成功しました。")
                audio_blob_name = temp_audio_blob_name
                content_duration = audio_duration
                break # 成功したので処理ブロックを抜ける
        # ▲▲▲【修正はここまでです】▲▲▲
        
        # 最終的なスライドの表示時間は「コンテンツの時間 + 間」
        total_duration = content_duration + pause_duration
        
        return {
            "png_blob_name": image_blob_name,
            "audio_blob_name": audio_blob_name,
            "duration": total_duration,
            "content_duration": content_duration
        }
    except Exception as e:
        logger.error(f"タスク {task_id}: スライド {index + 1} のアセット準備中に予期せぬエラー: {e}", exc_info=True)
        return None

def _run_slide_video_export_task(task_id: str, slides_data: list, user_info: dict, language: str, voice_name: str | None, add_telops: bool):
    """
    【改訂版・テロップ自動改行＆サイズ調整対応】
    画像ベースのスライドから動画を生成する非同期ワーカー。
    ffmpegのコマンドに相対パスを使用することで、Windowsでのファイルパス問題を完全に解決する。
    テロップが有効な場合、ノートを文単位に分割し、長すぎる文は自動で改行する。
    全体のフォントサイズはconfig.pyから調整可能にする。
    """
    temp_dir = tempfile.mkdtemp(prefix=f"export_{task_id}_")
    original_cwd = os.getcwd() # 元のカレントディレクトリを保存
    clips_to_close = []
    blobs_to_delete = []
    
    def _update_status(message, percent, status="PROCESSING"):
        update_payload = { "status": status, "status_message": message, "progress_percent": percent }
        update_task_in_cosmos(task_id, update_payload)

    try:
        _update_status("動画素材の準備を開始...", 5)
        
        prepared_assets = [None] * len(slides_data)
        max_workers = min(4, (os.cpu_count() or 1) + 2)
        total_slides = len(slides_data)
        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            future_to_index = {
                executor.submit(_prepare_slide_assets_from_base64, slide, i, temp_dir, language, task_id, voice_name): i
                for i, slide in enumerate(slides_data)
            }
            processed_count = 0
            for future in as_completed(future_to_index):
                index = future_to_index[future]
                try:
                    asset_data = future.result()
                    if asset_data:
                        prepared_assets[index] = asset_data
                        if asset_data.get("png_blob_name"): blobs_to_delete.append(asset_data["png_blob_name"])
                        if asset_data.get("audio_blob_name"): blobs_to_delete.append(asset_data["audio_blob_name"])
                except Exception as e:
                    logger.error(f"タスク {task_id}: スライド {index + 1} のアセット準備タスクで例外が発生: {e}", exc_info=True)
                processed_count += 1
                progress = 5 + int(35 * (processed_count / total_slides))
                _update_status(f"スライド素材を準備中 ({processed_count}/{total_slides})...", progress)

        _update_status("動画クリップを作成中...", 40)
        
        video_clips = []
        for i, asset in enumerate(prepared_assets):
            if not asset or not asset.get("png_blob_name"):
                logger.warning(f"タスク {task_id}: スライド {i + 1} の素材準備に失敗したため、このスライドは動画から除外されます。")
                continue
            clip = _create_moviepy_clip(asset, clips_to_close, temp_dir, task_id)
            if clip:
                if FadeIn and FadeOut:
                    video_clips.append(clip.with_effects([FadeIn(0.5), FadeOut(0.5)]))
                else:
                    video_clips.append(clip)
        
        if not video_clips:
            raise ValueError("有効な動画クリップを1つも生成できませんでした。")

        final_clip = concatenate_videoclips(video_clips, method="compose")
        final_clip.fps = 24
        clips_to_close.append(final_clip)
        
        base_video_filename = f"base_video_{task_id}.mp4"
        base_video_path = os.path.join(temp_dir, base_video_filename)
        output_filename = f"slide_video_{task_id}.mp4"
        final_output_path = os.path.join(temp_dir, output_filename)

        _update_status("動画をエンコード中...", 80)
        progress_logger = FFMPEGProgressLogger(task_id)
        final_clip.write_videofile(
            base_video_path, codec='libx264', audio_codec='aac', preset='veryfast',
            threads=os.cpu_count() or 2, logger=progress_logger
        )

        if add_telops:
            _update_status("テロップ（字幕）を動画に焼き付け中...", 90)

            # ▼▼▼【ここからが修正箇所です (1/2)】▼▼▼
            def _create_srt_from_slide_data(assets, slides):
                """
                スピーカーノートを文単位に分割し、長すぎる文は自動で改行してSRTを生成する。
                """
                srt_parts = []
                current_time = 0.0
                srt_index = 1
                
                # 1行あたりの最大文字数（この値を調整することで改行の頻度を変更できます）
                MAX_CHARS_PER_LINE = 25 

                def format_srt_time(seconds):
                    ms = int((seconds - int(seconds)) * 1000)
                    s = int(seconds); m, s = divmod(s, 60); h, m = divmod(m, 60)
                    return f"{h:02d}:{m:02d}:{s:02d},{ms:03d}"

                for i, asset_data in enumerate(assets):
                    if asset_data and i < len(slides):
                        notes_text = slides[i].get('notes', '').strip()
                        
                        if notes_text:
                            content_duration = asset_data.get('content_duration', asset_data['duration'] - 2.0)
                            sentences = re.split(r'(?<=[。．.！？?!])\s*', notes_text)
                            sentences = [s.strip() for s in sentences if s.strip()]
                            if not sentences: sentences = [notes_text]
                            total_chars = sum(len(s) for s in sentences)
                            
                            if total_chars > 0:
                                current_slide_start_time = current_time
                                for sentence in sentences:
                                    # 長すぎる文を自動で改行
                                    wrapped_lines = textwrap.wrap(sentence, width=MAX_CHARS_PER_LINE)
                                    final_sentence_text = "\n".join(wrapped_lines)

                                    sentence_chars = len(sentence)
                                    sentence_duration = (sentence_chars / total_chars) * content_duration if total_chars > 0 else content_duration
                                    start_time = current_slide_start_time
                                    end_time = start_time + sentence_duration
                                    
                                    srt_parts.append(f"{srt_index}\n{format_srt_time(start_time)} --> {format_srt_time(end_time)}\n{final_sentence_text}\n")
                                    
                                    current_slide_start_time = end_time
                                    srt_index += 1
                        
                        current_time += asset_data['duration']
                        
                return "\n".join(srt_parts)
            
            srt_content = _create_srt_from_slide_data(prepared_assets, slides_data)
            srt_filename = "subtitles.srt"
            srt_path = os.path.join(temp_dir, srt_filename)
            with open(srt_path, "w", encoding='utf-8') as f: f.write(srt_content)

            ffmpeg_path = config.FFMPEG_PATH or shutil.which('ffmpeg')
            if not ffmpeg_path or not os.path.exists(ffmpeg_path):
                raise FileNotFoundError(f"FFmpeg実行可能ファイルが見つかりません。設定パス: {config.FFMPEG_PATH}")
            
            video_height = final_clip.h
            
            # config.pyからフォントサイズの除数を読み込む（なければデフォルト値120）
            font_size_ratio_divisor = getattr(config, 'VIDEO_TELOP_FONT_SIZE_DIVISOR', 120)
            
            calculated_font_size = int(video_height / font_size_ratio_divisor)
            final_font_size = max(14, min(calculated_font_size, 120))
            logger.info(f"解像度に合わせてフォントサイズを {final_font_size} に調整しました。 (基準: 高さ / {font_size_ratio_divisor})")
            
            subtitle_style = f"FontName=MS Gothic,FontSize={final_font_size},PrimaryColour=&HFFFFFF,BorderStyle=1,OutlineColour=&H000000,Outline=1.5,Shadow=0.8,Alignment=2,MarginV=25"
            # ▲▲▲【修正はここまでです (1/2)】▲▲▲
            
            video_filter_string = f"subtitles={srt_filename}:force_style='{subtitle_style}':fontsdir=."

            font_filename_in_temp = os.path.basename(config.FONT_PATH)
            font_path_in_temp = os.path.join(temp_dir, font_filename_in_temp)
            shutil.copy(config.FONT_PATH, font_path_in_temp)

            command = [
                ffmpeg_path, '-i', base_video_filename, '-vf', video_filter_string,
                '-c:v', 'libx264', '-preset', 'fast', '-crf', '23',
                '-c:a', 'copy', '-y', output_filename
            ]
            
            logger.info(f"タスク {task_id}: FFmpeg字幕焼き付けコマンドを実行 (CWD: {temp_dir}): {' '.join(command)}")
            os.chdir(temp_dir)
            
            subprocess.run(
                command, capture_output=True, text=True, check=True, 
                encoding='utf-8', errors='ignore', shell=(platform.system() == "Windows")
            )
            
        else:
            shutil.move(base_video_path, final_output_path)

        _update_status("成果物をアップロード中...", 98)
        
        video_blob_name = f"results/{output_filename}"
        with open(final_output_path, "rb") as f_video:
            upload_bytes_to_blob(f_video.read(), video_blob_name)

        _update_status("動画の生成が完了しました。", 100, "SUCCESS")
        
        success_payload = {
            "status": "SUCCESS",
            "result": { "files_data": { "video": { "blob_name": video_blob_name, "filename": output_filename, "mimetype": "video/mp4" } } }
        }
        update_task_in_cosmos(task_id, success_payload)

        logger.info(f"タスク {task_id}: 動画生成成功。Blob: {video_blob_name}")

    except Exception as e:
        error_msg = f"動画生成タスク中にエラー: {e}"
        if isinstance(e, subprocess.CalledProcessError):
            error_msg += f"\nFFmpeg Log: {e.stderr[:1000]}"
        logger.error(f"タスク {task_id}: {error_msg}", exc_info=True)
        failure_payload = {
            "status": "FAILURE", "error": error_msg,
            "status_message": f"エラーが発生しました: {str(e)[:100]}...",
            "progress_percent": 100
        }
        update_task_in_cosmos(task_id, failure_payload)
        
    finally:
        os.chdir(original_cwd)
        for clip in clips_to_close:
            try:
                if hasattr(clip, 'close') and callable(clip.close):
                    clip.close()
            except Exception: pass
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)
        for blob_name in blobs_to_delete:
            delete_blob(blob_name)


@app.route('/api/slides/get_video_download_url/<task_id>', methods=['GET'])
def get_slide_video_download_url(task_id):
    """
    完了したスライド動画生成タスクの成果物（動画ファイル）への
    署名付きURLをJSON形式で返す、新しい専用エンドポイント。
    """
    task_info = get_task_from_cosmos(task_id)
    if not task_info or task_info.get("status") != "SUCCESS":
        return jsonify({"success": False, "error": "タスクが完了していないか、存在しません。"}), 404

    video_info = task_info.get("result", {}).get("files_data", {}).get("video", {})
    video_blob_name = video_info.get("blob_name")

    if not video_blob_name:
        return jsonify({"success": False, "error": "生成された動画ファイルの情報が見つかりません。"}), 404

    # 10分間有効なダウンロード用URLを生成
    download_url = get_blob_sas_url(video_blob_name, expiration_minutes=10)

    if download_url:
        return jsonify({"success": True, "download_url": download_url})
    else:
        return jsonify({"success": False, "error": "ダウンロードリンクの生成に失敗しました。"}), 500


def _chunk_list(data, chunk_size):
    """リストを指定サイズごとに分割するジェネレータ"""
    for i in range(0, len(data), chunk_size):
        yield data[i:i + chunk_size]

def _generate_slide_batch_svg(objective, slides_outline_batch, ref_parts, img_parts, img_placeholder_map, user_info, design_concept_key, master_design_svg, svg_width=1600, svg_height=900) -> list | None:
    """
    【バッチ処理版・サイズ指定対応】
    """
    
    # デザインコンセプト情報の取得
    design_concept_info = config.DESIGN_CONCEPTS.get(design_concept_key, config.DESIGN_CONCEPTS["auto"])
    design_concept_name_for_prompt = design_concept_info["name"]

    # バッチ内のスライド情報をプロンプト用に整形
    slides_req_text = ""
    for i, slide in enumerate(slides_outline_batch):
        # スライド番号はバッチ内での相対番号ではなく、ユニークな識別子としてタイトルを使用
        slides_req_text += f"""
---
【スライド ID: {i}】
- タイトル: {slide.get("title", "無題")}
- コンテンツ（要素）:
{json.dumps(slide.get("content", []), ensure_ascii=False, indent=2)}
---
"""

    # プロンプトの構築
    prompt = f"""
あなたは、与えられた構成案に基づいて、プレゼンテーションスライドをデザインする専門家です。
今回は、以下の「全体の目的」と「デザインマスター（表紙）」に基づき、**指定された複数枚のスライド（{len(slides_outline_batch)}枚）を一括で**デザイン・生成してください。

**プレゼンテーション全体の目的:**
{objective}

**【最重要】デザインコンセプトとマスターデザイン:**
**コンセプト名:** `{design_concept_name_for_prompt}`
以下のSVGコードは、このプレゼンテーションの「表紙（タイトルスライド）」として既に生成されたものです。
**この表紙と全く同じカラーパレット、フォント、図形スタイル、背景デザイン、雰囲気**を使用して、プレゼンテーション全体で完璧な統一感を維持したスライドを作成してください。

--- デザインマスター (表紙SVG) ---
```xml
{master_design_svg}
```
---

**【今回生成するスライド群】:**
{slides_req_text}

**【あなたのタスク】:**
上記の各スライド（ID: 0 〜 {len(slides_outline_batch)-1}）について、以下の処理を行ってください。
1.  **レイアウトの最適化:** 各スライドの内容（箇条書き、プロセス、比較など）に最も適したレイアウトを考案してください。単なる箇条書きだけでなく、図解やボックス配置などを積極的に使用して視覚的に表現してください。
2.  **一貫性の維持:** 前述の「デザインマスター」のスタイルを厳守してください。
3.  **SVGとノートの生成:** 各スライドのSVGコードと、ナレーション原稿（スピーカーノート）を生成してください。

"""

    if img_placeholder_map:
        prompt += f"""
**【重要】添付画像の利用:**
以下の画像プレースホルダーを利用して、スライド内に画像を配置してください。
**利用可能な画像プレースホルダー:** {', '.join(img_placeholder_map.keys())}
"""

    prompt += """
**出力形式 (厳格なJSON配列):**
必ず以下の構造を持つ **JSON配列** のみを出力してください。Markdownのコードブロック(```json)で囲んでください。
配列の順番は、入力されたスライドの順番（ID順）と一致させてください。

```json
[
  {
    "title": "1枚目のスライドタイトル",
    "svg": "<svg ...>...</svg>",
    "notes": "1枚目のスピーカーノート..."
  },
  {
    "title": "2枚目のスライドタイトル",
    "svg": "<svg ...>...</svg>",
    "notes": "2枚目のスピーカーノート..."
  }
  ...
]
```
"""
    
    # API入力用のパーツ作成
    parts_for_api = [types.Part.from_text(text=prompt)]
    if ref_parts:
        parts_for_api.append(types.Part.from_text(text="\n--- 参考資料 ---\n"))
        parts_for_api.extend(ref_parts)
    if img_parts:
        parts_for_api.append(types.Part.from_text(text="\n--- 参考画像 ---\n"))
        parts_for_api.extend(img_parts)

    contents = [types.Content(role="user", parts=parts_for_api)]
    
    # サイズ引数を渡す
    base_system_instruction = _get_detailed_pptx_system_instruction(width=svg_width, height=svg_height)
    system_instruction = base_system_instruction + "\n\n**追加指示:** 今回は複数のスライドを一括で生成するタスクです。出力形式は必ず**スライドオブジェクトのJSON配列**としてください。"
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))

    # 自己修正ループのための設定
    max_retries = 2
    for attempt in range(max_retries + 1):
        try:
            # Gemini API呼び出し
            # SVGを含む複数枚のJSONは長くなるため、max_output_tokensを大きめに確保する
            # ※使用モデルがGemini 1.5 Pro/Flashであることを前提としています
            response_text, _ = generate_with_gemini(
                model_name=os.environ.get("PPTX_GEN_MODEL_NAME"),
                contents=contents,
                system_instruction=system_instruction + glossary_instruction,
                max_output_tokens=65535, # 大きめのトークン数を指定
                temperature=0.6,
                user_info=user_info,
                log_prompt_text=f"PPTX Batch Gen (Attempt {attempt+1}): {len(slides_outline_batch)} slides",
                feature_category="PPTX詳細生成(バッチ)",
                skip_cosmos_log=False,
                generation_config_override={"response_mime_type": "application/json"}
            )

            if not response_text or response_text.startswith(("[エラー:", "[APIエラー:")):
                raise ValueError(f"AI API returned an error: {response_text}")

            # JSON抽出
            json_match = re.search(r"```json\s*([\s\S]+?)\s*```", response_text)
            if json_match:
                json_to_parse = json_match.group(1)
            else:
                # JSONブロックがない場合、配列の開始と終了を探す
                start_index = response_text.find('[')
                end_index = response_text.rfind(']')
                if start_index != -1 and end_index > start_index:
                    json_to_parse = response_text[start_index : end_index + 1]
                else:
                    json_to_parse = response_text.strip()

            parsed_json_list = json.loads(json_to_parse)

            if not isinstance(parsed_json_list, list):
                raise ValueError("AIの応答がJSON配列ではありません。")
            
            if len(parsed_json_list) != len(slides_outline_batch):
                logger.warning(f"要求したスライド数({len(slides_outline_batch)})と生成された数({len(parsed_json_list)})が一致しませんが、処理を続行します。")

            validated_slides = []
            for i, slide_data in enumerate(parsed_json_list):
                if 'svg' not in slide_data or 'notes' not in slide_data:
                    raise ValueError(f"スライド(インデックス {i}) に必要なキー('svg', 'notes')が不足しています。")

                svg_code = slide_data['svg']
                # '&' のサニタイズ処理
                sanitized_svg_code = re.sub(r'&(?!amp;|lt;|gt;|quot;|apos;)', '&amp;', svg_code)
                if svg_code != sanitized_svg_code:
                    slide_data['svg'] = sanitized_svg_code

                # SVG構文チェック
                try:
                    ET.fromstring(slide_data['svg'])
                except ET.ParseError as e_parse_svg:
                    raise ValueError(f"スライド(インデックス {i}) のSVG構文が不正です。Error: {e_parse_svg}")
                
                validated_slides.append(slide_data)

            # すべて成功した場合、結果を返す
            return validated_slides

        except (json.JSONDecodeError, ValueError, Exception) as e:
            logger.warning(f"スライドバッチ生成に失敗 (試行 {attempt + 1}/{max_retries + 1})。エラー: {e}")
            if attempt < max_retries:
                correction_prompt = f"""
                直前のバッチ生成処理で以下のエラーが発生しました。
                エラー内容: {str(e)}
                
                このエラーを修正し、要求された全てのスライドを含む有効なJSON配列のみを再度出力してください。
                各スライドのSVG構文が正しいXMLであることを特に注意してください。
                """
                # 会話履歴に追加してリトライ
                if response_text:
                    contents.append(types.Content(role="model", parts=[types.Part.from_text(text=response_text)]))
                contents.append(types.Content(role="user", parts=[types.Part.from_text(text=correction_prompt)]))
                logger.info(f"バッチ生成の自己修正を要求します...")
            else:
                logger.error(f"スライドバッチ生成が最終的に失敗しました。")
                return None
    
    return None

def _generate_single_slide_svg(objective: str, slide_title: str, slide_content: list, chat_history_text: str, user_info: dict, design_concept_key: str) -> dict | None:
    """
    【デザインコンセプト対応版】プレゼンテーションの全体目的、単一スライドの構成案、会話履歴、デザインコンセプトを基に、
    そのスライドのSVGとノートを生成するヘルパー関数。
    """
    glossary_instruction = _get_formatted_glossary_instruction(user_info.get("userId"))

    design_concept_info = config.DESIGN_CONCEPTS.get(design_concept_key, config.DESIGN_CONCEPTS["auto"])
    design_concept_name_for_prompt = design_concept_info["name"]

    prompt = f"""
あなたは、与えられた構成案に基づいて、プレゼンテーションの単一のスライドをデザインする専門家です。

**プレゼンテーション全体の目的:**
{objective}

**【最重要】デザインコンセプト:**
**`{design_concept_name_for_prompt}`**
このコンセプトに厳密に従い、プレゼンテーション全体で統一感のあるデザインを維持してください。

**これまでの会話の文脈:**
---
{chat_history_text}
---

**このスライドで表現すべき内容:**
- **タイトル:** {slide_title}
- **コンテンツ（箇条書き）:**
{"".join([f"  - {item}\\n" for item in slide_content])}

**あなたのタスク:**
上記の情報を元に、モダンで視覚的に洗練されたSVGスライドと、そのナレーション原稿（スピーカーノート）を生成してください。

**出力形式:**
*   SVGコード (`svg`) とスピーカーノート (`notes`) を含む、単一のJSONオブジェクトを生成してください。
*   応答は、このJSONオブジェクトの文字列のみとし、他の説明やマークダウン、コードブロックの囲み文字は絶対に含めないでください。
"""
    contents = [types.Content(role="user", parts=[types.Part.from_text(text=prompt)])]
    system_instruction = _get_detailed_pptx_system_instruction()

    try:
        response_text, _ = generate_with_gemini(
            model_name=os.environ.get("PPTX_GEN_MODEL_NAME"),
            contents=contents,
            system_instruction=system_instruction + glossary_instruction,
            max_output_tokens=65535,
            temperature=0.6,
            user_info=user_info,
            log_prompt_text=f"PPTX Single Slide Gen: {slide_title}",
            feature_category="PPTX詳細生成(単一スライド)",
            skip_cosmos_log=False,
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not response_text or response_text.startswith(("[エラー:", "[APIエラー:")):
            logger.error(f"単一スライドSVG生成に失敗 (Title: {slide_title}): {response_text}")
            return None

        json_match = re.search(r"```json\s*([\s\S]+?)\s*```", response_text)
        json_to_parse = json_match.group(1) if json_match else response_text.strip()
        
        start_index = json_to_parse.find('{')
        end_index = json_to_parse.rfind('}')
        if start_index != -1 and end_index > start_index:
            json_to_parse = json_to_parse[start_index : end_index + 1]

        parsed_json = json.loads(json_to_parse)

        if 'svg' in parsed_json and 'notes' in parsed_json:
            parsed_json['title'] = slide_title
            return parsed_json
        else:
            logger.warning(f"単一スライド生成結果に必要なキーがありません。Title: {slide_title}")
            return None

    except (json.JSONDecodeError, ValueError) as e:
        logger.error(f"単一スライドSVG生成時のJSONパースに失敗。Title: {slide_title}, Error: {e}, Raw Response: {response_text[:200]}")
        return None
    except Exception as e:
        logger.error(f"単一スライド生成中に予期せぬエラーが発生。Title: {slide_title}, Error: {e}", exc_info=True)
        return None

@app.route('/api/pptx/generate_detailed_from_chat', methods=['POST'])
def generate_pptx_detailed_from_chat_endpoint():
    """
    【ロジック統合版】AIチャットの会話履歴から、PPTX詳細生成タスクを開始する。
    """
    if not request.json or 'conversation_history' not in request.json:
        return jsonify({"error": "会話履歴データがリクエストに含まれていません。"}), 400

    conversation_history = request.json['conversation_history']
    if not isinstance(conversation_history, list) or len(conversation_history) == 0:
        return jsonify({"error": "会話履歴が空または不正な形式です。"}), 400
    
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    task_id = str(uuid.uuid4())

    try:
        # --- 前処理: 会話履歴のテキスト化と目的抽出 ---
        history_text = "\n".join([f"{msg.get('role', 'unknown')}: {str(msg.get('content', ''))[:500]}" for msg in conversation_history])
        
        # 1. 目的の抽出
        objective_prompt = f"以下の会話履歴全体を要約し、この会話から作成すべきプレゼンテーションの「目的」を簡潔な一文で抽出してください。\n\n--- 会話履歴 ---\n{history_text}\n--- 会話履歴ここまで ---\n\nプレゼンテーションの目的:"
        objective, _ = generate_with_gemini(
            model_name=config.DEFAULT_MODEL_NAME, max_output_tokens=512,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=objective_prompt)])],
            user_info=user_info, feature_category="PPTX詳細生成(目的抽出・チャット)", skip_cosmos_log=False
        )
        objective = objective or "会話履歴に基づくプレゼンテーション"
        
        # 2. デザインコンセプトの決定
        design_concepts_list_str = "\n".join([f"- `{key}`: {info['name']} ({info['description']})" for key, info in config.DESIGN_CONCEPTS.items()])
        concept_prompt = f"""あなたはデザインコンサルタントです。
以下の「プレゼンテーションの目的」と「会話の文脈」を分析し、最も適したデザインコンセプトを、提示された選択肢の中から**キー名（例: `modern_corporate`）のみ**で回答してください。

**プレゼンテーションの目的:** {objective}
**会話の文脈:**
---
{history_text}
---

**デザインコンセプトの選択肢:**
{design_concepts_list_str}

**最適なデザインコンセプトのキー名 (1つだけ):**
"""
        design_concept_key, _ = generate_with_gemini(
            model_name=config.DEFAULT_MODEL_NAME, max_output_tokens=50,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=concept_prompt)])],
            user_info=user_info, feature_category="PPTX詳細生成(コンセプト決定・チャット)", skip_cosmos_log=False
        )
        design_concept_key = design_concept_key.strip().replace('`', '') if design_concept_key else "auto"
        if design_concept_key not in config.DESIGN_CONCEPTS:
            design_concept_key = "auto"
        
        # 3. アウトライン生成
        outline_prompt = f"""あなたはプレゼンテーションの構成作家です。
以下の「目的」と「会話履歴」に基づき、プレゼンテーション全体のアウトラインをJSON形式で生成してください。
**目的:** {objective}
**会話履歴:**
---
{history_text}
---
**出力形式:**
各スライドの「タイトル」と「主要コンテンツ（箇条書きのリスト）」を持つオブジェクトの配列としてください。
```json
[
  {{ "title": "...", "content": ["...", "..."] }}
]
```
応答はJSON配列の文字列のみとし、他の説明は含めないでください。
"""
        outline_json_str, _ = generate_with_gemini(
            model_name=config.PPTX_OUTLINE_MODEL_NAME, max_output_tokens=65535,
            contents=[types.Content(role="user", parts=[types.Part.from_text(text=outline_prompt)])],
            user_info=user_info, feature_category="PPTX詳細生成(アウトライン生成・チャット)", skip_cosmos_log=False,
            generation_config_override={"response_mime_type": "application/json"}
        )
        if not outline_json_str or outline_json_str.startswith("[エラー:"):
            raise Exception(f"AIによるアウトライン生成に失敗: {outline_json_str}")

        # --- 共通タスクの準備と実行 ---
        ref_parts = [types.Part.from_text(text=f"--- 会話履歴 ---\n{history_text}")]
        ref_filenames = ["conversation_history.txt"]
        img_parts = []
        img_placeholder_map = {}
        img_filenames = []
        target_languages = ['ja'] 
        confidentiality_level_ja = 'なし'
        aspect_ratio = '16:9' # チャット経由の場合はデフォルト16:9

        create_task_in_cosmos({
            "id": task_id, "task_id": task_id, "status": "PENDING",
            "task_type": "ppt_detailed_generation_from_chat", "user_info": user_info,
            "status_message": "チャットからの生成タスクを開始しました。", "progress_percent": 10,
            "aspect_ratio": aspect_ratio
        })

        _submit_with_request_id(
            _run_slide_generation_task,
            task_id, objective, ref_parts, img_parts, img_placeholder_map,
            user_info, design_concept_key, ref_filenames, img_filenames,
            outline_json_str, target_languages, confidentiality_level_ja,
            aspect_ratio,
        )
        
        return jsonify({"task_id": task_id}), 202

    except Exception as e:
        logger.error(f"チャットからのPPTX詳細生成タスク開始中にエラー: {e}", exc_info=True)
        return jsonify({"success": False, "error": f"サーバー内部でエラーが発生しました: {str(e)}"}), 500

