@app.route('/api/video_explainer/create', methods=['POST'])
def create_video_explainer_task_endpoint():
    """動画解説生成の非同期タスクを開始するAPI。"""
    if 'text' not in request.form or not request.form['text'].strip():
        return jsonify({"error": "動画の元になるテキストが必要です。"}), 400

    text = request.form['text']
    language = request.form.get('language', 'ja')
    voice_name = request.form.get('voice_name')
    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    
    # 参考資料ファイルを受け取る
    reference_files = request.files.getlist('reference_files')
    video_file = request.files.get('video_file')

    try:
        files_to_check = list(reference_files)
        if video_file:
            files_to_check.append(video_file)

        validate_token_limit(
            files_to_check, 
            text, 
            None, # file_references_json はこのエンドポイントでは使用しないため None
            model_name=config.SLIDE_VIDEO_NARRATION_MODEL # 生成に使用するモデルを指定
        )
        
        for f in files_to_check:
            f.seek(0)

    except ValueError as e:
        return jsonify({"error": str(e)}), 400


    reference_files_data = []
    for f in reference_files:
        if f and f.filename:
            reference_files_data.append({"name": f.filename, "bytes": f.read()})
    
    task_id = str(uuid.uuid4())
    task_initial_data = {
        "id": task_id, "task_id": task_id, "status": "PENDING",
        "task_type": "video_explainer_creation",
        "user_info": user_info, "original_filename": f"Video Explainer from text ({text[:20]}...)",
        "status_message": "動画解説の生成タスクを受付ました。", "progress_percent": 0
    }
    create_task_in_cosmos(task_initial_data)

    # ▼▼▼【ここからが修正箇所です (2/2)】▼▼▼
    # executor.submit に reference_files_data を渡す ＋ request_id を伝播
    _submit_with_request_id(
        _run_video_explainer_creation_task,
        task_id,
        text,
        language,
        voice_name,
        user_info,
        reference_files_data,
    )
    # ▲▲▲【修正はここまでです (2/2)】▲▲▲
    
    logger.info(f"動画解説生成タスク {task_id} を開始しました。")
    return jsonify({"task_id": task_id}), 202


def _draw_highlighted_text_on_image(image_bytes: bytes, markdown_text: str, position: str) -> bytes:
    """
    画像に、**で囲まれた部分のみをハイライトしたテキストを描画する。
    長いテキストは自動で折り返して複数行で表示するよう修正。
    【修正】視認性向上のため、全てのテキストを白文字＋黒縁取りで描画する。
           ハイライト箇所は背景に黄色のハッチングを追加する。
    【再修正】Pillowのtextlengthが改行文字に対応していない問題に対処。
    """
    try:
        img = Image.open(io.BytesIO(image_bytes)).convert("RGBA")
        draw = ImageDraw.Draw(img)
        # フォントサイズを少し小さくし、より多くの文字が収まるように調整
        font_size = int(img.height / 22)
        font = ImageFont.truetype(config.FONT_PATH, font_size)
        
        # 縁取りの幅を計算
        stroke_width = max(1, int(font_size / 15))

        # 描画可能な幅を計算 (左右に5%のマージン)
        drawable_width = img.width * 0.9
        
        # 1. まずテキスト全体を行単位に分割する（明示的な改行を処理）
        # これにより、textlengthに渡される文字列に改行が含まれるのを防ぐ
        paragraphs = markdown_text.split('\n')
        
        lines_to_draw = [] # 描画する全行のリスト（各行はセグメントのリスト）

        for paragraph in paragraphs:
            if not paragraph: # 空行の場合
                # 空のセグメントを追加して行間を空けるなどの処理も可能だが、ここではスキップ
                continue

            # 各パラグラフ内でMarkdownのハイライト解析と折り返し処理を行う
            parts = re.split(r'(\*\*.*?\*\*)', paragraph)
            text_segments = []
            for part in parts:
                if not part: continue
                if part.startswith('**') and part.endswith('**'):
                    text_segments.append({'text': part[2:-2], 'highlight': True})
                else:
                    text_segments.append({'text': part, 'highlight': False})
            
            current_line_segments = []
            
            for segment in text_segments:
                text = segment['text']
                is_highlight = segment['highlight']
                
                # セグメントを1文字ずつ処理して、改行位置を決定
                current_segment_buffer = ""
                for char in text:
                    # 改行文字はここでは含まれないはずだが、念のため除外
                    if char == '\n': continue

                    # 現在の行のテキストと、処理中のバッファ、そして次の1文字を合わせた幅を計算
                    line_so_far_text = "".join(s['text'] for s in current_line_segments)
                    
                    # 縁取り幅も含めて長さを計算
                    # ここで渡す文字列には改行が含まれていないことが保証されている
                    next_line_width = draw.textlength(line_so_far_text + current_segment_buffer + char, font=font) + stroke_width * 2
                    
                    # 幅が描画可能領域を超え、かつ現在の行に何かしらのテキストがある場合
                    if next_line_width > drawable_width and (line_so_far_text or current_segment_buffer):
                        # 現在のセグメントバッファを行に追加して、行を確定
                        if current_segment_buffer:
                            current_line_segments.append({'text': current_segment_buffer, 'highlight': is_highlight})
                        lines_to_draw.append(current_line_segments)
                        
                        # 次の行の準備
                        current_line_segments = []
                        current_segment_buffer = char # 次の行の最初の文字としてバッファをリセット
                    else:
                        # 幅に収まる場合は、バッファに文字を追加
                        current_segment_buffer += char
                
                # セグメントの処理が終わった後、残りのバッファを現在の行に追加
                if current_segment_buffer:
                    current_line_segments.append({'text': current_segment_buffer, 'highlight': is_highlight})

            # パラグラフの最後の行を追加
            if current_line_segments:
                lines_to_draw.append(current_line_segments)

        # 3. 描画処理
        line_height = font.getbbox("A")[3] * 1.5
        total_height = len(lines_to_draw) * line_height
        margin_y = int(img.height * 0.1)
        
        if "top" in position: y_start = margin_y
        elif "bottom" in position: y_start = img.height - total_height - margin_y
        else: y_start = (img.height - total_height) / 2
        
        current_y = y_start
        margin_x = int(img.width * 0.05)

        for line_segments in lines_to_draw:
            # 行全体の幅を計算（配置決定用）
            full_line_text = "".join(p['text'] for p in line_segments)
            if not full_line_text: continue

            line_width = draw.textlength(full_line_text, font=font) + stroke_width * 2
            
            if "center" in position: current_x_draw = (img.width - line_width) / 2
            elif "right" in position: current_x_draw = img.width - line_width - margin_x
            else: current_x_draw = margin_x
            
            for segment in line_segments:
                text = segment['text']
                highlight = segment['highlight']
                
                # 縁取りを考慮してバウンディングボックスを取得
                part_bbox = draw.textbbox((0,0), text, font=font, stroke_width=stroke_width)
                part_width = part_bbox[2] - part_bbox[0]
                part_height = part_bbox[3]
                
                if highlight:
                    highlight_padding_x = int(font_size * 0.1)
                    highlight_padding_y = int(font_size * 0.2)
                    highlight_color = (255, 240, 100, 220)
                    # 背景のハッチング（黄色い矩形）を描画
                    draw.rectangle(
                        [current_x_draw - highlight_padding_x, current_y + highlight_padding_y, 
                         current_x_draw + part_width + highlight_padding_x, current_y + part_height + highlight_padding_y],
                        fill=highlight_color
                    )
                
                # 共通の文字描画処理（白文字＋黒縁取り）
                # ハイライト有無にかかわらず、視認性を確保するためにこのスタイルを使用
                draw.text(
                    (current_x_draw, current_y), 
                    text, 
                    font=font, 
                    fill="white", 
                    stroke_width=stroke_width, 
                    stroke_fill="black"
                )
                
                current_x_draw += part_width

            current_y += line_height

        output_buffer = io.BytesIO()
        img.convert("RGB").save(output_buffer, "PNG")
        return output_buffer.getvalue()

    except Exception as e:
        logger.error(f"Pillowでのハイライトテキスト描画に失敗: {e}", exc_info=True)
        return image_bytes

def _run_video_explainer_creation_task(task_id, text, language, voice_name, user_info, reference_files_data):
    """
    テキストから構成案・画像・音声を生成し、動画を作成する非同期タスク。(言語指定対応版 v5)
    """
    temp_dir = tempfile.mkdtemp(prefix=f"video_explainer_{task_id}_")
    clips_to_close = []

    try:
        ffmpeg_path = config.FFMPEG_PATH or shutil.which('ffmpeg')
        if not ffmpeg_path:
            raise FileNotFoundError("サーバー設定エラー: FFmpeg実行可能ファイルが見つかりません。")
        
        # --- フェーズ1: AIによる脚本（シナリオ）生成 ---
        update_task_in_cosmos(task_id, {"status_message": "AIによる分析準備中 (動画アップロード)...", "progress_percent": 10})
        
        # 言語コードから言語名を決定
        lang_map = {'ja': 'Japanese', 'en': 'English', 'zh': 'Chinese (Simplified)'}
        target_lang_name = lang_map.get(language, 'Japanese')
        
        step1_parts = []
        prompt_step1_base = f"""あなたはプロの脚本家兼プレゼンテーションデザイナーです。
以下の「入力テキスト」と「参考資料」を元に、初心者にも分かりやすい短い動画解説の完全な構成案をJSON形式で生成してください。

**あなたのタスク:**
動画の各スライドについて、以下の4つの要素を考案してください。
1.  `narration`: 発表者が話すナレーション原稿（400字程度の話し言葉）。【最重要】このテキストには`**`、`*`、`#`などのMarkdown記号を絶対に含めないでください。
2.  `image_prompt`: そのシーンの情景を生成するための、詳細な英語の画像生成プロンプト。
3.  `slide_text` (オブジェクト): スライド画像の上に重ねて表示するテキストとその位置。
    - `text`: ナレーションの核心を表す、キャッチーな短い見出し（100～300字以内）。最も重要な単語を`**...**`で囲むこと。
    - `position`: テキストを描画するのに最適な位置。'top_left', 'top_center', 'top_right', 'middle_left', 'middle_center', 'middle_right', 'bottom_left', 'bottom_center', 'bottom_right' のいずれか。

**制約:**
- スライド枚数は3～5枚程度。
- 参考資料の内容を最優先する。
- **【最重要】出力言語:** `narration` および `slide_text` の `text` は、必ず **{target_lang_name}** で記述してください。

**入力テキスト:**
---
{text}
---

**厳格な出力形式:** 応答は以下の構造を持つJSON配列の文字列のみとし、他の説明や囲み文字は絶対に含めないでください。
```json
[
  {{
    "narration": "({target_lang_name}のナレーション原稿)",
    "image_prompt": "(English prompt for slide 1 illustration)",
    "slide_text": {{
      "text": "({target_lang_name}のスライド表示テキスト、強調は**ハイライト**)",
      "position": "(top_centerなどの位置キーワード)"
    }}
  }},
  {{
    "narration": "({target_lang_name}のナレーション原稿)",
    "image_prompt": "(English prompt for slide 2 illustration)",
    "slide_text": {{
      "text": "({target_lang_name}のスライド表示テキスト)",
      "position": "(bottom_centerなどの位置キーワード)"
    }}
  }}
]
```
"""
        step1_parts.append(types.Part.from_text(text=prompt_step1_base))
        if reference_files_data:
            step1_parts.append(types.Part.from_text(text="\n--- 参考資料ここから ---\n"))
            for file_data in reference_files_data:
                ref_file_stream = io.BytesIO(file_data["bytes"]); ref_file_stream.filename = file_data["name"]
                part = extract_file_content_to_part(ref_file_stream)
                if part:
                    step1_parts.append(types.Part.from_text(text=f"\n[参考資料: {file_data['name']}]\n")); step1_parts.append(part)
        
        slide_plan_str, _ = generate_with_gemini(
            model_name=config.SLIDE_VIDEO_NARRATION_MODEL, contents=[types.Content(role="user", parts=step1_parts)],
            max_output_tokens=65535, temperature=0.7, user_info=user_info, feature_category="動画解説生成(構成案・統合版)",
            generation_config_override={"response_mime_type": "application/json"}
        )
        if not slide_plan_str or slide_plan_str.startswith("[エラー:"): raise Exception(f"AIによる構成案の生成に失敗: {slide_plan_str}")
        try:
            slide_plan = json.loads(slide_plan_str)
            # 新しいJSON構造を検証
            if not isinstance(slide_plan, list) or not all("narration" in s and "image_prompt" in s and "slide_text" in s and "text" in s["slide_text"] and "position" in s["slide_text"] for s in slide_plan):
                raise ValueError("JSONの形式が不正です。必要なキーが不足しています。")
        except (json.JSONDecodeError, ValueError) as e:
            logger.error(f"構成案JSONのパースに失敗: {e}\nRaw: {slide_plan_str[:500]}"); raise Exception(f"AIが生成した構成案の形式が不正: {e}")
        logger.info(f"タスク {task_id}: {len(slide_plan)}枚のスライド構成案を生成。")

        # --- ステップ2 & 3: 画像・音声生成とテキスト描画 (逐次処理) ---
        slide_assets = []; previous_image_bytes = None
        total_slides = len(slide_plan)
        for index, slide_content in enumerate(slide_plan):
            progress = 20 + int(60 * (index / total_slides))
            update_task_in_cosmos(task_id, {"status_message": f"スライド {index + 1}/{total_slides} を生成中...", "progress_percent": progress})
            
            # 画像生成
            user_image_prompt = slide_content['image_prompt']
            image_gen_parts = []
            style_instruction = "A simple, rough sketch style illustration with a consistent character design and color palette across all images. The background should be a subtle grid paper pattern."
            if previous_image_bytes:
                style_instruction = "Use the style, characters, and color palette of the provided previous slide image as a strict reference to maintain visual consistency."
                image_gen_parts.append(types.Part(inline_data=types.Blob(mime_type="image/png", data=previous_image_bytes)))
            enhanced_image_prompt = f"{style_instruction}\n**Image content for this new slide:** {user_image_prompt}.\n**Crucial constraint:** Do not include any text, letters, or words in the image."
            image_gen_parts.append(types.Part.from_text(text=enhanced_image_prompt))
            image_bytes = None
            try:
                response_iterator = generate_with_gemini(model_name=config.SLIDE_VIDEO_IMAGE_MODEL,max_output_tokens=65535,contents=[types.Content(role="user", parts=image_gen_parts)], stream=True, user_info=user_info, skip_cosmos_log=False, feature_category="動画解説生成(画像生成)", aspect_ratio="16:9")
                for chunk in response_iterator:
                    if hasattr(chunk, 'image_data_url') and chunk.image_data_url:
                        try:
                            if "," in chunk.image_data_url:
                                header, base64_data = chunk.image_data_url.split(",", 1)
                            else:
                                base64_data = chunk.image_data_url
                            
                            image_bytes = base64.b64decode(base64_data)
                            break # 成功したらループを抜ける
                        except Exception as e_img_parse:
                            logger.warning(f"画像データのパースに失敗しました (Chunk): {e_img_parse}")
                            continue
                
                if image_bytes: 
                    previous_image_bytes = image_bytes
                else:
                    previous_image_bytes = None

            except Exception as e: 
                logger.error(f"タスク {task_id}: スライド {index+1} 画像生成エラー: {e}", exc_info=True)
                previous_image_bytes = None
                continue
            
            if not image_bytes: continue

            # 音声生成の前にナレーションテキストからMarkdown記号を除去
            narration_raw = slide_content['narration']
            narration_clean = re.sub(r'([*_`#])', '', narration_raw)
            audio_bytes = generate_speech_for_pptx(narration_clean, language, voice_name)
            if not audio_bytes:
                logger.warning(f"タスク {task_id}: スライド {index+1} の音声生成に失敗しました。")
                continue

            # テキスト描画
            slide_text_info = slide_content['slide_text']
            text_for_slide = slide_text_info.get('text', '')
            text_pos = slide_text_info.get('position', 'middle_center')
            
            final_image_bytes = _draw_highlighted_text_on_image(image_bytes, text_for_slide, text_pos)

            final_image_path = os.path.join(temp_dir, f"slide_final_{index}.png"); audio_path = os.path.join(temp_dir, f"audio_{index}.mp3")
            with open(final_image_path, "wb") as f: f.write(final_image_bytes)
            with open(audio_path, "wb") as f: f.write(audio_bytes)
            slide_assets.append({"text_image_path": final_image_path, "audio_path": audio_path, "index": index})

        if not slide_assets: raise Exception("有効なスライド素材を1枚も生成できませんでした。")

        # --- ステップ4 & 5: 動画編集と完了処理 ---
        update_task_in_cosmos(task_id, {"status_message": "動画をエンコード中...", "progress_percent": 90})
        if ImageClip is None: raise ImportError("moviepyが未インストールです。")
        final_video_clips = []
        for asset in slide_assets:
            try:
                audio_clip = AudioFileClip(asset['audio_path']); clips_to_close.append(audio_clip)
                video_clip = ImageClip(asset['text_image_path'], duration=audio_clip.duration).with_audio(audio_clip)
                video_clip.fps = config.VIDEO_FPS; final_video_clips.append(video_clip); clips_to_close.append(video_clip)
            except Exception as e: logger.error(f"タスク {task_id}: スライド {asset['index']+1} クリップ作成エラー: {e}", exc_info=True)
        if not final_video_clips: raise Exception("動画クリップの生成に失敗。")
        final_video = concatenate_videoclips(final_video_clips, method="compose"); clips_to_close.append(final_video)
        output_filename = f"video_explainer_{task_id}.mp4"; output_path = os.path.join(temp_dir, output_filename)
        progress_logger = FFMPEGProgressLogger(task_id)
        final_video.write_videofile(output_path, codec="libx264", audio_codec="aac", preset='fast', threads=os.cpu_count() or 2, logger=progress_logger)
        update_task_in_cosmos(task_id, {"status_message": "成果物をアップロード中...", "progress_percent": 98})
        with open(output_path, "rb") as f: video_bytes = f.read()
        video_blob_name = f"results/{output_filename}"
        if not upload_bytes_to_blob(video_bytes, video_blob_name): raise Exception("最終動画ファイルのアップロードに失敗。")
        update_task_in_cosmos(task_id, {
            "status": "SUCCESS", "status_message": "動画の生成が完了しました。", "progress_percent": 100,
            "result": { "files_data": { "video": { "blob_name": video_blob_name, "filename": output_filename, "mimetype": "video/mp4"}}}
        })
        logger.info(f"タスク {task_id}: 動画解説生成成功。Blob: {video_blob_name}")

    except Exception as e:
        logger.error(f"動画解説生成タスク {task_id} でエラー: {e}", exc_info=True)
        update_task_in_cosmos(task_id, {"status": "FAILURE", "error": f"サーバーエラー: {e}", "status_message": "エラーが発生しました。"})
    finally:
        for clip in clips_to_close:
            try:
                if hasattr(clip, 'close') and callable(clip.close): clip.close()
            except Exception: pass
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)
            logger.info(f"タスク {task_id}: 一時ディレクトリ {temp_dir} をクリーンアップ。")


