@app.route('/api/video/create_explanation_video_async', methods=['POST'])
def create_explanation_video_async_endpoint():
    """解説動画生成の非同期タスクを開始するAPI"""
    if 'video_file' not in request.files or 'objective' not in request.form:
        return jsonify({"error": "動画ファイルと目的は必須です。"}), 400

    video_file = request.files['video_file']
    objective = request.form.get('objective')

    narration_language = request.form.get('narration_language', 'ja') # デフォルトは日本語
    narration_voice = request.form.get('narration_voice', None) # 指定がなければNone
    reference_file = request.files.get('reference_file') # 参考資料は任意

    reference_file_data = None
    if reference_file and reference_file.filename:
        # ワーカー関数で扱えるように、ファイル名とバイトデータを辞書に格納
        reference_file_data = {
            "name": reference_file.filename,
            "bytes": reference_file.read()
        }

    if not video_file or not video_file.filename:
        return jsonify({"error": "動画ファイルが選択されていません。"}), 400
    if not objective or not objective.strip():
        return jsonify({"error": "動画の目的が入力されていません。"}), 400

    # user_info = get_entra_user_info(request)
    user_info = g.user_info
    video_bytes = video_file.read()
    original_filename = secure_filename(video_file.filename)

    task_id = str(uuid.uuid4())
    task_initial_data = {
        "id": task_id,
        "task_id": task_id,
        "status": "PENDING",
        "task_type": "explanation_video_creation",
        "user_info": user_info,
        "original_filename": original_filename,
        "status_message": "解説動画の生成タスクを受付ました。",
        "progress_percent": 0
    }

    if create_task_in_cosmos(task_initial_data) is None:
        return jsonify({"error": "タスクの初期化に失敗しました。データベースを確認してください。"}), 500

    # バックグラウンドで実行するワーカー関数を呼び出す
    _submit_with_request_id(
        _run_explanation_video_task,
        task_id,
        video_bytes,
        original_filename,
        objective,
        user_info,
        narration_language,
        narration_voice,
        reference_file_data,
    )
    
    logger.info(f"解説動画生成タスク {task_id} を開始しました。目的: {objective[:50]}...")
    return jsonify({"task_id": task_id}), 202

# routes.py に、_run_explanation_video_task 関数の前に追加

def _create_comment_image(text: str, temp_dir: str) -> str | None:
    """
    指定されたテキストで吹き出し画像を生成し、一時ファイルとして保存してそのパスを返す。
    """
    if not text:
        return None
    
    try:
        # フォントとサイズを設定
        font_path = config.FONT_PATH
        if not os.path.exists(font_path):
            logger.error(f"吹き出し用のフォントファイルが見つかりません: {font_path}")
            # フォールバックとして、Pillowのデフォルトフォントを試みる
            try:
                font = ImageFont.load_default()
                font_size = 24
            except IOError:
                logger.error("Pillowのデフォルトフォントも読み込めませんでした。")
                return None
        else:
            font_size = 32
            font = ImageFont.truetype(font_path, font_size)

        # テキストの描画サイズを計算
        text_bbox = font.getbbox(text)
        text_width = text_bbox[2] - text_bbox[0]
        text_height = text_bbox[3] - text_bbox[1]
        
        # 画像のサイズを決定 (余白を追加)
        padding = 20
        bubble_padding = 30 # 吹き出しのしっぽ部分のスペース
        img_width = text_width + padding * 2
        img_height = text_height + padding * 2 + bubble_padding
        
        # 透明な背景の画像を作成
        image = Image.new("RGBA", (img_width, img_height), (255, 255, 255, 0))
        draw = ImageDraw.Draw(image)

        # 吹き出しの本体を描画
        bubble_x0, bubble_y0 = 0, 0
        bubble_x1, bubble_y1 = img_width -1, img_height - bubble_padding -1
        draw.rounded_rectangle(
            (bubble_x0, bubble_y0, bubble_x1, bubble_y1), 
            radius=20, 
            fill=(255, 255, 255, 220), 
            outline=(0, 0, 0, 220), 
            width=3
        )
        
        # 吹き出しのしっぽを描画
        tail_points = [
            (img_width / 2 - 20, bubble_y1),
            (img_width / 2, img_height -1),
            (img_width / 2 + 20, bubble_y1)
        ]
        draw.polygon(tail_points, fill=(255, 255, 255, 220))
        draw.line([tail_points[0], tail_points[1]], fill=(0, 0, 0, 220), width=3)
        draw.line([tail_points[1], tail_points[2]], fill=(0, 0, 0, 220), width=3)

        # テキストを描画
        draw.text(
            (padding, padding), 
            text, 
            font=font, 
            fill=(0, 0, 0, 255)
        )

        # 画像を一時ファイルとして保存
        output_path = os.path.join(temp_dir, f"comment_{uuid.uuid4().hex}.png")
        image.save(output_path, "PNG")
        
        logger.info(f"吹き出し画像を生成しました: {output_path}")
        return output_path

    except Exception as e:
        logger.error(f"吹き出し画像の生成に失敗しました: {e}", exc_info=True)
        return None

def _create_text_image_with_pillow(text, font_path, fontsize, color, stroke_color, stroke_width):
    """
    Pillowを使用して、テキストが描画された透過PNG画像をメモリ上に生成し、そのバイトデータを返す。
    【縁取り機能を追加した修正版】
    """
    try:
        # フォントをロード
        font = ImageFont.truetype(font_path, fontsize)
        
        # テキストの描画サイズを計算
        text_bbox = font.getbbox(text, stroke_width=stroke_width) # 縁取りの幅を考慮
        text_width = text_bbox[2] - text_bbox[0]
        text_height = text_bbox[3] - text_bbox[1]
        
        # 画像のサイズを決定 (余白を考慮)
        padding = 10 + stroke_width # 縁取りがはみ出ないように余白を調整
        img_width = text_width + padding * 2
        img_height = text_height + padding * 2
        
        # 透過背景の画像を作成
        img = Image.new("RGBA", (img_width, img_height), (255, 255, 255, 0))
        draw = ImageDraw.Draw(img)
        
        # メインのテキストと縁取りを同時に描画
        draw.text(
            (padding, padding), 
            text, 
            font=font, 
            fill=color, 
            stroke_width=stroke_width, 
            stroke_fill=stroke_color
        )
        
        # 画像をバイトデータに変換
        buffer = io.BytesIO()
        img.save(buffer, format="PNG")
        return buffer.getvalue()

    except Exception as e:
        logger.error(f"Pillowによるテキスト画像生成に失敗: {e}", exc_info=True)
        return None

def _run_explanation_video_task(task_id, video_bytes, original_filename, objective, user_info, narration_language, narration_voice, reference_file_data):
    """
    【改訂版 v2】解説動画の生成を非同期で実行するワーカー関数。
    言語指定がAIの脚本生成に反映されるようにプロンプトを修正。
    """
    temp_dir = tempfile.mkdtemp(prefix=f"explainer_{task_id}_")
    original_cwd = os.getcwd() # 元のカレントディレクトリを保存
    clips_to_close = []

    try:
        ffmpeg_path = config.FFMPEG_PATH or shutil.which('ffmpeg')
        if not ffmpeg_path:
            raise FileNotFoundError("サーバー設定エラー: FFmpeg実行可能ファイルが見つかりません。")
        
        # --- フェーズ1: AIによる脚本（シナリオ）生成 ---
        update_task_in_cosmos(task_id, {"status_message": "AIによる分析準備中 (動画アップロード)...", "progress_percent": 10})
        gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")
        if not gcs_bucket_name: raise Exception("サーバー設定エラー: 動画処理に必要なGCSバケットが設定されていません。")
        
        gcs_blob_name_main_video = f"temp_explainer_videos/{task_id}_{secure_filename(original_filename)}"
        gcs_uri = _upload_to_gcs(io.BytesIO(video_bytes), gcs_blob_name_main_video, gcs_bucket_name)
        if not gcs_uri: raise Exception("GCSへの動画アップロードに失敗しました。")
        
        update_task_in_cosmos(task_id, {"status_message": "AIが動画を分析し、脚本を作成中...", "progress_percent": 25})
        
        lang_map = {'ja': 'Japanese', 'en': 'English', 'zh': 'Chinese (Simplified)'}
        target_lang_name = lang_map.get(narration_language, 'Japanese')

        prompt_text = f"""あなたはプロの映像編集ディレクターです。
提供された動画を分析し、以下の「ユーザーの目的」を達成するための解説動画の構成案を、厳格なJSON形式で出力してください。

# ユーザーの目的
{objective}

# 【最重要】出力言語の指定
生成する `narration` (ナレーション原稿) と `telop` (テロップ) は、必ず **{target_lang_name}** で記述してください。
プロンプトは日本語ですが、出力結果の内容は指定された言語に従ってください。
"""

        # 参考資料があればプロンプトにその旨を追記
        if reference_file_data:
            prompt_text += f"""
# 参考資料
以下の参考資料の内容を最優先で考慮し、専門用語の定義、手順の正確性、製品名などを確認し、ナレーションやテロップの内容に反映させてください。
(ファイル名: {reference_file_data.get('name', '不明')})
"""
        
        prompt_text += """
# あなたのタスク
動画を視聴し、動画の開始から終了まで、話されている内容や主要な操作をすべて網羅するように、複数のステップ（シーン）に分割してください。
省略するのは、意味のない間（つなぎとして不要な部分）や準備動作のみです。最終的な動画の長さが、元の動画と大きくかけ離れないようにしてください。

各シーンについて、以下の情報をJSONオブジェクトとして生成し、それらを配列にまとめてください。

1.  `timestamp`: {{ "start": (float), "end": (float) }}
    - **【重要】** このシーンが開始/終了する時間を秒単位で記述してください。
    - **【厳守】** 各シーンの時間は重複せず、昇順になるようにしてください。前のシーンの終了時間よりも後に開始時間を設定してください。

2.  `narration`: "（このシーンで話すべきナレーション原稿）"
    - 映像の内容を分かりやすく解説する、自然な話し言葉の原稿を生成してください。ナレーションが不要なシーンでは空文字列 `""` としてください。

3.  `telop`: "（画面下部に表示するテロップ文）"
    - ナレーションの要点をまとめた、簡潔なテキストを生成してください。

# 厳格な出力形式
- 応答は、上記の構造を持つJSON配列の文字列のみとし、他のテキスト（説明、マークダウン、```jsonの囲み文字など）は**絶対に含めないでください**。
- タイムスタンプは必ず昇順にしてください。
"""
        video_part = types.Part(file_data=types.FileData(file_uri=gcs_uri, mime_type=_get_video_mime_type(original_filename)))
        prompt_part = types.Part.from_text(text=prompt_text)
        
        # Geminiに渡すcontentsリストを作成
        contents_for_gemini = [video_part, prompt_part]
        log_filenames_for_gemini = [original_filename]
        
        # 参考資料があればPartに変換してcontentsリストに追加
        if reference_file_data:
            ref_file_stream = io.BytesIO(reference_file_data["bytes"])
            ref_file_stream.filename = reference_file_data["name"]
            ref_part = extract_file_content_to_part(ref_file_stream)
            if ref_part:
                contents_for_gemini.append(ref_part)
                log_filenames_for_gemini.append(reference_file_data["name"])

        analysis_result_str, metadata = generate_with_gemini(
            model_name=config.EXPLANATION_VIDEO_MODEL_NAME,
            contents=[types.Content(role="user", parts=contents_for_gemini)],
            system_instruction="あなたは、ユーザーの指示に厳密に従い、JSON形式で構造化されたデータを出力するAIアシスタントです。",
            max_output_tokens=65535, temperature=0.2, user_info=user_info,
            log_prompt_text=f"Explainer Video Script Gen: {objective[:100]}...",
            log_filenames=log_filenames_for_gemini,
            feature_category="解説動画生成(フェーズ1:脚本生成)",
            skip_cosmos_log=False,
            generation_config_override={"response_mime_type": "application/json"}
        )

        if not analysis_result_str or analysis_result_str.startswith(("[エラー:", "[APIエラー:")):
            raise Exception(f"AIによる脚本生成に失敗しました: {analysis_result_str}")
        try:
            json_match = re.search(r'\[.*\]', analysis_result_str, re.DOTALL)
            if not json_match: raise ValueError("AIの応答からJSON配列が見つかりませんでした。")
            script_plan = json.loads(json_match.group(0))
        except (json.JSONDecodeError, ValueError) as e:
            logger.error(f"AIの応答JSONのパースに失敗: {e}. Raw Response: {analysis_result_str[:500]}")
            raise Exception(f"AIが生成した脚本の形式が不正です: {e}")
        
        # --- フェーズ2: 各シーンの素材準備（音声生成と尺決定） ---
        update_task_in_cosmos(task_id, {"status_message": "ナレーション音声を生成し、各シーンの長さを確定中...", "progress_percent": 50})
        
        edit_plan = []
        for i, step in enumerate(script_plan):
            narration_text = step.get("narration")
            video_cut_duration = step["timestamp"]["end"] - step["timestamp"]["start"]
            duration = max(0.1, video_cut_duration) 
            audio_path = None

            if narration_text and narration_text.strip():
                # フロントエンドから渡された言語と音声でナレーションを生成
                audio_bytes = generate_speech_for_pptx(narration_text, narration_language, narration_voice)
                if audio_bytes:
                    audio_path = os.path.join(temp_dir, f"step_{i}_audio.mp3")
                    with open(audio_path, "wb") as f: f.write(audio_bytes)
                    audio_duration = _get_audio_duration_seconds(audio_bytes, temp_dir)
                    if audio_duration:
                        duration = audio_duration 
            
            step["timestamp"]["duration"] = duration
            step["video_cut_duration"] = video_cut_duration
            step["pause_duration"] = max(0, duration - video_cut_duration)
            step["assets"] = {"audio_path": audio_path}
            edit_plan.append(step)

        # --- フェーズ3: FFmpegによる動画編集・合成 ---
        update_task_in_cosmos(task_id, {"status_message": "動画を編集・合成中...", "progress_percent": 75})
        
        input_video_path = os.path.join(temp_dir, "original.mp4")
        with open(input_video_path, "wb") as f: f.write(video_bytes)
        
        temp_clip_paths = []
        os.chdir(temp_dir)
        
        for i, step in enumerate(edit_plan):
            start, end = step["timestamp"]["start"], step["timestamp"]["end"]
            segment_duration = step["timestamp"]["duration"]
            pause_duration = step["pause_duration"]
            step_output_path = f"step_{i}.mp4"
            
            filter_complex_parts = []
            command = [ffmpeg_path, '-y']
            current_input_index = 0

            if step["assets"].get("audio_path"):
                command.extend(['-i', os.path.basename(step["assets"]["audio_path"])])
            else:
                command.extend(['-f', 'lavfi', '-i', f'anullsrc=r=48000:cl=stereo', '-t', str(segment_duration)])
            audio_input_index = current_input_index; current_input_index += 1

            command.extend(['-i', "original.mp4"])
            video_input_stream_index = current_input_index; current_input_index += 1
            
            video_stream_name = f"[v{i}_base]"
            filter_complex_parts.append(f"[{video_input_stream_index}:v]trim={start}:{end},setpts=PTS-STARTPTS,tpad=stop_mode=clone:stop_duration={pause_duration}{video_stream_name}")

            if step.get("telop"):
                text_image_bytes = _create_text_image_with_pillow(step["telop"], config.FONT_PATH, 40, 'white', 'black', 2)
                if text_image_bytes:
                    telop_image_path = f"telop_{i}.png"
                    with open(telop_image_path, "wb") as f: f.write(text_image_bytes)
                    
                    command.extend(['-i', telop_image_path])
                    telop_input_index = current_input_index; current_input_index += 1
                    
                    teloped_stream_name = f"[v{i}_telop]"
                    filter_complex_parts.append(f"{video_stream_name}[{telop_input_index}:v]overlay=(W-w)/2:H-h-30{teloped_stream_name}")
                    video_stream_name = teloped_stream_name

            command.extend(['-filter_complex', ";".join(filter_complex_parts)])
            
            map_video_stream = video_stream_name.replace('[', '').replace(']', '')
            command.extend(['-map', f"[{map_video_stream}]", '-map', f'{audio_input_index}:a'])
            command.extend(['-t', str(segment_duration)])
            command.extend(['-c:v', 'libx264', '-pix_fmt', 'yuv420p', '-preset', 'fast', '-c:a', 'aac', step_output_path])
            
            try:
                subprocess.run(command, check=True, capture_output=True, text=True, encoding='utf-8', errors='ignore')
                temp_clip_paths.append(f"file '{step_output_path}'")
            except subprocess.CalledProcessError as e:
                logger.error(f"FFmpegステップ {i} の処理に失敗: {e.stderr}")
                continue
        
        if not temp_clip_paths:
            raise Exception("編集ステップの生成に失敗しました。動画を作成できません。")

        concat_file_path = "concat.txt"
        with open(concat_file_path, "w") as f: f.write("\n".join(temp_clip_paths))
        
        final_output_filename = f"explanation_video_{task_id}.mp4"
        concat_command = [
            ffmpeg_path, '-f', 'concat', '-safe', '0', '-i', concat_file_path,
            '-c:v', 'libx264', '-preset', 'fast', '-c:a', 'aac',
            '-y', final_output_filename
        ]
        subprocess.run(concat_command, check=True, capture_output=True, text=True)

        # --- フェーズ4: アップロードと完了処理 ---
        update_task_in_cosmos(task_id, {"status_message": "成果物をアップロード中...", "progress_percent": 95})
        with open(final_output_filename, "rb") as f_final:
            final_video_bytes = f_final.read()
        
        final_blob_name = f"results/{final_output_filename}"
        if not upload_bytes_to_blob(final_video_bytes, final_blob_name):
            raise Exception("最終動画のアップロードに失敗しました。")

        success_payload = {
            "status": "SUCCESS", "status_message": "解説動画の生成が完了しました。", "progress_percent": 100,
            "result": {"files_data": {"video": {"blob_name": final_blob_name, "filename": f"explanation_{original_filename}", "mimetype": "video/mp4"}}}
        }
        update_task_in_cosmos(task_id, success_payload)

    except Exception as e:
        error_message = f"解説動画生成タスクでエラーが発生しました: {str(e)}"
        logger.error(f"タスク {task_id}: {error_message}", exc_info=True)
        update_task_in_cosmos(task_id, {"status": "FAILURE", "error": error_message, "status_message": "エラーが発生しました。", "progress_percent": 100})
    finally:
        os.chdir(original_cwd) 
        if temp_dir and os.path.exists(temp_dir):
            shutil.rmtree(temp_dir, ignore_errors=True)

@app.route('/api/chat/summarize_for_infographic', methods=['POST'])
def summarize_for_infographic():
    """
    長い会話履歴をインフォグラフィック生成用に要約する。
    結論や重要な生成内容は詳細に残し、不要なやり取りを削る。
    """
    data = request.get_json()
    history = data.get('history', [])
    user_info = get_entra_user_info(request)

    if not history:
        return jsonify({"error": "履歴がありません"}), 400

    # 会話をテキスト化
    history_text = ""
    for msg in history:
        role = "ユーザー" if msg.get('role') == 'user' else "AI"
        content = msg.get('content', '')
        if isinstance(content, dict):
            content = json.dumps(content, ensure_ascii=False)
        history_text += f"{role}: {content}\n\n"

    summary_prompt = f"""
以下の会話履歴を、インフォグラフィック（図解画像）生成用のプロンプト素材として要約してください。

# 制約事項:
1. トークン制限を回避するため、全体のボリュームを適切に凝縮すること。
2. **結論、具体的な数値、AIが提案した主要な構成案やコンテンツの内容は、詳細を維持し、なるべくそのまま出力すること。**
3. 導入の挨拶、重複した説明、画像生成に関係のない雑談は徹底的に削除すること。
4. 出力は、画像生成AIが理解しやすい論理的な構造（箇条書きなど）にすること。

# 会話履歴:
---
{history_text}
---

# 要約結果（詳細な結論を含む）:
"""

    generated_summary, _ = generate_with_gemini(
        model_name=config.DEFAULT_MODEL_NAME,
        contents=[types.Content(role="user", parts=[types.Part.from_text(text=summary_prompt)])],
        system_instruction="あなたは情報の要約と構造化のスペシャリストです。画像生成のインプットとして最適な、密度が高く正確な要約を作成してください。",
        max_output_tokens=8192, # 要約後のサイズを制限
        temperature=0.2,
        user_info=user_info,
        feature_category="インフォグラフィック用要約"
    )

    return jsonify({"summary": generated_summary.strip()})

@m365_search_bp.route('/api/m365/browse', methods=['POST'])
def m365_browse_endpoint():
    user_info = g.user_info
    access_token = request.headers.get('x-ms-token-aad-access-token')
    if not access_token:
        return jsonify({"error": "Unauthorized"}), 401

    data = request.json
    source = data.get('source') # sharepoint, teams, outlook
    parent_id = data.get('parentId')
    parent_type = data.get('parentType')
    
    # SharePoint用: 検索キーワード
    keyword = data.get('keyword') 

    # コンテキスト維持用ID
    drive_id = data.get('driveId')
    site_id = data.get('siteId')
    team_id = data.get('teamId')
    chat_id = data.get('chatId')

    headers = {"Authorization": f"Bearer {access_token}"}
    items = []

    try:
        # === SharePoint / OneDrive ===
        if source == 'sharepoint':
            if not parent_id:
                # Root: OneDrive + (検索キーワードがあればサイト検索 / なければフォローサイト)
                
                # 1. OneDrive (常に表示)
                items.append({
                    "id": "me_drive_root", "name": "My OneDrive", "type": "drive", 
                    "isContainer": True, "driveId": "me"
                })

                # 2. Sites
                if keyword:
                    # サイト検索
                    # quote関数がないエラーを防ぐため requests.utils.quote を使用
                    logger.info(f"Searching SharePoint sites with keyword: {keyword}")
                    search_url = f"https://graph.microsoft.com/v1.0/sites?search={requests.utils.quote(keyword)}"
                    resp = requests.get(search_url, headers=headers)
                    if resp.ok:
                        for site in resp.json().get('value', []):
                            items.append({
                                "id": site['id'], "name": site.get('displayName', site.get('name', 'Site')), 
                                "type": "site", "isContainer": True, "siteId": site['id'],
                                "rawData": site
                            })
                else:
                    # フォローしているサイト (デフォルト)
                    resp = requests.get("https://graph.microsoft.com/v1.0/me/followedSites", headers=headers)
                    if resp.ok:
                        for site in resp.json().get('value', []):
                            items.append({
                                "id": site['id'], "name": site.get('displayName', 'Site'), 
                                "type": "site", "isContainer": True, "siteId": site['id'],
                                "rawData": site
                            })
            
            elif parent_type == 'site':
                # Site -> Drives (Document Libraries)
                resp = requests.get(f"https://graph.microsoft.com/v1.0/sites/{site_id}/drives", headers=headers)
                if resp.ok:
                    for drive in resp.json().get('value', []):
                        items.append({
                            "id": drive['id'], "name": drive.get('name', 'Library'), 
                            "type": "drive", "isContainer": True, "driveId": drive['id'],
                            "rawData": drive
                        })

            elif parent_type == 'drive' or parent_type == 'folder':
                # Drive/Folder -> Children
                url = ""
                current_drive_id = drive_id
                
                if parent_id == "me_drive_root":
                     url = "https://graph.microsoft.com/v1.0/me/drive/root/children"
                     current_drive_id = "me"
                elif parent_type == 'drive':
                     url = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/root/children"
                else:
                     # フォルダの中身を見る場合もdriveIdが必要
                     url = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/items/{parent_id}/children"
                
                resp = requests.get(url, headers=headers)
                if resp.ok:
                    for item in resp.json().get('value', []):
                        is_folder = 'folder' in item
                        items.append({
                            "id": item['id'], 
                            "name": item.get('name'), 
                            "type": "folder" if is_folder else "file", 
                            "isContainer": is_folder,
                            "driveId": current_drive_id, # 子要素にもDriveIDを引き継ぐ
                            "date": item.get('lastModifiedDateTime'),
                            "parentReference": item.get('parentReference'),
                            "rawData": item
                        })

        # === Teams & Chats ===
        elif source == 'teams':
            if not parent_id:
                # Root: 「参加しているチーム」と「チャット」の2つの入り口を表示
                items.append({
                    "id": "root_teams_list",
                    "name": "参加しているチーム",
                    "type": "folder", # 仮想フォルダ
                    "isContainer": True,
                    "subType": "joined_teams"
                })
                items.append({
                    "id": "root_chats_list",
                    "name": "チャット (個人/グループ/会議)",
                    "type": "folder", # 仮想フォルダ
                    "isContainer": True,
                    "subType": "chats"
                })

            # --- チーム一覧の取得 ---
            elif parent_id == "root_teams_list":
                resp = requests.get("https://graph.microsoft.com/v1.0/me/joinedTeams", headers=headers)
                if resp.ok:
                    for team in resp.json().get('value', []):
                        items.append({
                            "id": team['id'], "name": team.get('displayName'), 
                            "type": "team", "isContainer": True,
                            "teamId": team['id'],
                            "rawData": team
                        })

            # --- チャット一覧の取得 ---
            elif parent_id == "root_chats_list":
                # 【修正】件数を20に絞り、メンバー情報を展開($expand)して取得する
                url = "https://graph.microsoft.com/v1.0/me/chats?$expand=members&$top=20"
                
                logger.info(f"Fetching chats from: {url}")
                resp = requests.get(url, headers=headers)
                
                if resp.ok:
                    chats = resp.json().get('value', [])
                    # 更新日時順にソート
                    chats.sort(key=lambda x: x.get('lastUpdatedDateTime', ''), reverse=True)
                    
                    for chat in chats:
                        chat_name = chat.get('topic')
                        chat_type = chat.get('chatType')
                        
                        # 【修正】トピックがない場合、メンバー名からチャット名を生成する
                        if not chat_name:
                            members = chat.get('members', [])
                            # 自分以外のメンバー名を抽出（簡易実装）
                            member_names = [
                                m.get('displayName') 
                                for m in members 
                                if 'displayName' in m
                            ]
                            # メンバーがいれば名前を連結、いなければ「名称未設定」
                            if member_names:
                                chat_name = ", ".join(member_names)
                            else:
                                chat_name = "名称未設定チャット"

                        # アイコン設定など（既存コード）
                        prefix = "👤" if chat_type == 'oneOnOne' else ("📅" if chat_type == 'meeting' else "👥")

                        items.append({
                            "id": chat['id'], 
                            "name": f"{prefix} {chat_name}",
                            "type": "chat", 
                            "isContainer": True,
                            "chatId": chat['id'], # ChatIDを保持
                            "lastUpdated": chat.get('lastUpdatedDateTime'),
                            "rawData": chat
                        })
                else:
                    logger.error(f"Failed to fetch chats: {resp.status_code} - {resp.text}")

            # --- チーム -> チャネル一覧 ---
            elif parent_type == 'team':
                # parent_id が teamId
                resp = requests.get(f"https://graph.microsoft.com/v1.0/teams/{parent_id}/channels", headers=headers)
                if resp.ok:
                    for ch in resp.json().get('value', []):
                        items.append({
                            "id": ch['id'], "name": ch.get('displayName'), 
                            "type": "channel", "isContainer": True,
                            "teamId": parent_id,
                            "rawData": ch
                        })

            # --- チャネル -> メッセージ一覧 ---
            elif parent_type == 'channel':
                current_team_id = team_id 
                if not current_team_id:
                    return jsonify({"error": "Team ID is missing"}), 400
                
                url = f"https://graph.microsoft.com/v1.0/teams/{current_team_id}/channels/{parent_id}/messages?$top=50"
                resp = requests.get(url, headers=headers)
                if resp.ok:
                    messages = resp.json().get('value', [])
                    for msg in messages:
                        if msg.get('messageType') == 'message' or not msg.get('messageType'):
                            body_content = msg.get('body', {}).get('content', '')
                            clean_body = re.sub(r'<[^>]+>', '', body_content).strip()
                            if not clean_body: clean_body = "(画像/添付ファイル)"
                            
                            sender = (msg.get('from', {}).get('user', {}) or {}).get('displayName', 'Unknown')
                            
                            items.append({
                                "id": msg['id'],
                                "name": f"{sender}: {clean_body[:60]}...",
                                "type": "teams_message",
                                "isContainer": False,
                                "date": msg.get('createdDateTime'),
                                "teamId": current_team_id,
                                "channelId": parent_id,
                                "rawData": {
                                    "channelIdentity": {"teamId": current_team_id, "channelId": parent_id},
                                    "summary": clean_body[:100],
                                    "body": msg.get('body')
                                }
                            })

            # --- チャット -> メッセージ一覧 ---
            elif parent_type == 'chat':
                # parent_id が chatId
                url = f"https://graph.microsoft.com/v1.0/chats/{parent_id}/messages?$top=50"
                resp = requests.get(url, headers=headers)
                if resp.ok:
                    messages = resp.json().get('value', [])
                    for msg in messages:
                        if msg.get('messageType') == 'message' or not msg.get('messageType'):
                            body_content = msg.get('body', {}).get('content', '')
                            clean_body = re.sub(r'<[^>]+>', '', body_content).strip()
                            if not clean_body: clean_body = "(画像/添付ファイル)"
                            
                            sender = (msg.get('from', {}).get('user', {}) or {}).get('displayName', 'Unknown')
                            
                            items.append({
                                "id": msg['id'],
                                "name": f"{sender}: {clean_body[:60]}...",
                                "type": "teams_message", # 共通のタイプで扱う
                                "isContainer": False,
                                "date": msg.get('createdDateTime'),
                                "chatId": parent_id, # ChatIDを紐付け
                                "rawData": {
                                    "chatId": parent_id,
                                    "summary": clean_body[:100],
                                    "body": msg.get('body')
                                }
                            })

        # === Outlook ===
        elif source == 'outlook':
            if not parent_id:
                # Root: Mail Folders
                resp = requests.get("https://graph.microsoft.com/v1.0/me/mailFolders", headers=headers)
                if resp.ok:
                    for folder in resp.json().get('value', []):
                        items.append({
                            "id": folder['id'], "name": folder.get('displayName'), 
                            "type": "folder", "isContainer": True,
                            "rawData": folder
                        })
            elif parent_type == 'folder':
                # Folder -> [Child Folders] AND [Messages]
                
                # 1. Child Folders (サブフォルダ)
                folders_url = f"https://graph.microsoft.com/v1.0/me/mailFolders/{parent_id}/childFolders"
                resp_folders = requests.get(folders_url, headers=headers)
                if resp_folders.ok:
                    for folder in resp_folders.json().get('value', []):
                        items.append({
                            "id": folder['id'], "name": f"📁 {folder.get('displayName')}", 
                            "type": "folder", "isContainer": True,
                            "rawData": folder
                        })

                # 2. Messages (メール)
                msgs_url = f"https://graph.microsoft.com/v1.0/me/mailFolders/{parent_id}/messages?$top=50&$select=id,subject,receivedDateTime,from,bodyPreview"
                resp_msgs = requests.get(msgs_url, headers=headers)
                if resp_msgs.ok:
                    for msg in resp_msgs.json().get('value', []):
                        subject = msg.get('subject') or "(No Subject)"
                        sender = (msg.get('from', {}).get('emailAddress', {}) or {}).get('name', 'Unknown')
                        items.append({
                            "id": msg['id'], 
                            "name": f"{subject} ({sender})", 
                            "type": "mail", 
                            "isContainer": False,
                            "date": msg.get('receivedDateTime'),
                            "rawData": msg
                        })

    except Exception as e:
        logger.error(f"Browse API Error: {e}", exc_info=True)
        return jsonify({"error": str(e)}), 500

    return jsonify({"items": items})

# --- 会議設定API ---
@app.route('/api/meeting/setup', methods=['POST'])
def setup_meeting_endpoint():
    sid = request.form.get('sid')
    if not sid:
        return jsonify({"error": "Session ID (sid) is required"}), 400

    purpose = request.form.get('purpose', '')
    try:
        interval = int(request.form.get('interval', 20))
    except ValueError:
        interval = 20
    
    try:
        duration = int(request.form.get('duration', 60))
    except ValueError:
        duration = 60

    uploaded_files = request.files.getlist('files')
    context_parts = [] # ここにはGCSのURI(types.Part)のみを格納する
    
    # 会議の目的もテキストファイルとしてGCSに保存推奨だが、短いのでここはテキストPartにする
    if purpose:
        context_parts.append(types.Part.from_text(text=f"【会議の目的】\n{purpose}"))

    gcs_bucket_name = os.environ.get("GOOGLE_CLOUD_STORAGE_BUCKET_NAME")

    # --- 参考資料のGCSアップロード処理 ---
    for file in uploaded_files:
        if file and file.filename:
            # GCS上のパス: meeting_data/{sid}/refs/{filename}
            blob_name = f"meeting_data/{sid}/refs/{secure_filename(file.filename)}"
            
            if gcs_bucket_name:
                file.seek(0)
                gcs_uri = _upload_to_gcs(file, blob_name, gcs_bucket_name)
                
                if gcs_uri:
                    # MIMEタイプを判定
                    mime_type = file.mimetype
                    if not mime_type:
                        import mimetypes
                        mime_type, _ = mimetypes.guess_type(file.filename)
                        if not mime_type: mime_type = "application/pdf"

                    logger.info(f"Uploaded ref to GCS: {gcs_uri}")
                    # メモリにはファイルの中身ではなく、URI参照のみを持つ
                    part = types.Part.from_uri(file_uri=gcs_uri, mime_type=mime_type)
                    context_parts.append(part)
            else:
                logger.error("GCS bucket not configured.")

    user_info = g.user_info

    # ハンドラーのセットアップ呼び出し
    setup_meeting_context(sid, interval, purpose, context_parts, user_info, duration=duration)

    return jsonify({"success": True})

def _get_formatted_glossary_instruction(user_id):
    """
    ユーザーの用語集を取得し、AI向けの指示テキストとして整形して返す。
    """
    if not user_id:
        return ""

    container = get_sessions_container()
    if not container:
        return ""

    try:
        settings_id = f"settings_{user_id}"
        item = container.read_item(item=settings_id, partition_key=user_id)
        glossary = item.get('glossary', [])
        
        if not glossary:
            return ""

        # AIへの指示プロンプト形式を構築
        instruction = "\n\n## 用語集 (表記指定)\n以下の用語は、出力時の表記統一ルールとしてのみ使用してください。用語の説明文を本文に追記したり、文脈を変更したりしないでください。\n"
        for entry in glossary:
            term = entry.get('term', '')
            reading = entry.get('reading', '')
            meaning = entry.get('meaning', '')
            
            if term:
                line = f"- {term}"
                if reading:
                    line += f" ({reading})"
                if meaning:
                    line += f": {meaning}"
                instruction += line + "\n"
        
        return instruction

    except cosmos_exceptions.CosmosResourceNotFoundError:
        return ""
    except Exception as e:
        logger.error(f"Failed to load glossary for user {user_id}: {e}")
        return ""

@app.route('/api/settings/glossary', methods=['GET'])
def get_glossary():
    """現在の用語集リストを取得する"""
    user_id = g.user_info.get("userId")
    container = get_sessions_container()
    try:
        settings_id = f"settings_{user_id}"
        item = container.read_item(item=settings_id, partition_key=user_id)
        return jsonify({"glossary": item.get('glossary', [])})
    except cosmos_exceptions.CosmosResourceNotFoundError:
        return jsonify({"glossary": []})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/settings/glossary', methods=['POST'])
def save_glossary():
    """用語集リストを保存する"""
    user_id = g.user_info.get("userId")
    data = request.get_json()
    new_glossary = data.get('glossary', [])

    # 上限チェック
    if len(new_glossary) > config.MAX_GLOSSARY_TERMS:
        return jsonify({"error": f"登録件数が上限({config.MAX_GLOSSARY_TERMS}件)を超えています。"}), 400

    container = get_sessions_container()
    try:
        settings_id = f"settings_{user_id}"
        try:
            item = container.read_item(item=settings_id, partition_key=user_id)
        except cosmos_exceptions.CosmosResourceNotFoundError:
            item = {"id": settings_id, "userId": user_id, "type": "UserSettings"}
        
        item['glossary'] = new_glossary
        container.upsert_item(body=item)
        return jsonify({"success": True, "message": "用語集を保存しました。"})
    except Exception as e:
        logger.error(f"Failed to save glossary: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/settings/glossary/upload', methods=['POST'])
def upload_glossary():
    """Excel/CSVから用語集を読み込む"""
    if 'file' not in request.files:
        return jsonify({"error": "ファイルがありません"}), 400
    
    file = request.files['file']
    filename = file.filename.lower()
    
    try:
        # ファイル読み込み
        if filename.endswith('.csv'):
            df = pd.read_csv(file, encoding='utf-8-sig')
        elif filename.endswith(('.xls', '.xlsx')):
            df = pd.read_excel(file)
        else:
            return jsonify({"error": "対応していないファイル形式です"}), 400

        # カラム名の名寄せ（表記, 読み, 意味）
        # ユーザーが「用語」「内容」などの名前を使っていても拾えるようにする
        col_map = {
            '表記': ['表記', '用語', '単語', 'term', 'word'],
            '読み': ['読み', 'よみ', '読み方', 'reading', 'kana'],
            '意味': ['意味', '内容', '説明', 'meaning', 'description', 'definition']
        }
        
        final_list = []
        for _, row in df.iterrows():
            entry = {}
            for target_col, synonyms in col_map.items():
                # 行の中からsynonymsに合致するカラムを探す
                found_col = next((c for c in df.columns if c in synonyms), None)
                entry[target_col] = str(row[found_col]) if found_col and pd.notna(row[found_col]) else ""
            
            if entry.get('表記'): # 表記がある場合のみ追加
                final_list.append({
                    "term": entry['表記'],
                    "reading": entry['読み'],
                    "meaning": entry['意味']
                })

        # 上限チェック
        if len(final_list) > config.MAX_GLOSSARY_TERMS:
            return jsonify({"error": f"ファイル内の件数が上限({config.MAX_GLOSSARY_TERMS}件)を超えています。"}), 400

        return jsonify({"success": True, "glossary": final_list})

    except Exception as e:
        logger.error(f"Glossary upload error: {e}")
        return jsonify({"error": f"ファイルの解析に失敗しました: {str(e)}"}), 500

